import { useState, useEffect } from "react";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Badge } from "@/components/ui/badge";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogTrigger } from "@/components/ui/dialog";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Plus, User, Trash2, Clock, DollarSign } from "lucide-react";
import { toast } from "sonner";
import { supabase } from "@/integrations/supabase/client";

interface Agenda {
  id: string;
  nome: string;
  tipo: string;
  status: string;
  capacidade_simultanea: number;
  tempo_medio_servico: number;
  disponibilidade: any;
  responsavel_id?: string;
}

export function AgendaColaboradores() {
  const [agendas, setAgendas] = useState<Agenda[]>([]);
  const [loading, setLoading] = useState(true);
  const [dialogOpen, setDialogOpen] = useState(false);
  
  const [formData, setFormData] = useState({
    nome: "",
    tipo: "colaborador",
    capacidade_simultanea: 1,
    tempo_medio_servico: 30,
    horario_inicio: "08:00",
    horario_fim: "18:00",
    dias_semana: ["seg", "ter", "qua", "qui", "sex"],
  });

  useEffect(() => {
    carregarAgendas();
  }, []);

  const carregarAgendas = async () => {
    try {
      const { data, error } = await supabase
        .from('agendas')
        .select('*')
        .order('nome');

      if (error) throw error;
      setAgendas(data || []);
    } catch (error) {
      console.error('Erro ao carregar agendas:', error);
      toast.error("Erro ao carregar agendas");
    } finally {
      setLoading(false);
    }
  };

  const criarAgenda = async () => {
    try {
      const { data: { user } } = await supabase.auth.getUser();
      if (!user) throw new Error("Usuário não autenticado");

      const { data: userRole } = await supabase
        .from('user_roles')
        .select('company_id')
        .eq('user_id', user.id)
        .single();

      if (!userRole?.company_id) throw new Error("Empresa não encontrada");

      const { error } = await supabase
        .from('agendas')
        .insert({
          nome: formData.nome,
          tipo: formData.tipo,
          status: 'ativo',
          capacidade_simultanea: formData.capacidade_simultanea,
          tempo_medio_servico: formData.tempo_medio_servico,
          disponibilidade: {
            dias: formData.dias_semana,
            horario_inicio: formData.horario_inicio,
            horario_fim: formData.horario_fim,
          },
          owner_id: user.id,
          company_id: userRole.company_id,
        });

      if (error) throw error;

      toast.success("Agenda criada com sucesso!");
      setDialogOpen(false);
      carregarAgendas();
      
      // Reset form
      setFormData({
        nome: "",
        tipo: "colaborador",
        capacidade_simultanea: 1,
        tempo_medio_servico: 30,
        horario_inicio: "08:00",
        horario_fim: "18:00",
        dias_semana: ["seg", "ter", "qua", "qui", "sex"],
      });
    } catch (error: any) {
      console.error('Erro ao criar agenda:', error);
      toast.error(error.message || "Erro ao criar agenda");
    }
  };

  const excluirAgenda = async (id: string) => {
    try {
      const { error } = await supabase
        .from('agendas')
        .delete()
        .eq('id', id);

      if (error) throw error;

      toast.success("Agenda excluída");
      carregarAgendas();
    } catch (error: any) {
      console.error('Erro ao excluir agenda:', error);
      toast.error(error.message || "Erro ao excluir agenda");
    }
  };

  const getStatusBadge = (status: string) => {
    return status === 'ativo' 
      ? <Badge className="bg-success">Ativo</Badge>
      : <Badge variant="secondary">Inativo</Badge>;
  };

  const getTipoBadge = (tipo: string) => {
    const badges = {
      colaborador: <Badge variant="outline">Colaborador</Badge>,
      recurso: <Badge variant="outline" className="border-primary text-primary">Recurso</Badge>,
      sala: <Badge variant="outline" className="border-accent text-accent">Sala</Badge>,
    };
    return badges[tipo as keyof typeof badges] || badges.colaborador;
  };

  if (loading) {
    return <div>Carregando...</div>;
  }

  return (
    <div className="space-y-4">
      <div className="flex justify-between items-center">
        <div>
          <h3 className="text-lg font-semibold">Minhas Agendas</h3>
          <p className="text-sm text-muted-foreground">
            Gerencie colaboradores, recursos e salas
          </p>
        </div>
        <Dialog open={dialogOpen} onOpenChange={setDialogOpen}>
          <DialogTrigger asChild>
            <Button>
              <Plus className="h-4 w-4 mr-2" />
              Nova Agenda
            </Button>
          </DialogTrigger>
          <DialogContent className="max-w-2xl">
            <DialogHeader>
              <DialogTitle>Criar Nova Agenda</DialogTitle>
            </DialogHeader>
            <div className="space-y-4">
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-2">
                  <Label>Nome *</Label>
                  <Input
                    placeholder="Ex: Dr. João Silva"
                    value={formData.nome}
                    onChange={(e) => setFormData({ ...formData, nome: e.target.value })}
                  />
                </div>
                
                <div className="space-y-2">
                  <Label>Tipo</Label>
                  <Select
                    value={formData.tipo}
                    onValueChange={(value) => setFormData({ ...formData, tipo: value })}
                  >
                    <SelectTrigger>
                      <SelectValue />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value="colaborador">Colaborador</SelectItem>
                      <SelectItem value="recurso">Recurso</SelectItem>
                      <SelectItem value="sala">Sala</SelectItem>
                    </SelectContent>
                  </Select>
                </div>
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-2">
                  <Label>Capacidade Simultânea</Label>
                  <Input
                    type="number"
                    min="1"
                    value={formData.capacidade_simultanea}
                    onChange={(e) => setFormData({ ...formData, capacidade_simultanea: parseInt(e.target.value) })}
                  />
                  <p className="text-xs text-muted-foreground">
                    Quantos atendimentos ao mesmo tempo
                  </p>
                </div>
                
                <div className="space-y-2">
                  <Label>Tempo Médio (minutos)</Label>
                  <Input
                    type="number"
                    min="5"
                    step="5"
                    value={formData.tempo_medio_servico}
                    onChange={(e) => setFormData({ ...formData, tempo_medio_servico: parseInt(e.target.value) })}
                  />
                  <p className="text-xs text-muted-foreground">
                    Duração média de cada atendimento
                  </p>
                </div>
              </div>

              <div className="space-y-2">
                <Label>Horário de Funcionamento</Label>
                <div className="grid grid-cols-2 gap-4">
                  <Input
                    type="time"
                    value={formData.horario_inicio}
                    onChange={(e) => setFormData({ ...formData, horario_inicio: e.target.value })}
                  />
                  <Input
                    type="time"
                    value={formData.horario_fim}
                    onChange={(e) => setFormData({ ...formData, horario_fim: e.target.value })}
                  />
                </div>
              </div>

              <Button onClick={criarAgenda} className="w-full">
                Criar Agenda
              </Button>
            </div>
          </DialogContent>
        </Dialog>
      </div>

      <div className="grid gap-4 md:grid-cols-2">
        {agendas.map((agenda) => (
          <Card key={agenda.id} className="border-0 shadow-card">
            <CardHeader>
              <div className="flex justify-between items-start">
                <div className="space-y-1">
                  <CardTitle className="flex items-center gap-2">
                    <User className="h-5 w-5" />
                    {agenda.nome}
                  </CardTitle>
                  <div className="flex gap-2">
                    {getTipoBadge(agenda.tipo)}
                    {getStatusBadge(agenda.status)}
                  </div>
                </div>
                <Button
                  variant="ghost"
                  size="icon"
                  onClick={() => excluirAgenda(agenda.id)}
                  className="text-destructive hover:text-destructive hover:bg-destructive/10"
                >
                  <Trash2 className="h-4 w-4" />
                </Button>
              </div>
            </CardHeader>
            <CardContent className="space-y-2">
              <div className="flex items-center gap-2 text-sm text-muted-foreground">
                <User className="h-4 w-4" />
                <span>Capacidade: {agenda.capacidade_simultanea} simultâneos</span>
              </div>
              <div className="flex items-center gap-2 text-sm text-muted-foreground">
                <Clock className="h-4 w-4" />
                <span>Tempo médio: {agenda.tempo_medio_servico} min</span>
              </div>
              {agenda.disponibilidade && (
                <div className="flex items-center gap-2 text-sm text-muted-foreground">
                  <Clock className="h-4 w-4" />
                  <span>
                    {agenda.disponibilidade.horario_inicio} - {agenda.disponibilidade.horario_fim}
                  </span>
                </div>
              )}
            </CardContent>
          </Card>
        ))}
      </div>

      {agendas.length === 0 && (
        <Card className="border-dashed">
          <CardContent className="flex flex-col items-center justify-center py-12">
            <User className="h-12 w-12 text-muted-foreground mb-4" />
            <h3 className="text-lg font-semibold mb-2">Nenhuma agenda criada</h3>
            <p className="text-muted-foreground text-center mb-4">
              Crie agendas para colaboradores, recursos ou salas
            </p>
            <Button onClick={() => setDialogOpen(true)}>
              <Plus className="h-4 w-4 mr-2" />
              Criar Primeira Agenda
            </Button>
          </CardContent>
        </Card>
      )}
    </div>
  );
}

import { useState, useEffect } from "react";
import { Pencil, CalendarIcon } from "lucide-react";
import { Button } from "@/components/ui/button";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogTrigger,
} from "@/components/ui/dialog";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import {
  Popover,
  PopoverContent,
  PopoverTrigger,
} from "@/components/ui/popover";
import { Calendar } from "@/components/ui/calendar";
import { Switch } from "@/components/ui/switch";
import { supabase } from "@/integrations/supabase/client";
import { toast } from "sonner";
import { format, parseISO } from "date-fns";
import { ptBR } from "date-fns/locale";
import { cn } from "@/lib/utils";

interface Compromisso {
  id: string;
  lead_id?: string;
  data_hora_inicio: string;
  data_hora_fim: string;
  tipo_servico: string;
  observacoes?: string;
  custo_estimado?: number;
  status: string;
}

interface Lead {
  id: string;
  name: string;
  phone?: string;
}

interface EditarCompromissoDialogProps {
  compromisso: Compromisso;
  onCompromissoUpdated: () => void;
}

export function EditarCompromissoDialog({
  compromisso,
  onCompromissoUpdated,
}: EditarCompromissoDialogProps) {
  const [open, setOpen] = useState(false);
  const [leads, setLeads] = useState<Lead[]>([]);
  const [errors, setErrors] = useState<Record<string, string>>({});
  
  const [leadId, setLeadId] = useState(compromisso.lead_id || "");
  const [data, setData] = useState<Date>(parseISO(compromisso.data_hora_inicio));
  const [horaInicio, setHoraInicio] = useState(
    format(parseISO(compromisso.data_hora_inicio), "HH:mm")
  );
  const [horaFim, setHoraFim] = useState(
    format(parseISO(compromisso.data_hora_fim), "HH:mm")
  );
  const [tipoServico, setTipoServico] = useState(compromisso.tipo_servico);
  const [observacoes, setObservacoes] = useState(compromisso.observacoes || "");
  const [custoEstimado, setCustoEstimado] = useState(
    compromisso.custo_estimado?.toString() || ""
  );

  useEffect(() => {
    if (open) {
      loadLeads();
      resetForm();
    }
  }, [open, compromisso]);

  const resetForm = () => {
    setLeadId(compromisso.lead_id || "");
    setData(parseISO(compromisso.data_hora_inicio));
    setHoraInicio(format(parseISO(compromisso.data_hora_inicio), "HH:mm"));
    setHoraFim(format(parseISO(compromisso.data_hora_fim), "HH:mm"));
    setTipoServico(compromisso.tipo_servico);
    setObservacoes(compromisso.observacoes || "");
    setCustoEstimado(compromisso.custo_estimado?.toString() || "");
    setErrors({});
  };

  const loadLeads = async () => {
    try {
      const { data, error } = await supabase
        .from("leads")
        .select("id, name, phone")
        .order("name");

      if (error) throw error;
      setLeads(data || []);
    } catch (error) {
      console.error("Erro ao carregar leads:", error);
    }
  };

  const validateForm = () => {
    const newErrors: Record<string, string> = {};

    // Validar data
    const hoje = new Date();
    hoje.setHours(0, 0, 0, 0);
    const dataSelecionada = new Date(data);
    dataSelecionada.setHours(0, 0, 0, 0);

    if (dataSelecionada < hoje && compromisso.status === 'agendado') {
      newErrors.data = "A data não pode ser no passado para compromissos agendados";
    }

    // Validar horários
    const [horaInicioH, horaInicioM] = horaInicio.split(":").map(Number);
    const [horaFimH, horaFimM] = horaFim.split(":").map(Number);
    const minutosInicio = horaInicioH * 60 + horaInicioM;
    const minutosFim = horaFimH * 60 + horaFimM;

    if (minutosFim <= minutosInicio) {
      newErrors.horaFim = "Horário de término deve ser após o início";
    }

    if (minutosFim - minutosInicio < 15) {
      newErrors.horaFim = "Compromisso deve ter no mínimo 15 minutos";
    }

    // Validar tipo de serviço
    if (!tipoServico.trim()) {
      newErrors.tipoServico = "Tipo de serviço é obrigatório";
    }

    // Validar observações
    if (observacoes.length > 500) {
      newErrors.observacoes = "Observações devem ter no máximo 500 caracteres";
    }

    // Validar custo
    if (custoEstimado && parseFloat(custoEstimado) < 0) {
      newErrors.custoEstimado = "Valor não pode ser negativo";
    }

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleSubmit = async () => {
    if (!validateForm()) {
      toast.error("Corrija os erros antes de salvar");
      return;
    }

    try {
      const dataFormatada = format(data, "yyyy-MM-dd");
      const dataHoraInicio = new Date(`${dataFormatada}T${horaInicio}`);
      const dataHoraFim = new Date(`${dataFormatada}T${horaFim}`);

      const { error } = await supabase
        .from("compromissos")
        .update({
          lead_id: leadId || null,
          data_hora_inicio: dataHoraInicio.toISOString(),
          data_hora_fim: dataHoraFim.toISOString(),
          tipo_servico: tipoServico.trim(),
          observacoes: observacoes.trim(),
          custo_estimado: custoEstimado ? parseFloat(custoEstimado) : null,
        })
        .eq("id", compromisso.id);

      if (error) throw error;

      toast.success("Compromisso atualizado com sucesso!");
      setOpen(false);
      setErrors({});
      onCompromissoUpdated();
    } catch (error) {
      console.error("Erro ao atualizar compromisso:", error);
      toast.error("Erro ao atualizar compromisso");
    }
  };

  return (
    <Dialog open={open} onOpenChange={setOpen}>
      <DialogTrigger asChild>
        <Button
          variant="ghost"
          size="sm"
          onClick={(e) => e.stopPropagation()}
          className="h-8 w-8 p-0"
        >
          <Pencil className="h-4 w-4" />
        </Button>
      </DialogTrigger>
      <DialogContent className="max-w-2xl max-h-[90vh] overflow-y-auto">
        <DialogHeader>
          <DialogTitle>Editar Compromisso</DialogTitle>
        </DialogHeader>
        <div className="space-y-4">
          <div>
            <Label>Cliente / Lead</Label>
            <Select value={leadId} onValueChange={setLeadId}>
              <SelectTrigger>
                <SelectValue placeholder="Selecione um cliente" />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value="">Nenhum</SelectItem>
                {leads.map((lead) => (
                  <SelectItem key={lead.id} value={lead.id}>
                    {lead.name} {lead.phone && `(${lead.phone})`}
                  </SelectItem>
                ))}
              </SelectContent>
            </Select>
          </div>

          <div>
            <Label>Data *</Label>
            <Popover>
              <PopoverTrigger asChild>
                <Button
                  variant="outline"
                  className={cn(
                    "w-full justify-start text-left font-normal",
                    !data && "text-muted-foreground",
                    errors.data && "border-destructive"
                  )}
                >
                  <CalendarIcon className="mr-2 h-4 w-4" />
                  {data ? format(data, "PPP", { locale: ptBR }) : "Selecione a data"}
                </Button>
              </PopoverTrigger>
              <PopoverContent className="w-auto p-0" align="start">
                <Calendar
                  mode="single"
                  selected={data}
                  onSelect={(newDate) => {
                    if (newDate) {
                      setData(newDate);
                      if (errors.data) setErrors({ ...errors, data: "" });
                    }
                  }}
                  locale={ptBR}
                  initialFocus
                  className="pointer-events-auto"
                />
              </PopoverContent>
            </Popover>
            {errors.data && (
              <p className="text-xs text-destructive mt-1">{errors.data}</p>
            )}
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div>
              <Label>Horário de início *</Label>
              <Input
                type="time"
                value={horaInicio}
                onChange={(e) => {
                  setHoraInicio(e.target.value);
                  if (errors.horaInicio) setErrors({ ...errors, horaInicio: "" });
                }}
                className={errors.horaInicio ? "border-destructive" : ""}
              />
              {errors.horaInicio && (
                <p className="text-xs text-destructive mt-1">{errors.horaInicio}</p>
              )}
            </div>
            <div>
              <Label>Horário de término *</Label>
              <Input
                type="time"
                value={horaFim}
                onChange={(e) => {
                  setHoraFim(e.target.value);
                  if (errors.horaFim) setErrors({ ...errors, horaFim: "" });
                }}
                className={errors.horaFim ? "border-destructive" : ""}
              />
              {errors.horaFim && (
                <p className="text-xs text-destructive mt-1">{errors.horaFim}</p>
              )}
            </div>
          </div>

          <div>
            <Label>Tipo de serviço *</Label>
            <Select value={tipoServico} onValueChange={setTipoServico}>
              <SelectTrigger className={errors.tipoServico ? "border-destructive" : ""}>
                <SelectValue />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value="reuniao">Reunião</SelectItem>
                <SelectItem value="consultoria">Consultoria</SelectItem>
                <SelectItem value="atendimento">Atendimento</SelectItem>
                <SelectItem value="visita">Visita</SelectItem>
                <SelectItem value="apresentacao">Apresentação</SelectItem>
                <SelectItem value="outro">Outro</SelectItem>
              </SelectContent>
            </Select>
            {errors.tipoServico && (
              <p className="text-xs text-destructive mt-1">{errors.tipoServico}</p>
            )}
          </div>

          <div>
            <Label>Valor estimado (R$)</Label>
            <Input
              type="number"
              step="0.01"
              placeholder="0.00"
              value={custoEstimado}
              onChange={(e) => {
                setCustoEstimado(e.target.value);
                if (errors.custoEstimado) setErrors({ ...errors, custoEstimado: "" });
              }}
              className={errors.custoEstimado ? "border-destructive" : ""}
            />
            {errors.custoEstimado && (
              <p className="text-xs text-destructive mt-1">{errors.custoEstimado}</p>
            )}
          </div>

          <div>
            <Label>Observações</Label>
            <Textarea
              placeholder="Observações internas sobre o compromisso..."
              value={observacoes}
              onChange={(e) => {
                setObservacoes(e.target.value);
                if (errors.observacoes) setErrors({ ...errors, observacoes: "" });
              }}
              rows={3}
              className={errors.observacoes ? "border-destructive" : ""}
            />
            {errors.observacoes && (
              <p className="text-xs text-destructive mt-1">{errors.observacoes}</p>
            )}
            <p className="text-xs text-muted-foreground mt-1">
              {observacoes.length}/500 caracteres
            </p>
          </div>

          <Button onClick={handleSubmit} className="w-full">
            Salvar Alterações
          </Button>
        </div>
      </DialogContent>
    </Dialog>
  );
}

import { useState } from "react";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Badge } from "@/components/ui/badge";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogTrigger } from "@/components/ui/dialog";
import { 
  Send, 
  Users, 
  Calendar,
  Image as ImageIcon,
  FileText,
  Loader2,
  Check,
  Filter
} from "lucide-react";
import { toast } from "sonner";

export function DisparoEmMassa() {
  const [campanhaOpen, setCampanhaOpen] = useState(false);
  const [loading, setLoading] = useState(false);
  const [formData, setFormData] = useState({
    nome: "",
    tipo: "texto",
    mensagem: "",
    segmentacao: "todos",
    agendamento: "",
    arquivo: null as File | null,
  });

  const campanhasRecentes = [
    {
      id: "1",
      nome: "Promoção Black Friday",
      status: "enviada",
      total: 150,
      lidos: 123,
      respondidos: 45,
      data: "2024-01-15",
    },
    {
      id: "2",
      nome: "Follow-up Pendentes",
      status: "agendada",
      total: 78,
      data: "2024-01-20",
    },
  ];

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      if (file.size > 20 * 1024 * 1024) {
        toast.error("Arquivo muito grande. Máximo 20MB");
        return;
      }
      setFormData({ ...formData, arquivo: file });
      toast.success("Arquivo anexado com sucesso");
    }
  };

  const handleEnviar = async () => {
    if (!formData.mensagem.trim()) {
      toast.error("Digite uma mensagem");
      return;
    }

    setLoading(true);

    try {
      // Simular envio
      await new Promise(resolve => setTimeout(resolve, 2000));
      
      toast.success(`Campanha ${formData.agendamento ? 'agendada' : 'enviada'} com sucesso!`);
      setCampanhaOpen(false);
      
      // Reset form
      setFormData({
        nome: "",
        tipo: "texto",
        mensagem: "",
        segmentacao: "todos",
        agendamento: "",
        arquivo: null,
      });
    } catch (error: any) {
      toast.error("Erro ao enviar campanha");
    } finally {
      setLoading(false);
    }
  };

  const getStatusBadge = (status: string) => {
    const badges = {
      enviada: <Badge className="bg-success">Enviada</Badge>,
      agendada: <Badge className="bg-info">Agendada</Badge>,
      rascunho: <Badge variant="outline">Rascunho</Badge>,
    };
    return badges[status as keyof typeof badges];
  };

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <div>
          <h2 className="text-2xl font-bold">Disparo em Massa</h2>
          <p className="text-muted-foreground">Envie mensagens segmentadas via WhatsApp</p>
        </div>
        <Dialog open={campanhaOpen} onOpenChange={setCampanhaOpen}>
          <DialogTrigger asChild>
            <Button>
              <Send className="h-4 w-4 mr-2" />
              Nova Campanha
            </Button>
          </DialogTrigger>
          <DialogContent className="max-w-2xl max-h-[90vh] overflow-y-auto">
            <DialogHeader>
              <DialogTitle>Criar Campanha de Disparo</DialogTitle>
            </DialogHeader>
            <div className="space-y-4">
              <div className="space-y-2">
                <Label>Nome da Campanha *</Label>
                <Input
                  placeholder="Ex: Promoção Janeiro 2024"
                  value={formData.nome}
                  onChange={(e) => setFormData({ ...formData, nome: e.target.value })}
                />
              </div>

              <div className="space-y-2">
                <Label>Tipo de Mídia</Label>
                <Select 
                  value={formData.tipo} 
                  onValueChange={(value) => setFormData({ ...formData, tipo: value })}
                >
                  <SelectTrigger>
                    <SelectValue />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="texto">Apenas Texto</SelectItem>
                    <SelectItem value="imagem">Imagem + Texto</SelectItem>
                    <SelectItem value="video">Vídeo + Texto</SelectItem>
                    <SelectItem value="documento">Documento + Texto</SelectItem>
                  </SelectContent>
                </Select>
              </div>

              {formData.tipo !== "texto" && (
                <div className="space-y-2">
                  <Label>Arquivo</Label>
                  <div className="flex items-center gap-2">
                    <Input
                      type="file"
                      accept={
                        formData.tipo === "imagem" ? "image/*" :
                        formData.tipo === "video" ? "video/*" :
                        ".pdf,.doc,.docx"
                      }
                      onChange={handleFileChange}
                    />
                    {formData.arquivo && (
                      <Badge className="bg-success">
                        <Check className="h-3 w-3 mr-1" />
                        Anexado
                      </Badge>
                    )}
                  </div>
                  <p className="text-xs text-muted-foreground">Tamanho máximo: 20MB</p>
                </div>
              )}

              <div className="space-y-2">
                <Label>Mensagem *</Label>
                <Textarea
                  placeholder="Digite a mensagem que será enviada..."
                  value={formData.mensagem}
                  onChange={(e) => setFormData({ ...formData, mensagem: e.target.value })}
                  rows={6}
                />
                <div className="flex items-center justify-between text-xs text-muted-foreground">
                  <span>Use variáveis: {'{nome}'}, {'{empresa}'}, {'{valor}'}</span>
                  <span>{formData.mensagem.length}/4096 caracteres</span>
                </div>
              </div>

              <div className="space-y-2">
                <Label>Segmentação</Label>
                <Select 
                  value={formData.segmentacao} 
                  onValueChange={(value) => setFormData({ ...formData, segmentacao: value })}
                >
                  <SelectTrigger>
                    <SelectValue />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="todos">Todos os leads</SelectItem>
                    <SelectItem value="etapa_novo">Leads: Novos</SelectItem>
                    <SelectItem value="etapa_qualificado">Leads: Qualificados</SelectItem>
                    <SelectItem value="tag_cliente">Tag: Cliente</SelectItem>
                    <SelectItem value="tag_interesse">Tag: Interesse</SelectItem>
                    <SelectItem value="sem_resposta">Sem resposta há 7 dias</SelectItem>
                  </SelectContent>
                </Select>
                <p className="text-xs text-muted-foreground">
                  <Users className="h-3 w-3 inline mr-1" />
                  Aproximadamente 150 contatos serão alcançados
                </p>
              </div>

              <div className="space-y-2">
                <Label>Agendamento (Opcional)</Label>
                <Input
                  type="datetime-local"
                  value={formData.agendamento}
                  onChange={(e) => setFormData({ ...formData, agendamento: e.target.value })}
                />
                <p className="text-xs text-muted-foreground">
                  Deixe em branco para enviar imediatamente
                </p>
              </div>

              <div className="p-4 bg-warning/10 border border-warning/20 rounded-lg">
                <p className="text-sm">
                  <strong>⚠️ Importante:</strong> Respeite as regras do WhatsApp para evitar bloqueios:
                </p>
                <ul className="text-xs space-y-1 mt-2 ml-4">
                  <li>• Envie apenas para contatos que autorizaram</li>
                  <li>• Evite spam ou mensagens não solicitadas</li>
                  <li>• Respeite horários comerciais</li>
                </ul>
              </div>

              <div className="flex gap-2">
                <Button
                  variant="outline"
                  onClick={() => setCampanhaOpen(false)}
                  disabled={loading}
                  className="flex-1"
                >
                  Cancelar
                </Button>
                <Button
                  onClick={handleEnviar}
                  disabled={loading || !formData.mensagem.trim()}
                  className="flex-1"
                >
                  {loading ? (
                    <>
                      <Loader2 className="h-4 w-4 mr-2 animate-spin" />
                      Enviando...
                    </>
                  ) : formData.agendamento ? (
                    <>
                      <Calendar className="h-4 w-4 mr-2" />
                      Agendar Envio
                    </>
                  ) : (
                    <>
                      <Send className="h-4 w-4 mr-2" />
                      Enviar Agora
                    </>
                  )}
                </Button>
              </div>
            </div>
          </DialogContent>
        </Dialog>
      </div>

      {/* Estatísticas */}
      <div className="grid gap-4 md:grid-cols-3">
        <Card className="border-0 shadow-card">
          <CardHeader className="pb-3">
            <CardTitle className="text-sm font-medium text-muted-foreground">
              Campanhas Enviadas
            </CardTitle>
          </CardHeader>
          <CardContent>
            <div className="text-3xl font-bold">12</div>
            <p className="text-xs text-muted-foreground mt-1">Neste mês</p>
          </CardContent>
        </Card>

        <Card className="border-0 shadow-card">
          <CardHeader className="pb-3">
            <CardTitle className="text-sm font-medium text-muted-foreground">
              Taxa de Abertura
            </CardTitle>
          </CardHeader>
          <CardContent>
            <div className="text-3xl font-bold text-primary">82%</div>
            <p className="text-xs text-muted-foreground mt-1">Média geral</p>
          </CardContent>
        </Card>

        <Card className="border-0 shadow-card">
          <CardHeader className="pb-3">
            <CardTitle className="text-sm font-medium text-muted-foreground">
              Taxa de Resposta
            </CardTitle>
          </CardHeader>
          <CardContent>
            <div className="text-3xl font-bold text-success">34%</div>
            <p className="text-xs text-muted-foreground mt-1">Conversões ativas</p>
          </CardContent>
        </Card>
      </div>

      {/* Campanhas Recentes */}
      <Card className="border-0 shadow-card">
        <CardHeader>
          <CardTitle>Campanhas Recentes</CardTitle>
          <CardDescription>Histórico e performance das últimas campanhas</CardDescription>
        </CardHeader>
        <CardContent>
          <div className="space-y-4">
            {campanhasRecentes.map((campanha) => (
              <div
                key={campanha.id}
                className="flex items-center justify-between p-4 bg-muted/30 rounded-lg hover:bg-muted/50 transition-colors"
              >
                <div className="flex-1">
                  <div className="flex items-center gap-3 mb-2">
                    <h4 className="font-semibold">{campanha.nome}</h4>
                    {getStatusBadge(campanha.status)}
                  </div>
                  {campanha.status === "enviada" ? (
                    <div className="flex items-center gap-4 text-sm text-muted-foreground">
                      <span>{campanha.total} enviadas</span>
                      <span>{campanha.lidos} lidas ({((campanha.lidos! / campanha.total) * 100).toFixed(0)}%)</span>
                      <span>{campanha.respondidos} responderam</span>
                    </div>
                  ) : (
                    <div className="text-sm text-muted-foreground">
                      {campanha.total} destinatários • Agendada para {new Date(campanha.data).toLocaleDateString('pt-BR')}
                    </div>
                  )}
                </div>
                <Button variant="outline" size="sm">
                  Ver Detalhes
                </Button>
              </div>
            ))}
          </div>
        </CardContent>
      </Card>
    </div>
  );
}

import { useState, useEffect } from "react";
import { Dialog, DialogContent, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { supabase } from "@/integrations/supabase/client";
import { useToast } from "@/hooks/use-toast";

interface Company {
  id: string;
  name: string;
  cnpj: string | null;
  plan: string;
  max_users: number;
  max_leads: number;
  settings: any;
}

interface EditarSubcontaDialogProps {
  company: Company;
  open: boolean;
  onOpenChange: (open: boolean) => void;
  onSuccess: () => void;
}

export function EditarSubcontaDialog({ company, open, onOpenChange, onSuccess }: EditarSubcontaDialogProps) {
  const [loading, setLoading] = useState(false);
  const [showRedefinirSenha, setShowRedefinirSenha] = useState(false);
  const [novaSenha, setNovaSenha] = useState("");
  const [userId, setUserId] = useState<string | null>(null);
  const [formData, setFormData] = useState({
    name: "",
    cnpj: "",
    email: "",
    telefone: "",
    responsavel: "",
    plan: "basic",
    max_users: 5,
    max_leads: 1000,
  });
  const { toast } = useToast();

  useEffect(() => {
    if (company) {
      setFormData({
        name: company.name,
        cnpj: company.cnpj || "",
        email: company.settings?.email || "",
        telefone: company.settings?.telefone || "",
        responsavel: company.settings?.responsavel || "",
        plan: company.plan,
        max_users: company.max_users,
        max_leads: company.max_leads,
      });
      
      // Buscar user_id do admin da empresa
      loadAdminUser();
    }
  }, [company]);

  const loadAdminUser = async () => {
    try {
      const { data } = await supabase
        .from('user_roles')
        .select('user_id')
        .eq('company_id', company.id)
        .eq('role', 'company_admin')
        .single();
      
      if (data) {
        setUserId(data.user_id);
      }
    } catch (error) {
      console.error('Erro ao buscar user_id:', error);
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);

    try {
      const { error } = await supabase
        .from("companies")
        .update({
          name: formData.name,
          cnpj: formData.cnpj,
          plan: formData.plan,
          max_users: formData.max_users,
          max_leads: formData.max_leads,
          settings: {
            email: formData.email,
            telefone: formData.telefone,
            responsavel: formData.responsavel,
          },
        })
        .eq("id", company.id);

      if (error) throw error;

      toast({
        title: "Subconta atualizada",
        description: "As informações foram atualizadas com sucesso.",
      });

      onSuccess();
      onOpenChange(false);
    } catch (error: any) {
      toast({
        title: "Erro ao atualizar subconta",
        description: error.message,
        variant: "destructive",
      });
    } finally {
      setLoading(false);
    }
  };

  const handleRedefinirSenha = async () => {
    if (!novaSenha || novaSenha.length < 6) {
      toast({
        title: "Erro",
        description: "A senha deve ter no mínimo 6 caracteres",
        variant: "destructive",
      });
      return;
    }

    if (!userId) {
      toast({
        title: "Erro",
        description: "Usuário não encontrado",
        variant: "destructive",
      });
      return;
    }

    setLoading(true);
    try {
      const { error } = await supabase.functions.invoke('redefinir-senha-subconta', {
        body: {
          userId,
          novaSenha,
          notificar: true,
          email: formData.email,
          telefone: formData.telefone,
          nome: formData.responsavel,
        },
      });

      if (error) throw error;

      toast({
        title: "Senha redefinida",
        description: "A nova senha foi enviada por email e WhatsApp",
      });

      setShowRedefinirSenha(false);
      setNovaSenha("");
    } catch (error: any) {
      toast({
        title: "Erro ao redefinir senha",
        description: error.message,
        variant: "destructive",
      });
    } finally {
      setLoading(false);
    }
  };

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="max-w-2xl">
        <DialogHeader>
          <DialogTitle>Editar Subconta</DialogTitle>
        </DialogHeader>
        <form onSubmit={handleSubmit} className="space-y-4">
          <div className="grid grid-cols-2 gap-4">
            <div className="space-y-2">
              <Label htmlFor="name">Nome da Empresa *</Label>
              <Input
                id="name"
                value={formData.name}
                onChange={(e) => setFormData({ ...formData, name: e.target.value })}
                required
              />
            </div>
            <div className="space-y-2">
              <Label htmlFor="cnpj">CNPJ</Label>
              <Input
                id="cnpj"
                value={formData.cnpj}
                onChange={(e) => setFormData({ ...formData, cnpj: e.target.value })}
              />
            </div>
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div className="space-y-2">
              <Label htmlFor="email">E-mail *</Label>
              <Input
                id="email"
                type="email"
                value={formData.email}
                onChange={(e) => setFormData({ ...formData, email: e.target.value })}
                required
              />
            </div>
            <div className="space-y-2">
              <Label htmlFor="telefone">Telefone *</Label>
              <Input
                id="telefone"
                value={formData.telefone}
                onChange={(e) => setFormData({ ...formData, telefone: e.target.value })}
                required
              />
            </div>
          </div>

          <div className="space-y-2">
            <Label htmlFor="responsavel">Responsável *</Label>
            <Input
              id="responsavel"
              value={formData.responsavel}
              onChange={(e) => setFormData({ ...formData, responsavel: e.target.value })}
              required
            />
          </div>

          <div className="grid grid-cols-3 gap-4">
            <div className="space-y-2">
              <Label htmlFor="plan">Plano</Label>
              <Select
                value={formData.plan}
                onValueChange={(value) => setFormData({ ...formData, plan: value })}
              >
                <SelectTrigger>
                  <SelectValue />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="free">Free</SelectItem>
                  <SelectItem value="basic">Padrão</SelectItem>
                  <SelectItem value="premium">Premium</SelectItem>
                </SelectContent>
              </Select>
            </div>
            <div className="space-y-2">
              <Label htmlFor="max_users">Limite de Usuários</Label>
              <Input
                id="max_users"
                type="number"
                value={formData.max_users}
                onChange={(e) => setFormData({ ...formData, max_users: parseInt(e.target.value) })}
              />
            </div>
            <div className="space-y-2">
              <Label htmlFor="max_leads">Limite de Leads</Label>
              <Input
                id="max_leads"
                type="number"
                value={formData.max_leads}
                onChange={(e) => setFormData({ ...formData, max_leads: parseInt(e.target.value) })}
              />
            </div>
          </div>

          {showRedefinirSenha ? (
            <div className="space-y-4 p-4 border rounded-lg bg-muted/50">
              <h4 className="font-semibold">Redefinir Senha do Administrador</h4>
              <div className="space-y-2">
                <Label htmlFor="nova-senha">Nova Senha *</Label>
                <Input
                  id="nova-senha"
                  type="text"
                  placeholder="Digite a nova senha (mín. 6 caracteres)"
                  value={novaSenha}
                  onChange={(e) => setNovaSenha(e.target.value)}
                  minLength={6}
                />
              </div>
              <div className="flex gap-2">
                <Button
                  type="button"
                  variant="outline"
                  onClick={() => {
                    setShowRedefinirSenha(false);
                    setNovaSenha("");
                  }}
                >
                  Cancelar
                </Button>
                <Button type="button" onClick={handleRedefinirSenha} disabled={loading}>
                  {loading ? "Redefinindo..." : "Confirmar Nova Senha"}
                </Button>
              </div>
              <p className="text-xs text-muted-foreground">
                ✉️ A nova senha será enviada automaticamente por email e WhatsApp
              </p>
            </div>
          ) : (
            <Button
              type="button"
              variant="outline"
              onClick={() => setShowRedefinirSenha(true)}
              className="w-full"
            >
              🔐 Redefinir Senha do Administrador
            </Button>
          )}

          <div className="flex justify-end gap-2">
            <Button type="button" variant="outline" onClick={() => onOpenChange(false)}>
              Cancelar
            </Button>
            <Button type="submit" disabled={loading}>
              {loading ? "Salvando..." : "Salvar Alterações"}
            </Button>
          </div>
        </form>
      </DialogContent>
    </Dialog>
  );
}

import { useState } from "react";
import { Dialog, DialogContent, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Checkbox } from "@/components/ui/checkbox";
import { supabase } from "@/integrations/supabase/client";
import { useToast } from "@/hooks/use-toast";

interface NovaSubcontaDialogProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  onSuccess: () => void;
}

export function NovaSubcontaDialog({ open, onOpenChange, onSuccess }: NovaSubcontaDialogProps) {
  const [loading, setLoading] = useState(false);
  const [formData, setFormData] = useState({
    name: "",
    cnpj: "",
    email: "",
    telefone: "",
    responsavel: "",
    plan: "basic",
    max_users: 5,
    max_leads: 1000,
  });
  const [isTestAccount, setIsTestAccount] = useState(false);
  const [showCredentials, setShowCredentials] = useState(false);
  const [credentials, setCredentials] = useState({
    email: "",
    password: "",
    url: "",
    companyName: "",
  });
  const { toast } = useToast();

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);

    try {
      const companyData = {
        name: isTestAccount ? "Empresa Teste CEUSIA" : formData.name,
        cnpj: isTestAccount ? "00.000.000/0001-00" : formData.cnpj,
        plan: isTestAccount ? "premium" : formData.plan,
        status: "active",
        max_users: isTestAccount ? 50 : formData.max_users,
        max_leads: isTestAccount ? 10000 : formData.max_leads,
        settings: {
          email: isTestAccount ? "teste@ceusia.app" : formData.email,
          telefone: isTestAccount ? "(00) 0000-0000" : formData.telefone,
          responsavel: isTestAccount ? "Administrador Teste" : formData.responsavel,
        },
      };

      console.log("🏢 [NOVA SUBCONTA] Iniciando criação:", companyData);

      // 1. Criar a empresa
      const { data: company, error: companyError } = await supabase
        .from("companies")
        .insert([companyData])
        .select()
        .single();

      if (companyError) {
        console.error("❌ [NOVA SUBCONTA] Erro ao criar empresa:", companyError);
        throw companyError;
      }

      console.log("✅ [NOVA SUBCONTA] Empresa criada:", company.id);

      // 2. Gerar senha automática forte
      const generatedPassword = Math.random().toString(36).slice(-10) + Math.random().toString(36).slice(-10).toUpperCase() + "!@#123";
      const adminEmail = isTestAccount ? "admin@ceusia.app" : formData.email;

      console.log("👤 [NOVA SUBCONTA] Criando usuário admin:", adminEmail);
      
      // 3. Criar usuário administrador
      const { data: authUser, error: authError } = await supabase.auth.signUp({
        email: adminEmail,
        password: generatedPassword,
        options: {
          data: {
            full_name: isTestAccount ? "Administrador Teste" : formData.responsavel,
          },
          emailRedirectTo: `${window.location.origin}/`,
        },
      });

      if (authError) {
        console.error("❌ [NOVA SUBCONTA] Erro ao criar usuário:", authError);
        // Remover empresa se falhar
        await supabase.from("companies").delete().eq("id", company.id);
        throw authError;
      }

      console.log("✅ [NOVA SUBCONTA] Usuário criado:", authUser.user?.id);

      // 4. Vincular usuário à empresa como company_admin
      if (authUser.user) {
        const { error: roleError } = await supabase
          .from("user_roles")
          .insert([
            {
              user_id: authUser.user.id,
              company_id: company.id,
              role: "company_admin",
            },
          ]);

        if (roleError) {
          console.error("❌ [NOVA SUBCONTA] Erro ao criar role:", roleError);
          throw roleError;
        }
        
        console.log("✅ [NOVA SUBCONTA] Role criada com sucesso");
      }

      // 5. Enviar credenciais por email e WhatsApp
      console.log("📧 [NOVA SUBCONTA] Enviando credenciais...");
      
      try {
        const { error: envioError } = await supabase.functions.invoke('enviar-credenciais-subconta', {
          body: {
            nome: formData.responsavel,
            email: adminEmail,
            senha: generatedPassword,
            telefone: formData.telefone,
            nomeConta: companyData.name,
            url: window.location.origin,
          },
        });

        if (envioError) {
          console.error("⚠️ [NOVA SUBCONTA] Erro ao enviar credenciais:", envioError);
          toast({
            title: "⚠️ Atenção",
            description: "Subconta criada, mas houve erro ao enviar credenciais automaticamente.",
            variant: "destructive",
          });
        } else {
          console.log("✅ [NOVA SUBCONTA] Credenciais enviadas com sucesso");
        }
      } catch (envioError) {
        console.error("⚠️ [NOVA SUBCONTA] Exceção ao enviar credenciais:", envioError);
      }

      // 6. Preparar credenciais de acesso para exibição
      const accessUrl = window.location.origin;
      
      setCredentials({
        email: adminEmail,
        password: generatedPassword,
        url: accessUrl,
        companyName: companyData.name,
      });

      setShowCredentials(true);

      console.log("🎉 [NOVA SUBCONTA] Subconta criada com sucesso!");

      toast({
        title: "Subconta criada com sucesso! ✅",
        description: `${companyData.name} foi criada. Credenciais enviadas por email e WhatsApp!`,
      });

      onSuccess();
    } catch (error: any) {
      console.error("❌ [NOVA SUBCONTA] Erro completo:", error);
      toast({
        title: "Erro ao criar subconta",
        description: error.message || "Ocorreu um erro desconhecido. Verifique o console.",
        variant: "destructive",
      });
    } finally {
      setLoading(false);
    }
  };

  const handleClose = () => {
    setShowCredentials(false);
    setCredentials({ email: "", password: "", url: "", companyName: "" });
    onOpenChange(false);
    setFormData({
      name: "",
      cnpj: "",
      email: "",
      telefone: "",
      responsavel: "",
      plan: "basic",
      max_users: 5,
      max_leads: 1000,
    });
    setIsTestAccount(false);
  };

  const copyToClipboard = (text: string, label: string) => {
    navigator.clipboard.writeText(text);
    toast({
      title: "Copiado!",
      description: `${label} copiado para a área de transferência.`,
    });
  };

  return (
    <Dialog open={open} onOpenChange={handleClose}>
      <DialogContent className="max-w-2xl max-h-[90vh] overflow-y-auto">
        <DialogHeader>
          <DialogTitle>
            {showCredentials ? "Credenciais de Acesso" : "Nova Subconta"}
          </DialogTitle>
        </DialogHeader>

        {showCredentials ? (
          <div className="space-y-4">
            <div className="rounded-md bg-green-50 dark:bg-green-900/20 p-4 border border-green-200 dark:border-green-800">
              <h3 className="font-semibold text-green-900 dark:text-green-100 mb-2 flex items-center gap-2">
                <span className="text-xl">✅</span>
                Subconta "{credentials.companyName}" criada com sucesso!
              </h3>
              <p className="text-sm text-green-800 dark:text-green-200">
                Copie e guarde as credenciais de acesso abaixo. Esta é a única vez que a senha será exibida!
              </p>
            </div>

            <div className="space-y-3">
              <div className="space-y-2">
                <Label className="text-sm font-medium">URL de Acesso</Label>
                <div className="flex gap-2">
                  <Input value={credentials.url} readOnly className="font-mono text-sm" />
                  <Button
                    type="button"
                    variant="outline"
                    size="sm"
                    onClick={() => copyToClipboard(credentials.url, "URL")}
                  >
                    Copiar
                  </Button>
                </div>
              </div>

              <div className="space-y-2">
                <Label className="text-sm font-medium">E-mail</Label>
                <div className="flex gap-2">
                  <Input value={credentials.email} readOnly className="font-mono text-sm" />
                  <Button
                    type="button"
                    variant="outline"
                    size="sm"
                    onClick={() => copyToClipboard(credentials.email, "E-mail")}
                  >
                    Copiar
                  </Button>
                </div>
              </div>

              <div className="space-y-2">
                <Label className="text-sm font-medium">Senha</Label>
                <div className="flex gap-2">
                  <Input value={credentials.password} readOnly className="font-mono text-sm" />
                  <Button
                    type="button"
                    variant="outline"
                    size="sm"
                    onClick={() => copyToClipboard(credentials.password, "Senha")}
                  >
                    Copiar
                  </Button>
                </div>
              </div>
            </div>

            <div className="rounded-md bg-yellow-50 dark:bg-yellow-900/20 p-3 border border-yellow-200 dark:border-yellow-800">
              <p className="text-xs text-yellow-800 dark:text-yellow-200">
                ⚠️ <strong>Importante:</strong> Guarde estas credenciais em local seguro. A senha não poderá ser recuperada depois!
              </p>
            </div>

            <div className="rounded-md bg-blue-50 dark:bg-blue-900/20 p-4 border border-blue-200 dark:border-blue-800 space-y-2">
              <h4 className="text-sm font-semibold text-blue-900 dark:text-blue-100">
                📱 Próximos Passos - Configurar WhatsApp:
              </h4>
              <ol className="text-xs text-blue-800 dark:text-blue-200 space-y-1 list-decimal list-inside">
                <li>Acesse o sistema com as credenciais acima</li>
                <li>Vá em <strong>Configurações → Integrações</strong></li>
                <li>Clique em <strong>"Nova Instância"</strong> no card WhatsApp</li>
                <li>Escolha entre escanear QR Code ou configurar manualmente</li>
                <li>Configure o webhook na Evolution API para receber mensagens</li>
              </ol>
              <p className="text-xs text-blue-700 dark:text-blue-300 mt-2">
                ✅ Cada subconta terá sua própria instância WhatsApp isolada e independente.
              </p>
            </div>

            <Button onClick={handleClose} className="w-full">
              Fechar
            </Button>
          </div>
        ) : (
          <form onSubmit={handleSubmit} className="space-y-4">
            <div className="flex items-center space-x-2">
              <Checkbox
                id="test"
                checked={isTestAccount}
                onCheckedChange={(checked) => setIsTestAccount(checked as boolean)}
              />
              <Label htmlFor="test">Marcar como Subconta de Teste</Label>
            </div>

            {!isTestAccount && (
              <>
                <div className="grid grid-cols-2 gap-4">
                  <div className="space-y-2">
                    <Label htmlFor="name">Nome da Empresa *</Label>
                    <Input
                      id="name"
                      value={formData.name}
                      onChange={(e) => setFormData({ ...formData, name: e.target.value })}
                      required
                    />
                  </div>
                  <div className="space-y-2">
                    <Label htmlFor="cnpj">CNPJ</Label>
                    <Input
                      id="cnpj"
                      value={formData.cnpj}
                      onChange={(e) => setFormData({ ...formData, cnpj: e.target.value })}
                    />
                  </div>
                </div>

                <div className="grid grid-cols-2 gap-4">
                  <div className="space-y-2">
                    <Label htmlFor="email">E-mail do Administrador *</Label>
                    <Input
                      id="email"
                      type="email"
                      value={formData.email}
                      onChange={(e) => setFormData({ ...formData, email: e.target.value })}
                      required
                    />
                  </div>
                  <div className="space-y-2">
                    <Label htmlFor="telefone">Telefone *</Label>
                    <Input
                      id="telefone"
                      value={formData.telefone}
                      onChange={(e) => setFormData({ ...formData, telefone: e.target.value })}
                      required
                    />
                  </div>
                </div>

                <div className="space-y-2">
                  <Label htmlFor="responsavel">Nome do Responsável *</Label>
                  <Input
                    id="responsavel"
                    value={formData.responsavel}
                    onChange={(e) => setFormData({ ...formData, responsavel: e.target.value })}
                    required
                  />
                </div>

                <div className="grid grid-cols-3 gap-4">
                  <div className="space-y-2">
                    <Label htmlFor="plan">Plano</Label>
                    <Select
                      value={formData.plan}
                      onValueChange={(value) => setFormData({ ...formData, plan: value })}
                    >
                      <SelectTrigger>
                        <SelectValue />
                      </SelectTrigger>
                      <SelectContent>
                        <SelectItem value="free">Free</SelectItem>
                        <SelectItem value="basic">Padrão</SelectItem>
                        <SelectItem value="premium">Premium</SelectItem>
                      </SelectContent>
                    </Select>
                  </div>
                  <div className="space-y-2">
                    <Label htmlFor="max_users">Limite de Usuários</Label>
                    <Input
                      id="max_users"
                      type="number"
                      value={formData.max_users}
                      onChange={(e) => setFormData({ ...formData, max_users: parseInt(e.target.value) })}
                    />
                  </div>
                  <div className="space-y-2">
                    <Label htmlFor="max_leads">Limite de Leads</Label>
                    <Input
                      id="max_leads"
                      type="number"
                      value={formData.max_leads}
                      onChange={(e) => setFormData({ ...formData, max_leads: parseInt(e.target.value) })}
                    />
                  </div>
                </div>
              </>
            )}

            {isTestAccount && (
              <div className="rounded-md bg-muted p-4">
                <p className="text-sm text-muted-foreground">
                  Será criada uma subconta de teste com as seguintes configurações:
                </p>
                <ul className="mt-2 text-sm space-y-1">
                  <li>• Nome: Empresa Teste CEUSIA</li>
                  <li>• E-mail Admin: admin@ceusia.app</li>
                  <li>• Plano: Premium</li>
                  <li>• Limite de Usuários: 50</li>
                  <li>• Limite de Leads: 10.000</li>
                </ul>
              </div>
            )}

            <div className="flex justify-end gap-2">
              <Button type="button" variant="outline" onClick={handleClose}>
                Cancelar
              </Button>
              <Button type="submit" disabled={loading}>
                {loading ? "Criando..." : "Criar Subconta"}
              </Button>
            </div>
          </form>
        )}
      </DialogContent>
    </Dialog>
  );
}

import { useState, useEffect } from "react";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "@/components/ui/table";
import { Plus, Building2, Users, Edit, Power, Trash2, LogIn } from "lucide-react";
import { supabase } from "@/integrations/supabase/client";
import { useToast } from "@/hooks/use-toast";
import { NovaSubcontaDialog } from "./NovaSubcontaDialog";
import { EditarSubcontaDialog } from "./EditarSubcontaDialog";
import { UsuariosSubcontaDialog } from "./UsuariosSubcontaDialog";

interface Company {
  id: string;
  name: string;
  cnpj: string | null;
  plan: string;
  status: string;
  max_users: number;
  max_leads: number;
  settings: any;
  created_at: string;
}

export function SubcontasManager() {
  const [companies, setCompanies] = useState<Company[]>([]);
  const [loading, setLoading] = useState(true);
  const [showNovaDialog, setShowNovaDialog] = useState(false);
  const [editingCompany, setEditingCompany] = useState<Company | null>(null);
  const [managingUsers, setManagingUsers] = useState<Company | null>(null);
  const { toast } = useToast();

  useEffect(() => {
    loadCompanies();
  }, []);

  const loadCompanies = async () => {
    try {
      setLoading(true);
      console.log("🏢 [SUBCONTAS] Carregando empresas...");
      
      const { data, error } = await supabase
        .from("companies")
        .select("*")
        .order("created_at", { ascending: false });

      if (error) {
        console.error("❌ [SUBCONTAS] Erro ao carregar:", error);
        throw error;
      }
      
      console.log("✅ [SUBCONTAS] Empresas carregadas:", data?.length || 0);
      console.log("📊 [SUBCONTAS] Dados:", data);
      
      setCompanies(data || []);
    } catch (error: any) {
      console.error("❌ [SUBCONTAS] Erro completo:", error);
      toast({
        title: "Erro ao carregar subcontas",
        description: error.message,
        variant: "destructive",
      });
    } finally {
      setLoading(false);
    }
  };

  const handleToggleStatus = async (company: Company) => {
    try {
      const newStatus = company.status === "active" ? "inactive" : "active";
      const { error } = await supabase
        .from("companies")
        .update({ status: newStatus })
        .eq("id", company.id);

      if (error) throw error;

      toast({
        title: "Status atualizado",
        description: `Empresa ${newStatus === "active" ? "ativada" : "desativada"} com sucesso.`,
      });

      loadCompanies();
    } catch (error: any) {
      toast({
        title: "Erro ao atualizar status",
        description: error.message,
        variant: "destructive",
      });
    }
  };

  const handleDelete = async (companyId: string) => {
    if (!confirm("Tem certeza que deseja excluir esta subconta? Esta ação não pode ser desfeita.")) {
      return;
    }

    try {
      const { error } = await supabase
        .from("companies")
        .delete()
        .eq("id", companyId);

      if (error) throw error;

      toast({
        title: "Subconta excluída",
        description: "A subconta foi excluída com sucesso.",
      });

      loadCompanies();
    } catch (error: any) {
      toast({
        title: "Erro ao excluir subconta",
        description: error.message,
        variant: "destructive",
      });
    }
  };

  const getPlanBadge = (plan: string) => {
    const variants: Record<string, any> = {
      free: "secondary",
      basic: "default",
      premium: "default",
    };

    return (
      <Badge variant={variants[plan] || "default"}>
        {plan.toUpperCase()}
      </Badge>
    );
  };

  const getStatusBadge = (status: string) => {
    return (
      <Badge variant={status === "active" ? "default" : "secondary"}>
        {status === "active" ? "Ativo" : "Inativo"}
      </Badge>
    );
  };

  return (
    <>
      <Card>
        <CardHeader>
          <div className="flex items-center justify-between">
            <div>
              <CardTitle className="flex items-center gap-2">
                <Building2 className="h-5 w-5" />
                Gestão de Subcontas
              </CardTitle>
              <CardDescription>
                Gerencie as empresas licenciadas do sistema
              </CardDescription>
            </div>
            <Button onClick={() => setShowNovaDialog(true)}>
              <Plus className="mr-2 h-4 w-4" />
              Nova Subconta
            </Button>
          </div>
        </CardHeader>
        <CardContent>
          {loading ? (
            <div className="flex justify-center py-8">
              <div className="h-8 w-8 animate-spin rounded-full border-4 border-primary border-t-transparent" />
            </div>
          ) : companies.length === 0 ? (
            <div className="text-center py-8 text-muted-foreground">
              Nenhuma subconta cadastrada
            </div>
          ) : (
            <Table>
              <TableHeader>
                <TableRow>
                  <TableHead>Empresa</TableHead>
                  <TableHead>CNPJ</TableHead>
                  <TableHead>Responsável</TableHead>
                  <TableHead>Plano</TableHead>
                  <TableHead>Status</TableHead>
                  <TableHead>Data Criação</TableHead>
                  <TableHead className="text-right">Ações</TableHead>
                </TableRow>
              </TableHeader>
              <TableBody>
                {companies.map((company) => (
                  <TableRow key={company.id}>
                    <TableCell className="font-medium">{company.name}</TableCell>
                    <TableCell>{company.cnpj || "-"}</TableCell>
                    <TableCell>{company.settings?.responsavel || "-"}</TableCell>
                    <TableCell>{getPlanBadge(company.plan)}</TableCell>
                    <TableCell>{getStatusBadge(company.status)}</TableCell>
                    <TableCell>
                      {new Date(company.created_at).toLocaleDateString("pt-BR")}
                    </TableCell>
                    <TableCell className="text-right">
                      <div className="flex justify-end gap-2">
                        <Button
                          variant="ghost"
                          size="icon"
                          onClick={() => setManagingUsers(company)}
                          title="Gerenciar usuários"
                        >
                          <Users className="h-4 w-4" />
                        </Button>
                        <Button
                          variant="ghost"
                          size="icon"
                          onClick={() => setEditingCompany(company)}
                          title="Editar"
                        >
                          <Edit className="h-4 w-4" />
                        </Button>
                        <Button
                          variant="ghost"
                          size="icon"
                          onClick={() => handleToggleStatus(company)}
                          title={company.status === "active" ? "Desativar" : "Ativar"}
                        >
                          <Power className="h-4 w-4" />
                        </Button>
                        <Button
                          variant="ghost"
                          size="icon"
                          onClick={() => handleDelete(company.id)}
                          title="Excluir"
                        >
                          <Trash2 className="h-4 w-4" />
                        </Button>
                      </div>
                    </TableCell>
                  </TableRow>
                ))}
              </TableBody>
            </Table>
          )}
        </CardContent>
      </Card>

      <NovaSubcontaDialog
        open={showNovaDialog}
        onOpenChange={setShowNovaDialog}
        onSuccess={loadCompanies}
      />

      {editingCompany && (
        <EditarSubcontaDialog
          company={editingCompany}
          open={!!editingCompany}
          onOpenChange={(open) => !open && setEditingCompany(null)}
          onSuccess={loadCompanies}
        />
      )}

      {managingUsers && (
        <UsuariosSubcontaDialog
          company={managingUsers}
          open={!!managingUsers}
          onOpenChange={(open) => !open && setManagingUsers(null)}
        />
      )}
    </>
  );
}

import { useState, useEffect } from "react";
import { Dialog, DialogContent, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
import { Badge } from "@/components/ui/badge";
import { supabase } from "@/integrations/supabase/client";
import { useToast } from "@/hooks/use-toast";
import { Plus, Trash2, Power } from "lucide-react";

interface Company {
  id: string;
  name: string;
}

interface UserRole {
  id: string;
  user_id: string;
  role: string;
  profiles: {
    full_name: string;
    email: string;
  };
}

interface UsuariosSubcontaDialogProps {
  company: Company;
  open: boolean;
  onOpenChange: (open: boolean) => void;
}

export function UsuariosSubcontaDialog({ company, open, onOpenChange }: UsuariosSubcontaDialogProps) {
  const [users, setUsers] = useState<UserRole[]>([]);
  const [loading, setLoading] = useState(true);
  const [showAddForm, setShowAddForm] = useState(false);
  const [formData, setFormData] = useState({
    email: "",
    full_name: "",
    role: "user",
  });
  const { toast } = useToast();

  useEffect(() => {
    if (open) {
      loadUsers();
    }
  }, [open]);

  const loadUsers = async () => {
    try {
      setLoading(true);
      console.log("Carregando usuários para empresa:", company.id);
      
      // Busca user_roles com profiles em uma única query usando JOIN
      const { data: userRoles, error } = await supabase
        .from("user_roles")
        .select(`
          id,
          user_id,
          role,
          profiles!user_roles_user_id_fkey (
            full_name,
            email
          )
        `)
        .eq("company_id", company.id);

      if (error) {
        console.error("Erro ao buscar user_roles:", error);
        throw error;
      }

      console.log("Usuários carregados:", userRoles);
      setUsers(userRoles as any || []);
    } catch (error: any) {
      console.error("Erro completo ao carregar usuários:", error);
      toast({
        title: "Erro ao carregar usuários",
        description: error.message,
        variant: "destructive",
      });
    } finally {
      setLoading(false);
    }
  };

  const handleAddUser = async (e: React.FormEvent) => {
    e.preventDefault();
    
    try {
      console.log("➕ [USUÁRIOS] Adicionando novo usuário:", formData.email);
      
      // Gerar senha forte automática
      const tempPassword = Math.random().toString(36).slice(-8) + "Aa1!";
      
      // Criar usuário de autenticação
      const { data: authData, error: authError } = await supabase.auth.signUp({
        email: formData.email,
        password: tempPassword,
        options: {
          data: {
            full_name: formData.full_name,
          },
          emailRedirectTo: `${window.location.origin}/`,
        },
      });

      if (authError) {
        console.error("❌ [USUÁRIOS] Erro ao criar auth:", authError);
        throw authError;
      }
      
      if (!authData.user) {
        console.error("❌ [USUÁRIOS] Usuário não retornado");
        throw new Error("Falha ao criar usuário");
      }

      console.log("✅ [USUÁRIOS] Auth criado:", authData.user.id);

      // Criar role do usuário
      const { error: roleError } = await supabase
        .from("user_roles")
        .insert([
          {
            user_id: authData.user.id,
            company_id: company.id,
            role: formData.role as any,
          },
        ]);

      if (roleError) {
        console.error("❌ [USUÁRIOS] Erro ao criar role:", roleError);
        throw roleError;
      }

      console.log("✅ [USUÁRIOS] Role criada com sucesso");

      toast({
        title: "Usuário adicionado",
        description: "O usuário foi adicionado com sucesso. Um e-mail de confirmação foi enviado.",
      });

      setShowAddForm(false);
      setFormData({ email: "", full_name: "", role: "user" });
      loadUsers();
    } catch (error: any) {
      console.error("❌ [USUÁRIOS] Erro completo:", error);
      toast({
        title: "Erro ao adicionar usuário",
        description: error.message,
        variant: "destructive",
      });
    }
  };

  const handleRemoveUser = async (userRoleId: string) => {
    if (!confirm("Tem certeza que deseja remover este usuário?")) {
      return;
    }

    try {
      const { error } = await supabase
        .from("user_roles")
        .delete()
        .eq("id", userRoleId);

      if (error) throw error;

      toast({
        title: "Usuário removido",
        description: "O usuário foi removido da empresa.",
      });

      loadUsers();
    } catch (error: any) {
      toast({
        title: "Erro ao remover usuário",
        description: error.message,
        variant: "destructive",
      });
    }
  };

  const getRoleBadge = (role: string) => {
    const labels: Record<string, string> = {
      super_admin: "Super Admin",
      company_admin: "Administrador",
      gestor: "Gestor",
      vendedor: "Vendedor",
      suporte: "Suporte",
      user: "Usuário",
    };

    return <Badge>{labels[role] || role}</Badge>;
  };

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="max-w-4xl">
        <DialogHeader>
          <DialogTitle>Usuários - {company.name}</DialogTitle>
        </DialogHeader>

        <div className="space-y-4">
          {!showAddForm ? (
            <Button onClick={() => setShowAddForm(true)}>
              <Plus className="mr-2 h-4 w-4" />
              Adicionar Usuário
            </Button>
          ) : (
            <form onSubmit={handleAddUser} className="space-y-4 rounded-md border p-4">
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-2">
                  <Label htmlFor="full_name">Nome Completo *</Label>
                  <Input
                    id="full_name"
                    value={formData.full_name}
                    onChange={(e) => setFormData({ ...formData, full_name: e.target.value })}
                    required
                  />
                </div>
                <div className="space-y-2">
                  <Label htmlFor="email">E-mail *</Label>
                  <Input
                    id="email"
                    type="email"
                    value={formData.email}
                    onChange={(e) => setFormData({ ...formData, email: e.target.value })}
                    required
                  />
                </div>
              </div>
              <div className="space-y-2">
                <Label htmlFor="role">Perfil</Label>
                <Select
                  value={formData.role}
                  onValueChange={(value) => setFormData({ ...formData, role: value })}
                >
                  <SelectTrigger>
                    <SelectValue />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="company_admin">Administrador</SelectItem>
                    <SelectItem value="gestor">Gestor</SelectItem>
                    <SelectItem value="vendedor">Vendedor</SelectItem>
                    <SelectItem value="suporte">Suporte</SelectItem>
                    <SelectItem value="user">Usuário</SelectItem>
                  </SelectContent>
                </Select>
              </div>
              <div className="flex justify-end gap-2">
                <Button type="button" variant="outline" onClick={() => setShowAddForm(false)}>
                  Cancelar
                </Button>
                <Button type="submit">Adicionar</Button>
              </div>
            </form>
          )}

          {loading ? (
            <div className="flex justify-center py-8">
              <div className="h-8 w-8 animate-spin rounded-full border-4 border-primary border-t-transparent" />
            </div>
          ) : users.length === 0 ? (
            <div className="text-center py-8 text-muted-foreground">
              Nenhum usuário cadastrado nesta empresa
            </div>
          ) : (
            <Table>
              <TableHeader>
                <TableRow>
                  <TableHead>Nome</TableHead>
                  <TableHead>E-mail</TableHead>
                  <TableHead>Perfil</TableHead>
                  <TableHead className="text-right">Ações</TableHead>
                </TableRow>
              </TableHeader>
              <TableBody>
                {users.map((user: any) => (
                  <TableRow key={user.id}>
                    <TableCell>{user.profiles?.full_name || "-"}</TableCell>
                    <TableCell>{user.profiles?.email || "-"}</TableCell>
                    <TableCell>{getRoleBadge(user.role)}</TableCell>
                    <TableCell className="text-right">
                      <Button
                        variant="ghost"
                        size="icon"
                        onClick={() => handleRemoveUser(user.id)}
                        title="Remover"
                        className="text-destructive hover:text-destructive hover:bg-destructive/10"
                      >
                        <Trash2 className="h-4 w-4" />
                      </Button>
                    </TableCell>
                  </TableRow>
                ))}
              </TableBody>
            </Table>
          )}
        </div>
      </DialogContent>
    </Dialog>
  );
}

import { useState, useEffect } from "react";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Badge } from "@/components/ui/badge";
import { Loader2, QrCode, CheckCircle, XCircle, RefreshCw, Plus, Trash2, KeyRound } from "lucide-react";
import { toast } from "sonner";
import { supabase } from "@/integrations/supabase/client";
import { ScrollArea } from "@/components/ui/scroll-area";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { Alert, AlertDescription } from "@/components/ui/alert";

export function WhatsAppQRCode() {
  const [loading, setLoading] = useState(false);
  const [connections, setConnections] = useState<any[]>([]);
  const [selectedConnection, setSelectedConnection] = useState<any>(null);
  const [qrCode, setQrCode] = useState<string>("");
  const [instanceName, setInstanceName] = useState("");
  const [showNewInstance, setShowNewInstance] = useState(false);
  const [apiKey, setApiKey] = useState("");
  const [apiUrl, setApiUrl] = useState("https://evolution-evolution-api.kxuvcf.easypanel.host");
  const [creationMode, setCreationMode] = useState<"qrcode" | "manual">("qrcode");

  useEffect(() => {
    loadConnections();
    
    const interval = setInterval(() => {
      loadConnections();
    }, 15000);

    return () => clearInterval(interval);
  }, []);

  const loadConnections = async () => {
    try {
      const { data: { user } } = await supabase.auth.getUser();
      if (!user) return;

      const { data: userRole } = await supabase
        .from('user_roles')
        .select('company_id')
        .eq('user_id', user.id)
        .single();

      if (!userRole?.company_id) return;

      const { data } = await supabase
        .from('whatsapp_connections')
        .select('*')
        .eq('company_id', userRole.company_id)
        .order('created_at', { ascending: false });

      if (data) {
        setConnections(data);
        if (!selectedConnection && data.length > 0) {
          setSelectedConnection(data[0]);
        }
      }
    } catch (error) {
      console.error('Erro ao carregar conexões:', error);
    }
  };

  const generateQRCode = async () => {
    if (!instanceName.trim()) {
      toast.error("Digite um nome para a instância");
      return;
    }

    if (creationMode === "manual") {
      if (!apiKey.trim() || !apiUrl.trim()) {
        toast.error("Preencha API Key e URL da Evolution API");
        return;
      }
    }

    setLoading(true);

    try {
      const { data: { user } } = await supabase.auth.getUser();
      if (!user) throw new Error("Usuário não autenticado");

      const { data: userRole } = await supabase
        .from('user_roles')
        .select('company_id')
        .eq('user_id', user.id)
        .single();

      if (!userRole?.company_id) throw new Error("Empresa não encontrada");

      // Verificar se já existe instância com este nome nesta empresa
      const { data: existingConn } = await supabase
        .from('whatsapp_connections')
        .select('id')
        .eq('company_id', userRole.company_id)
        .eq('instance_name', instanceName.toUpperCase())
        .single();

      if (existingConn) {
        toast.error("Já existe uma instância com este nome nesta empresa");
        setLoading(false);
        return;
      }

      const connectionData = {
        company_id: userRole.company_id,
        instance_name: instanceName.toUpperCase(),
        evolution_api_url: creationMode === "manual" ? apiUrl : "https://evolution-evolution-api.kxuvcf.easypanel.host",
        evolution_api_key: creationMode === "manual" ? apiKey : null,
        status: 'connecting',
        qr_code_expires_at: new Date(Date.now() + 2 * 60 * 1000).toISOString(),
      };

      const { data: conn, error: connError } = await supabase
        .from('whatsapp_connections')
        .insert(connectionData)
        .select()
        .single();

      if (connError) throw connError;
      
      setSelectedConnection(conn);
      
      // Se modo manual, marcar como conectado imediatamente
      if (creationMode === "manual") {
        await supabase
          .from('whatsapp_connections')
          .update({ status: 'connected', last_connected_at: new Date().toISOString() })
          .eq('id', conn.id);
        
        toast.success("Instância configurada manualmente com sucesso!");
        setShowNewInstance(false);
        resetForm();
        loadConnections();
      } else {
        // Gerar QR Code mock (em produção, integrar com Evolution API real)
        const mockQR = `https://api.qrserver.com/v1/create-qr-code/?size=300x300&data=${encodeURIComponent(`whatsapp-${instanceName}-${Date.now()}`)}`;
        setQrCode(mockQR);
        setShowNewInstance(false);
        toast.success("QR Code gerado! Escaneie com seu WhatsApp");
        loadConnections();
      }
    } catch (error: any) {
      console.error('Erro ao criar instância:', error);
      toast.error(error.message || "Erro ao criar instância");
    } finally {
      setLoading(false);
    }
  };

  const resetForm = () => {
    setInstanceName("");
    setApiKey("");
    setApiUrl("https://evolution-evolution-api.kxuvcf.easypanel.host");
    setCreationMode("qrcode");
  };

  const deleteConnection = async (connectionId: string) => {
    try {
      const { error } = await supabase
        .from('whatsapp_connections')
        .delete()
        .eq('id', connectionId);

      if (error) throw error;

      toast.success("Instância removida");
      if (selectedConnection?.id === connectionId) {
        setSelectedConnection(null);
        setQrCode("");
      }
      loadConnections();
    } catch (error: any) {
      console.error('Erro ao deletar:', error);
      toast.error("Erro ao remover instância");
    }
  };

  const getStatusBadge = (status: string) => {
    const badges = {
      disconnected: <Badge variant="outline" className="gap-1"><XCircle className="h-3 w-3" /> Desconectado</Badge>,
      connecting: <Badge variant="secondary" className="gap-1"><Loader2 className="h-3 w-3 animate-spin" /> Conectando...</Badge>,
      connected: <Badge className="gap-1 bg-success"><CheckCircle className="h-3 w-3" /> Conectado</Badge>,
    };
    return badges[status as keyof typeof badges] || badges.disconnected;
  };

  return (
    <Card className="border-0 shadow-card">
      <CardHeader>
        <div className="flex items-center justify-between">
          <div>
            <CardTitle className="flex items-center gap-2">
              <QrCode className="h-5 w-5 text-success" />
              Instâncias WhatsApp
            </CardTitle>
            <CardDescription>
              Gerencie múltiplas conexões WhatsApp via Evolution API
            </CardDescription>
          </div>
          <Button onClick={() => setShowNewInstance(true)} size="sm">
            <Plus className="h-4 w-4 mr-2" />
            Nova Instância
          </Button>
        </div>
      </CardHeader>
      <CardContent className="space-y-4">
        {showNewInstance && (
          <div className="p-4 border rounded-lg space-y-4 bg-muted/50">
            <Alert>
              <AlertDescription className="text-xs">
                <strong>🔒 Isolamento Garantido:</strong> Cada instância é exclusiva desta empresa e não será compartilhada com outras subcontas.
              </AlertDescription>
            </Alert>

            <Tabs value={creationMode} onValueChange={(v) => setCreationMode(v as "qrcode" | "manual")}>
              <TabsList className="grid w-full grid-cols-2">
                <TabsTrigger value="qrcode" className="text-xs">
                  <QrCode className="h-3 w-3 mr-1" /> Escanear QR Code
                </TabsTrigger>
                <TabsTrigger value="manual" className="text-xs">
                  <KeyRound className="h-3 w-3 mr-1" /> Configuração Manual
                </TabsTrigger>
              </TabsList>

              <TabsContent value="qrcode" className="space-y-3 mt-3">
                <div className="space-y-2">
                  <Label>Nome da Instância *</Label>
                  <Input
                    placeholder="Ex: EMPRESA_VENDAS"
                    value={instanceName}
                    onChange={(e) => setInstanceName(e.target.value.toUpperCase().replace(/[^A-Z0-9_]/g, ''))}
                    maxLength={20}
                  />
                  <p className="text-xs text-muted-foreground">
                    Apenas letras, números e underscore. Será único para esta empresa.
                  </p>
                </div>
              </TabsContent>

              <TabsContent value="manual" className="space-y-3 mt-3">
                <div className="space-y-2">
                  <Label>Nome da Instância *</Label>
                  <Input
                    placeholder="Ex: EMPRESA_VENDAS"
                    value={instanceName}
                    onChange={(e) => setInstanceName(e.target.value.toUpperCase().replace(/[^A-Z0-9_]/g, ''))}
                    maxLength={20}
                  />
                </div>

                <div className="space-y-2">
                  <Label>API Key da Evolution API *</Label>
                  <Input
                    type="password"
                    placeholder="Sua API Key da instância"
                    value={apiKey}
                    onChange={(e) => setApiKey(e.target.value)}
                  />
                </div>

                <div className="space-y-2">
                  <Label>URL da Evolution API *</Label>
                  <Input
                    placeholder="https://sua-api.com"
                    value={apiUrl}
                    onChange={(e) => setApiUrl(e.target.value)}
                  />
                </div>

                <Alert>
                  <AlertDescription className="text-xs">
                    Use esta opção se você já tem uma instância configurada na Evolution API e deseja apenas conectá-la ao CRM.
                  </AlertDescription>
                </Alert>
              </TabsContent>
            </Tabs>

            <div className="flex gap-2">
              <Button onClick={generateQRCode} disabled={loading} className="flex-1">
                {loading ? <Loader2 className="h-4 w-4 animate-spin" /> : creationMode === "manual" ? "Conectar" : "Gerar QR Code"}
              </Button>
              <Button variant="outline" onClick={() => {setShowNewInstance(false); resetForm();}}>
                Cancelar
              </Button>
            </div>
          </div>
        )}

        <ScrollArea className="h-[400px]">
          <div className="space-y-3">
            {connections.map((conn) => (
              <div key={conn.id} className="p-4 border rounded-lg space-y-2 hover:bg-muted/50 transition-colors">
                <div className="flex items-center justify-between">
                  <div className="flex items-center gap-3">
                    <QrCode className="h-5 w-5 text-muted-foreground" />
                    <div>
                      <p className="font-semibold">{conn.instance_name}</p>
                      {conn.whatsapp_number && (
                        <p className="text-xs text-muted-foreground">{conn.whatsapp_number}</p>
                      )}
                    </div>
                  </div>
                  <div className="flex items-center gap-2">
                    {getStatusBadge(conn.status)}
                    <Button
                      variant="ghost"
                      size="sm"
                      onClick={() => deleteConnection(conn.id)}
                    >
                      <Trash2 className="h-4 w-4 text-destructive" />
                    </Button>
                  </div>
                </div>
                
                {conn.status === 'connecting' && selectedConnection?.id === conn.id && qrCode && (
                  <div className="mt-3 p-3 bg-background rounded-lg">
                    <img src={qrCode} alt="QR Code" className="w-48 h-48 mx-auto border" />
                    <p className="text-xs text-center mt-2 text-muted-foreground">
                      Escaneie com WhatsApp em até 2 minutos
                    </p>
                  </div>
                )}
                
                {conn.last_connected_at && (
                  <p className="text-xs text-muted-foreground">
                    Última conexão: {new Date(conn.last_connected_at).toLocaleString('pt-BR')}
                  </p>
                )}
              </div>
            ))}
            
            {connections.length === 0 && !showNewInstance && (
              <div className="text-center py-8 text-muted-foreground">
                <QrCode className="h-12 w-12 mx-auto mb-2 opacity-20" />
                <p>Nenhuma instância configurada</p>
                <p className="text-sm">Clique em "Nova Instância" para começar</p>
              </div>
            )}
          </div>
        </ScrollArea>

        <div className="pt-4 border-t space-y-2">
          <p className="text-xs text-muted-foreground">
            <strong>✅ Isolamento por Empresa:</strong> Cada instância criada aqui pertence exclusivamente a esta empresa e não será visível ou acessível por outras subcontas do sistema.
          </p>
          <p className="text-xs text-muted-foreground">
            <strong>📱 Webhook Evolution API:</strong> Configure o webhook na Evolution API para:
          </p>
          <code className="block bg-muted px-2 py-1 rounded text-xs break-all">
            https://dteppsfseusqixuppglh.supabase.co/functions/v1/webhook-conversas
          </code>
          <p className="text-xs text-muted-foreground mt-1">
            O sistema identificará automaticamente a instância pelo nome configurado.
          </p>
        </div>
      </CardContent>
    </Card>
  );
}

import { Button } from "@/components/ui/button";
import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar";
import { Badge } from "@/components/ui/badge";
import { Phone, Video, Info, User, MessageSquare, Instagram, Facebook, FileText, DollarSign, RefreshCw, CheckCircle2, AlertCircle, Loader2, Check, Plus } from "lucide-react";

type SyncStatus = 'synced' | 'syncing' | 'error' | 'idle';

interface ConversationHeaderProps {
  contactName: string;
  channel: "whatsapp" | "instagram" | "facebook";
  avatarUrl?: string;
  produto?: string;
  valor?: string;
  responsavel?: string;
  tags?: string[];
  funnelStage?: string;
  showInfoPanel: boolean;
  onToggleInfoPanel: () => void;
  syncStatus?: SyncStatus;
  leadVinculado?: any;
  verificandoLead?: boolean;
  mostrarBotaoCriarLead?: boolean;
  onCriarLead?: () => void;
}

export function ConversationHeader({
  contactName,
  channel,
  avatarUrl,
  produto,
  valor,
  responsavel,
  tags = [],
  funnelStage,
  showInfoPanel,
  onToggleInfoPanel,
  syncStatus = 'idle',
  leadVinculado,
  verificandoLead = false,
  mostrarBotaoCriarLead = false,
  onCriarLead,
}: ConversationHeaderProps) {
  const getChannelIcon = () => {
    switch (channel) {
      case "whatsapp":
        return <MessageSquare className="h-4 w-4 text-[#25D366]" />;
      case "instagram":
        return <Instagram className="h-4 w-4 text-pink-500" />;
      case "facebook":
        return <Facebook className="h-4 w-4 text-blue-600" />;
      default:
        return <MessageSquare className="h-4 w-4" />;
    }
  };

  const getInitials = (name: string) => {
    return name
      .split(" ")
      .map((n) => n[0])
      .join("")
      .toUpperCase()
      .slice(0, 2);
  };

  const getSyncStatusBadge = () => {
    switch (syncStatus) {
      case 'syncing':
        return (
          <Badge variant="outline" className="gap-1.5 bg-blue-500/10 text-blue-600 border-blue-500/20 animate-pulse">
            <RefreshCw className="h-3 w-3 animate-spin" />
            <span className="text-xs font-medium">Sincronizando...</span>
          </Badge>
        );
      case 'synced':
        return (
          <Badge variant="outline" className="gap-1.5 bg-green-500/10 text-green-600 border-green-500/20">
            <CheckCircle2 className="h-3 w-3" />
            <span className="text-xs font-medium">Sincronizado</span>
          </Badge>
        );
      case 'error':
        return (
          <Badge variant="outline" className="gap-1.5 bg-red-500/10 text-red-600 border-red-500/20">
            <AlertCircle className="h-3 w-3" />
            <span className="text-xs font-medium">Erro na sincronização</span>
          </Badge>
        );
      default:
        return null;
    }
  };

  return (
    <div className="sticky top-0 z-20 bg-background border-b border-border shadow-md backdrop-blur-sm">
      <div className="p-4 space-y-3">
        <div className="flex items-center justify-between">
          <div className="flex items-center gap-3">
            {/* Avatar do Lead com Indicador de Rede */}
            <div className="relative">
              <Avatar className="h-14 w-14 border-2 border-primary/20">
                <AvatarImage src={avatarUrl} alt={contactName} />
                <AvatarFallback className="bg-gradient-to-br from-primary/20 to-primary/10 text-primary font-semibold text-lg">
                  {getInitials(contactName)}
                </AvatarFallback>
              </Avatar>
              {/* Badge da Rede Social */}
              <div className="absolute -bottom-1 -right-1 bg-background rounded-full p-1 border-2 border-background shadow-sm">
                {getChannelIcon()}
              </div>
            </div>
            
            {/* Nome e Canal */}
            <div className="flex flex-col">
              <div className="flex items-center gap-2">
                <h2 className="font-bold text-lg text-foreground">
                  {contactName}
                </h2>
                {getSyncStatusBadge()}
              </div>
              <div className="flex items-center gap-2 text-xs">
                <div className="flex items-center gap-1.5 text-muted-foreground">
                  <div className="w-2 h-2 rounded-full bg-green-500 animate-pulse"></div>
                  <span className="capitalize font-medium">{channel}</span>
                </div>
                
                {/* Badge de Lead Vinculado */}
                {verificandoLead && (
                  <Badge variant="outline" className="gap-1">
                    <Loader2 className="h-3 w-3 animate-spin" />
                    Verificando...
                  </Badge>
                )}
                
                {!verificandoLead && leadVinculado && (
                  <Badge className="gap-1 bg-green-600 hover:bg-green-700">
                    <Check className="h-3 w-3" />
                    Lead Cadastrado
                  </Badge>
                )}
                
                {!verificandoLead && mostrarBotaoCriarLead && onCriarLead && (
                  <Button
                    variant="outline"
                    size="sm"
                    onClick={onCriarLead}
                    className="h-6 text-xs gap-1"
                  >
                    <Plus className="h-3 w-3" />
                    Criar Lead no CRM
                  </Button>
                )}
              </div>
            </div>
          </div>
          
          {/* Ações */}
          <div className="flex items-center gap-1">
            <Button 
              variant="ghost" 
              size="icon"
              className="hover:bg-primary/10"
              title="Ligar"
            >
              <Phone className="h-5 w-5" />
            </Button>
            <Button 
              variant="ghost" 
              size="icon"
              className="hover:bg-primary/10"
              title="Videochamada"
            >
              <Video className="h-5 w-5" />
            </Button>
            <Button 
              variant="ghost" 
              size="icon"
              onClick={onToggleInfoPanel}
              className={showInfoPanel ? "bg-primary/10 text-primary" : "hover:bg-primary/10"}
              title="Informações"
            >
              <Info className="h-5 w-5" />
            </Button>
          </div>
        </div>
        
        {/* Informações do Lead */}
        {(tags.length > 0 || funnelStage || produto || valor || responsavel) && (
          <div className="space-y-2 pt-2 border-t border-border/50">
            {/* Tags */}
            {tags.length > 0 && (
              <div className="flex flex-wrap gap-1.5">
                {tags.map((tag, index) => (
                  <Badge 
                    key={index} 
                    variant="secondary" 
                    className="text-xs px-2 py-0.5"
                  >
                    {tag}
                  </Badge>
                ))}
              </div>
            )}
            
            {/* Dados do Lead */}
            <div className="flex items-center gap-2 flex-wrap">
              {funnelStage && (
                <div className="flex items-center gap-1.5 px-2.5 py-1 bg-purple-500/10 rounded-md">
                  <span className="text-xs font-medium text-purple-700">📊 {funnelStage}</span>
                </div>
              )}
              {produto && (
                <div className="flex items-center gap-1.5 px-2.5 py-1 bg-muted/50 rounded-md">
                  <FileText className="h-3.5 w-3.5 text-primary" />
                  <span className="text-xs font-medium text-foreground">{produto}</span>
                </div>
              )}
              {valor && (
                <div className="flex items-center gap-1.5 px-2.5 py-1 bg-green-500/10 rounded-md">
                  <DollarSign className="h-3.5 w-3.5 text-green-600" />
                  <span className="text-xs font-semibold text-green-700">{valor}</span>
                </div>
              )}
              {responsavel && (
                <div className="flex items-center gap-1.5 px-2.5 py-1 bg-blue-500/10 rounded-md">
                  <User className="h-3.5 w-3.5 text-blue-600" />
                  <span className="text-xs font-medium text-blue-700">{responsavel}</span>
                </div>
              )}
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

import { useState, useEffect } from "react";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogTrigger } from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { FileText, Tag, X, Plus, TrendingUp } from "lucide-react";
import { Badge } from "@/components/ui/badge";
import { supabase } from "@/integrations/supabase/client";
import { toast } from "sonner";

interface EditarInformacoesLeadDialogProps {
  leadId: string | null;
  telefone: string;
  nomeContato: string;
  onLeadUpdated: () => void;
}

export function EditarInformacoesLeadDialog({ 
  leadId, 
  telefone,
  nomeContato,
  onLeadUpdated 
}: EditarInformacoesLeadDialogProps) {
  const [open, setOpen] = useState(false);
  const [loading, setLoading] = useState(false);
  const [funis, setFunis] = useState<any[]>([]);
  const [etapas, setEtapas] = useState<any[]>([]);
  const [etapasFiltradas, setEtapasFiltradas] = useState<any[]>([]);
  const [formData, setFormData] = useState({
    nome: nomeContato,
    telefone: telefone,
    email: "",
    cpf: "",
    valor: "",
    company: "",
    source: "",
    notes: "",
    funil_id: "",
    etapa_id: "",
    tags: [] as string[],
    servico: "",
    segmentacao: ""
  });
  const [newTag, setNewTag] = useState("");

  // Garantir que o dialog está fechado ao carregar nova conversa
  useEffect(() => {
    setOpen(false);
  }, [leadId, telefone]);

  useEffect(() => {
    if (open) {
      carregarDados();
    }
  }, [open]);

  useEffect(() => {
    if (formData.funil_id) {
      const filtered = etapas.filter(e => e.funil_id === formData.funil_id);
      setEtapasFiltradas(filtered);
    }
  }, [formData.funil_id, etapas]);

  const carregarDados = async () => {
    try {
      console.log('🔄 Carregando funis e etapas do banco de dados...');
      
      // Buscar company_id do usuário
      const { data: { session } } = await supabase.auth.getSession();
      if (!session) {
        toast.error("Usuário não autenticado");
        return;
      }

      const { data: userRole } = await supabase
        .from("user_roles")
        .select("company_id")
        .eq("user_id", session.user.id)
        .maybeSingle();

      if (!userRole?.company_id) {
        toast.error("Empresa não encontrada");
        return;
      }

      // Carregar funis da empresa
      const { data: funisData, error: funisError } = await supabase
        .from("funis")
        .select("*")
        .eq("company_id", userRole.company_id)
        .order("criado_em");

      if (funisError) {
        console.error('❌ Erro ao carregar funis:', funisError);
        toast.error("Erro ao carregar funis");
        return;
      }

      console.log('📊 Funis carregados:', funisData?.length || 0, funisData);
      setFunis(funisData || []);

      // Carregar todas as etapas da empresa
      const { data: etapasData, error: etapasError } = await supabase
        .from("etapas")
        .select("*")
        .eq("company_id", userRole.company_id)
        .order("posicao");

      if (etapasError) {
        console.error('❌ Erro ao carregar etapas:', etapasError);
        toast.error("Erro ao carregar etapas");
        return;
      }

      console.log('📍 Etapas carregadas:', etapasData?.length || 0, etapasData);
      setEtapas(etapasData || []);

      // Se existe leadId, carregar os dados completos do lead
      if (leadId) {
        console.log('📋 Carregando dados do lead:', leadId);
        const { data: leadData, error: leadError } = await supabase
          .from("leads")
          .select("*")
          .eq("id", leadId)
          .maybeSingle();

        if (leadError) {
          console.error('❌ Erro ao carregar lead:', leadError);
        }

        if (leadData) {
          console.log('✅ Dados do lead carregados:', {
            nome: leadData.name,
            funil: leadData.funil_id,
            etapa: leadData.etapa_id,
            tags: leadData.tags,
            totalTags: leadData.tags?.length || 0
          });
          
          setFormData({
            nome: leadData.name || nomeContato,
            telefone: leadData.telefone || telefone,
            email: leadData.email || "",
            cpf: leadData.cpf || "",
            valor: leadData.value?.toString() || "",
            company: leadData.company || "",
            source: leadData.source || "",
            notes: leadData.notes || "",
            funil_id: leadData.funil_id || (funisData && funisData.length > 0 ? funisData[0].id : ""),
            etapa_id: leadData.etapa_id || "",
            tags: Array.isArray(leadData.tags) ? leadData.tags : [],
            servico: leadData.servico || "",
            segmentacao: leadData.segmentacao || ""
          });
        }
      } else {
        console.log('ℹ️ Nenhum lead vinculado, iniciando com dados básicos');
        // Resetar para dados básicos da conversa
        setFormData(prev => ({
          ...prev,
          nome: nomeContato,
          telefone: telefone,
          funil_id: funisData && funisData.length > 0 ? funisData[0].id : "",
          etapa_id: "",
          tags: []
        }));
      }

      // Se não há funis, avisar o usuário
      if (!funisData || funisData.length === 0) {
        toast.error("Nenhum funil encontrado. Crie um funil no menu Kanban primeiro.");
      }
    } catch (error) {
      console.error("❌ Erro ao carregar dados:", error);
      toast.error("Erro ao carregar informações do lead");
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    
    if (!formData.nome.trim()) {
      toast.error("Digite o nome do lead");
      return;
    }

    setLoading(true);

    try {
      const { data: { session } } = await supabase.auth.getSession();

      if (!session) {
        toast.error("Usuário não autenticado");
        return;
      }

      // Buscar company_id do usuário
      const { data: userRole } = await supabase
        .from("user_roles")
        .select("company_id")
        .eq("user_id", session.user.id)
        .single();

      if (!userRole?.company_id) {
        toast.error("Empresa não encontrada");
        setLoading(false);
        return;
      }

      // Formatar telefone
      let telefoneFormatado = formData.telefone;
      if (telefoneFormatado) {
        telefoneFormatado = telefoneFormatado.replace(/\D/g, "");
        if (!telefoneFormatado.startsWith("55")) {
          telefoneFormatado = "55" + telefoneFormatado;
        }
      }

      const leadDataToSave = {
        name: formData.nome,
        telefone: telefoneFormatado || null,
        phone: telefoneFormatado || null,
        email: formData.email || null,
        cpf: formData.cpf || null,
        value: formData.valor ? parseFloat(formData.valor) : 0,
        company: formData.company || null,
        source: formData.source || null,
        notes: formData.notes || null,
        etapa_id: formData.etapa_id || null,
        funil_id: formData.funil_id || null,
        tags: formData.tags,
        servico: formData.servico || null,
        segmentacao: formData.segmentacao || null,
        company_id: userRole.company_id,
        owner_id: session.user.id,
        status: "novo",
        stage: "prospeccao"
      };

      if (leadId) {
        // Atualizar lead existente
        console.log('🔄 Atualizando lead:', leadId, {
          tags: leadDataToSave.tags,
          totalTags: leadDataToSave.tags?.length || 0
        });
        
        const { error } = await supabase
          .from("leads")
          .update(leadDataToSave)
          .eq("id", leadId);

        if (error) {
          console.error("❌ Erro ao atualizar lead:", error);
          throw error;
        }

        console.log('✅ Lead atualizado com sucesso');
        toast.success("Informações atualizadas com sucesso!");
      } else {
        // Criar novo lead
        console.log('➕ Criando novo lead com tags:', leadDataToSave.tags);
        
        const { error } = await supabase
          .from("leads")
          .insert([leadDataToSave]);

        if (error) {
          console.error("❌ Erro ao criar lead:", error);
          throw error;
        }

        console.log('✅ Lead criado com sucesso');
        toast.success("Lead criado com sucesso!");
      }

      setOpen(false);
      onLeadUpdated();
    } catch (error) {
      console.error("Erro ao salvar lead:", error);
      toast.error("Erro ao salvar informações. Tente novamente.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <Dialog open={open} onOpenChange={setOpen}>
      <DialogTrigger asChild>
        <Button size="sm" variant="outline" className="w-full mb-2">
          <FileText className="h-3 w-3 mr-2" /> Editar Informações
        </Button>
      </DialogTrigger>
      <DialogContent className="max-w-md max-h-[90vh] overflow-y-auto">
        <DialogHeader>
          <DialogTitle>Informações do Lead</DialogTitle>
          <p className="text-sm text-muted-foreground mt-1">
            {leadId ? 'Edite as informações e mova o lead entre etapas' : 'Adicione o lead ao funil de vendas'}
          </p>
        </DialogHeader>
        <form onSubmit={handleSubmit} className="space-y-4">
          <div className="bg-primary/5 border border-primary/20 rounded-lg p-3 space-y-3">
            <h3 className="text-sm font-semibold text-foreground flex items-center gap-2">
              <TrendingUp className="h-4 w-4" />
              Funil de Vendas
            </h3>
            
            <div>
              <Label htmlFor="funil">Selecione o Funil *</Label>
              <Select 
                value={formData.funil_id} 
                onValueChange={(value) => {
                  console.log('📊 Funil selecionado:', value);
                  const funilSelecionado = funis.find(f => f.id === value);
                  console.log('📊 Funil encontrado:', funilSelecionado?.nome);
                  setFormData({ ...formData, funil_id: value, etapa_id: "" });
                }}
              >
                <SelectTrigger>
                  <SelectValue placeholder={
                    funis.length === 0 
                      ? "Nenhum funil disponível" 
                      : "Escolha um funil de vendas"
                  } />
                </SelectTrigger>
                <SelectContent>
                  {funis.length === 0 ? (
                    <div className="p-2 text-sm text-muted-foreground text-center">
                      <p>Nenhum funil criado</p>
                      <p className="text-xs mt-1">Crie um funil no menu Kanban</p>
                    </div>
                  ) : (
                    funis.map((funil) => (
                      <SelectItem key={funil.id} value={funil.id}>
                        📊 {funil.nome}
                        {funil.descricao && (
                          <span className="text-xs text-muted-foreground ml-2">
                            - {funil.descricao}
                          </span>
                        )}
                      </SelectItem>
                    ))
                  )}
                </SelectContent>
              </Select>
              {funis.length === 0 && (
                <p className="text-xs text-destructive mt-1">
                  ⚠️ Crie um funil no menu Kanban para continuar
                </p>
              )}
            </div>

            <div>
              <Label htmlFor="etapa">
                Selecione a Etapa {leadId ? '(mover lead)' : '(adicionar lead)'} *
              </Label>
              <Select 
                value={formData.etapa_id} 
                onValueChange={(value) => {
                  console.log('📍 Etapa selecionada:', value);
                  setFormData({ ...formData, etapa_id: value });
                }}
                disabled={!formData.funil_id}
              >
                <SelectTrigger>
                  <SelectValue placeholder={
                    !formData.funil_id 
                      ? "Selecione um funil primeiro" 
                      : "Escolha a etapa do funil"
                  } />
                </SelectTrigger>
                <SelectContent>
                  {etapasFiltradas.length === 0 ? (
                    <div className="p-2 text-sm text-muted-foreground">
                      Nenhuma etapa disponível neste funil
                    </div>
                  ) : (
                    etapasFiltradas.map((etapa) => (
                      <SelectItem key={etapa.id} value={etapa.id}>
                        <div className="flex items-center gap-2">
                          <div 
                            className="w-3 h-3 rounded-full" 
                            style={{ backgroundColor: etapa.cor || '#3b82f6' }}
                          />
                          {etapa.nome}
                        </div>
                      </SelectItem>
                    ))
                  )}
                </SelectContent>
              </Select>
              {!formData.funil_id && (
                <p className="text-xs text-muted-foreground mt-1">
                  💡 Selecione um funil para ver as etapas disponíveis
                </p>
              )}
            </div>
          </div>

          <div>
            <Label htmlFor="nome">Nome *</Label>
            <Input
              id="nome"
              value={formData.nome}
              onChange={(e) => setFormData({ ...formData, nome: e.target.value })}
              placeholder="Nome do lead"
              required
            />
          </div>

          <div>
            <Label htmlFor="telefone">Telefone / WhatsApp</Label>
            <Input
              id="telefone"
              type="tel"
              value={formData.telefone}
              onChange={(e) => setFormData({ ...formData, telefone: e.target.value })}
              placeholder="(00) 00000-0000"
            />
          </div>

          <div>
            <Label htmlFor="email">E-mail</Label>
            <Input
              id="email"
              type="email"
              value={formData.email}
              onChange={(e) => setFormData({ ...formData, email: e.target.value })}
              placeholder="email@exemplo.com"
            />
          </div>

          <div>
            <Label htmlFor="cpf">CPF</Label>
            <Input
              id="cpf"
              value={formData.cpf}
              onChange={(e) => setFormData({ ...formData, cpf: e.target.value })}
              placeholder="000.000.000-00"
            />
          </div>

          <div>
            <Label htmlFor="company">Empresa</Label>
            <Input
              id="company"
              value={formData.company}
              onChange={(e) => setFormData({ ...formData, company: e.target.value })}
              placeholder="Nome da empresa"
            />
          </div>

          <div>
            <Label htmlFor="servico">Serviço de Interesse</Label>
            <Input
              id="servico"
              value={formData.servico}
              onChange={(e) => setFormData({ ...formData, servico: e.target.value })}
              placeholder="Ex: Consultoria, Produto X"
            />
          </div>

          <div>
            <Label htmlFor="valor">Valor (R$)</Label>
            <Input
              id="valor"
              type="number"
              step="0.01"
              value={formData.valor}
              onChange={(e) => setFormData({ ...formData, valor: e.target.value })}
              placeholder="0.00"
            />
          </div>

          <div>
            <Label htmlFor="segmentacao">Segmentação</Label>
            <Input
              id="segmentacao"
              value={formData.segmentacao}
              onChange={(e) => setFormData({ ...formData, segmentacao: e.target.value })}
              placeholder="Ex: Empresarial, Residencial"
            />
          </div>

          <div>
            <Label htmlFor="source">Origem</Label>
            <Input
              id="source"
              value={formData.source}
              onChange={(e) => setFormData({ ...formData, source: e.target.value })}
              placeholder="Ex: WhatsApp, Instagram, Indicação"
            />
          </div>

          <div>
            <Label htmlFor="notes">Observações</Label>
            <Textarea
              id="notes"
              value={formData.notes}
              onChange={(e) => setFormData({ ...formData, notes: e.target.value })}
              rows={3}
              placeholder="Informações adicionais sobre o lead"
            />
          </div>

          <div>
            <Label htmlFor="tags">Tags</Label>
            <div className="flex gap-2 mb-2">
              <Input
                id="tags"
                value={newTag}
                onChange={(e) => setNewTag(e.target.value)}
                onKeyDown={(e) => {
                  if (e.key === "Enter") {
                    e.preventDefault();
                    const tagTrimmed = newTag.trim();
                    if (tagTrimmed && !formData.tags.includes(tagTrimmed)) {
                      console.log('➕ Adicionando tag:', tagTrimmed);
                      setFormData({ ...formData, tags: [...formData.tags, tagTrimmed] });
                      setNewTag("");
                    } else if (formData.tags.includes(tagTrimmed)) {
                      toast.error("Esta tag já foi adicionada");
                    }
                  }
                }}
                placeholder="Digite uma tag e pressione Enter"
              />
              <Button
                type="button"
                size="icon"
                onClick={() => {
                  const tagTrimmed = newTag.trim();
                  if (tagTrimmed && !formData.tags.includes(tagTrimmed)) {
                    console.log('➕ Adicionando tag:', tagTrimmed);
                    setFormData({ ...formData, tags: [...formData.tags, tagTrimmed] });
                    setNewTag("");
                  } else if (tagTrimmed && formData.tags.includes(tagTrimmed)) {
                    toast.error("Esta tag já foi adicionada");
                  }
                }}
              >
                <Plus className="h-4 w-4" />
              </Button>
            </div>
            <div className="flex flex-wrap gap-2 min-h-[60px] p-2 border rounded-md bg-muted/20">
              {formData.tags.length === 0 ? (
                <p className="text-xs text-muted-foreground">Nenhuma tag adicionada</p>
              ) : (
                formData.tags.map((tag, index) => (
                  <Badge key={`${tag}-${index}`} variant="secondary" className="gap-1">
                    <Tag className="h-3 w-3" />
                    {tag}
                    <Button
                      type="button"
                      variant="ghost"
                      size="icon"
                      className="h-4 w-4 p-0 hover:bg-transparent"
                      onClick={() => {
                        console.log('🗑️ Removendo tag:', tag);
                        setFormData({ ...formData, tags: formData.tags.filter(t => t !== tag) });
                      }}
                    >
                      <X className="h-3 w-3" />
                    </Button>
                  </Badge>
                ))
              )}
            </div>
            {leadId && (
              <p className="text-xs text-muted-foreground mt-2">
                💡 As tags são sincronizadas com o funil de vendas e menu de leads
              </p>
            )}
          </div>

          <div className="flex gap-2 pt-4">
            <Button type="button" variant="outline" onClick={() => setOpen(false)} className="flex-1">
              Cancelar
            </Button>
            <Button type="submit" disabled={loading} className="flex-1">
              {loading ? "Salvando..." : "Salvar Informações"}
            </Button>
          </div>
        </form>
      </DialogContent>
    </Dialog>
  );
}

import { useState, useRef } from "react";
import { Button } from "@/components/ui/button";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogTrigger } from "@/components/ui/dialog";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import { 
  Paperclip, 
  Image as ImageIcon, 
  File, 
  Video, 
  Mic,
  X,
  Send,
  Loader2
} from "lucide-react";
import { toast } from "sonner";

interface MediaUploadProps {
  onSendMedia: (file: File, caption: string, type: string) => Promise<void>;
}

export function MediaUpload({ onSendMedia }: MediaUploadProps) {
  const [open, setOpen] = useState(false);
  const [selectedFile, setSelectedFile] = useState<File | null>(null);
  const [preview, setPreview] = useState<string>("");
  const [caption, setCaption] = useState("");
  const [uploading, setUploading] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    // Validar tamanho (max 20MB)
    if (file.size > 20 * 1024 * 1024) {
      toast.error("Arquivo muito grande. Máximo 20MB");
      return;
    }

    setSelectedFile(file);

    // Criar preview para imagens e vídeos
    if (file.type.startsWith('image/') || file.type.startsWith('video/')) {
      const reader = new FileReader();
      reader.onload = (e) => {
        setPreview(e.target?.result as string);
      };
      reader.readAsDataURL(file);
    } else {
      setPreview("");
    }
  };

  const getFileType = (file: File): string => {
    if (file.type.startsWith('image/')) return 'image';
    if (file.type.startsWith('video/')) return 'video';
    if (file.type.startsWith('audio/')) return 'audio';
    if (file.type === 'application/pdf') return 'pdf';
    return 'document';
  };

  const handleSend = async () => {
    if (!selectedFile) {
      toast.error("Selecione um arquivo");
      return;
    }

    setUploading(true);
    try {
      const fileType = getFileType(selectedFile);
      await onSendMedia(selectedFile, caption, fileType);
      
      // Resetar formulário
      setSelectedFile(null);
      setPreview("");
      setCaption("");
      setOpen(false);
      
      toast.success("Mídia enviada com sucesso!");
    } catch (error: any) {
      console.error('Erro ao enviar mídia:', error);
      toast.error(error.message || "Erro ao enviar mídia");
    } finally {
      setUploading(false);
    }
  };

  const handleCancel = () => {
    setSelectedFile(null);
    setPreview("");
    setCaption("");
    if (fileInputRef.current) {
      fileInputRef.current.value = "";
    }
  };

  const getFileIcon = () => {
    if (!selectedFile) return <File className="h-8 w-8" />;
    
    const type = getFileType(selectedFile);
    switch(type) {
      case 'image': return <ImageIcon className="h-8 w-8 text-blue-500" />;
      case 'video': return <Video className="h-8 w-8 text-purple-500" />;
      case 'audio': return <Mic className="h-8 w-8 text-green-500" />;
      case 'pdf': return <File className="h-8 w-8 text-red-500" />;
      default: return <File className="h-8 w-8 text-gray-500" />;
    }
  };

  const formatFileSize = (bytes: number): string => {
    if (bytes < 1024) return bytes + ' B';
    if (bytes < 1024 * 1024) return (bytes / 1024).toFixed(1) + ' KB';
    return (bytes / (1024 * 1024)).toFixed(1) + ' MB';
  };

  return (
    <Dialog open={open} onOpenChange={setOpen}>
      <DialogTrigger asChild>
        <Button 
          variant="ghost" 
          size="icon" 
          className="hover:bg-primary/10"
          onClick={(e) => {
            e.stopPropagation();
            setOpen(true);
          }}
        >
          <Paperclip className="h-5 w-5" />
        </Button>
      </DialogTrigger>
      <DialogContent className="max-w-lg">
        <DialogHeader>
          <DialogTitle>Enviar Mídia</DialogTitle>
        </DialogHeader>
        
        <div className="space-y-4">
          {!selectedFile ? (
            <div className="space-y-4">
              <input
                ref={fileInputRef}
                type="file"
                onChange={handleFileSelect}
                className="hidden"
                accept="image/*,video/*,audio/*,.pdf,.doc,.docx,.xls,.xlsx,.zip"
              />
              
              <div className="grid grid-cols-2 gap-3">
                <Button
                  variant="outline"
                  className="h-24 flex-col gap-2"
                  onClick={() => {
                    fileInputRef.current?.click();
                    fileInputRef.current?.setAttribute('accept', 'image/*');
                  }}
                >
                  <ImageIcon className="h-6 w-6 text-blue-500" />
                  <span className="text-sm">Imagem</span>
                </Button>
                
                <Button
                  variant="outline"
                  className="h-24 flex-col gap-2"
                  onClick={() => {
                    fileInputRef.current?.click();
                    fileInputRef.current?.setAttribute('accept', 'video/*');
                  }}
                >
                  <Video className="h-6 w-6 text-purple-500" />
                  <span className="text-sm">Vídeo</span>
                </Button>
                
                <Button
                  variant="outline"
                  className="h-24 flex-col gap-2"
                  onClick={() => {
                    fileInputRef.current?.click();
                    fileInputRef.current?.setAttribute('accept', 'audio/*');
                  }}
                >
                  <Mic className="h-6 w-6 text-green-500" />
                  <span className="text-sm">Áudio</span>
                </Button>
                
                <Button
                  variant="outline"
                  className="h-24 flex-col gap-2"
                  onClick={() => {
                    fileInputRef.current?.click();
                    fileInputRef.current?.setAttribute('accept', '.pdf,.doc,.docx,.xls,.xlsx');
                  }}
                >
                  <File className="h-6 w-6 text-red-500" />
                  <span className="text-sm">Documento</span>
                </Button>
              </div>
              
              <p className="text-xs text-muted-foreground text-center">
                Tamanho máximo: 20MB
              </p>
            </div>
          ) : (
            <div className="space-y-4">
              {/* Preview */}
              <div className="relative">
                {preview && (getFileType(selectedFile) === 'image' || getFileType(selectedFile) === 'video') ? (
                  <div className="rounded-lg overflow-hidden bg-muted">
                    {getFileType(selectedFile) === 'image' ? (
                      <img src={preview} alt="Preview" className="w-full h-auto max-h-64 object-contain" />
                    ) : (
                      <video src={preview} controls className="w-full h-auto max-h-64" />
                    )}
                  </div>
                ) : (
                  <div className="flex items-center gap-3 p-4 bg-muted rounded-lg">
                    {getFileIcon()}
                    <div className="flex-1">
                      <p className="font-medium text-sm">{selectedFile.name}</p>
                      <p className="text-xs text-muted-foreground">{formatFileSize(selectedFile.size)}</p>
                    </div>
                  </div>
                )}
                
                <Button
                  size="icon"
                  variant="destructive"
                  className="absolute top-2 right-2"
                  onClick={handleCancel}
                >
                  <X className="h-4 w-4" />
                </Button>
              </div>

              {/* Caption */}
              <div className="space-y-2">
                <Label>Legenda (opcional)</Label>
                <Textarea
                  placeholder="Adicione uma legenda..."
                  value={caption}
                  onChange={(e) => setCaption(e.target.value)}
                  rows={3}
                />
              </div>

              {/* Actions */}
              <div className="flex gap-2">
                <Button
                  variant="outline"
                  onClick={handleCancel}
                  disabled={uploading}
                  className="flex-1"
                >
                  Cancelar
                </Button>
                <Button
                  onClick={handleSend}
                  disabled={uploading}
                  className="flex-1"
                >
                  {uploading ? (
                    <>
                      <Loader2 className="h-4 w-4 mr-2 animate-spin" />
                      Enviando...
                    </>
                  ) : (
                    <>
                      <Send className="h-4 w-4 mr-2" />
                      Enviar
                    </>
                  )}
                </Button>
              </div>
            </div>
          )}
        </div>
      </DialogContent>
    </Dialog>
  );
}

import { useState, useEffect } from "react";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Avatar, AvatarFallback } from "@/components/ui/avatar";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogTrigger } from "@/components/ui/dialog";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Users, UserPlus, X } from "lucide-react";
import { supabase } from "@/integrations/supabase/client";
import { toast } from "sonner";

interface ResponsaveisManagerProps {
  leadId: string | null;
  responsaveisAtuais?: string[];
  onResponsaveisUpdated: (responsaveis: string[]) => void;
}

export function ResponsaveisManager({ 
  leadId, 
  responsaveisAtuais = [],
  onResponsaveisUpdated 
}: ResponsaveisManagerProps) {
  const [open, setOpen] = useState(false);
  const [usuarios, setUsuarios] = useState<any[]>([]);
  const [novoResponsavel, setNovoResponsavel] = useState("");
  const [responsaveis, setResponsaveis] = useState<string[]>(responsaveisAtuais);
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    setResponsaveis(responsaveisAtuais);
  }, [responsaveisAtuais]);

  useEffect(() => {
    if (open) {
      carregarUsuarios();
    }
  }, [open]);

  const carregarUsuarios = async () => {
    try {
      const { data: { session } } = await supabase.auth.getSession();
      if (!session) return;

      // Buscar usuários da mesma empresa
      const { data: userRole } = await supabase
        .from("user_roles")
        .select("company_id")
        .eq("user_id", session.user.id)
        .maybeSingle();

      if (!userRole?.company_id) return;

      // Buscar IDs dos usuários da empresa
      const { data: userRoles } = await supabase
        .from("user_roles")
        .select("user_id")
        .eq("company_id", userRole.company_id);

      if (!userRoles || userRoles.length === 0) return;

      const userIds = userRoles.map(ur => ur.user_id);

      // Buscar perfis dos usuários
      const { data: profiles } = await supabase
        .from("profiles")
        .select("id, full_name, email")
        .in('id', userIds);

      if (profiles) {
        setUsuarios(profiles);
      }
    } catch (error) {
      console.error("Erro ao carregar usuários:", error);
    }
  };

  const adicionarResponsavel = async () => {
    if (!novoResponsavel) {
      toast.error("Selecione um responsável");
      return;
    }

    const usuario = usuarios.find(u => u.id === novoResponsavel);
    if (!usuario) return;

    const nomeResponsavel = usuario.full_name || usuario.email;

    if (responsaveis.includes(nomeResponsavel)) {
      toast.error("Este responsável já foi adicionado");
      return;
    }

    const novosResponsaveis = [...responsaveis, nomeResponsavel];
    setResponsaveis(novosResponsaveis);
    
    // Se tem leadId, salvar no banco
    if (leadId) {
      setLoading(true);
      try {
        const { error } = await supabase
          .from("leads")
          .update({ 
            notes: `Responsáveis: ${novosResponsaveis.join(', ')}`
          })
          .eq("id", leadId);

        if (error) throw error;

        console.log('✅ Responsável adicionado:', nomeResponsavel);
        toast.success(`${nomeResponsavel} adicionado como responsável`);
      } catch (error) {
        console.error("Erro ao salvar responsável:", error);
        toast.error("Erro ao adicionar responsável");
      } finally {
        setLoading(false);
      }
    }

    onResponsaveisUpdated(novosResponsaveis);
    setNovoResponsavel("");
  };

  const removerResponsavel = async (nome: string) => {
    const novosResponsaveis = responsaveis.filter(r => r !== nome);
    setResponsaveis(novosResponsaveis);

    // Se tem leadId, salvar no banco
    if (leadId) {
      setLoading(true);
      try {
        const { error } = await supabase
          .from("leads")
          .update({ 
            notes: novosResponsaveis.length > 0 
              ? `Responsáveis: ${novosResponsaveis.join(', ')}`
              : ''
          })
          .eq("id", leadId);

        if (error) throw error;

        console.log('🗑️ Responsável removido:', nome);
        toast.success(`${nome} removido dos responsáveis`);
      } catch (error) {
        console.error("Erro ao remover responsável:", error);
        toast.error("Erro ao remover responsável");
      } finally {
        setLoading(false);
      }
    }

    onResponsaveisUpdated(novosResponsaveis);
  };

  return (
    <div>
      <h4 className="text-foreground font-medium mb-2 flex items-center gap-2">
        <Users className="h-4 w-4" /> 
        Responsáveis {responsaveis.length > 0 && `(${responsaveis.length})`}
      </h4>
      
      <div className="flex flex-wrap gap-2 mb-3 min-h-[40px]">
        {responsaveis.length === 0 ? (
          <p className="text-sm text-muted-foreground">Nenhum responsável atribuído</p>
        ) : (
          responsaveis.map((nome, index) => (
            <Badge 
              key={`${nome}-${index}`} 
              variant="secondary" 
              className="gap-2 py-1.5 pr-1"
            >
              <Avatar className="h-5 w-5">
                <AvatarFallback className="text-xs bg-primary/10 text-primary">
                  {nome.charAt(0).toUpperCase()}
                </AvatarFallback>
              </Avatar>
              <span className="text-xs">{nome}</span>
              <Button
                type="button"
                variant="ghost"
                size="icon"
                className="h-5 w-5 p-0 hover:bg-destructive/20 hover:text-destructive rounded-full"
                onClick={() => removerResponsavel(nome)}
                disabled={loading}
              >
                <X className="h-3 w-3" />
              </Button>
            </Badge>
          ))
        )}
      </div>

      <Dialog open={open} onOpenChange={setOpen}>
        <DialogTrigger asChild>
          <Button size="sm" variant="outline" className="w-full">
            <UserPlus className="h-3 w-3 mr-2" /> 
            Adicionar Responsável
          </Button>
        </DialogTrigger>
        <DialogContent className="max-w-sm">
          <DialogHeader>
            <DialogTitle>Adicionar Responsável</DialogTitle>
            <p className="text-sm text-muted-foreground">
              Responsáveis podem visualizar e responder a conversa
            </p>
          </DialogHeader>
          
          <div className="space-y-4">
            <div>
              <Select 
                value={novoResponsavel} 
                onValueChange={setNovoResponsavel}
              >
                <SelectTrigger>
                  <SelectValue placeholder="Selecione um usuário" />
                </SelectTrigger>
                <SelectContent>
                  {usuarios.map((usuario) => (
                    <SelectItem key={usuario.id} value={usuario.id}>
                      <div className="flex items-center gap-2">
                        <Avatar className="h-6 w-6">
                          <AvatarFallback className="text-xs bg-primary/10 text-primary">
                            {(usuario.full_name || usuario.email).charAt(0).toUpperCase()}
                          </AvatarFallback>
                        </Avatar>
                        <div>
                          <p className="text-sm font-medium">{usuario.full_name || usuario.email}</p>
                          {usuario.full_name && (
                            <p className="text-xs text-muted-foreground">{usuario.email}</p>
                          )}
                        </div>
                      </div>
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>

            <div className="flex gap-2">
              <Button 
                variant="outline" 
                onClick={() => setOpen(false)}
                className="flex-1"
              >
                Cancelar
              </Button>
              <Button 
                onClick={adicionarResponsavel}
                disabled={loading || !novoResponsavel}
                className="flex-1"
              >
                {loading ? "Adicionando..." : "Adicionar"}
              </Button>
            </div>
          </div>

          {responsaveis.length > 0 && (
            <div className="border-t pt-4">
              <p className="text-xs font-medium text-muted-foreground mb-2">
                Responsáveis atuais:
              </p>
              <div className="flex flex-wrap gap-2">
                {responsaveis.map((nome, index) => (
                  <Badge 
                    key={`current-${nome}-${index}`} 
                    variant="outline" 
                    className="text-xs"
                  >
                    {nome}
                  </Badge>
                ))}
              </div>
            </div>
          )}
        </DialogContent>
      </Dialog>

      {responsaveis.length > 0 && (
        <p className="text-xs text-muted-foreground mt-2">
          💡 Todos podem visualizar e responder esta conversa
        </p>
      )}
    </div>
  );
}

import { useState } from "react";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { VisualFlowBuilder } from "./VisualFlowBuilder";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { 
  Plus, 
  MessageSquare, 
  User, 
  Calendar, 
  Target,
  ArrowRight,
  Trash2,
  Play,
  Save
} from "lucide-react";
import { Badge } from "@/components/ui/badge";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogTrigger } from "@/components/ui/dialog";
import { toast } from "sonner";

interface FluxoNode {
  id: string;
  type: "trigger" | "action" | "condition";
  label: string;
  config: any;
  next?: string[];
}

interface Fluxo {
  id: string;
  nome: string;
  ativo: boolean;
  nodes: FluxoNode[];
}

export function FluxoAutomacaoBuilder() {
  const [fluxos, setFluxos] = useState<Fluxo[]>([
    {
      id: "1",
      nome: "Boas-vindas Automático",
      ativo: true,
      nodes: [
        { id: "n1", type: "trigger", label: "Nova mensagem WhatsApp", config: { channel: "whatsapp" }, next: ["n2"] },
        { id: "n2", type: "action", label: "Enviar saudação", config: { message: "Olá! Como posso ajudar?" }, next: ["n3"] },
        { id: "n3", type: "action", label: "Criar lead", config: { funil: "Novo" }, next: [] },
      ]
    }
  ]);
  
  const [selectedFluxo, setSelectedFluxo] = useState<Fluxo | null>(null);
  const [editMode, setEditMode] = useState(false);

  const nodeTypes = [
    { value: "trigger", label: "Gatilho", icon: MessageSquare, color: "bg-blue-500" },
    { value: "action", label: "Ação", icon: Play, color: "bg-green-500" },
    { value: "condition", label: "Condição", icon: Target, color: "bg-orange-500" },
  ];

  const triggers = [
    { value: "nova_mensagem", label: "Nova mensagem recebida" },
    { value: "novo_lead", label: "Novo lead criado" },
    { value: "lead_movido", label: "Lead movido no funil" },
    { value: "horario", label: "Em horário específico" },
  ];

  const actions = [
    { value: "enviar_mensagem", label: "Enviar mensagem", icon: MessageSquare },
    { value: "criar_lead", label: "Criar lead", icon: User },
    { value: "criar_tarefa", label: "Criar tarefa", icon: Calendar },
    { value: "mover_funil", label: "Mover no funil", icon: Target },
    { value: "notificar_usuario", label: "Notificar usuário", icon: User },
  ];

  const adicionarNode = (fluxoId: string, tipo: string) => {
    const newNode: FluxoNode = {
      id: `n${Date.now()}`,
      type: tipo as any,
      label: `Novo ${tipo}`,
      config: {},
      next: []
    };

    setFluxos(prev => prev.map(f => {
      if (f.id === fluxoId) {
        return { ...f, nodes: [...f.nodes, newNode] };
      }
      return f;
    }));

    toast.success("Etapa adicionada ao fluxo");
  };

  const removerNode = (fluxoId: string, nodeId: string) => {
    setFluxos(prev => prev.map(f => {
      if (f.id === fluxoId) {
        return { ...f, nodes: f.nodes.filter(n => n.id !== nodeId) };
      }
      return f;
    }));
    toast.success("Etapa removida");
  };

  const toggleFluxo = (fluxoId: string) => {
    setFluxos(prev => prev.map(f => {
      if (f.id === fluxoId) {
        const newStatus = !f.ativo;
        toast.success(newStatus ? "Fluxo ativado" : "Fluxo desativado");
        return { ...f, ativo: newStatus };
      }
      return f;
    }));
  };

  const criarNovoFluxo = () => {
    const novoFluxo: Fluxo = {
      id: `f${Date.now()}`,
      nome: "Novo Fluxo",
      ativo: false,
      nodes: []
    };
    setFluxos(prev => [...prev, novoFluxo]);
    setSelectedFluxo(novoFluxo);
    setEditMode(true);
    toast.success("Novo fluxo criado");
  };

  const getNodeIcon = (type: string) => {
    const nodeType = nodeTypes.find(nt => nt.value === type);
    return nodeType ? nodeType.icon : Play;
  };

  const getNodeColor = (type: string) => {
    const nodeType = nodeTypes.find(nt => nt.value === type);
    return nodeType ? nodeType.color : "bg-gray-500";
  };

  return (
    <div className="space-y-6">
      {editMode && selectedFluxo ? (
        <div>
          <div className="flex justify-between items-center mb-4">
            <h2 className="text-2xl font-bold">Editor Visual - {selectedFluxo.nome}</h2>
            <Button onClick={() => { setEditMode(false); setSelectedFluxo(null); }} variant="outline">
              Voltar para Lista
            </Button>
          </div>
          <VisualFlowBuilder 
            fluxoId={selectedFluxo.id} 
            onSave={() => {
              setEditMode(false);
              setSelectedFluxo(null);
            }}
          />
        </div>
      ) : (
        <>
          <div className="flex justify-between items-center">
            <div>
              <h2 className="text-2xl font-bold">Fluxos de Automação</h2>
              <p className="text-muted-foreground">
                Crie fluxos visuais para automatizar atendimento e processos
              </p>
            </div>
            <Button onClick={criarNovoFluxo}>
              <Plus className="h-4 w-4 mr-2" />
              Novo Fluxo
            </Button>
          </div>

      <div className="grid gap-6 md:grid-cols-2">
        {fluxos.map((fluxo) => (
          <Card key={fluxo.id} className="border-0 shadow-card hover:shadow-lg transition-all">
            <CardHeader>
              <div className="flex items-center justify-between">
                <CardTitle className="text-lg">{fluxo.nome}</CardTitle>
                <div className="flex items-center gap-2">
                  <Badge variant={fluxo.ativo ? "default" : "secondary"}>
                    {fluxo.ativo ? "Ativo" : "Inativo"}
                  </Badge>
                  <Button
                    size="sm"
                    variant={fluxo.ativo ? "outline" : "default"}
                    onClick={() => toggleFluxo(fluxo.id)}
                  >
                    {fluxo.ativo ? "Desativar" : "Ativar"}
                  </Button>
                </div>
              </div>
            </CardHeader>
            <CardContent className="space-y-4">
              <div className="space-y-2">
                {fluxo.nodes.map((node, index) => (
                  <div key={node.id}>
                    <div className="flex items-center gap-3 p-3 bg-muted/50 rounded-lg group hover:bg-muted transition-colors">
                      <div className={`p-2 rounded-lg ${getNodeColor(node.type)}`}>
                        {(() => {
                          const Icon = getNodeIcon(node.type);
                          return <Icon className="h-4 w-4 text-white" />;
                        })()}
                      </div>
                      <div className="flex-1">
                        <p className="text-sm font-medium">{node.label}</p>
                        <p className="text-xs text-muted-foreground">
                          {node.type === "trigger" ? "Gatilho" : 
                           node.type === "action" ? "Ação" : "Condição"}
                        </p>
                      </div>
                      <Button
                        size="icon"
                        variant="ghost"
                        className="opacity-0 group-hover:opacity-100 transition-opacity"
                        onClick={() => removerNode(fluxo.id, node.id)}
                      >
                        <Trash2 className="h-4 w-4 text-destructive" />
                      </Button>
                    </div>
                    {index < fluxo.nodes.length - 1 && (
                      <div className="flex justify-center py-1">
                        <ArrowRight className="h-4 w-4 text-muted-foreground" />
                      </div>
                    )}
                  </div>
                ))}
              </div>

              <Dialog>
                <DialogTrigger asChild>
                  <Button variant="outline" className="w-full">
                    <Plus className="h-4 w-4 mr-2" />
                    Adicionar Etapa
                  </Button>
                </DialogTrigger>
                <DialogContent>
                  <DialogHeader>
                    <DialogTitle>Adicionar Etapa ao Fluxo</DialogTitle>
                  </DialogHeader>
                  <div className="space-y-4">
                    <div className="space-y-2">
                      <Label>Tipo de Etapa</Label>
                      <div className="grid grid-cols-3 gap-2">
                        {nodeTypes.map((tipo) => (
                          <Button
                            key={tipo.value}
                            variant="outline"
                            className="h-auto flex-col gap-2 py-4"
                            onClick={() => {
                              adicionarNode(fluxo.id, tipo.value);
                            }}
                          >
                            <div className={`p-2 rounded-lg ${tipo.color}`}>
                              <tipo.icon className="h-5 w-5 text-white" />
                            </div>
                            <span className="text-xs">{tipo.label}</span>
                          </Button>
                        ))}
                      </div>
                    </div>

                    {selectedFluxo && (
                      <>
                        <div className="space-y-2">
                          <Label>Configurar Gatilho</Label>
                          <Select>
                            <SelectTrigger>
                              <SelectValue placeholder="Selecione o gatilho" />
                            </SelectTrigger>
                            <SelectContent>
                              {triggers.map((t) => (
                                <SelectItem key={t.value} value={t.value}>
                                  {t.label}
                                </SelectItem>
                              ))}
                            </SelectContent>
                          </Select>
                        </div>

                        <div className="space-y-2">
                          <Label>Configurar Ação</Label>
                          <Select>
                            <SelectTrigger>
                              <SelectValue placeholder="Selecione a ação" />
                            </SelectTrigger>
                            <SelectContent>
                              {actions.map((a) => (
                                <SelectItem key={a.value} value={a.value}>
                                  {a.label}
                                </SelectItem>
                              ))}
                            </SelectContent>
                          </Select>
                        </div>

                        <div className="space-y-2">
                          <Label>Mensagem / Conteúdo</Label>
                          <Textarea 
                            placeholder="Digite a mensagem ou conteúdo da ação..."
                            rows={3}
                          />
                        </div>
                      </>
                    )}
                  </div>
                </DialogContent>
              </Dialog>

              <div className="flex gap-2">
                <Button 
                  variant="outline" 
                  size="sm" 
                  className="flex-1"
                  onClick={() => {
                    setSelectedFluxo(fluxo);
                    setEditMode(true);
                  }}
                >
                  <Save className="h-4 w-4 mr-2" />
                  Editor Visual
                </Button>
                <Button 
                  variant="outline" 
                  size="sm" 
                  className="flex-1"
                  onClick={() => {
                    setFluxos(prev => prev.filter(f => f.id !== fluxo.id));
                    toast.success("Fluxo excluído");
                  }}
                >
                  <Trash2 className="h-4 w-4 mr-2" />
                  Excluir
                </Button>
              </div>
            </CardContent>
          </Card>
        ))}
      </div>

      {fluxos.length === 0 && (
        <Card className="border-dashed">
          <CardContent className="flex flex-col items-center justify-center py-12">
            <Play className="h-12 w-12 text-muted-foreground mb-4" />
            <h3 className="text-lg font-semibold mb-2">Nenhum fluxo criado</h3>
            <p className="text-muted-foreground text-center mb-4">
              Crie seu primeiro fluxo de automação para começar
            </p>
            <Button onClick={criarNovoFluxo}>
              <Plus className="h-4 w-4 mr-2" />
              Criar Primeiro Fluxo
            </Button>
          </CardContent>
        </Card>
      )}
        </>
      )}
    </div>
  );
}

import { Node } from 'reactflow';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Label } from '@/components/ui/label';
import { Input } from '@/components/ui/input';
import { Textarea } from '@/components/ui/textarea';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { Switch } from '@/components/ui/switch';
import { Settings2 } from 'lucide-react';

interface NodePropertiesPanelProps {
  selectedNode: Node | null;
  onUpdate: (node: Node) => void;
}

export function NodePropertiesPanel({ selectedNode, onUpdate }: NodePropertiesPanelProps) {
  if (!selectedNode) {
    return (
      <Card className="w-80 border-0 bg-slate-900 text-white">
        <CardContent className="flex flex-col items-center justify-center h-full py-12">
          <Settings2 className="h-12 w-12 text-slate-600 mb-4" />
          <p className="text-sm text-slate-400 text-center">
            Selecione um card no canvas para editar suas propriedades
          </p>
        </CardContent>
      </Card>
    );
  }

  const updateNodeData = (key: string, value: any) => {
    const updatedNode = {
      ...selectedNode,
      data: { ...selectedNode.data, [key]: value },
    };
    onUpdate(updatedNode);
  };

  const renderProperties = () => {
    switch (selectedNode.type) {
      case 'trigger':
        return (
          <>
            <div className="space-y-2">
              <Label className="text-white">Tipo de Gatilho</Label>
              <Select 
                value={selectedNode.data.triggerType} 
                onValueChange={(v) => updateNodeData('triggerType', v)}
              >
                <SelectTrigger className="bg-slate-800 border-slate-700 text-white">
                  <SelectValue />
                </SelectTrigger>
                <SelectContent className="bg-slate-800 border-slate-700">
                  <SelectItem value="nova_mensagem">Nova mensagem recebida</SelectItem>
