import { useState } from "react";
import { Button } from "@/components/ui/button";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogTrigger,
} from "@/components/ui/dialog";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Plus } from "lucide-react";
import { supabase } from "@/integrations/supabase/client";
import { toast } from "sonner";

interface AdicionarEtapaDialogProps {
  funilId: string;
  onEtapaAdded: () => void;
}

const CORES_PADRAO = ["#3b82f6", "#22c55e", "#eab308", "#f97316", "#ef4444", "#8b5cf6", "#ec4899"];

export function AdicionarEtapaDialog({ funilId, onEtapaAdded }: AdicionarEtapaDialogProps) {
  const [open, setOpen] = useState(false);
  const [nome, setNome] = useState("");
  const [cor, setCor] = useState(CORES_PADRAO[0]);
  const [loading, setLoading] = useState(false);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    
    const nomeFormatado = nome.trim();
    
    if (!nomeFormatado) {
      toast.error("Digite o nome da etapa");
      return;
    }

    if (nomeFormatado.length < 3) {
      toast.error("Nome deve ter pelo menos 3 caracteres");
      return;
    }

    if (nomeFormatado.length > 50) {
      toast.error("Nome deve ter no máximo 50 caracteres");
      return;
    }

    setLoading(true);

    try {
      // Pegar company_id do usuário
      const { data: userData } = await supabase.auth.getUser();
      if (!userData.user) throw new Error("Usuário não autenticado");

      const { data: userRole } = await supabase
        .from("user_roles")
        .select("company_id")
        .eq("user_id", userData.user.id)
        .single();

      if (!userRole) throw new Error("Empresa não encontrada");

      // Verificar se já existe etapa com mesmo nome neste funil
      const { data: etapaExistente } = await supabase
        .from("etapas")
        .select("id")
        .eq("funil_id", funilId)
        .ilike("nome", nomeFormatado)
        .maybeSingle();

      if (etapaExistente) {
        toast.error("Já existe uma etapa com este nome neste funil");
        setLoading(false);
        return;
      }

      // Buscar maior posição atual
      const { data: etapas } = await supabase
        .from("etapas")
        .select("posicao")
        .eq("funil_id", funilId)
        .order("posicao", { ascending: false })
        .limit(1);

      const novaPosicao = etapas && etapas.length > 0 ? etapas[0].posicao + 1 : 0;

      // Criar nova etapa
      const { error } = await supabase.from("etapas").insert({
        nome: nomeFormatado,
        cor,
        posicao: novaPosicao,
        funil_id: funilId,
        company_id: userRole.company_id,
      });

      if (error) throw error;

      toast.success(`Etapa "${nomeFormatado}" adicionada com sucesso!`);
      setNome("");
      setCor(CORES_PADRAO[0]);
      setOpen(false);
      onEtapaAdded();
    } catch (error: any) {
      console.error("Erro ao adicionar etapa:", error);
      toast.error(error.message || "Erro ao adicionar etapa");
    } finally {
      setLoading(false);
    }
  };

  return (
    <Dialog open={open} onOpenChange={setOpen}>
      <DialogTrigger asChild>
        <Button variant="outline" size="sm">
          <Plus className="h-4 w-4 mr-2" />
          Nova Etapa
        </Button>
      </DialogTrigger>
      <DialogContent>
        <DialogHeader>
          <DialogTitle>Adicionar Nova Etapa</DialogTitle>
        </DialogHeader>
        <form onSubmit={handleSubmit} className="space-y-4">
          <div>
            <Label htmlFor="nome">Nome da Etapa *</Label>
            <Input
              id="nome"
              value={nome}
              onChange={(e) => setNome(e.target.value)}
              placeholder="Ex: Qualificação, Negociação, Fechamento"
              disabled={loading}
              maxLength={50}
              required
            />
            <p className="text-xs text-muted-foreground mt-1">
              {nome.length}/50 caracteres
            </p>
          </div>

          <div>
            <Label>Cor da Etapa</Label>
            <div className="flex gap-2 mt-2 flex-wrap">
              {CORES_PADRAO.map((corPadrao) => (
                <button
                  key={corPadrao}
                  type="button"
                  className="w-10 h-10 rounded-lg border-2 transition-all hover:scale-110 shadow-sm"
                  style={{
                    backgroundColor: corPadrao,
                    borderColor: cor === corPadrao ? "#000" : "transparent",
                    boxShadow: cor === corPadrao ? "0 0 0 2px rgba(0,0,0,0.1)" : "none",
                  }}
                  onClick={() => setCor(corPadrao)}
                  disabled={loading}
                  title={corPadrao}
                />
              ))}
              <div className="flex items-center ml-2">
                <Input
                  type="color"
                  value={cor}
                  onChange={(e) => setCor(e.target.value)}
                  className="w-10 h-10 p-1 cursor-pointer"
                  disabled={loading}
                  title="Escolher cor personalizada"
                />
              </div>
            </div>
          </div>

          <div className="flex justify-end gap-2 pt-4">
            <Button
              type="button"
              variant="outline"
              onClick={() => setOpen(false)}
              disabled={loading}
            >
              Cancelar
            </Button>
            <Button type="submit" disabled={loading}>
              {loading ? "Adicionando..." : "Adicionar Etapa"}
            </Button>
          </div>
        </form>
      </DialogContent>
    </Dialog>
  );
}

import { useDroppable } from "@dnd-kit/core";
import { ReactNode, useState } from "react";
import { Button } from "@/components/ui/button";
import { Trash2 } from "lucide-react";
import { EditarEtapaDialog } from "./EditarEtapaDialog";
import { supabase } from "@/integrations/supabase/client";
import { toast } from "sonner";
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
} from "@/components/ui/alert-dialog";

interface DroppableColumnProps {
  id: string;
  children: ReactNode;
  cor: string;
  nome: string;
  quantidadeLeads: number;
  totalEtapa: number;
  onEtapaUpdated: () => void;
}

export function DroppableColumn({ id, children, cor, nome, quantidadeLeads, totalEtapa, onEtapaUpdated }: DroppableColumnProps) {
  const [showDeleteDialog, setShowDeleteDialog] = useState(false);
  const [isDeleting, setIsDeleting] = useState(false);
  
  const { setNodeRef, isOver } = useDroppable({
    id: id,
    data: {
      type: 'etapa',
      etapaId: id
    }
  });

  const handleDeleteClick = () => {
    if (quantidadeLeads > 0) {
      toast.error("Não é possível deletar etapa com leads. Mova os leads primeiro.");
      return;
    }
    setShowDeleteDialog(true);
  };

  const handleConfirmDelete = async () => {
    setIsDeleting(true);
    try {
      const { error } = await supabase.from("etapas").delete().eq("id", id);
      if (error) throw error;

      toast.success(`Etapa "${nome}" deletada com sucesso!`);
      setShowDeleteDialog(false);
      onEtapaUpdated();
    } catch (error: any) {
      console.error("Erro ao deletar etapa:", error);
      toast.error(error.message || "Erro ao deletar etapa");
    } finally {
      setIsDeleting(false);
    }
  };

  return (
    <>
      <div>
        <div className="text-white p-3 rounded-t-lg" style={{ backgroundColor: cor }}>
          <div className="flex items-center justify-between mb-2">
            <h3 className="font-semibold">{nome}</h3>
            <div className="flex gap-1">
              <EditarEtapaDialog 
                etapaId={id}
                nomeAtual={nome}
                corAtual={cor}
                onEtapaUpdated={onEtapaUpdated}
              />
              <Button
                variant="ghost"
                size="icon"
                className="h-7 w-7 text-white hover:bg-white/20"
                onClick={handleDeleteClick}
                title={quantidadeLeads > 0 ? "Mova os leads antes de deletar" : "Deletar Etapa"}
                disabled={isDeleting}
              >
                <Trash2 className="h-3.5 w-3.5" />
              </Button>
            </div>
          </div>
          <div className="text-sm">
            <div>{quantidadeLeads} lead{quantidadeLeads !== 1 ? 's' : ''}</div>
            <div className="font-bold">
              R$ {totalEtapa.toLocaleString('pt-BR', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}
            </div>
          </div>
        </div>
        <div 
          ref={setNodeRef}
          className={`bg-secondary/20 p-4 rounded-b-lg min-h-[500px] transition-colors ${
            isOver ? 'bg-primary/10 border-2 border-primary border-dashed' : ''
          }`}
        >
          {children}
        </div>
      </div>

      <AlertDialog open={showDeleteDialog} onOpenChange={setShowDeleteDialog}>
        <AlertDialogContent>
          <AlertDialogHeader>
            <AlertDialogTitle>Confirmar exclusão da etapa</AlertDialogTitle>
            <AlertDialogDescription>
              Tem certeza que deseja deletar a etapa <strong>"{nome}"</strong>?
              <br />
              Esta ação não pode ser desfeita.
            </AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogCancel disabled={isDeleting}>Cancelar</AlertDialogCancel>
            <AlertDialogAction
              onClick={handleConfirmDelete}
              disabled={isDeleting}
              className="bg-destructive text-destructive-foreground hover:bg-destructive/90"
            >
              {isDeleting ? "Deletando..." : "Deletar"}
            </AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>
    </>
  );
}

import { useState, useEffect } from "react";
import { Button } from "@/components/ui/button";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogTrigger,
} from "@/components/ui/dialog";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Pencil } from "lucide-react";
import { supabase } from "@/integrations/supabase/client";
import { toast } from "sonner";

interface EditarEtapaDialogProps {
  etapaId: string;
  nomeAtual: string;
  corAtual: string;
  onEtapaUpdated: () => void;
}

const CORES_PADRAO = ["#3b82f6", "#22c55e", "#eab308", "#f97316", "#ef4444", "#8b5cf6", "#ec4899"];

export function EditarEtapaDialog({ etapaId, nomeAtual, corAtual, onEtapaUpdated }: EditarEtapaDialogProps) {
  const [open, setOpen] = useState(false);
  const [nome, setNome] = useState(nomeAtual);
  const [cor, setCor] = useState(corAtual);
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    if (open) {
      setNome(nomeAtual);
      setCor(corAtual);
    }
  }, [open, nomeAtual, corAtual]);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    
    const nomeFormatado = nome.trim();
    
    if (!nomeFormatado) {
      toast.error("Digite o nome da etapa");
      return;
    }

    if (nomeFormatado.length < 3) {
      toast.error("Nome deve ter pelo menos 3 caracteres");
      return;
    }

    if (nomeFormatado.length > 50) {
      toast.error("Nome deve ter no máximo 50 caracteres");
      return;
    }

    setLoading(true);

    try {
      // Buscar funil_id da etapa atual
      const { data: etapaAtual } = await supabase
        .from("etapas")
        .select("funil_id")
        .eq("id", etapaId)
        .single();

      if (!etapaAtual) throw new Error("Etapa não encontrada");

      // Verificar duplicata apenas se mudou o nome
      if (nomeFormatado.toLowerCase() !== nomeAtual.toLowerCase()) {
        const { data: etapaExistente } = await supabase
          .from("etapas")
          .select("id")
          .eq("funil_id", etapaAtual.funil_id)
          .ilike("nome", nomeFormatado)
          .neq("id", etapaId)
          .maybeSingle();

        if (etapaExistente) {
          toast.error("Já existe uma etapa com este nome neste funil");
          setLoading(false);
          return;
        }
      }

      const { error } = await supabase
        .from("etapas")
        .update({
          nome: nomeFormatado,
          cor,
        })
        .eq("id", etapaId);

      if (error) throw error;

      toast.success(`Etapa "${nomeFormatado}" atualizada com sucesso!`);
      setOpen(false);
      onEtapaUpdated();
    } catch (error: any) {
      console.error("Erro ao atualizar etapa:", error);
      toast.error(error.message || "Erro ao atualizar etapa");
    } finally {
      setLoading(false);
    }
  };

  return (
    <Dialog open={open} onOpenChange={setOpen}>
      <DialogTrigger asChild>
        <Button variant="ghost" size="icon" className="h-7 w-7">
          <Pencil className="h-3.5 w-3.5" />
        </Button>
      </DialogTrigger>
      <DialogContent>
        <DialogHeader>
          <DialogTitle>Editar Etapa</DialogTitle>
        </DialogHeader>
        <form onSubmit={handleSubmit} className="space-y-4">
          <div>
            <Label htmlFor="nome">Nome da Etapa *</Label>
            <Input
              id="nome"
              value={nome}
              onChange={(e) => setNome(e.target.value)}
              placeholder="Ex: Qualificação, Negociação"
              disabled={loading}
              maxLength={50}
              required
            />
            <p className="text-xs text-muted-foreground mt-1">
              {nome.length}/50 caracteres
            </p>
          </div>

          <div>
            <Label>Cor da Etapa</Label>
            <div className="flex gap-2 mt-2 flex-wrap">
              {CORES_PADRAO.map((corPadrao) => (
                <button
                  key={corPadrao}
                  type="button"
                  className="w-10 h-10 rounded-lg border-2 transition-all hover:scale-110 shadow-sm"
                  style={{
                    backgroundColor: corPadrao,
                    borderColor: cor === corPadrao ? "#000" : "transparent",
                    boxShadow: cor === corPadrao ? "0 0 0 2px rgba(0,0,0,0.1)" : "none",
                  }}
                  onClick={() => setCor(corPadrao)}
                  disabled={loading}
                  title={corPadrao}
                />
              ))}
              <div className="flex items-center ml-2">
                <Input
                  type="color"
                  value={cor}
                  onChange={(e) => setCor(e.target.value)}
                  className="w-10 h-10 p-1 cursor-pointer"
                  disabled={loading}
                  title="Escolher cor personalizada"
                />
              </div>
            </div>
          </div>

          <div className="flex justify-end gap-2 pt-4">
            <Button
              type="button"
              variant="outline"
              onClick={() => setOpen(false)}
              disabled={loading}
            >
              Cancelar
            </Button>
            <Button type="submit" disabled={loading}>
              {loading ? "Salvando..." : "Salvar Alterações"}
            </Button>
          </div>
        </form>
      </DialogContent>
    </Dialog>
  );
}

import { useState, useEffect } from "react";
import { Plus, X, GripVertical, Pencil, Settings } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogTrigger } from "@/components/ui/dialog";
import { supabase } from "@/integrations/supabase/client";
import { toast } from "sonner";

interface EditarFunilDialogProps {
  funilId: string;
  funilNome: string;
  onFunilUpdated: () => void;
}

interface Etapa {
  id: string;
  nome: string;
  posicao: number;
  cor: string;
  funil_id: string;
}

const CORES_PADRAO = [
  "#ef4444", "#f97316", "#eab308", "#22c55e", "#3b82f6", "#8b5cf6", "#ec4899",
];

export function EditarFunilDialog({ funilId, funilNome, onFunilUpdated }: EditarFunilDialogProps) {
  const [open, setOpen] = useState(false);
  const [loading, setLoading] = useState(false);
  const [nomeFunil, setNomeFunil] = useState(funilNome);
  const [etapas, setEtapas] = useState<Etapa[]>([]);

  useEffect(() => {
    if (open) {
      carregarEtapas();
    }
  }, [open, funilId]);

  const carregarEtapas = async () => {
    const { data, error } = await supabase
      .from("etapas")
      .select("*")
      .eq("funil_id", funilId)
      .order("posicao");
    
    if (error) {
      toast.error("Erro ao carregar etapas");
      return;
    }
    
    setEtapas(data || []);
  };

  const adicionarEtapa = () => {
    const novaEtapa: Etapa = {
      id: `temp-${Date.now()}`,
      nome: `Etapa ${etapas.length + 1}`,
      posicao: etapas.length,
      cor: CORES_PADRAO[etapas.length % CORES_PADRAO.length],
      funil_id: funilId,
    };
    setEtapas([...etapas, novaEtapa]);
  };

  const removerEtapa = async (etapa: Etapa) => {
    if (etapas.length <= 1) {
      toast.error("O funil precisa ter pelo menos uma etapa");
      return;
    }

    if (!etapa.id.startsWith("temp-")) {
      console.log(`🗑️ Removendo etapa "${etapa.nome}" (ID: ${etapa.id})`);
      
      // Verificar se há leads nesta etapa
      const { data: leadsNaEtapa, error: checkError } = await supabase
        .from("leads")
        .select("id")
        .eq("etapa_id", etapa.id)
        .limit(1);
      
      if (checkError) {
        console.error("Erro ao verificar leads:", checkError);
        toast.error("Erro ao verificar etapa");
        return;
      }

      if (leadsNaEtapa && leadsNaEtapa.length > 0) {
        toast.error("Não é possível excluir uma etapa que contém leads");
        return;
      }

      // Deletar etapa do banco
      const { error: deleteError } = await supabase
        .from("etapas")
        .delete()
        .eq("id", etapa.id);
      
      if (deleteError) {
        console.error("Erro ao deletar etapa:", deleteError);
        toast.error("Erro ao remover etapa");
        return;
      }
      
      console.log(`✅ Etapa "${etapa.nome}" removida do banco`);
      toast.success("Etapa removida com sucesso");
      
      // Recarregar etapas após deletar
      await carregarEtapas();
    } else {
      // Apenas remover localmente se for temporária
      const novasEtapas = etapas
        .filter(e => e.id !== etapa.id)
        .map((e, index) => ({ ...e, posicao: index }));
      
      setEtapas(novasEtapas);
    }
  };

  const atualizarNomeEtapa = (id: string, novoNome: string) => {
    setEtapas(etapas.map(e => e.id === id ? { ...e, nome: novoNome } : e));
  };

  const atualizarCorEtapa = (id: string, novaCor: string) => {
    setEtapas(etapas.map(e => e.id === id ? { ...e, cor: novaCor } : e));
  };

  const excluirFunil = async () => {
    if (!confirm("⚠️ ATENÇÃO: Tem certeza que deseja excluir este funil?\n\nTodas as etapas e leads associados serão perdidos permanentemente!")) {
      return;
    }

    setLoading(true);
    try {
      const { data: { session } } = await supabase.auth.getSession();
      if (!session) {
        toast.error("Não autenticado");
        setLoading(false);
        return;
      }

      console.log(`🗑️ Excluindo funil "${nomeFunil}" (ID: ${funilId})`);

      // Verificar quantos leads serão afetados
      const { data: leadsCount } = await supabase
        .from("leads")
        .select("id", { count: "exact", head: true })
        .eq("funil_id", funilId);

      console.log(`📊 Leads que serão excluídos: ${leadsCount || 0}`);

      // Deletar funil (cascade irá deletar etapas e leads)
      const { error: deleteError } = await supabase
        .from("funis")
        .delete()
        .eq("id", funilId)
        .eq("owner_id", session.user.id);

      if (deleteError) {
        console.error("❌ Erro ao excluir funil:", deleteError);
        throw deleteError;
      }

      console.log("✅ Funil excluído com sucesso");
      toast.success("Funil excluído com sucesso!");
      setOpen(false);
      onFunilUpdated();
    } catch (error: any) {
      console.error("❌ Erro ao excluir funil:", error);
      toast.error(`Erro ao excluir funil: ${error.message || 'Erro desconhecido'}`);
    } finally {
      setLoading(false);
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    if (!nomeFunil.trim()) {
      toast.error("Digite o nome do funil");
      return;
    }

    if (etapas.length === 0) {
      toast.error("Adicione pelo menos uma etapa");
      return;
    }

    const etapasInvalidas = etapas.filter(e => !e.nome.trim());
    if (etapasInvalidas.length > 0) {
      toast.error("Todas as etapas precisam ter um nome");
      return;
    }

    setLoading(true);

    try {
      const { data: { session } } = await supabase.auth.getSession();
      if (!session) {
        toast.error("Não autenticado");
        setLoading(false);
        return;
      }

      console.log("=== ATUALIZANDO FUNIL ===");
      console.log("Funil ID:", funilId);
      console.log("Novo nome:", nomeFunil);
      console.log("User ID:", session.user.id);
      console.log("Etapas a processar:", etapas);

      // 1. Atualizar nome do funil
      const { error: funilError } = await supabase
        .from("funis")
        .update({ 
          nome: nomeFunil
        })
        .eq("id", funilId)
        .eq("owner_id", session.user.id);

      if (funilError) {
        console.error("❌ Erro ao atualizar nome do funil:", funilError);
        throw funilError;
      }

      console.log("✅ Nome do funil atualizado");

      // 2. Processar etapas
      for (let i = 0; i < etapas.length; i++) {
        const etapa = etapas[i];
        
        if (etapa.id.startsWith("temp-")) {
          console.log(`➕ Criando nova etapa ${i + 1}: "${etapa.nome}"`);
          
          const { data, error: etapaError } = await supabase
            .from("etapas")
            .insert({
              nome: etapa.nome,
              funil_id: funilId,
              posicao: i,
              cor: etapa.cor
            })
            .select();
          
          if (etapaError) {
            console.error("❌ Erro ao criar etapa:", etapaError);
            toast.error(`Erro ao criar etapa "${etapa.nome}"`);
            throw etapaError;
          }
          
          console.log(`✅ Etapa "${etapa.nome}" criada:`, data);
        } else {
          console.log(`🔄 Atualizando etapa ${i + 1}: "${etapa.nome}"`);
          
          const { error: updateError } = await supabase
            .from("etapas")
            .update({
              nome: etapa.nome,
              posicao: i,
              cor: etapa.cor
            })
            .eq("id", etapa.id)
            .eq("funil_id", funilId);
          
          if (updateError) {
            console.error("❌ Erro ao atualizar etapa:", updateError);
            toast.error(`Erro ao atualizar etapa "${etapa.nome}"`);
            throw updateError;
          }
          
          console.log(`✅ Etapa "${etapa.nome}" atualizada`);
        }
      }

      console.log("✅ Funil completo atualizado com sucesso!");
      toast.success("Funil atualizado com sucesso!");
      setOpen(false);
      onFunilUpdated();
    } catch (error: any) {
      console.error("❌ Erro completo ao atualizar funil:", error);
      toast.error(`Erro ao atualizar: ${error.message || 'Erro desconhecido'}`);
    } finally {
      setLoading(false);
    }
  };

  return (
    <Dialog open={open} onOpenChange={setOpen}>
      <DialogTrigger asChild>
        <Button variant="ghost" size="sm" className="h-8 w-8 p-0">
          <Settings className="h-4 w-4" />
        </Button>
      </DialogTrigger>
      <DialogContent className="max-w-2xl max-h-[90vh] overflow-y-auto">
        <DialogHeader>
          <DialogTitle>Editar Funil de Vendas</DialogTitle>
        </DialogHeader>
        <form onSubmit={handleSubmit} className="space-y-6">
          <div>
            <Label htmlFor="nomeFunil">Nome do Funil *</Label>
            <Input
              id="nomeFunil"
              value={nomeFunil}
              onChange={(e) => setNomeFunil(e.target.value)}
              placeholder="Ex: Vendas Produto X"
              required
            />
          </div>

          <div className="space-y-4">
            <div className="flex items-center justify-between">
              <Label>Etapas do Funil *</Label>
              <Button 
                type="button" 
                variant="outline" 
                size="sm"
                onClick={adicionarEtapa}
              >
                <Plus className="mr-2 h-4 w-4" />
                Adicionar Etapa
              </Button>
            </div>

            <div className="space-y-3">
              {etapas.map((etapa, index) => (
                <div 
                  key={etapa.id} 
                  className="flex items-center gap-2 p-3 border rounded-lg bg-secondary/20"
                >
                  <div className="flex items-center gap-2 text-muted-foreground">
                    <GripVertical className="h-4 w-4" />
                    <span className="text-sm font-medium">{index + 1}</span>
                  </div>

                  <Input
                    value={etapa.nome}
                    onChange={(e) => atualizarNomeEtapa(etapa.id, e.target.value)}
                    placeholder="Nome da etapa"
                    className="flex-1"
                  />

                  <div className="flex items-center gap-2">
                    <div className="relative">
                      <input
                        type="color"
                        value={etapa.cor}
                        onChange={(e) => atualizarCorEtapa(etapa.id, e.target.value)}
                        className="w-10 h-10 rounded cursor-pointer border"
                        title="Escolher cor"
                      />
                    </div>

                    <Button
                      type="button"
                      variant="ghost"
                      size="sm"
                      onClick={() => removerEtapa(etapa)}
                      disabled={etapas.length <= 1}
                      className="text-destructive hover:text-destructive"
                    >
                      <X className="h-4 w-4" />
                    </Button>
                  </div>
                </div>
              ))}
            </div>
          </div>

          <div className="flex gap-2 pt-4 border-t">
            <Button 
              type="button" 
              variant="destructive" 
              onClick={excluirFunil}
              disabled={loading}
              className="flex-1"
            >
              Excluir Funil
            </Button>
            <Button 
              type="button" 
              variant="outline" 
              onClick={() => setOpen(false)} 
              className="flex-1"
            >
              Cancelar
            </Button>
            <Button 
              type="submit" 
              disabled={loading} 
              className="flex-1"
            >
              {loading ? "Salvando..." : "Salvar Alterações"}
            </Button>
          </div>
        </form>
      </DialogContent>
    </Dialog>
  );
}

