            <Input
              id="cpf"
              value={formData.cpf}
              onChange={(e) => setFormData({ ...formData, cpf: e.target.value })}
              placeholder="000.000.000-00"
            />
          </div>

          <div>
            <Label htmlFor="company">Empresa</Label>
            <Input
              id="company"
              value={formData.company}
              onChange={(e) => setFormData({ ...formData, company: e.target.value })}
              placeholder="Nome da empresa"
            />
          </div>

          <div>
            <Label htmlFor="servico">Serviço de Interesse</Label>
            <Input
              id="servico"
              value={formData.servico}
              onChange={(e) => setFormData({ ...formData, servico: e.target.value })}
              placeholder="Ex: Consultoria, Produto X"
            />
          </div>

          <div>
            <Label htmlFor="valor">Valor (R$)</Label>
            <Input
              id="valor"
              type="number"
              step="0.01"
              value={formData.valor}
              onChange={(e) => setFormData({ ...formData, valor: e.target.value })}
              placeholder="0.00"
            />
          </div>

          <div>
            <Label htmlFor="segmentacao">Segmentação</Label>
            <Input
              id="segmentacao"
              value={formData.segmentacao}
              onChange={(e) => setFormData({ ...formData, segmentacao: e.target.value })}
              placeholder="Ex: Empresarial, Residencial"
            />
          </div>

          <div>
            <Label htmlFor="source">Origem</Label>
            <Input
              id="source"
              value={formData.source}
              onChange={(e) => setFormData({ ...formData, source: e.target.value })}
              placeholder="Ex: WhatsApp, Instagram, Indicação"
            />
          </div>

          <div>
            <Label htmlFor="notes">Observações</Label>
            <Textarea
              id="notes"
              value={formData.notes}
              onChange={(e) => setFormData({ ...formData, notes: e.target.value })}
              rows={3}
              placeholder="Informações adicionais sobre o lead"
            />
          </div>

          <div>
            <Label htmlFor="tags">Tags</Label>
            <div className="flex gap-2 mb-2">
              <Input
                id="tags"
                value={newTag}
                onChange={(e) => setNewTag(e.target.value)}
                onKeyDown={(e) => {
                  if (e.key === "Enter") {
                    e.preventDefault();
                    const tagTrimmed = newTag.trim();
                    if (tagTrimmed && !formData.tags.includes(tagTrimmed)) {
                      console.log('➕ Adicionando tag:', tagTrimmed);
                      setFormData({ ...formData, tags: [...formData.tags, tagTrimmed] });
                      setNewTag("");
                    } else if (formData.tags.includes(tagTrimmed)) {
                      toast.error("Esta tag já foi adicionada");
                    }
                  }
                }}
                placeholder="Digite uma tag e pressione Enter"
              />
              <Button
                type="button"
                size="icon"
                onClick={() => {
                  const tagTrimmed = newTag.trim();
                  if (tagTrimmed && !formData.tags.includes(tagTrimmed)) {
                    console.log('➕ Adicionando tag:', tagTrimmed);
                    setFormData({ ...formData, tags: [...formData.tags, tagTrimmed] });
                    setNewTag("");
                  } else if (tagTrimmed && formData.tags.includes(tagTrimmed)) {
                    toast.error("Esta tag já foi adicionada");
                  }
                }}
              >
                <Plus className="h-4 w-4" />
              </Button>
            </div>
            <div className="flex flex-wrap gap-2 min-h-[60px] p-2 border rounded-md bg-muted/20">
              {formData.tags.length === 0 ? (
                <p className="text-xs text-muted-foreground">Nenhuma tag adicionada</p>
              ) : (
                formData.tags.map((tag, index) => (
                  <Badge key={`${tag}-${index}`} variant="secondary" className="gap-1">
                    <Tag className="h-3 w-3" />
                    {tag}
                    <Button
                      type="button"
                      variant="ghost"
                      size="icon"
                      className="h-4 w-4 p-0 hover:bg-transparent"
                      onClick={() => {
                        console.log('🗑️ Removendo tag:', tag);
                        setFormData({ ...formData, tags: formData.tags.filter(t => t !== tag) });
                      }}
                    >
                      <X className="h-3 w-3" />
                    </Button>
                  </Badge>
                ))
              )}
            </div>
            {leadId && (
              <p className="text-xs text-muted-foreground mt-2">
                💡 As tags são sincronizadas com o funil de vendas e menu de leads
              </p>
            )}
          </div>

          <div className="flex gap-2 pt-4">
            <Button type="button" variant="outline" onClick={() => setOpen(false)} className="flex-1">
              Cancelar
            </Button>
            <Button type="submit" disabled={loading} className="flex-1">
              {loading ? "Salvando..." : "Salvar Informações"}
            </Button>
          </div>
        </form>
      </DialogContent>
    </Dialog>
  );
}

import { useState, useRef } from "react";
import { Button } from "@/components/ui/button";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogTrigger } from "@/components/ui/dialog";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import { 
  Paperclip, 
  Image as ImageIcon, 
  File, 
  Video, 
  Mic,
  X,
  Send,
  Loader2
} from "lucide-react";
import { toast } from "sonner";

interface MediaUploadProps {
  onSendMedia: (file: File, caption: string, type: string) => Promise<void>;
}

export function MediaUpload({ onSendMedia }: MediaUploadProps) {
  const [open, setOpen] = useState(false);
  const [selectedFile, setSelectedFile] = useState<File | null>(null);
  const [preview, setPreview] = useState<string>("");
  const [caption, setCaption] = useState("");
  const [uploading, setUploading] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    // Validar tamanho (max 20MB)
    if (file.size > 20 * 1024 * 1024) {
      toast.error("Arquivo muito grande. Máximo 20MB");
      return;
    }

    setSelectedFile(file);

    // Criar preview para imagens e vídeos
    if (file.type.startsWith('image/') || file.type.startsWith('video/')) {
      const reader = new FileReader();
      reader.onload = (e) => {
        setPreview(e.target?.result as string);
      };
      reader.readAsDataURL(file);
    } else {
      setPreview("");
    }
  };

  const getFileType = (file: File): string => {
    if (file.type.startsWith('image/')) return 'image';
    if (file.type.startsWith('video/')) return 'video';
    if (file.type.startsWith('audio/')) return 'audio';
    if (file.type === 'application/pdf') return 'pdf';
    return 'document';
  };

  const handleSend = async () => {
    if (!selectedFile) {
      toast.error("Selecione um arquivo");
      return;
    }

    setUploading(true);
    try {
      const fileType = getFileType(selectedFile);
      await onSendMedia(selectedFile, caption, fileType);
      
      // Resetar formulário
      setSelectedFile(null);
      setPreview("");
      setCaption("");
      setOpen(false);
      
      toast.success("Mídia enviada com sucesso!");
    } catch (error: any) {
      console.error('Erro ao enviar mídia:', error);
      toast.error(error.message || "Erro ao enviar mídia");
    } finally {
      setUploading(false);
    }
  };

  const handleCancel = () => {
    setSelectedFile(null);
    setPreview("");
    setCaption("");
    if (fileInputRef.current) {
      fileInputRef.current.value = "";
    }
  };

  const getFileIcon = () => {
    if (!selectedFile) return <File className="h-8 w-8" />;
    
    const type = getFileType(selectedFile);
    switch(type) {
      case 'image': return <ImageIcon className="h-8 w-8 text-blue-500" />;
      case 'video': return <Video className="h-8 w-8 text-purple-500" />;
      case 'audio': return <Mic className="h-8 w-8 text-green-500" />;
      case 'pdf': return <File className="h-8 w-8 text-red-500" />;
      default: return <File className="h-8 w-8 text-gray-500" />;
    }
  };

  const formatFileSize = (bytes: number): string => {
    if (bytes < 1024) return bytes + ' B';
    if (bytes < 1024 * 1024) return (bytes / 1024).toFixed(1) + ' KB';
    return (bytes / (1024 * 1024)).toFixed(1) + ' MB';
  };

  return (
    <Dialog open={open} onOpenChange={setOpen}>
      <DialogTrigger asChild>
        <Button 
          variant="ghost" 
          size="icon" 
          className="hover:bg-primary/10"
          onClick={(e) => {
            e.stopPropagation();
            setOpen(true);
          }}
        >
          <Paperclip className="h-5 w-5" />
        </Button>
      </DialogTrigger>
      <DialogContent className="max-w-lg">
        <DialogHeader>
          <DialogTitle>Enviar Mídia</DialogTitle>
        </DialogHeader>
        
        <div className="space-y-4">
          {!selectedFile ? (
            <div className="space-y-4">
              <input
                ref={fileInputRef}
                type="file"
                onChange={handleFileSelect}
                className="hidden"
                accept="image/*,video/*,audio/*,.pdf,.doc,.docx,.xls,.xlsx,.zip"
              />
              
              <div className="grid grid-cols-2 gap-3">
                <Button
                  variant="outline"
                  className="h-24 flex-col gap-2"
                  onClick={() => {
                    fileInputRef.current?.click();
                    fileInputRef.current?.setAttribute('accept', 'image/*');
                  }}
                >
                  <ImageIcon className="h-6 w-6 text-blue-500" />
                  <span className="text-sm">Imagem</span>
                </Button>
                
                <Button
                  variant="outline"
                  className="h-24 flex-col gap-2"
                  onClick={() => {
                    fileInputRef.current?.click();
                    fileInputRef.current?.setAttribute('accept', 'video/*');
                  }}
                >
                  <Video className="h-6 w-6 text-purple-500" />
                  <span className="text-sm">Vídeo</span>
                </Button>
                
                <Button
                  variant="outline"
                  className="h-24 flex-col gap-2"
                  onClick={() => {
                    fileInputRef.current?.click();
                    fileInputRef.current?.setAttribute('accept', 'audio/*');
                  }}
                >
                  <Mic className="h-6 w-6 text-green-500" />
                  <span className="text-sm">Áudio</span>
                </Button>
                
                <Button
                  variant="outline"
                  className="h-24 flex-col gap-2"
                  onClick={() => {
                    fileInputRef.current?.click();
                    fileInputRef.current?.setAttribute('accept', '.pdf,.doc,.docx,.xls,.xlsx');
                  }}
                >
                  <File className="h-6 w-6 text-red-500" />
                  <span className="text-sm">Documento</span>
                </Button>
              </div>
              
              <p className="text-xs text-muted-foreground text-center">
                Tamanho máximo: 20MB
              </p>
            </div>
          ) : (
            <div className="space-y-4">
              {/* Preview */}
              <div className="relative">
                {preview && (getFileType(selectedFile) === 'image' || getFileType(selectedFile) === 'video') ? (
                  <div className="rounded-lg overflow-hidden bg-muted">
                    {getFileType(selectedFile) === 'image' ? (
                      <img src={preview} alt="Preview" className="w-full h-auto max-h-64 object-contain" />
                    ) : (
                      <video src={preview} controls className="w-full h-auto max-h-64" />
                    )}
                  </div>
                ) : (
                  <div className="flex items-center gap-3 p-4 bg-muted rounded-lg">
                    {getFileIcon()}
                    <div className="flex-1">
                      <p className="font-medium text-sm">{selectedFile.name}</p>
                      <p className="text-xs text-muted-foreground">{formatFileSize(selectedFile.size)}</p>
                    </div>
                  </div>
                )}
                
                <Button
                  size="icon"
                  variant="destructive"
                  className="absolute top-2 right-2"
                  onClick={handleCancel}
                >
                  <X className="h-4 w-4" />
                </Button>
              </div>

              {/* Caption */}
              <div className="space-y-2">
                <Label>Legenda (opcional)</Label>
                <Textarea
                  placeholder="Adicione uma legenda..."
                  value={caption}
                  onChange={(e) => setCaption(e.target.value)}
                  rows={3}
                />
              </div>

              {/* Actions */}
              <div className="flex gap-2">
                <Button
                  variant="outline"
                  onClick={handleCancel}
                  disabled={uploading}
                  className="flex-1"
                >
                  Cancelar
                </Button>
                <Button
                  onClick={handleSend}
                  disabled={uploading}
                  className="flex-1"
                >
                  {uploading ? (
                    <>
                      <Loader2 className="h-4 w-4 mr-2 animate-spin" />
                      Enviando...
                    </>
                  ) : (
                    <>
                      <Send className="h-4 w-4 mr-2" />
                      Enviar
                    </>
                  )}
                </Button>
              </div>
            </div>
          )}
        </div>
      </DialogContent>
    </Dialog>
  );
}

import { useState, useEffect } from "react";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Avatar, AvatarFallback } from "@/components/ui/avatar";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogTrigger } from "@/components/ui/dialog";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Users, UserPlus, X } from "lucide-react";
import { supabase } from "@/integrations/supabase/client";
import { toast } from "sonner";

interface ResponsaveisManagerProps {
  leadId: string | null;
  responsaveisAtuais?: string[];
  onResponsaveisUpdated: (responsaveis: string[]) => void;
}

export function ResponsaveisManager({ 
  leadId, 
  responsaveisAtuais = [],
  onResponsaveisUpdated 
}: ResponsaveisManagerProps) {
  const [open, setOpen] = useState(false);
  const [usuarios, setUsuarios] = useState<any[]>([]);
  const [novoResponsavel, setNovoResponsavel] = useState("");
  const [responsaveis, setResponsaveis] = useState<string[]>(responsaveisAtuais);
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    setResponsaveis(responsaveisAtuais);
  }, [responsaveisAtuais]);

  useEffect(() => {
    if (open) {
      carregarUsuarios();
    }
  }, [open]);

  const carregarUsuarios = async () => {
    try {
      const { data: { session } } = await supabase.auth.getSession();
      if (!session) return;

      // Buscar usuários da mesma empresa
      const { data: userRole } = await supabase
        .from("user_roles")
        .select("company_id")
        .eq("user_id", session.user.id)
        .maybeSingle();

      if (!userRole?.company_id) return;

      // Buscar IDs dos usuários da empresa
      const { data: userRoles } = await supabase
        .from("user_roles")
        .select("user_id")
        .eq("company_id", userRole.company_id);

      if (!userRoles || userRoles.length === 0) return;

      const userIds = userRoles.map(ur => ur.user_id);

      // Buscar perfis dos usuários
      const { data: profiles } = await supabase
        .from("profiles")
        .select("id, full_name, email")
        .in('id', userIds);

      if (profiles) {
        setUsuarios(profiles);
      }
    } catch (error) {
      console.error("Erro ao carregar usuários:", error);
    }
  };

  const adicionarResponsavel = async () => {
    if (!novoResponsavel) {
      toast.error("Selecione um responsável");
      return;
    }

    const usuario = usuarios.find(u => u.id === novoResponsavel);
    if (!usuario) return;

    const nomeResponsavel = usuario.full_name || usuario.email;

    if (responsaveis.includes(nomeResponsavel)) {
      toast.error("Este responsável já foi adicionado");
      return;
    }

    const novosResponsaveis = [...responsaveis, nomeResponsavel];
    setResponsaveis(novosResponsaveis);
    
    // Se tem leadId, salvar no banco
    if (leadId) {
      setLoading(true);
      try {
        const { error } = await supabase
          .from("leads")
          .update({ 
            notes: `Responsáveis: ${novosResponsaveis.join(', ')}`
          })
          .eq("id", leadId);

        if (error) throw error;

        console.log('✅ Responsável adicionado:', nomeResponsavel);
        toast.success(`${nomeResponsavel} adicionado como responsável`);
      } catch (error) {
        console.error("Erro ao salvar responsável:", error);
        toast.error("Erro ao adicionar responsável");
      } finally {
        setLoading(false);
      }
    }

    onResponsaveisUpdated(novosResponsaveis);
    setNovoResponsavel("");
  };

  const removerResponsavel = async (nome: string) => {
    const novosResponsaveis = responsaveis.filter(r => r !== nome);
    setResponsaveis(novosResponsaveis);

    // Se tem leadId, salvar no banco
    if (leadId) {
      setLoading(true);
      try {
        const { error } = await supabase
          .from("leads")
          .update({ 
            notes: novosResponsaveis.length > 0 
              ? `Responsáveis: ${novosResponsaveis.join(', ')}`
              : ''
          })
          .eq("id", leadId);

        if (error) throw error;

        console.log('🗑️ Responsável removido:', nome);
        toast.success(`${nome} removido dos responsáveis`);
      } catch (error) {
        console.error("Erro ao remover responsável:", error);
        toast.error("Erro ao remover responsável");
      } finally {
        setLoading(false);
      }
    }

    onResponsaveisUpdated(novosResponsaveis);
  };

  return (
    <div>
      <h4 className="text-foreground font-medium mb-2 flex items-center gap-2">
        <Users className="h-4 w-4" /> 
        Responsáveis {responsaveis.length > 0 && `(${responsaveis.length})`}
      </h4>
      
      <div className="flex flex-wrap gap-2 mb-3 min-h-[40px]">
        {responsaveis.length === 0 ? (
          <p className="text-sm text-muted-foreground">Nenhum responsável atribuído</p>
        ) : (
          responsaveis.map((nome, index) => (
            <Badge 
              key={`${nome}-${index}`} 
              variant="secondary" 
              className="gap-2 py-1.5 pr-1"
            >
              <Avatar className="h-5 w-5">
                <AvatarFallback className="text-xs bg-primary/10 text-primary">
                  {nome.charAt(0).toUpperCase()}
                </AvatarFallback>
              </Avatar>
              <span className="text-xs">{nome}</span>
              <Button
                type="button"
                variant="ghost"
                size="icon"
                className="h-5 w-5 p-0 hover:bg-destructive/20 hover:text-destructive rounded-full"
                onClick={() => removerResponsavel(nome)}
                disabled={loading}
              >
                <X className="h-3 w-3" />
              </Button>
            </Badge>
          ))
        )}
      </div>

      <Dialog open={open} onOpenChange={setOpen}>
        <DialogTrigger asChild>
          <Button size="sm" variant="outline" className="w-full">
            <UserPlus className="h-3 w-3 mr-2" /> 
            Adicionar Responsável
          </Button>
        </DialogTrigger>
        <DialogContent className="max-w-sm">
          <DialogHeader>
            <DialogTitle>Adicionar Responsável</DialogTitle>
            <p className="text-sm text-muted-foreground">
              Responsáveis podem visualizar e responder a conversa
            </p>
          </DialogHeader>
          
          <div className="space-y-4">
            <div>
              <Select 
                value={novoResponsavel} 
                onValueChange={setNovoResponsavel}
              >
                <SelectTrigger>
                  <SelectValue placeholder="Selecione um usuário" />
                </SelectTrigger>
                <SelectContent>
                  {usuarios.map((usuario) => (
                    <SelectItem key={usuario.id} value={usuario.id}>
                      <div className="flex items-center gap-2">
                        <Avatar className="h-6 w-6">
                          <AvatarFallback className="text-xs bg-primary/10 text-primary">
                            {(usuario.full_name || usuario.email).charAt(0).toUpperCase()}
                          </AvatarFallback>
                        </Avatar>
                        <div>
                          <p className="text-sm font-medium">{usuario.full_name || usuario.email}</p>
                          {usuario.full_name && (
                            <p className="text-xs text-muted-foreground">{usuario.email}</p>
                          )}
                        </div>
                      </div>
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>

            <div className="flex gap-2">
              <Button 
                variant="outline" 
                onClick={() => setOpen(false)}
                className="flex-1"
              >
                Cancelar
              </Button>
              <Button 
                onClick={adicionarResponsavel}
                disabled={loading || !novoResponsavel}
                className="flex-1"
              >
                {loading ? "Adicionando..." : "Adicionar"}
              </Button>
            </div>
          </div>

          {responsaveis.length > 0 && (
            <div className="border-t pt-4">
              <p className="text-xs font-medium text-muted-foreground mb-2">
                Responsáveis atuais:
              </p>
              <div className="flex flex-wrap gap-2">
                {responsaveis.map((nome, index) => (
                  <Badge 
                    key={`current-${nome}-${index}`} 
                    variant="outline" 
                    className="text-xs"
                  >
                    {nome}
                  </Badge>
                ))}
              </div>
            </div>
          )}
        </DialogContent>
      </Dialog>

      {responsaveis.length > 0 && (
        <p className="text-xs text-muted-foreground mt-2">
          💡 Todos podem visualizar e responder esta conversa
        </p>
      )}
    </div>
  );
}

import { useState } from "react";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { VisualFlowBuilder } from "./VisualFlowBuilder";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { 
  Plus, 
  MessageSquare, 
  User, 
  Calendar, 
  Target,
  ArrowRight,
  Trash2,
  Play,
  Save
} from "lucide-react";
import { Badge } from "@/components/ui/badge";
