interface FluxoNode {
  id: string;
  type: "trigger" | "action" | "condition";
  label: string;
  config: any;
  next?: string[];
}

interface Fluxo {
  id: string;
  nome: string;
  ativo: boolean;
  nodes: FluxoNode[];
}

export function FluxoAutomacaoBuilder() {
  const [fluxos, setFluxos] = useState<Fluxo[]>([
    {
      id: "1",
      nome: "Boas-vindas Automático",
      ativo: true,
      nodes: [
        { id: "n1", type: "trigger", label: "Nova mensagem WhatsApp", config: { channel: "whatsapp" }, next: ["n2"] },
        { id: "n2", type: "action", label: "Enviar saudação", config: { message: "Olá! Como posso ajudar?" }, next: ["n3"] },
        { id: "n3", type: "action", label: "Criar lead", config: { funil: "Novo" }, next: [] },
      ]
    }
  ]);
  
  const [selectedFluxo, setSelectedFluxo] = useState<Fluxo | null>(null);
  const [editMode, setEditMode] = useState(false);

  const nodeTypes = [
    { value: "trigger", label: "Gatilho", icon: MessageSquare, color: "bg-blue-500" },
    { value: "action", label: "Ação", icon: Play, color: "bg-green-500" },
    { value: "condition", label: "Condição", icon: Target, color: "bg-orange-500" },
  ];

  const triggers = [
    { value: "nova_mensagem", label: "Nova mensagem recebida" },
    { value: "novo_lead", label: "Novo lead criado" },
    { value: "lead_movido", label: "Lead movido no funil" },
    { value: "horario", label: "Em horário específico" },
  ];

  const actions = [
    { value: "enviar_mensagem", label: "Enviar mensagem", icon: MessageSquare },
    { value: "criar_lead", label: "Criar lead", icon: User },
    { value: "criar_tarefa", label: "Criar tarefa", icon: Calendar },
    { value: "mover_funil", label: "Mover no funil", icon: Target },
    { value: "notificar_usuario", label: "Notificar usuário", icon: User },
  ];

  const adicionarNode = (fluxoId: string, tipo: string) => {
    const newNode: FluxoNode = {
      id: `n${Date.now()}`,
      type: tipo as any,
      label: `Novo ${tipo}`,
      config: {},
      next: []
    };

    setFluxos(prev => prev.map(f => {
      if (f.id === fluxoId) {
        return { ...f, nodes: [...f.nodes, newNode] };
      }
      return f;
    }));

    toast.success("Etapa adicionada ao fluxo");
  };

  const removerNode = (fluxoId: string, nodeId: string) => {
    setFluxos(prev => prev.map(f => {
      if (f.id === fluxoId) {
        return { ...f, nodes: f.nodes.filter(n => n.id !== nodeId) };
      }
      return f;
    }));
    toast.success("Etapa removida");
  };

  const toggleFluxo = (fluxoId: string) => {
    setFluxos(prev => prev.map(f => {
      if (f.id === fluxoId) {
        const newStatus = !f.ativo;
        toast.success(newStatus ? "Fluxo ativado" : "Fluxo desativado");
        return { ...f, ativo: newStatus };
      }
      return f;
    }));
  };

  const criarNovoFluxo = () => {
    const novoFluxo: Fluxo = {
      id: `f${Date.now()}`,
      nome: "Novo Fluxo",
      ativo: false,
      nodes: []
    };
    setFluxos(prev => [...prev, novoFluxo]);
    setSelectedFluxo(novoFluxo);
    setEditMode(true);
    toast.success("Novo fluxo criado");
  };

  const getNodeIcon = (type: string) => {
    const nodeType = nodeTypes.find(nt => nt.value === type);
    return nodeType ? nodeType.icon : Play;
  };

  const getNodeColor = (type: string) => {
    const nodeType = nodeTypes.find(nt => nt.value === type);
    return nodeType ? nodeType.color : "bg-gray-500";
  };

  return (
    <div className="space-y-6">
      {editMode && selectedFluxo ? (
        <div>
          <div className="flex justify-between items-center mb-4">
            <h2 className="text-2xl font-bold">Editor Visual - {selectedFluxo.nome}</h2>
            <Button onClick={() => { setEditMode(false); setSelectedFluxo(null); }} variant="outline">
              Voltar para Lista
            </Button>
          </div>
          <VisualFlowBuilder 
            fluxoId={selectedFluxo.id} 
            onSave={() => {
              setEditMode(false);
              setSelectedFluxo(null);
            }}
          />
        </div>
      ) : (
        <>
          <div className="flex justify-between items-center">
            <div>
              <h2 className="text-2xl font-bold">Fluxos de Automação</h2>
              <p className="text-muted-foreground">
                Crie fluxos visuais para automatizar atendimento e processos
              </p>
            </div>
            <Button onClick={criarNovoFluxo}>
              <Plus className="h-4 w-4 mr-2" />
              Novo Fluxo
            </Button>
          </div>

      <div className="grid gap-6 md:grid-cols-2">
        {fluxos.map((fluxo) => (
          <Card key={fluxo.id} className="border-0 shadow-card hover:shadow-lg transition-all">
            <CardHeader>
              <div className="flex items-center justify-between">
                <CardTitle className="text-lg">{fluxo.nome}</CardTitle>
                <div className="flex items-center gap-2">
                  <Badge variant={fluxo.ativo ? "default" : "secondary"}>
                    {fluxo.ativo ? "Ativo" : "Inativo"}
                  </Badge>
                  <Button
                    size="sm"
                    variant={fluxo.ativo ? "outline" : "default"}
                    onClick={() => toggleFluxo(fluxo.id)}
                  >
                    {fluxo.ativo ? "Desativar" : "Ativar"}
                  </Button>
                </div>
              </div>
            </CardHeader>
            <CardContent className="space-y-4">
              <div className="space-y-2">
                {fluxo.nodes.map((node, index) => (
                  <div key={node.id}>
                    <div className="flex items-center gap-3 p-3 bg-muted/50 rounded-lg group hover:bg-muted transition-colors">
                      <div className={`p-2 rounded-lg ${getNodeColor(node.type)}`}>
                        {(() => {
                          const Icon = getNodeIcon(node.type);
                          return <Icon className="h-4 w-4 text-white" />;
                        })()}
                      </div>
                      <div className="flex-1">
                        <p className="text-sm font-medium">{node.label}</p>
                        <p className="text-xs text-muted-foreground">
                          {node.type === "trigger" ? "Gatilho" : 
                           node.type === "action" ? "Ação" : "Condição"}
                        </p>
                      </div>
                      <Button
                        size="icon"
                        variant="ghost"
                        className="opacity-0 group-hover:opacity-100 transition-opacity"
                        onClick={() => removerNode(fluxo.id, node.id)}
                      >
                        <Trash2 className="h-4 w-4 text-destructive" />
                      </Button>
                    </div>
                    {index < fluxo.nodes.length - 1 && (
                      <div className="flex justify-center py-1">
                        <ArrowRight className="h-4 w-4 text-muted-foreground" />
                      </div>
                    )}
                  </div>
                ))}
              </div>

              <Dialog>
                <DialogTrigger asChild>
                  <Button variant="outline" className="w-full">
                    <Plus className="h-4 w-4 mr-2" />
                    Adicionar Etapa
                  </Button>
                </DialogTrigger>
                <DialogContent>
                  <DialogHeader>
                    <DialogTitle>Adicionar Etapa ao Fluxo</DialogTitle>
                  </DialogHeader>
                  <div className="space-y-4">
                    <div className="space-y-2">
                      <Label>Tipo de Etapa</Label>
                      <div className="grid grid-cols-3 gap-2">
                        {nodeTypes.map((tipo) => (
                          <Button
                            key={tipo.value}
                            variant="outline"
                            className="h-auto flex-col gap-2 py-4"
                            onClick={() => {
                              adicionarNode(fluxo.id, tipo.value);
                            }}
                          >
                            <div className={`p-2 rounded-lg ${tipo.color}`}>
                              <tipo.icon className="h-5 w-5 text-white" />
                            </div>
                            <span className="text-xs">{tipo.label}</span>
                          </Button>
                        ))}
                      </div>
                    </div>

                    {selectedFluxo && (
                      <>
                        <div className="space-y-2">
                          <Label>Configurar Gatilho</Label>
                          <Select>
                            <SelectTrigger>
                              <SelectValue placeholder="Selecione o gatilho" />
                            </SelectTrigger>
                            <SelectContent>
                              {triggers.map((t) => (
                                <SelectItem key={t.value} value={t.value}>
                                  {t.label}
                                </SelectItem>
                              ))}
                            </SelectContent>
                          </Select>
                        </div>

                        <div className="space-y-2">
                          <Label>Configurar Ação</Label>
                          <Select>
                            <SelectTrigger>
                              <SelectValue placeholder="Selecione a ação" />
                            </SelectTrigger>
                            <SelectContent>
                              {actions.map((a) => (
                                <SelectItem key={a.value} value={a.value}>
                                  {a.label}
                                </SelectItem>
                              ))}
                            </SelectContent>
                          </Select>
                        </div>

                        <div className="space-y-2">
                          <Label>Mensagem / Conteúdo</Label>
                          <Textarea 
                            placeholder="Digite a mensagem ou conteúdo da ação..."
                            rows={3}
                          />
                        </div>
                      </>
                    )}
                  </div>
                </DialogContent>
              </Dialog>

              <div className="flex gap-2">
                <Button 
                  variant="outline" 
                  size="sm" 
                  className="flex-1"
                  onClick={() => {
                    setSelectedFluxo(fluxo);
                    setEditMode(true);
                  }}
                >
                  <Save className="h-4 w-4 mr-2" />
                  Editor Visual
                </Button>
                <Button 
                  variant="outline" 
                  size="sm" 
                  className="flex-1"
                  onClick={() => {
                    setFluxos(prev => prev.filter(f => f.id !== fluxo.id));
                    toast.success("Fluxo excluído");
                  }}
                >
                  <Trash2 className="h-4 w-4 mr-2" />
                  Excluir
                </Button>
              </div>
            </CardContent>
          </Card>
        ))}
      </div>

      {fluxos.length === 0 && (
        <Card className="border-dashed">
          <CardContent className="flex flex-col items-center justify-center py-12">
            <Play className="h-12 w-12 text-muted-foreground mb-4" />
            <h3 className="text-lg font-semibold mb-2">Nenhum fluxo criado</h3>
            <p className="text-muted-foreground text-center mb-4">
              Crie seu primeiro fluxo de automação para começar
            </p>
            <Button onClick={criarNovoFluxo}>
              <Plus className="h-4 w-4 mr-2" />
              Criar Primeiro Fluxo
            </Button>
          </CardContent>
        </Card>
      )}
        </>
      )}
    </div>
  );
}

import { Node } from 'reactflow';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Label } from '@/components/ui/label';
import { Input } from '@/components/ui/input';
import { Textarea } from '@/components/ui/textarea';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { Switch } from '@/components/ui/switch';
import { Settings2 } from 'lucide-react';

interface NodePropertiesPanelProps {
  selectedNode: Node | null;
  onUpdate: (node: Node) => void;
}

export function NodePropertiesPanel({ selectedNode, onUpdate }: NodePropertiesPanelProps) {
  if (!selectedNode) {
    return (
      <Card className="w-80 border-0 bg-slate-900 text-white">
        <CardContent className="flex flex-col items-center justify-center h-full py-12">
          <Settings2 className="h-12 w-12 text-slate-600 mb-4" />
          <p className="text-sm text-slate-400 text-center">
            Selecione um card no canvas para editar suas propriedades
          </p>
        </CardContent>
      </Card>
    );
  }

  const updateNodeData = (key: string, value: any) => {
    const updatedNode = {
      ...selectedNode,
      data: { ...selectedNode.data, [key]: value },
    };
    onUpdate(updatedNode);
  };

  const renderProperties = () => {
    switch (selectedNode.type) {
      case 'trigger':
        return (
          <>
            <div className="space-y-2">
              <Label className="text-white">Tipo de Gatilho</Label>
              <Select 
                value={selectedNode.data.triggerType} 
                onValueChange={(v) => updateNodeData('triggerType', v)}
              >
                <SelectTrigger className="bg-slate-800 border-slate-700 text-white">
                  <SelectValue />
                </SelectTrigger>
                <SelectContent className="bg-slate-800 border-slate-700">
                  <SelectItem value="nova_mensagem">Nova mensagem recebida</SelectItem>
                  <SelectItem value="novo_lead">Novo lead criado</SelectItem>
                  <SelectItem value="lead_movido">Lead movido no funil</SelectItem>
                  <SelectItem value="horario">Em horário específico</SelectItem>
                </SelectContent>
              </Select>
            </div>
            <div className="space-y-2">
              <Label className="text-white">Título</Label>
              <Input
                value={selectedNode.data.label || ''}
                onChange={(e) => updateNodeData('label', e.target.value)}
                className="bg-slate-800 border-slate-700 text-white"
                placeholder="Ex: Nova mensagem WhatsApp"
              />
            </div>
            <div className="space-y-2">
              <Label className="text-white">Descrição</Label>
              <Textarea
                value={selectedNode.data.description || ''}
                onChange={(e) => updateNodeData('description', e.target.value)}
                className="bg-slate-800 border-slate-700 text-white"
                placeholder="Descreva quando este gatilho será acionado..."
                rows={3}
              />
            </div>
          </>
        );

      case 'action':
        return (
          <>
            <div className="space-y-2">
              <Label className="text-white">Tipo de Ação</Label>
              <Select 
                value={selectedNode.data.actionType} 
                onValueChange={(v) => updateNodeData('actionType', v)}
              >
                <SelectTrigger className="bg-slate-800 border-slate-700 text-white">
                  <SelectValue />
                </SelectTrigger>
                <SelectContent className="bg-slate-800 border-slate-700">
                  <SelectItem value="enviar_mensagem">Enviar mensagem</SelectItem>
                  <SelectItem value="criar_lead">Criar lead</SelectItem>
                  <SelectItem value="criar_tarefa">Criar tarefa</SelectItem>
                  <SelectItem value="mover_funil">Mover no funil</SelectItem>
                  <SelectItem value="notificar_usuario">Notificar usuário</SelectItem>
                  <SelectItem value="adicionar_nota">Adicionar nota</SelectItem>
                  <SelectItem value="acionar_ia">Acionar IA</SelectItem>
                </SelectContent>
              </Select>
            </div>
            <div className="space-y-2">
              <Label className="text-white">Título</Label>
              <Input
                value={selectedNode.data.label || ''}
                onChange={(e) => updateNodeData('label', e.target.value)}
                className="bg-slate-800 border-slate-700 text-white"
                placeholder="Ex: Enviar mensagem de boas-vindas"
              />
            </div>
            {selectedNode.data.actionType === 'enviar_mensagem' && (
              <div className="space-y-2">
                <Label className="text-white">Mensagem</Label>
                <Textarea
                  value={selectedNode.data.message || ''}
                  onChange={(e) => updateNodeData('message', e.target.value)}
                  className="bg-slate-800 border-slate-700 text-white"
                  placeholder="Digite a mensagem..."
                  rows={4}
                />
              </div>
            )}
            <div className="space-y-2">
              <Label className="text-white">Descrição</Label>
              <Textarea
                value={selectedNode.data.description || ''}
                onChange={(e) => updateNodeData('description', e.target.value)}
                className="bg-slate-800 border-slate-700 text-white"
                placeholder="Descreva o que esta ação faz..."
                rows={2}
              />
            </div>
          </>
        );

      case 'condition':
        return (
          <>
            <div className="space-y-2">
              <Label className="text-white">Tipo de Condição</Label>
              <Select 
                value={selectedNode.data.conditionType} 
                onValueChange={(v) => updateNodeData('conditionType', v)}
              >
                <SelectTrigger className="bg-slate-800 border-slate-700 text-white">
                  <SelectValue />
                </SelectTrigger>
                <SelectContent className="bg-slate-800 border-slate-700">
                  <SelectItem value="tag">Verificar tag</SelectItem>
                  <SelectItem value="etapa">Verificar etapa</SelectItem>
                  <SelectItem value="horario">Verificar horário</SelectItem>
                  <SelectItem value="palavra_chave">Palavra-chave na mensagem</SelectItem>
                </SelectContent>
              </Select>
            </div>
            <div className="space-y-2">
              <Label className="text-white">Título</Label>
              <Input
                value={selectedNode.data.label || ''}
                onChange={(e) => updateNodeData('label', e.target.value)}
                className="bg-slate-800 border-slate-700 text-white"
                placeholder="Ex: Cliente tem tag VIP?"
              />
            </div>
            <div className="space-y-2">
              <Label className="text-white">Valor a Verificar</Label>
              <Input
                value={selectedNode.data.checkValue || ''}
                onChange={(e) => updateNodeData('checkValue', e.target.value)}
                className="bg-slate-800 border-slate-700 text-white"
                placeholder="Ex: VIP, orçamento, 09:00-18:00"
              />
            </div>
          </>
        );

      case 'ia':
        return (
          <>
            <div className="space-y-2">
              <Label className="text-white">Título</Label>
              <Input
                value={selectedNode.data.label || ''}
                onChange={(e) => updateNodeData('label', e.target.value)}
                className="bg-slate-800 border-slate-700 text-white"
                placeholder="Ex: IA Atendimento Inicial"
              />
            </div>
            <div className="space-y-2">
              <Label className="text-white">Prompt Personalizado</Label>
              <Textarea
                value={selectedNode.data.prompt || ''}
                onChange={(e) => updateNodeData('prompt', e.target.value)}
                className="bg-slate-800 border-slate-700 text-white"
                placeholder="Você é um assistente que... [defina o comportamento da IA]"
                rows={5}
              />
            </div>
            <div className="space-y-2">
              <Label className="text-white">Modo de Operação</Label>
              <Select 
                value={selectedNode.data.mode || 'auto'} 
                onValueChange={(v) => updateNodeData('mode', v)}
              >
                <SelectTrigger className="bg-slate-800 border-slate-700 text-white">
                  <SelectValue />
                </SelectTrigger>
                <SelectContent className="bg-slate-800 border-slate-700">
                  <SelectItem value="auto">🤖 Resposta Automática</SelectItem>
                  <SelectItem value="assisted">👤 Resposta Assistida</SelectItem>
                </SelectContent>
              </Select>
            </div>
            <div className="flex items-center justify-between space-y-2">
              <Label className="text-white">Aprendizado Ativo</Label>
              <Switch
                checked={selectedNode.data.learning || false}
                onCheckedChange={(v) => updateNodeData('learning', v)}
              />
            </div>
          </>
        );

      default:
        return null;
    }
  };

  return (
    <Card className="w-80 border-0 bg-slate-900 text-white overflow-auto">
      <CardHeader className="border-b border-slate-800">
        <CardTitle className="flex items-center gap-2 text-white">
          <Settings2 className="h-5 w-5" />
          Propriedades
        </CardTitle>
      </CardHeader>
      <CardContent className="space-y-4 pt-6">
        {renderProperties()}
      </CardContent>
    </Card>
  );
}

import { useState, useCallback, useEffect } from 'react';
import ReactFlow, {
  Node,
  Edge,
  Controls,
  Background,
  applyNodeChanges,
  applyEdgeChanges,
  addEdge,
  NodeChange,
  EdgeChange,
  Connection,
  BackgroundVariant,
  MiniMap,
} from 'reactflow';
import 'reactflow/dist/style.css';
import { Button } from '@/components/ui/button';
import { Card } from '@/components/ui/card';
import { Save, Play, Download, Upload, ZoomIn, ZoomOut } from 'lucide-react';
import { toast } from 'sonner';
import { TriggerNode } from './nodes/TriggerNode';
import { ActionNode } from './nodes/ActionNode';
import { ConditionNode } from './nodes/ConditionNode';
import { IANode } from './nodes/IANode';
import { NodePropertiesPanel } from './NodePropertiesPanel';
import { NodeToolbar } from './NodeToolbar';
import { supabase } from '@/integrations/supabase/client';

interface AutomationFlow {
  id: string;
  name: string;
  nodes: Node[];
  edges: Edge[];
  active: boolean;
  company_id?: string;
  owner_id?: string;
}

const nodeTypes = {
  trigger: TriggerNode,
  action: ActionNode,
  condition: ConditionNode,
  ia: IANode,
};

interface VisualFlowBuilderProps {
  fluxoId?: string;
  onSave?: () => void;
}

export function VisualFlowBuilder({ fluxoId, onSave }: VisualFlowBuilderProps) {
  const [nodes, setNodes] = useState<Node[]>([]);
  const [edges, setEdges] = useState<Edge[]>([]);
  const [selectedNode, setSelectedNode] = useState<Node | null>(null);
  const [flowName, setFlowName] = useState('Novo Fluxo');

  useEffect(() => {
    if (fluxoId) {
      loadFlow(fluxoId);
    }
  }, [fluxoId]);

  const loadFlow = async (id: string) => {
    try {
      const { data, error } = await supabase
        .from('automation_flows' as any)
        .select('*')
        .eq('id', id)
        .maybeSingle();

      if (error) throw error;
      if (data) {
        const flowData = data as any;
        setFlowName(flowData.name || 'Fluxo sem nome');
        setNodes(flowData.nodes || []);
        setEdges(flowData.edges || []);
      }
    } catch (error) {
      console.error('Erro ao carregar fluxo:', error);
      toast.error('Erro ao carregar fluxo');
    }
  };

  const onNodesChange = useCallback(
    (changes: NodeChange[]) => setNodes((nds) => applyNodeChanges(changes, nds)),
    []
  );

  const onEdgesChange = useCallback(
    (changes: EdgeChange[]) => setEdges((eds) => applyEdgeChanges(changes, eds)),
    []
  );

  const onConnect = useCallback(
    (connection: Connection) => setEdges((eds) => addEdge(connection, eds)),
    []
  );

  const onNodeClick = useCallback((_: any, node: Node) => {
    setSelectedNode(node);
  }, []);

  const handleSaveFlow = async () => {
    try {
      const { data: { user } } = await supabase.auth.getUser();
      if (!user) throw new Error('Usuário não autenticado');

      // Get company_id from user_roles
      const { data: userRoles } = await supabase
        .from('user_roles')
        .select('company_id')
        .eq('user_id', user.id)
        .single();

      if (!userRoles?.company_id) {
        throw new Error('Empresa não encontrada');
      }

      const flowData = {
        name: flowName,
        nodes: nodes as any,
        edges: edges as any,
        active: true,
        company_id: userRoles.company_id,
        owner_id: user.id,
        updated_at: new Date().toISOString(),
      };

      if (fluxoId) {
        const { error } = await supabase
          .from('automation_flows' as any)
          .update(flowData)
          .eq('id', fluxoId);

        if (error) throw error;
      } else {
        const { error } = await supabase
          .from('automation_flows' as any)
          .insert(flowData);

        if (error) throw error;
      }

      toast.success('Fluxo salvo com sucesso!');
      onSave?.();
    } catch (error: any) {
      console.error('Erro ao salvar fluxo:', error);
      toast.error(error?.message || 'Erro ao salvar fluxo');
    }
  };

  const handleExportFlow = () => {
    const flowData = { name: flowName, nodes, edges };
    const dataStr = JSON.stringify(flowData, null, 2);
    const dataBlob = new Blob([dataStr], { type: 'application/json' });
    const url = URL.createObjectURL(dataBlob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `${flowName.replace(/\s+/g, '_')}.json`;
    link.click();
    toast.success('Fluxo exportado!');
  };

  const handleImportFlow = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const flowData = JSON.parse(e.target?.result as string);
        setFlowName(flowData.name || 'Fluxo Importado');
        setNodes(flowData.nodes || []);
        setEdges(flowData.edges || []);
        toast.success('Fluxo importado com sucesso!');
      } catch (error) {
        toast.error('Erro ao importar fluxo');
      }
    };
    reader.readAsText(file);
  };

  const handleTestFlow = () => {
    toast.info('Iniciando simulação do fluxo...');
    // Implementar lógica de simulação
  };

  return (
    <div className="flex h-[calc(100vh-12rem)] gap-4">
      {/* Canvas Principal */}
      <Card className="flex-1 relative border-0 bg-slate-950 overflow-hidden">
        {/* Toolbar Superior */}
        <div className="absolute top-4 left-4 z-10 flex items-center gap-2">
          <input
            type="text"
            value={flowName}
            onChange={(e) => setFlowName(e.target.value)}
            className="px-4 py-2 bg-slate-900/90 text-white border border-slate-700 rounded-lg font-semibold min-w-[200px]"
            placeholder="Nome do Fluxo"
          />
          <Button onClick={handleSaveFlow} size="sm" className="bg-blue-600 hover:bg-blue-700">
            <Save className="h-4 w-4 mr-2" />
            Salvar
          </Button>
          <Button onClick={handleTestFlow} size="sm" variant="outline" className="bg-slate-900/90 border-slate-700">
            <Play className="h-4 w-4 mr-2" />
            Testar
          </Button>
          <Button onClick={handleExportFlow} size="sm" variant="outline" className="bg-slate-900/90 border-slate-700">
            <Download className="h-4 w-4 mr-2" />
            Exportar
          </Button>
          <label>
            <Button size="sm" variant="outline" className="bg-slate-900/90 border-slate-700" asChild>
              <span>
                <Upload className="h-4 w-4 mr-2" />
                Importar
              </span>
            </Button>
            <input
              type="file"
              accept=".json"
              onChange={handleImportFlow}
              className="hidden"
            />
          </label>
        </div>

        {/* React Flow Canvas */}
        <ReactFlow
          nodes={nodes}
          edges={edges}
          onNodesChange={onNodesChange}
          onEdgesChange={onEdgesChange}
          onConnect={onConnect}
          onNodeClick={onNodeClick}
          nodeTypes={nodeTypes}
          fitView
          className="bg-slate-950"
        >
          <Background 
            variant={BackgroundVariant.Dots} 
            gap={16} 
            size={1} 
            color="#1e293b" 
          />
          <Controls className="bg-slate-900 border-slate-700" />
          <MiniMap 
            className="bg-slate-900 border border-slate-700" 
            nodeColor={(node) => {
              switch (node.type) {
                case 'trigger': return '#10b981';
                case 'action': return '#f59e0b';
                case 'condition': return '#8b5cf6';
                case 'ia': return '#3b82f6';
                default: return '#6b7280';
              }
            }}
          />
        </ReactFlow>

        {/* Node Toolbar */}
        <NodeToolbar setNodes={setNodes} setEdges={setEdges} />
      </Card>

      {/* Painel Lateral de Propriedades */}
      <NodePropertiesPanel 
        selectedNode={selectedNode} 
        onUpdate={(updatedNode) => {
          setNodes((nds) =>
            nds.map((n) => (n.id === updatedNode.id ? updatedNode : n))
          );
        }}
      />
    </div>
  );
}

