  // Função auxiliar para buscar ou criar lead no Supabase
  const findOrCreateLead = async (conversation: Conversation) => {
    try {
      console.log('🔍 Buscando/criando lead para conversa:', conversation.contactName);
      
      // Buscar user_id do usuário autenticado
      const { data: { user } } = await supabase.auth.getUser();
      if (!user) {
        console.warn('⚠️ Usuário não autenticado');
        return null;
      }

      // Buscar company_id do usuário
      const { data: userRole } = await supabase
        .from('user_roles')
        .select('company_id')
        .eq('user_id', user.id)
        .maybeSingle();

      if (!userRole?.company_id) {
        console.warn('⚠️ Usuário sem company_id');
        toast.error('Erro: Configuração de empresa não encontrada');
        return null;
      }

      const phoneToSearch = conversation.phoneNumber || conversation.id;
      console.log('📞 Buscando lead com telefone:', phoneToSearch);
      
      // Tentar buscar lead existente por telefone
      const { data: existingLead, error: searchError } = await supabase
        .from('leads')
        .select('*')
        .eq('company_id', userRole.company_id)
        .or(`phone.eq.${phoneToSearch},telefone.eq.${phoneToSearch}`)
        .maybeSingle();

      if (searchError && searchError.code !== 'PGRST116') {
        console.error('❌ Erro ao buscar lead:', searchError);
        return null;
      }

      // Se encontrou, retornar
      if (existingLead) {
        console.log('✅ Lead encontrado:', existingLead.id);
        return existingLead;
      }

      // Se não encontrou, criar novo lead
      console.log('📝 Criando novo lead no Supabase...');
      
      // Preparar dados do novo lead
      const newLeadData = {
        name: conversation.contactName,
        phone: phoneToSearch,
        telefone: phoneToSearch,
        company_id: userRole.company_id,
        owner_id: user.id,
        status: 'novo',
        stage: conversation.funnelStage?.toLowerCase() || 'prospeccao',
        value: conversation.valor ? parseFloat(conversation.valor.replace(/[^\d,]/g, '').replace(',', '.')) : 0,
        tags: conversation.tags || [],
        notes: conversation.anotacoes || null,
        servico: conversation.produto || null,
        source: `Conversa ${conversation.channel}`,
      };

      console.log('📦 Dados do novo lead:', newLeadData);

      const { data: newLead, error: createError } = await supabase
        .from('leads')
        .insert(newLeadData)
        .select()
        .single();

      if (createError) {
        console.error('❌ Erro ao criar lead:', createError);
        toast.error(`Erro ao criar lead: ${createError.message}`);
        return null;
      }

      console.log('✅ Novo lead criado com sucesso:', newLead.id);
      toast.success(`Lead "${conversation.contactName}" criado automaticamente!`);
      
      // O realtime vai propagar para Leads e Funil automaticamente
      return newLead;
    } catch (error) {
      console.error('❌ Erro em findOrCreateLead:', error);
      toast.error('Erro ao processar lead');
      return null;
    }
  };

  // Função para verificar se existe lead vinculado
  const verificarLeadVinculado = async (conversation: Conversation) => {
    try {
      setVerificandoLead(true);
      setMostrarBotaoCriarLead(false);
      
      const { data: userRole } = await supabase
        .from('user_roles')
        .select('company_id')
        .eq('user_id', (await supabase.auth.getUser()).data.user?.id)
        .maybeSingle();

      if (!userRole?.company_id) {
        setVerificandoLead(false);
        return;
      }

      const phoneToSearch = conversation.phoneNumber || conversation.id;
      
      const { data: existingLead } = await supabase
        .from('leads')
        .select('*')
        .eq('company_id', userRole.company_id)
        .or(`phone.eq.${phoneToSearch},telefone.eq.${phoneToSearch}`)
        .maybeSingle();

      if (existingLead) {
        setLeadVinculado(existingLead);
        setMostrarBotaoCriarLead(false);
        console.log("✅ Lead vinculado encontrado:", existingLead);
      } else {
        setLeadVinculado(null);
        setMostrarBotaoCriarLead(true);
        console.log("ℹ️ Nenhum lead vinculado a este contato");
      }
    } catch (error) {
      console.error('Erro ao verificar lead:', error);
      setLeadVinculado(null);
      setMostrarBotaoCriarLead(false);
    } finally {
      setVerificandoLead(false);
    }
  };

  // Função para criar lead manualmente
  const criarLeadManualmente = async () => {
    if (!selectedConv) return;
    
    try {
      setSyncStatus('syncing');
      const lead = await findOrCreateLead(selectedConv);
      
      if (lead) {
        setLeadVinculado(true);
        setSyncStatus('synced');
        setTimeout(() => setSyncStatus('idle'), 4000);
      } else {
        setSyncStatus('error');
        setTimeout(() => setSyncStatus('idle'), 5000);
      }
    } catch (error) {
      console.error('Erro ao criar lead:', error);
      setSyncStatus('error');
      setTimeout(() => setSyncStatus('idle'), 5000);
    }
  };

  const handleEditName = async (conversationId: string) => {
    const conv = conversations.find(c => c.id === conversationId);
    if (!conv) return;

    const novoNome = prompt("Digite o novo nome do contato:", conv.contactName);
    if (!novoNome || novoNome.trim() === "") return;

    try {
      // Atualizar no Supabase
      const { error } = await supabase
        .from('conversas')
        .update({ nome_contato: novoNome.trim() })
        .eq('numero', conv.phoneNumber || conv.id);

      if (error) throw error;

      // Atualizar localmente
      const updated = conversations.map(c =>
        c.id === conversationId ? { ...c, contactName: novoNome.trim() } : c
      );
      setConversations(updated);
      if (selectedConv?.id === conversationId) {
        setSelectedConv({ ...selectedConv, contactName: novoNome.trim() });
      }
      saveConversations(updated);

      toast.success("Nome atualizado com sucesso!");
    } catch (error) {
      console.error('Erro ao editar nome:', error);
      toast.error("Erro ao atualizar nome");
    }
  };

  const handleCreateLead = async (conversationId: string) => {
    const conv = conversations.find(c => c.id === conversationId);
    if (!conv) return;

    try {
      setSyncStatus('syncing');
      
      // Selecionar a conversa antes de criar o lead
      setSelectedConv(conv);
      
      // Aguardar um pouco para o state atualizar
      await new Promise(resolve => setTimeout(resolve, 100));
      
      const lead = await findOrCreateLead(conv);
      
      if (lead) {
        // Atualizar o mapeamento de leads vinculados
        const formatted = safeFormatPhoneNumber(conv.id);
        setLeadsVinculados(prev => ({
          ...prev,
          [conv.id]: lead.id,
          ...(formatted ? { [formatted]: lead.id } : {})
        }));
        
        setLeadVinculado(lead);
        setSyncStatus('synced');
        setTimeout(() => setSyncStatus('idle'), 4000);
        toast.success(`Lead ${conv.contactName} criado com sucesso!`);
      } else {
        setSyncStatus('error');
        setTimeout(() => setSyncStatus('idle'), 5000);
        toast.error("Erro ao criar lead");
      }
    } catch (error) {
      console.error('Erro ao criar lead:', error);
      setSyncStatus('error');
      setTimeout(() => setSyncStatus('idle'), 5000);
      toast.error("Erro ao criar lead");
    }
  };

  const handleDeleteConversation = async (conversationId: string) => {
    const conv = conversations.find(c => c.id === conversationId);
    if (!conv) return;

    const confirmar = window.confirm(`Tem certeza que deseja excluir a conversa com ${conv.contactName}?`);
    if (!confirmar) return;

    try {
      // Deletar no Supabase
      const { error } = await supabase
        .from('conversas')
        .delete()
        .eq('numero', conv.phoneNumber || conv.id);

      if (error) throw error;

      // Remover localmente
      const updated = conversations.filter(c => c.id !== conversationId);
      setConversations(updated);
      
      // Remover do mapeamento de leads vinculados
      setLeadsVinculados(prev => {
        const newMap = { ...prev };
        delete newMap[conv.id];
        const formatted = safeFormatPhoneNumber(conv.id);
        if (formatted) {
          delete newMap[formatted];
        }
        return newMap;
      });
      
      if (selectedConv?.id === conversationId) {
        setSelectedConv(null);
        setLeadVinculado(null);
      }
      saveConversations(updated);

      toast.success("Conversa excluída com sucesso!");
    } catch (error) {
      console.error('Erro ao excluir conversa:', error);
      toast.error("Erro ao excluir conversa");
    }
  };

  const filteredConversations = conversations
    .filter((conv) => filter === "all" || conv.status === filter)
    .filter((conv) => conv.contactName.toLowerCase().includes(searchTerm.toLowerCase()));

  return (
    <div className="h-screen bg-background flex overflow-hidden">
      {/* Sidebar esquerda - tema cinza claro */}
      <div className="w-[380px] bg-muted/30 border-r border-border flex flex-col">
        {/* Header */}
        <div className="p-4 bg-background border-b border-border">
          <div className="flex items-center justify-between mb-4">
            <h1 className="text-xl font-semibold text-foreground">Conversas</h1>
            <div className="flex gap-2 items-center">
              <Badge variant="outline" className="bg-green-500/10 text-green-600 border-green-500/20">
                <MessageSquare className="h-3 w-3 mr-1" />
                {conversations.length} conversas
              </Badge>
              <NovaConversaDialog
                onNovaConversa={(nome, numero) => {
                  // Verificar se já existe conversa com esse número
                  const existente = conversations.find(c => c.id === numero || c.phoneNumber === numero);
                  
                  if (existente) {
                    setSelectedConv(existente);
                    toast.info("Conversa já existe!");
                    return;
                  }
                  
                  // Criar nova conversa
                  const novaConversa: Conversation = {
                    id: numero,
                    contactName: nome,
                    channel: "whatsapp",
                    status: "waiting",
                    lastMessage: "Nova conversa",
                    unread: 0,
                    messages: [],
                    tags: [],
                    phoneNumber: numero,
                  };
                  
                  const updated = [novaConversa, ...conversations];
                  setConversations(updated);
                  setSelectedConv(novaConversa);
                  saveConversations(updated);
                  
                  toast.success(`Contato ${nome} salvo!`);
                }}
              />
              <Button 
                size="sm" 
                variant="outline"
                onClick={() => {
                  console.log('🔄 Botão Recarregar clicado');
                  loadSupabaseConversations();
                  toast.success('Recarregando conversas...');
                }}
                className="gap-2"
              >
                <RefreshCw className="h-4 w-4" />
                Recarregar
              </Button>
            </div>
          </div>
          
          {/* Search */}
          <div className="relative mb-4">
            <Search className="absolute left-3 top-2.5 h-4 w-4 text-muted-foreground" />
            <Input
              placeholder="🔍 Buscar conversa..."
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              className="pl-10 bg-background"
            />
          </div>

          {/* Filters */}
          <div className="flex gap-2 flex-wrap">
            <Button
              variant={filter === "all" ? "default" : "ghost"}
              size="sm"
              onClick={() => setFilter("all")}
            >
              Todos
            </Button>
            <Button
              variant={filter === "waiting" ? "default" : "ghost"}
              size="sm"
              onClick={() => setFilter("waiting")}
            >
              Aguardando
            </Button>
            <Button
              variant={filter === "answered" ? "default" : "ghost"}
              size="sm"
              onClick={() => setFilter("answered")}
            >
              Respondidos
            </Button>
            <Button
              variant={filter === "resolved" ? "default" : "ghost"}
              size="sm"
              onClick={() => setFilter("resolved")}
            >
              Resolvidos
            </Button>
          </div>
        </div>

        {/* Conversations List */}
        <ScrollArea className="flex-1">
          {filteredConversations.map((conv) => (
            <ConversationListItem
              key={conv.id}
              contactName={conv.contactName}
              channel={conv.channel}
              lastMessage={conv.lastMessage}
              timestamp={new Date(conv.messages[conv.messages.length - 1]?.timestamp)}
              unread={conv.unread}
              isSelected={selectedConv?.id === conv.id}
              avatarUrl={conv.avatarUrl}
              tags={conv.tags}
              responsavel={conv.responsavel}
              funnelStage={conv.funnelStage}
              valor={conv.valor}
              conversationId={conv.id}
              leadId={leadsVinculados[conv.id] || leadsVinculados[safeFormatPhoneNumber(conv.id)]}
              onEditName={() => handleEditName(conv.id)}
              onCreateLead={() => handleCreateLead(conv.id)}
              onDeleteConversation={() => handleDeleteConversation(conv.id)}
              onClick={() => {
                console.log('🔍 Conversa selecionada:', conv.id, 'Mensagens:', conv.messages.length);
                
                // Marcar mensagens como lidas e visualizadas
                const updatedConv = {
                  ...conv,
                  unread: 0,
                  messages: conv.messages.map(msg => ({
                    ...msg,
                    read: true
                  }))
                };
                
                setSelectedConv(updatedConv);
                
                // Verificar se existe lead vinculado
                verificarLeadVinculado(conv);
                
                // Atualizar no localStorage
                const updated = conversations.map(c => 
                  c.id === conv.id ? updatedConv : c
                );
                saveConversations(updated);
                
                // Mostrar toast de visualizado
                if (conv.unread > 0) {
                  toast.success('✔️ Mensagens visualizadas');
                }
              }}
            />
          ))}
        </ScrollArea>
      </div>

      {/* Chat Area */}
      <div className="flex-1 flex flex-col">
        {selectedConv ? (
          <>
            <ConversationHeader
              contactName={selectedConv.contactName}
              channel={selectedConv.channel}
              avatarUrl={selectedConv.avatarUrl}
              produto={selectedConv.produto}
              valor={selectedConv.valor}
              responsavel={selectedConv.responsavel}
              tags={selectedConv.tags}
              funnelStage={selectedConv.funnelStage}
              showInfoPanel={showInfoPanel}
              onToggleInfoPanel={() => setShowInfoPanel(!showInfoPanel)}
              syncStatus={syncStatus}
              leadVinculado={leadVinculado}
              verificandoLead={verificandoLead}
              mostrarBotaoCriarLead={mostrarBotaoCriarLead}
              onCriarLead={criarLeadManualmente}
            />

            <div className="flex flex-1 overflow-hidden">
              {/* Messages Area */}
              <div className="flex-1 flex flex-col">
                {/* Messages */}
                <ScrollArea className="flex-1 p-6 bg-[#e5ddd5]" style={{ backgroundImage: "url('data:image/svg+xml,%3Csvg width='60' height='60' viewBox='0 0 60 60' xmlns='http://www.w3.org/2000/svg'%3E%3Cg fill='none' fill-rule='evenodd'%3E%3Cg fill='%23d9d9d9' fill-opacity='0.2'%3E%3Cpath d='M36 34v-4h-2v4h-4v2h4v4h2v-4h4v-2h-4zm0-30V0h-2v4h-4v2h4v4h2V6h4V4h-4zM6 34v-4H4v4H0v2h4v4h2v-4h4v-2H6zM6 4V0H4v4H0v2h4v4h2V6h4V4H6z'/%3E%3C/g%3E%3C/g%3E%3C/svg%3E')" }}>
                  <div className="space-y-2 min-h-[200px]">
                     {selectedConv.messages.length === 0 ? (
                      <div className="text-center text-muted-foreground py-8">
                        Nenhuma mensagem ainda
                      </div>
                     ) : (
                      selectedConv.messages.map((msg) => (
                        <MessageItem
                          key={msg.id}
                          message={msg}
                          allMessages={selectedConv.messages}
                          onDownload={downloadMedia}
                          onTranscribe={transcreverAudio}
                          onImageClick={(url, name) => {
                            setSelectedMedia({ url, name });
                            setImageModalOpen(true);
                          }}
                          onPdfClick={(url, name) => {
                            setSelectedMedia({ url, name });
                            setPdfModalOpen(true);
                          }}
                          isTranscribing={transcrevendo === msg.id}
                          onReply={handleReply}
                          onEdit={handleEdit}
                          onDelete={handleDelete}
                          onReact={handleReact}
                        />
                      ))
                    )}
                    <div ref={messagesEndRef} />
                  </div>
                </ScrollArea>

                {/* Input Area */}
                <div className="bg-background border-t border-border p-4">
                  {replyingTo && (
                    <div className="mb-2 p-3 bg-blue-50 dark:bg-blue-950 rounded-lg border border-blue-200 dark:border-blue-800">
                      <div className="flex items-center justify-between">
                        <div className="flex items-start gap-2 flex-1 min-w-0">
                          <Reply className="h-4 w-4 text-blue-600 dark:text-blue-400 mt-0.5 flex-shrink-0" />
                          <div className="flex-1 min-w-0">
                            <p className="text-xs font-medium text-blue-600 dark:text-blue-400 mb-1">
                              Respondendo mensagem
                            </p>
                            <p className="text-sm text-muted-foreground truncate">
                              {selectedConv?.messages.find(m => m.id === replyingTo)?.content || ''}
                            </p>
                          </div>
                        </div>
                        <Button
                          size="sm"
                          variant="ghost"
                          onClick={() => setReplyingTo(null)}
                          className="flex-shrink-0 h-7 w-7 p-0"
                        >
                          ✕
                        </Button>
                      </div>
                    </div>
                  )}
                  <div className="flex items-center gap-2">
                    <MediaUpload onSendMedia={handleSendMedia} />
                    <Input
                      placeholder="Escreva sua mensagem..."
                      value={messageInput}
                      onChange={(e) => setMessageInput(e.target.value)}
                      onKeyPress={(e) => e.key === "Enter" && handleSendMessage()}
                      className="flex-1"
                    />
                    <AudioRecorder onSendAudio={handleSendAudio} />
                    <Button 
                      onClick={() => {
                        handleSendMessage();
                        setReplyingTo(null);
                      }} 
                      size="icon"
                      className="bg-[#25D366] hover:bg-[#128C7E] text-white"
                      disabled={!messageInput.trim()}
                    >
                      <Send className="h-5 w-5" />
                    </Button>
                  </div>
                </div>
              </div>

              {/* Info Panel */}
              {showInfoPanel && (
                <div className="w-[340px] bg-background border-l border-border overflow-y-auto">
                  <div className="p-6 space-y-6">
                    {/* Contact Info */}
                    <div className="text-center">
                      <div className="w-20 h-20 rounded-full bg-muted flex items-center justify-center mx-auto mb-3">
                        <User className="h-10 w-10 text-muted-foreground" />
                      </div>
                      <h3 className="text-foreground font-medium text-lg">{selectedConv.contactName}</h3>
                      <p className="text-muted-foreground text-sm capitalize">{selectedConv.channel}</p>
                    </div>

                    {/* Informações do Lead */}
                    <div>
                      <h4 className="text-foreground font-medium mb-3 flex items-center gap-2">
                        <DollarSign className="h-4 w-4" /> Informações do Lead
                      </h4>
                      
                      {/* Status de vinculação com Lead */}
                      <div className="mb-3">
                        {verificandoLead ? (
                          <Badge variant="outline" className="w-full justify-center gap-2 py-2">
                            <RefreshCw className="h-3 w-3 animate-spin" />
                            <span className="text-xs">Verificando...</span>
                          </Badge>
                        ) : leadVinculado ? (
                          <Badge variant="outline" className="w-full justify-center gap-2 py-2 bg-green-500/10 text-green-600 border-green-500/20">
                            <CheckCircle2 className="h-3 w-3" />
                            <span className="text-xs font-medium">Lead vinculado no CRM</span>
                          </Badge>
                        ) : (
                          <div className="space-y-2">
                            <Badge variant="outline" className="w-full justify-center gap-2 py-2 bg-amber-500/10 text-amber-600 border-amber-500/20">
                              <AlertCircle className="h-3 w-3" />
                              <span className="text-xs font-medium">Lead não cadastrado</span>
                            </Badge>
                            <Button 
                              size="sm" 
                              variant="outline" 
                              className="w-full border-primary/50 hover:bg-primary/10"
                              onClick={criarLeadManualmente}
                            >
                              <User className="h-3 w-3 mr-2" />
                              Criar Lead no CRM
                            </Button>
                          </div>
                        )}
                      </div>
                      
                      <EditarInformacoesLeadDialog 
                        leadId={leadsVinculados[selectedConv.id] || leadsVinculados[safeFormatPhoneNumber(selectedConv.id)] || null}
                        telefone={selectedConv.phoneNumber || selectedConv.id}
                        nomeContato={selectedConv.contactName}
                        onLeadUpdated={() => {
                          // Recarregar dados da conversa após atualização
                          verificarLeadVinculado(selectedConv);
                          loadSupabaseConversations();
                        }}
                      />
                      {selectedConv.produto && (
                        <p className="text-sm text-muted-foreground mb-1">
                          <strong>Produto:</strong> {selectedConv.produto}
                        </p>
                      )}
                      {selectedConv.valor && (
                        <p className="text-sm text-success font-medium mb-1">
                          <strong>Valor:</strong> {selectedConv.valor}
                        </p>
                      )}
                      {selectedConv.anotacoes && (
                        <div className="mt-2 p-2 bg-muted rounded text-sm">
                          <strong>Anotações:</strong> {selectedConv.anotacoes}
                        </div>
                      )}
                    </div>

                    {/* Responsáveis */}
                    <ResponsaveisManager 
                      leadId={leadsVinculados[selectedConv.id] || leadsVinculados[safeFormatPhoneNumber(selectedConv.id)] || null}
                      responsaveisAtuais={selectedConv.responsavel ? [selectedConv.responsavel] : []}
                      onResponsaveisUpdated={(responsaveis) => {
                        console.log('👥 Responsáveis atualizados:', responsaveis);
                        setConversations(prev => prev.map(conv => 
                          conv.id === selectedConv.id 
                            ? { ...conv, responsavel: responsaveis.join(', ') }
                            : conv
                        ));
                        setSelectedConv(prev => prev ? { ...prev, responsavel: responsaveis.join(', ') } : null);
                      }}
                    />

                    {/* Tags */}
                    <div>
                      <h4 className="text-foreground font-medium mb-2 flex items-center gap-2">
                        <Tag className="h-4 w-4" /> Tags
                      </h4>
                      <div className="flex flex-wrap gap-2 mb-2">
                        {selectedConv.tags?.map((tag, idx) => (
                          <Badge key={idx} variant="secondary">
                            {tag}
                          </Badge>
                        ))}
                      </div>
                      <Dialog>
                        <DialogTrigger asChild>
                          <Button size="sm" variant="outline" className="w-full">
                            <Tag className="h-3 w-3 mr-2" /> Adicionar Tag
                          </Button>
                        </DialogTrigger>
                        <DialogContent>
                          <DialogHeader>
                            <DialogTitle>Adicionar Tag</DialogTitle>
                          </DialogHeader>
                          <Input
                            placeholder="Nome da tag"
                            value={newTag}
                            onChange={(e) => setNewTag(e.target.value)}
                          />
                          <Button onClick={addTag}>
                            Adicionar
                          </Button>
                        </DialogContent>
                      </Dialog>
                    </div>

                    {/* Funnel Stage */}
                    <div>
                      <h4 className="text-foreground font-medium mb-2 flex items-center gap-2">
                        <TrendingUp className="h-4 w-4" /> Funil de Vendas
                      </h4>
                      {leadVinculado && leadVinculado.funil_id ? (
                        <div className="mb-2 p-2 bg-primary/5 rounded-md border border-primary/20">
                          <p className="text-xs text-muted-foreground">Lead no funil:</p>
                          <p className="text-sm font-medium">
                            {funis.find(f => f.id === leadVinculado.funil_id)?.nome || "Funil"}
                          </p>
                          <p className="text-xs text-muted-foreground mt-1">Etapa atual:</p>
                          <div className="flex items-center gap-2">
                            <div 
                              className="w-2 h-2 rounded-full" 
                              style={{ 
                                backgroundColor: etapas.find(e => e.id === leadVinculado.etapa_id)?.cor || '#3b82f6' 
                              }}
                            />
                            <p className="text-sm font-medium">
                              {etapas.find(e => e.id === leadVinculado.etapa_id)?.nome || "Não definida"}
                            </p>
                          </div>
                        </div>
                      ) : (
                        <p className="text-sm text-muted-foreground mb-2">Não está em nenhum funil</p>
                      )}
                      <Dialog>
                        <DialogTrigger asChild>
                          <Button size="sm" variant="outline" className="w-full">
                            <TrendingUp className="h-3 w-3 mr-2" /> Adicionar ao Funil
                          </Button>
                        </DialogTrigger>
                        <DialogContent>
                          <DialogHeader>
                            <DialogTitle>Adicionar ao Funil</DialogTitle>
                            <p className="text-sm text-muted-foreground mt-1">
                              Selecione o funil de vendas e a etapa para adicionar este lead
                            </p>
                          </DialogHeader>
                          
                          <div className="space-y-4">
                            <div>
                              <Label htmlFor="funil-select">Funil de Vendas *</Label>
                              <Select value={selectedFunilId} onValueChange={setSelectedFunilId}>
                                <SelectTrigger id="funil-select">
                                  <SelectValue placeholder={
                                    funis.length === 0 
                                      ? "Nenhum funil disponível" 
                                      : "Escolha um funil"
                                  } />
                                </SelectTrigger>
                                <SelectContent>
                                  {funis.length === 0 ? (
                                    <div className="p-2 text-sm text-muted-foreground text-center">
                                      <p>Nenhum funil criado</p>
                                      <p className="text-xs mt-1">Crie um no menu Kanban</p>
                                    </div>
                                  ) : (
                                    funis.map((funil) => (
                                      <SelectItem key={funil.id} value={funil.id}>
                                        📊 {funil.nome}
                                        {funil.descricao && (
                                          <span className="text-xs text-muted-foreground ml-2">
                                            - {funil.descricao}
                                          </span>
                                        )}
                                      </SelectItem>
                                    ))
                                  )}
                                </SelectContent>
                              </Select>
                              {funis.length === 0 && (
                                <p className="text-xs text-destructive mt-1">
                                  ⚠️ Crie um funil no menu Kanban
                                </p>
                              )}
                            </div>

                            <div>
                              <Label htmlFor="etapa-select">Etapa *</Label>
                              <Select 
                                value={selectedFunnel} 
                                onValueChange={setSelectedFunnel}
                                disabled={!selectedFunilId}
                              >
                                <SelectTrigger id="etapa-select">
                                  <SelectValue placeholder={
                                    !selectedFunilId 
                                      ? "Selecione um funil primeiro" 
                                      : "Escolha a etapa"
                                  } />
                                </SelectTrigger>
                                <SelectContent>
                                  {etapasFiltradas.length === 0 ? (
                                    <div className="p-2 text-sm text-muted-foreground">
                                      Nenhuma etapa disponível neste funil
                                    </div>
                                  ) : (
                                    etapasFiltradas.map((etapa) => (
                                      <SelectItem key={etapa.id} value={etapa.id}>
                                        <div className="flex items-center gap-2">
                                          <div 
                                            className="w-3 h-3 rounded-full" 
                                            style={{ backgroundColor: etapa.cor || '#3b82f6' }}
                                          />
                                          {etapa.nome}
                                        </div>
                                      </SelectItem>
                                    ))
                                  )}
                                </SelectContent>
                              </Select>
                              {!selectedFunilId && (
                                <p className="text-xs text-muted-foreground mt-1">
                                  💡 Selecione um funil para ver as etapas
                                </p>
                              )}
                            </div>
                          </div>
                          <Button onClick={addToFunnel}>
                            Adicionar
                          </Button>
                        </DialogContent>
                      </Dialog>
                    </div>

                    {/* Quick Actions */}
                    <div>
                      <h4 className="text-foreground font-medium mb-3">Ações Rápidas</h4>
                      <div className="space-y-2">
                        {/* AI Toggle */}
                        <Button
                          onClick={() => toggleAiMode(selectedConv.id)}
                          variant={aiMode[selectedConv.id] ? "default" : "outline"}
                          className="w-full justify-start"
                        >
                          <Bot className="h-4 w-4 mr-2" />
                          {aiMode[selectedConv.id] ? "Desativar IA" : "Ativar IA"}
                        </Button>

                        {/* Quick Messages */}
                        <Dialog>
                          <DialogTrigger asChild>
                            <Button variant="outline" className="w-full justify-start">
                              <Zap className="h-4 w-4 mr-2" /> Mensagens Rápidas
                            </Button>
                          </DialogTrigger>
                          <DialogContent className="max-w-3xl max-h-[80vh] overflow-y-auto">
                            <DialogHeader>
                              <DialogTitle>💡 Mensagens Rápidas</DialogTitle>
                            </DialogHeader>
                            
                            <Tabs defaultValue="messages" className="w-full">
                              <TabsList className="grid w-full grid-cols-2">
                                <TabsTrigger value="messages">Mensagens</TabsTrigger>
                                <TabsTrigger value="categories">Categorias</TabsTrigger>
                              </TabsList>
                              
                              <TabsContent value="messages" className="space-y-4">
                                {/* Botão para criar nova mensagem */}
                                <Dialog>
                                  <DialogTrigger asChild>
                                    <Button className="w-full">
                                      <Plus className="h-4 w-4 mr-2" />
                                      Criar Nova Mensagem
                                    </Button>
                                  </DialogTrigger>
                                  <DialogContent>
                                    <DialogHeader>
                                      <DialogTitle>Criar Nova Mensagem</DialogTitle>
                                    </DialogHeader>
                                    <div className="space-y-3">
                                      <div className="space-y-2">
                                        <Label>Categoria *</Label>
                                        <Select value={newQuickCategory} onValueChange={setNewQuickCategory}>
                                          <SelectTrigger>
                                            <SelectValue placeholder="Selecione a categoria" />
                                          </SelectTrigger>
                                          <SelectContent>
                                            {quickCategories.map((cat) => (
                                              <SelectItem key={cat.id} value={cat.id}>
                                                {cat.name}
                                              </SelectItem>
                                            ))}
                                          </SelectContent>
                                        </Select>
                                      </div>
                                      <div className="space-y-2">
                                        <Label>Título *</Label>
                                        <Input
                                          value={newQuickTitle}
                                          onChange={(e) => setNewQuickTitle(e.target.value)}
                                          placeholder="Ex: Saudação"
                                        />
                                      </div>
                                      <div className="space-y-2">
                                        <Label>Mensagem *</Label>
                                        <Textarea
                                          value={newQuickContent}
                                          onChange={(e) => setNewQuickContent(e.target.value)}
                                          placeholder="Digite a mensagem..."
                                          rows={3}
                                        />
                                      </div>
                                      <Button onClick={addQuickMessage} className="w-full">
                                        Criar Mensagem Rápida
                                      </Button>
                                    </div>
                                  </DialogContent>
                                </Dialog>

                                {/* Mensagens organizadas por categoria */}
                                <div className="border-t pt-4">
                                  <h4 className="text-sm font-medium mb-3">Mensagens por Categoria:</h4>
                                  {quickCategories.length === 0 ? (
                                    <p className="text-sm text-muted-foreground text-center py-4">
                                      Crie categorias na aba "Categorias"
                                    </p>
                                  ) : (
                                    <Accordion type="single" collapsible className="w-full">
                                      {quickCategories.map((category) => {
                                        const categoryMessages = quickMessages.filter(
                                          (msg) => msg.category === category.id
                                        );
                                        return (
                                          <AccordionItem key={category.id} value={category.id}>
                                            <AccordionTrigger className="hover:no-underline">
                                              <div className="flex items-center justify-between w-full pr-4">
                                                <span className="font-medium">{category.name}</span>
                                                <Badge variant="secondary">{categoryMessages.length}</Badge>
                                              </div>
                                            </AccordionTrigger>
                                            <AccordionContent>
                                              {categoryMessages.length === 0 ? (
                                                <p className="text-sm text-muted-foreground py-2 px-4">
                                                  Nenhuma mensagem nesta categoria
                                                </p>
                                              ) : (
                                                <div className="space-y-2">
                                                  {categoryMessages.map((qm) => (
                                                    <div
                                                      key={qm.id}
                                                      className="flex items-start justify-between p-3 bg-background rounded border"
                                                    >
                                                      <div className="flex-1 min-w-0">
                                                        <p className="text-sm font-medium">{qm.title}</p>
                                                        <p className="text-xs text-muted-foreground mt-1 break-words">
                                                          {qm.content}
                                                        </p>
                                                      </div>
                                                      <div className="flex gap-1 ml-2">
                                                        <Button
                                                          size="sm"
                                                          onClick={() => sendQuickMessage(qm.content)}
                                                        >
                                                          Enviar
                                                        </Button>
                                                        <Button
                                                          size="sm"
                                                          variant="destructive"
                                                          onClick={() => deleteQuickMessage(qm.id)}
                                                        >
                                                          ×
                                                        </Button>
                                                      </div>
                                                    </div>
                                                  ))}
                                                </div>
                                              )}
                                            </AccordionContent>
                                          </AccordionItem>
                                        );
                                      })}
                                    </Accordion>
                                  )}
                                </div>
                              </TabsContent>
                              
                              <TabsContent value="categories" className="space-y-4">
                                {/* Criar nova categoria */}
                                <div className="space-y-3 p-4 border rounded-lg bg-muted/20">
                                  <h4 className="text-sm font-semibold">Criar Nova Categoria</h4>
                                  <div className="flex gap-2">
                                    <Input
                                      value={newCategoryName}
                                      onChange={(e) => setNewCategoryName(e.target.value)}
                                      placeholder="Nome da categoria"
                                      onKeyDown={(e) => {
                                        if (e.key === "Enter") {
                                          e.preventDefault();
                                          addQuickCategory();
                                        }
                                      }}
                                    />
                                    <Button onClick={addQuickCategory}>
                                      Criar
                                    </Button>
                                  </div>
                                </div>

                                {/* Lista de categorias */}
                                <div>
                                  <h4 className="text-sm font-medium mb-3">Categorias Criadas:</h4>
                                  <div className="space-y-2">
                                    {quickCategories.map((cat) => {
                                      const messageCount = quickMessages.filter(
                                        (msg) => msg.category === cat.id
                                      ).length;
                                      return (
                                        <div
                                          key={cat.id}
                                          className="flex items-center justify-between p-3 bg-muted rounded border"
                                        >
                                          <div className="flex items-center gap-3">
                                            <span className="font-medium">{cat.name}</span>
                                            <Badge variant="secondary">
                                              {messageCount} {messageCount === 1 ? "mensagem" : "mensagens"}
                                            </Badge>
                                          </div>
                                          <Button
                                            size="sm"
                                            variant="destructive"
                                            onClick={() => deleteQuickCategory(cat.id)}
                                            disabled={messageCount > 0}
                                          >
                                            Excluir
                                          </Button>
                                        </div>
                                      );
                                    })}
                                  </div>
                                </div>
                              </TabsContent>
                            </Tabs>
                          </DialogContent>
                        </Dialog>

                        {/* Schedule Message */}
                        <Dialog>
                          <DialogTrigger asChild>
                            <Button variant="outline" className="w-full justify-start">
                              <Clock className="h-4 w-4 mr-2" /> Agendar Mensagem
                              {scheduledMessages.filter(m => m.status === 'pending').length > 0 && (
                                <Badge variant="secondary" className="ml-auto">
                                  {scheduledMessages.filter(m => m.status === 'pending').length}
                                </Badge>
                              )}
                            </Button>
                          </DialogTrigger>
                          <DialogContent className="max-w-2xl max-h-[80vh] overflow-y-auto">
                            <DialogHeader>
                              <DialogTitle>⏰ Agendar Mensagem WhatsApp</DialogTitle>
                              <p className="text-sm text-muted-foreground mt-1">
                                Programe mensagens para serem enviadas automaticamente
                              </p>
                            </DialogHeader>
                            
                            <Tabs defaultValue="agendar" className="w-full">
                              <TabsList className="grid w-full grid-cols-2">
                                <TabsTrigger value="agendar">Agendar Nova</TabsTrigger>
                                <TabsTrigger value="historico">
                                  Histórico 
                                  ({scheduledMessages.length})
                                </TabsTrigger>
                              </TabsList>

                              <TabsContent value="agendar" className="space-y-4">
                                <div className="space-y-3">
                                  <div className="space-y-2">
                                    <Label>Mensagem *</Label>
                                    <Textarea
                                      value={scheduledContent}
                                      onChange={(e) => setScheduledContent(e.target.value)}
                                      placeholder="Digite a mensagem que será enviada..."
                                      rows={4}
                                    />
                                  </div>
                                  <div className="space-y-2">
                                    <Label>Data e Hora *</Label>
                                    <Input
                                      type="datetime-local"
                                      value={scheduledDatetime}
                                      onChange={(e) => setScheduledDatetime(e.target.value)}
                                      min={new Date().toISOString().slice(0, 16)}
                                    />
                                    <p className="text-xs text-muted-foreground">
                                      A mensagem será enviada automaticamente no horário agendado
                                    </p>
                                  </div>
                                  <Button onClick={scheduleMessage} className="w-full">
                                    <Clock className="h-4 w-4 mr-2" />
                                    Agendar Envio
                                  </Button>
                                </div>
                              </TabsContent>

                              <TabsContent value="historico" className="space-y-4">
                                {scheduledMessages.length === 0 ? (
                                  <div className="text-center py-12 text-muted-foreground">
                                    <Clock className="h-12 w-12 mx-auto mb-3 opacity-50" />
                                    <p>Nenhuma mensagem agendada</p>
                                    <p className="text-xs mt-1">
                                      Agende mensagens na aba "Agendar Nova"
                                    </p>
                                  </div>
                                ) : (
                                  <div className="space-y-2">
                                    {scheduledMessages.map((msg) => (
                                      <div
                                        key={msg.id}
                                        className={`p-3 border rounded-lg ${
                                          msg.status === 'sent' ? 'bg-green-50 border-green-200' :
                                          msg.status === 'failed' ? 'bg-red-50 border-red-200' :
                                          'bg-background'
                                        }`}
                                      >
                                        <div className="flex items-start justify-between gap-3">
                                          <div className="flex-1 min-w-0">
                                            <div className="flex items-center gap-2 mb-1">
                                              {msg.status === 'pending' && (
                                                <Badge variant="outline" className="text-xs">
                                                  ⏳ Aguardando
                                                </Badge>
                                              )}
                                              {msg.status === 'sent' && (
                                                <Badge variant="default" className="text-xs bg-green-600">
                                                  ✓ Enviada
                                                </Badge>
                                              )}
                                              {msg.status === 'failed' && (
                                                <Badge variant="destructive" className="text-xs">
                                                  ✗ Falha
                                                </Badge>
                                              )}
                                            </div>
                                            <p className="text-sm font-medium break-words">
                                              {msg.message_content}
                                            </p>
                                            <div className="flex items-center gap-2 mt-2 text-xs text-muted-foreground">
                                              <span>
                                                📅 {new Date(msg.scheduled_datetime).toLocaleString('pt-BR')}
                                              </span>
                                              {msg.status === 'pending' && (
                                                <span className="text-primary font-medium">
                                                  <CountdownTimer targetDate={msg.scheduled_datetime} />
                                                </span>
                                              )}
                                              {msg.status === 'sent' && msg.sent_at && (
                                                <span className="text-green-600">
                                                  Enviado em {new Date(msg.sent_at).toLocaleString('pt-BR')}
                                                </span>
                                              )}
                                            </div>
                                            {msg.error_message && (
                                              <p className="text-xs text-destructive mt-1">
                                                Erro: {msg.error_message}
                                              </p>
                                            )}
                                          </div>
                                          {msg.status === 'pending' && (
                                            <Button
                                              size="sm"
                                              variant="ghost"
                                              onClick={() => cancelarMensagemAgendada(msg.id)}
                                            >
                                              <X className="h-4 w-4" />
                                            </Button>
                                          )}
                                        </div>
                                      </div>
                                    ))}
                                  </div>
                                )}
                              </TabsContent>
                            </Tabs>
                          </DialogContent>
                        </Dialog>

                        {/* Schedule Reminder */}
                        <Dialog>
                          <DialogTrigger asChild>
                            <Button variant="outline" className="w-full justify-start">
                              <Bell className="h-4 w-4 mr-2" /> Gerenciar Lembretes
                            </Button>
                          </DialogTrigger>
                          <DialogContent className="max-w-2xl max-h-[80vh] overflow-y-auto">
                            <DialogHeader>
                              <DialogTitle>Lembretes do Lead</DialogTitle>
                            </DialogHeader>
                            
                            <Tabs defaultValue="criar" className="w-full">
                              <TabsList className="grid w-full grid-cols-2">
                                <TabsTrigger value="criar">Criar Novo</TabsTrigger>
                                <TabsTrigger value="historico">
                                  Histórico ({reminders.length})
                                </TabsTrigger>
                              </TabsList>

                              <TabsContent value="criar" className="space-y-4">
                                <div>
                                  <Label>Título do Lembrete</Label>
                                  <Input
                                    value={reminderTitle}
                                    onChange={(e) => setReminderTitle(e.target.value)}
                                    placeholder="Ex: Ligar para cliente"
                                  />
                                </div>
                                <div>
                                  <Label>Data e Hora</Label>
                                  <Input
                                    type="datetime-local"
                                    value={reminderDatetime}
                                    onChange={(e) => setReminderDatetime(e.target.value)}
                                  />
                                </div>
                                <div>
                                  <Label>Observações</Label>
                                  <Textarea
                                    value={reminderNotes}
                                    onChange={(e) => setReminderNotes(e.target.value)}
                                    placeholder="Notas adicionais..."
                                  />
                                </div>
                                {!leadVinculado && (
                                  <div className="p-3 bg-yellow-500/10 border border-yellow-500/20 rounded-md">
                                    <p className="text-sm text-yellow-600">
                                      ⚠️ Vincule um lead primeiro para criar lembretes
                                    </p>
                                  </div>
                                )}
                                <Button 
                                  onClick={addReminder} 
                                  className="w-full"
                                  disabled={!leadVinculado}
                                >
                                  Criar Lembrete
                                </Button>
                              </TabsContent>

                              <TabsContent value="historico" className="space-y-4">
                                <ScrollArea className="h-[400px]">
                                  {reminders.length === 0 ? (
                                    <div className="text-center py-12 text-muted-foreground">
                                      <Bell className="h-12 w-12 mx-auto mb-2 opacity-50" />
                                      <p>Nenhum lembrete criado</p>
                                    </div>
                                  ) : (
                                    <div className="space-y-3">
                                      {reminders.map((lembrete) => (
                                        <Card key={lembrete.id} className={`border-l-4 ${
                                          lembrete.status_envio === 'enviado' ? 'border-l-green-500' :
                                          lembrete.status_envio === 'pendente' ? 'border-l-yellow-500' :
                                          'border-l-red-500'
                                        }`}>
                                          <CardContent className="pt-4">
                                            <div className="space-y-2">
                                              <div className="flex justify-between items-start">
                                                <div className="space-y-1 flex-1">
                                                  <div className="flex items-center gap-2">
                                                    <span className="font-medium">
                                                      {lembrete.compromisso?.tipo_servico || 'Lembrete'}
                                                    </span>
                                                    <Badge variant={
                                                      lembrete.status_envio === 'enviado' ? 'default' :
                                                      lembrete.status_envio === 'pendente' ? 'secondary' :
                                                      'destructive'
                                                    }>
                                                      {lembrete.status_envio === 'enviado' ? '✓ Enviado' :
                                                       lembrete.status_envio === 'pendente' ? '⏳ Pendente' :
                                                       '✗ Erro'}
                                                    </Badge>
                                                  </div>
                                                  <p className="text-sm text-muted-foreground flex items-center gap-1">
                                                    <Clock className="h-3 w-3" />
                                                    {lembrete.compromisso?.data_hora_inicio && 
                                                      format(parseISO(lembrete.compromisso.data_hora_inicio), "dd/MM/yyyy 'às' HH:mm", { locale: ptBR })
                                                    }
                                                  </p>
                                                  <p className="text-sm text-muted-foreground">
                                                    <strong>Destinatário:</strong> {
                                                      lembrete.destinatario === 'lead' ? 'Lead' :
                                                      lembrete.destinatario === 'responsavel' ? 'Responsável' :
                                                      lembrete.destinatario === 'ambos' ? 'Lead e Responsável' :
                                                      'Lead'
                                                    }
                                                  </p>
                                                  <p className="text-sm text-muted-foreground">
                                                    <strong>Canal:</strong> {lembrete.canal.toUpperCase()} | 
                                                    <strong> Antecedência:</strong> {lembrete.horas_antecedencia}h
                                                  </p>
                                                  {lembrete.data_envio && (
                                                    <p className="text-xs text-muted-foreground">
                                                      {lembrete.status_envio === 'enviado' ? 'Enviado em: ' : 'Última tentativa: '}
                                                      {format(parseISO(lembrete.data_envio), "dd/MM/yyyy 'às' HH:mm", { locale: ptBR })}
                                                    </p>
                                                  )}
                                                  {lembrete.mensagem && (
                                                    <p className="text-xs text-muted-foreground mt-2 p-2 bg-muted rounded">
                                                      {lembrete.mensagem}
                                                    </p>
                                                  )}
                                                </div>
                                              </div>
                                            </div>
                                          </CardContent>
                                        </Card>
                                      ))}
                                    </div>
                                  )}
                                </ScrollArea>
                              </TabsContent>
                            </Tabs>
                          </DialogContent>
                        </Dialog>

                        {/* Schedule Meeting */}
                        <Dialog>
                          <DialogTrigger asChild>
                            <Button variant="outline" className="w-full justify-start">
                              <Calendar className="h-4 w-4 mr-2" /> Gerenciar Reuniões
                            </Button>
                          </DialogTrigger>
                          <DialogContent className="max-w-2xl max-h-[80vh] overflow-y-auto">
                            <DialogHeader>
                              <DialogTitle>Reuniões e Compromissos</DialogTitle>
                            </DialogHeader>
                            
                            <Tabs defaultValue="criar" className="w-full">
                              <TabsList className="grid w-full grid-cols-2">
                                <TabsTrigger value="criar">Agendar Nova</TabsTrigger>
                                <TabsTrigger value="historico">
                                  Histórico ({meetings.length})
                                </TabsTrigger>
                              </TabsList>

                              <TabsContent value="criar" className="space-y-4">
                                <div>
                                  <Label>Título da Reunião</Label>
                                  <Input
                                    value={meetingTitle}
                                    onChange={(e) => setMeetingTitle(e.target.value)}
                                    placeholder="Ex: Apresentação de proposta"
                                  />
                                </div>
                                <div>
                                  <Label>Data e Hora</Label>
                                  <Input
                                    type="datetime-local"
                                    value={meetingDatetime}
                                    onChange={(e) => setMeetingDatetime(e.target.value)}
                                  />
                                </div>
                                <div>
                                  <Label>Observações</Label>
                                  <Textarea
                                    value={meetingNotes}
                                    onChange={(e) => setMeetingNotes(e.target.value)}
                                    placeholder="Pauta, participantes, etc..."
                                  />
                                </div>
                                {!leadVinculado && (
                                  <div className="p-3 bg-yellow-500/10 border border-yellow-500/20 rounded-md">
                                    <p className="text-sm text-yellow-600">
                                      ⚠️ Vincule um lead primeiro para agendar reuniões
                                    </p>
                                  </div>
                                )}
                                <Button 
                                  onClick={scheduleMeeting} 
                                  className="w-full"
                                  disabled={!leadVinculado}
                                >
                                  Agendar Reunião
                                </Button>
                              </TabsContent>

                              <TabsContent value="historico" className="space-y-4">
                                <ScrollArea className="h-[400px]">
                                  {meetings.length === 0 ? (
                                    <div className="text-center py-12 text-muted-foreground">
                                      <Calendar className="h-12 w-12 mx-auto mb-2 opacity-50" />
                                      <p>Nenhuma reunião agendada</p>
                                    </div>
                                  ) : (
                                    <div className="space-y-3">
                                      {meetings.map((meeting) => (
                                        <Card key={meeting.id} className={`border-l-4 ${
                                          meeting.status === 'concluido' ? 'border-l-green-500' :
                                          meeting.status === 'agendado' ? 'border-l-blue-500' :
                                          'border-l-red-500'
                                        }`}>
                                          <CardContent className="pt-4">
                                            <div className="space-y-2">
                                              <div className="flex justify-between items-start">
                                                <div className="space-y-1 flex-1">
                                                  <div className="flex items-center gap-2">
                                                    <span className="font-medium">
                                                      {meeting.tipo_servico}
                                                    </span>
                                                    <Badge variant={
                                                      meeting.status === 'concluido' ? 'default' :
                                                      meeting.status === 'agendado' ? 'secondary' :
                                                      'destructive'
                                                    }>
                                                      {meeting.status === 'concluido' ? '✓ Concluído' :
                                                       meeting.status === 'agendado' ? '📅 Agendado' :
                                                       '✗ Cancelado'}
                                                    </Badge>
                                                  </div>
                                                  <p className="text-sm text-muted-foreground flex items-center gap-1">
                                                    <Clock className="h-3 w-3" />
                                                    {format(parseISO(meeting.data_hora_inicio), "dd/MM/yyyy 'às' HH:mm", { locale: ptBR })}
                                                    {' - '}
                                                    {format(parseISO(meeting.data_hora_fim), "HH:mm", { locale: ptBR })}
                                                  </p>
                                                  {meeting.lead && (
                                                    <p className="text-sm text-muted-foreground flex items-center gap-1">
                                                      <User className="h-3 w-3" />
                                                      {meeting.lead.name}
                                                    </p>
                                                  )}
                                                  {meeting.custo_estimado && (
                                                    <p className="text-sm text-muted-foreground">
                                                      <strong>Valor:</strong> R$ {meeting.custo_estimado.toFixed(2)}
                                                    </p>
                                                  )}
                                                  {meeting.observacoes && (
                                                    <p className="text-xs text-muted-foreground mt-2 p-2 bg-muted rounded">
                                                      {meeting.observacoes}
                                                    </p>
                                                  )}
                                                </div>
                                              </div>
                                            </div>
                                          </CardContent>
                                        </Card>
                                      ))}
                                    </div>
                                  )}
                                </ScrollArea>
                              </TabsContent>
                            </Tabs>
                          </DialogContent>
                        </Dialog>

                        {/* Tarefas do Lead */}
                        <Dialog>
                          <DialogTrigger asChild>
                            <Button variant="outline" className="w-full justify-start">
                              <CheckSquare className="h-4 w-4 mr-2" /> Tarefas do Lead
                              {leadTasks.length > 0 && (
                                <Badge variant="secondary" className="ml-auto">
                                  {leadTasks.filter(t => t.status !== 'concluida').length}
                                </Badge>
                              )}
                            </Button>
                          </DialogTrigger>
                          <DialogContent className="max-w-2xl max-h-[80vh] overflow-y-auto">
                            <DialogHeader>
                              <DialogTitle>📋 Tarefas do Lead</DialogTitle>
                              <p className="text-sm text-muted-foreground mt-1">
                                Gerencie as tarefas relacionadas a este lead
                              </p>
                            </DialogHeader>

                            {!leadVinculado?.id ? (
                              <div className="text-center py-8 text-muted-foreground">
                                <CheckSquare className="h-12 w-12 mx-auto mb-3 opacity-50" />
                                <p>Crie um lead primeiro para adicionar tarefas</p>
                              </div>
                            ) : (
                              <div className="space-y-4">
                                {/* Criar nova tarefa */}
                                <div className="space-y-3 p-4 border rounded-lg bg-muted/20">
                                  <h4 className="text-sm font-semibold">Criar Nova Tarefa</h4>
                                  <div className="space-y-2">
                                    <Label>Título *</Label>
                                    <Input
                                      value={newTaskTitle}
                                      onChange={(e) => setNewTaskTitle(e.target.value)}
                                      placeholder="Ex: Enviar proposta comercial"
                                    />
                                  </div>
                                  <div className="space-y-2">
                                    <Label>Descrição</Label>
                                    <Textarea
                                      value={newTaskDescription}
                                      onChange={(e) => setNewTaskDescription(e.target.value)}
                                      placeholder="Detalhes da tarefa..."
                                      rows={2}
                                    />
                                  </div>
                                  <div className="grid grid-cols-2 gap-3">
                                    <div className="space-y-2">
                                      <Label>Prioridade</Label>
                                      <Select value={newTaskPriority} onValueChange={setNewTaskPriority}>
                                        <SelectTrigger>
                                          <SelectValue />
                                        </SelectTrigger>
                                        <SelectContent>
                                          <SelectItem value="baixa">🟢 Baixa</SelectItem>
                                          <SelectItem value="media">🟡 Média</SelectItem>
                                          <SelectItem value="alta">🔴 Alta</SelectItem>
                                        </SelectContent>
                                      </Select>
                                    </div>
                                    <div className="space-y-2">
                                      <Label>Data de Vencimento</Label>
                                      <Input
                                        type="date"
                                        value={newTaskDueDate}
                                        onChange={(e) => setNewTaskDueDate(e.target.value)}
                                      />
                                    </div>
                                  </div>
                                  <Button onClick={criarTarefaDoLead} className="w-full">
                                    <CheckSquare className="h-4 w-4 mr-2" />
                                    Criar Tarefa
                                  </Button>
                                </div>

                                {/* Lista de tarefas */}
                                <div className="border-t pt-4">
                                  <h4 className="text-sm font-medium mb-3">
                                    Tarefas ({leadTasks.length})
                                  </h4>
                                  {leadTasks.length === 0 ? (
                                    <p className="text-sm text-muted-foreground text-center py-8">
                                      Nenhuma tarefa criada ainda
                                    </p>
                                  ) : (
                                    <div className="space-y-2">
                                      {leadTasks.map((task) => (
                                        <div
                                          key={task.id}
                                          className={`p-3 border rounded-lg ${
                                            task.status === 'concluida' 
                                              ? 'bg-muted/50 opacity-60' 
                                              : 'bg-background'
                                          }`}
                                        >
                                          <div className="flex items-start gap-3">
                                            <Button
                                              size="icon"
                                              variant="ghost"
                                              className="h-6 w-6 mt-0.5"
                                              onClick={() => toggleTaskStatus(task.id, task.status)}
                                            >
                                              {task.status === 'concluida' ? (
                                                <CheckCircle2 className="h-5 w-5 text-green-500" />
                                              ) : (
                                                <div className="h-5 w-5 border-2 rounded-full" />
                                              )}
                                            </Button>
                                            <div className="flex-1 min-w-0">
                                              <p className={`text-sm font-medium ${
                                                task.status === 'concluida' ? 'line-through' : ''
                                              }`}>
                                                {task.title}
                                              </p>
                                              {task.description && (
                                                <p className="text-xs text-muted-foreground mt-1">
                                                  {task.description}
                                                </p>
                                              )}
                                              <div className="flex items-center gap-2 mt-2">
                                                {task.priority === 'alta' && (
                                                  <Badge variant="destructive" className="text-xs">
                                                    🔴 Alta
                                                  </Badge>
                                                )}
                                                {task.priority === 'media' && (
                                                  <Badge variant="secondary" className="text-xs">
                                                    🟡 Média
                                                  </Badge>
                                                )}
                                                {task.priority === 'baixa' && (
                                                  <Badge variant="outline" className="text-xs">
                                                    🟢 Baixa
                                                  </Badge>
                                                )}
                                                {task.due_date && (
                                                  <span className="text-xs text-muted-foreground">
                                                    📅 {new Date(task.due_date).toLocaleDateString('pt-BR')}
                                                  </span>
                                                )}
                                              </div>
                                            </div>
                                            <Button
                                              size="icon"
                                              variant="ghost"
                                              className="h-8 w-8"
                                              onClick={() => deletarTarefa(task.id)}
                                            >
                                              <X className="h-4 w-4" />
                                            </Button>
                                          </div>
                                        </div>
                                      ))}
                                    </div>
                                  )}
                                </div>
                              </div>
                            )}
                          </DialogContent>
                        </Dialog>

                        {/* Transfer */}
                        <Dialog>
                          <DialogTrigger asChild>
                            <Button variant="outline" className="w-full justify-start">
                              <ArrowRightLeft className="h-4 w-4 mr-2" /> Transferir Atendimento
                            </Button>
                          </DialogTrigger>
                          <DialogContent>
                            <DialogHeader>
                              <DialogTitle>Transferir Atendimento</DialogTitle>
                            </DialogHeader>
                            <div className="space-y-2">
                              {usuarios.filter(u => u !== selectedConv.responsavel).map((user) => (
                                <Button 
                                  key={user}
                                  variant="outline" 
                                  className="w-full justify-start"
                                  onClick={() => {
                                    setNewResponsavel(user);
                                    updateResponsavel();
                                  }}
                                >
                                  {user}
                                </Button>
                              ))}
                            </div>
                          </DialogContent>
                        </Dialog>
                      </div>
                    </div>
                  </div>
                </div>
              )}
            </div>
          </>
        ) : (
          <div className="flex-1 flex items-center justify-center bg-muted/30">
            <div className="text-center">
              <MessageSquare className="h-16 w-16 text-muted-foreground mx-auto mb-4" />
              <p className="text-muted-foreground text-lg">Selecione uma conversa para começar</p>
            </div>
          </div>
        )}
      </div>
      
      {/* Modal de Visualização de Imagem */}
      <Dialog open={imageModalOpen} onOpenChange={setImageModalOpen}>
        <DialogContent className="max-w-4xl max-h-[90vh] p-0">
          <div className="relative h-full">
            <img 
              src={selectedMedia?.url} 
              alt={selectedMedia?.name || "Imagem"}
              className="w-full h-full object-contain rounded-lg"
            />
            <Button
              variant="secondary"
              size="sm"
              className="absolute bottom-4 right-4"
              onClick={() => selectedMedia && downloadMedia(selectedMedia.url, `${selectedMedia.name}.jpg`)}
            >
              <Download className="h-4 w-4 mr-2" />
              Baixar
            </Button>
          </div>
        </DialogContent>
      </Dialog>

      {/* Modal de Visualização de PDF */}
      <Dialog open={pdfModalOpen} onOpenChange={setPdfModalOpen}>
        <DialogContent className="max-w-5xl max-h-[90vh] p-2">
          <DialogHeader className="px-4 pt-2">
            <DialogTitle>{selectedMedia?.name || 'Documento PDF'}</DialogTitle>
          </DialogHeader>
          <div className="h-[75vh] w-full">
            <iframe 
              src={selectedMedia?.url} 
              className="w-full h-full border-0 rounded"
              title="PDF Viewer"
            />
          </div>
          <div className="px-4 pb-2">
            <Button
              variant="secondary"
              size="sm"
              onClick={() => selectedMedia && downloadMedia(selectedMedia.url, selectedMedia.name || 'documento.pdf')}
            >
              <Download className="h-4 w-4 mr-2" />
              Baixar PDF
            </Button>
          </div>
        </DialogContent>
      </Dialog>
    </div>
  );
}

export default Conversas;

import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { TrendingUp, Users, DollarSign, Target, MessageSquare, Calendar, CheckCircle, Bot, Activity } from "lucide-react";
import { useEffect, useState } from "react";
import { supabase } from "@/integrations/supabase/client";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { Progress } from "@/components/ui/progress";

interface Stats {
  totalLeads: number;
  totalValue: number;
  conversionRate: number;
  activeDeals: number;
  conversas: number;
  compromissos: number;
  tarefas: number;
  mensagensIA: number;
}

export default function Dashboard() {
  const [stats, setStats] = useState<Stats>({
    totalLeads: 0,
    totalValue: 0,
    conversionRate: 0,
    activeDeals: 0,
    conversas: 0,
    compromissos: 0,
    tarefas: 0,
    mensagensIA: 0,
  });
  const [loading, setLoading] = useState(true);
  const [etapas, setEtapas] = useState<any[]>([]);

  useEffect(() => {
    fetchStats();
  }, []);

  const fetchStats = async () => {
    try {
      setLoading(true);

      // Leads
      const { data: leads } = await supabase.from("leads").select("value, status, etapa_id");
      const totalLeads = leads?.length || 0;
      const totalValue = leads?.reduce((sum, lead) => sum + (Number(lead.value) || 0), 0) || 0;
      const activeDeals = leads?.filter((l) => l.status !== "perdido" && l.status !== "ganho").length || 0;
      const wonDeals = leads?.filter((l) => l.status === "ganho").length || 0;
      const conversionRate = totalLeads > 0 ? (wonDeals / totalLeads) * 100 : 0;

      // Conversas
      const { count: conversasCount } = await supabase.from("conversas").select("*", { count: 'exact', head: true });

      // Compromissos
      const { count: compromissosCount } = await supabase.from("compromissos").select("*", { count: 'exact', head: true });

      // Tarefas
      const { count: tarefasCount } = await supabase.from("tasks").select("*", { count: 'exact', head: true });

      // Mensagens IA
      const { count: iaCount } = await supabase.from("ia_training_data").select("*", { count: 'exact', head: true });

      // Etapas para gráfico de funil
      const { data: etapasData } = await supabase
        .from("etapas")
        .select("id, nome, cor")
        .order("posicao");
      
      const etapasComContagem = await Promise.all((etapasData || []).map(async (etapa) => {
        const leadsNaEtapa = leads?.filter(l => l.etapa_id === etapa.id) || [];
        return {
          ...etapa,
          quantidade: leadsNaEtapa.length,
          valor: leadsNaEtapa.reduce((sum, l) => sum + (Number(l.value) || 0), 0),
        };
      }));

      setEtapas(etapasComContagem);

      setStats({
        totalLeads,
        totalValue,
        conversionRate: Math.round(conversionRate),
        activeDeals,
        conversas: conversasCount || 0,
        compromissos: compromissosCount || 0,
        tarefas: tarefasCount || 0,
        mensagensIA: iaCount || 0,
      });
    } catch (error) {
      console.error("Erro ao carregar estatísticas:", error);
    } finally {
      setLoading(false);
    }
  };

  const statCards = [
    {
      title: "Total de Leads",
      value: stats.totalLeads,
      icon: Users,
      description: "Leads ativos no sistema",
      color: "text-primary",
    },
    {
      title: "Valor em Pipeline",
      value: `R$ ${stats.totalValue.toLocaleString("pt-BR")}`,
      icon: DollarSign,
      description: "Valor total em negociação",
      color: "text-success",
    },
    {
      title: "Taxa de Conversão",
      value: `${stats.conversionRate}%`,
      icon: TrendingUp,
      description: "Conversão média",
      color: "text-accent",
    },
    {
      title: "Negócios Ativos",
      value: stats.activeDeals,
      icon: Target,
      description: "Em andamento",
      color: "text-warning",
    },
  ];

  const operacionalCards = [
    {
      title: "Conversas Ativas",
      value: stats.conversas,
      icon: MessageSquare,
      description: "WhatsApp, Instagram, Facebook",
      color: "text-blue-500",
    },
    {
      title: "Agendamentos",
      value: stats.compromissos,
      icon: Calendar,
      description: "Compromissos marcados",
      color: "text-purple-500",
    },
    {
      title: "Tarefas",
      value: stats.tarefas,
      icon: CheckCircle,
      description: "Em todos os quadros",
      color: "text-green-500",
    },
    {
      title: "Atendimentos IA",
      value: stats.mensagensIA,
      icon: Bot,
      description: "Mensagens processadas",
      color: "text-cyan-500",
    },
  ];

  if (loading) {
    return (
      <div className="flex items-center justify-center h-screen">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-primary"></div>
      </div>
    );
  }

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      <div className="space-y-2">
        <h1 className="text-4xl font-bold bg-gradient-primary bg-clip-text text-transparent">
          Dashboard Gerencial
        </h1>
        <p className="text-muted-foreground text-lg">Visão completa do seu CRM em tempo real</p>
      </div>

      <Tabs defaultValue="vendas" className="w-full">
        <TabsList className="grid w-full grid-cols-3">
          <TabsTrigger value="vendas">Vendas</TabsTrigger>
          <TabsTrigger value="operacional">Operacional</TabsTrigger>
          <TabsTrigger value="ia">Inteligência Artificial</TabsTrigger>
        </TabsList>

        <TabsContent value="vendas" className="space-y-6">
          <div className="grid gap-6 md:grid-cols-2 lg:grid-cols-4">
            {statCards.map((stat, index) => (
              <Card 
                key={stat.title} 
                className="group relative overflow-hidden border-0 shadow-card transition-all duration-300 hover:shadow-xl hover:-translate-y-1"
                style={{ animationDelay: `${index * 100}ms` }}
              >
                <div className="absolute inset-0 bg-gradient-card opacity-0 group-hover:opacity-100 transition-opacity duration-300" />
                <CardHeader className="relative flex flex-row items-center justify-between space-y-0 pb-2">
                  <CardTitle className="text-sm font-semibold text-muted-foreground group-hover:text-foreground transition-colors">
                    {stat.title}
                  </CardTitle>
                  <div className={`p-2.5 rounded-xl bg-gradient-to-br from-background to-muted group-hover:scale-110 transition-transform duration-300`}>
                    <stat.icon className={`h-5 w-5 ${stat.color}`} />
                  </div>
                </CardHeader>
                <CardContent className="relative">
                  <div className="text-3xl font-bold text-foreground">{stat.value}</div>
                  <p className="text-xs text-muted-foreground mt-1">{stat.description}</p>
                </CardContent>
              </Card>
            ))}
          </div>

          {/* Funil de Vendas Visualizado */}
          {etapas.length > 0 && (
            <Card className="border-0 shadow-card">
              <CardHeader>
                <CardTitle>Pipeline por Etapa</CardTitle>
              </CardHeader>
              <CardContent className="space-y-4">
                {etapas.map((etapa) => (
                  <div key={etapa.id} className="space-y-2">
                    <div className="flex justify-between items-center">
                      <div className="flex items-center gap-2">
                        <div 
                          className="w-3 h-3 rounded-full" 
                          style={{ backgroundColor: etapa.cor }}
                        />
                        <span className="font-medium">{etapa.nome}</span>
                      </div>
                      <div className="text-sm text-muted-foreground">
                        {etapa.quantidade} leads • R$ {etapa.valor.toLocaleString("pt-BR")}
                      </div>
                    </div>
                    <Progress 
                      value={stats.totalLeads > 0 ? (etapa.quantidade / stats.totalLeads) * 100 : 0} 
                      className="h-2"
                    />
                  </div>
                ))}
              </CardContent>
            </Card>
          )}

          <Card className="border-0 shadow-card overflow-hidden">
            <div className="absolute top-0 right-0 w-64 h-64 bg-gradient-primary opacity-5 rounded-full blur-3xl" />
            <CardHeader className="relative">
              <CardTitle className="text-2xl font-bold flex items-center gap-2">
                <Activity className="h-6 w-6 text-primary" />
                CEUSIA CRM - Sistema Multiempresa
              </CardTitle>
              <p className="text-muted-foreground mt-2">
                Plataforma completa de gestão comercial com IA integrada
              </p>
            </CardHeader>
            <CardContent className="relative">
              <div className="grid gap-3 md:grid-cols-2">
                <div className="flex items-start gap-3 p-3 rounded-lg bg-muted/50 hover:bg-muted transition-colors">
                  <div className="mt-0.5 p-1.5 rounded-md bg-primary/10">
                    <Users className="h-4 w-4 text-primary" />
                  </div>
                  <div>
                    <p className="font-medium text-foreground">Gestão de Leads e Funil</p>
                    <p className="text-sm text-muted-foreground">Kanban visual com drag & drop</p>
                  </div>
                </div>
                <div className="flex items-start gap-3 p-3 rounded-lg bg-muted/50 hover:bg-muted transition-colors">
                  <div className="mt-0.5 p-1.5 rounded-md bg-success/10">
                    <MessageSquare className="h-4 w-4 text-success" />
                  </div>
                  <div>
                    <p className="font-medium text-foreground">Conversas Unificadas</p>
                    <p className="text-sm text-muted-foreground">WhatsApp, Instagram, Facebook</p>
                  </div>
                </div>
                <div className="flex items-start gap-3 p-3 rounded-lg bg-muted/50 hover:bg-muted transition-colors">
                  <div className="mt-0.5 p-1.5 rounded-md bg-purple-500/10">
                    <Calendar className="h-4 w-4 text-purple-500" />
                  </div>
                  <div>
                    <p className="font-medium text-foreground">Agenda e Compromissos</p>
                    <p className="text-sm text-muted-foreground">Lembretes automáticos via WhatsApp</p>
                  </div>
                </div>
                <div className="flex items-start gap-3 p-3 rounded-lg bg-muted/50 hover:bg-muted transition-colors">
                  <div className="mt-0.5 p-1.5 rounded-md bg-cyan-500/10">
                    <Bot className="h-4 w-4 text-cyan-500" />
                  </div>
                  <div>
                    <p className="font-medium text-foreground">IAs Autônomas</p>
                    <p className="text-sm text-muted-foreground">Atendimento, Vendas e Suporte</p>
                  </div>
                </div>
              </div>
            </CardContent>
          </Card>
        </TabsContent>

        <TabsContent value="operacional" className="space-y-6">
          <div className="grid gap-6 md:grid-cols-2 lg:grid-cols-4">
            {operacionalCards.map((stat, index) => (
              <Card 
                key={stat.title} 
                className="group relative overflow-hidden border-0 shadow-card transition-all duration-300 hover:shadow-xl hover:-translate-y-1"
              >
                <div className="absolute inset-0 bg-gradient-card opacity-0 group-hover:opacity-100 transition-opacity duration-300" />
                <CardHeader className="relative flex flex-row items-center justify-between space-y-0 pb-2">
                  <CardTitle className="text-sm font-semibold text-muted-foreground group-hover:text-foreground transition-colors">
                    {stat.title}
                  </CardTitle>
                  <div className={`p-2.5 rounded-xl bg-gradient-to-br from-background to-muted group-hover:scale-110 transition-transform duration-300`}>
                    <stat.icon className={`h-5 w-5 ${stat.color}`} />
                  </div>
                </CardHeader>
                <CardContent className="relative">
                  <div className="text-3xl font-bold text-foreground">{stat.value}</div>
                  <p className="text-xs text-muted-foreground mt-1">{stat.description}</p>
                </CardContent>
              </Card>
            ))}
          </div>
        </TabsContent>

        <TabsContent value="ia" className="space-y-6">
          <div className="grid gap-6 md:grid-cols-3">
            <Card className="border-0 shadow-card">
              <CardHeader>
                <CardTitle className="flex items-center gap-2">
                  <Bot className="h-5 w-5 text-primary" />
                  IA de Atendimento
                </CardTitle>
              </CardHeader>
              <CardContent>
                <div className="space-y-2">
                  <div className="flex justify-between">
                    <span className="text-sm text-muted-foreground">Acurácia</span>
                    <span className="font-semibold">94%</span>
                  </div>
                  <Progress value={94} />
                  <div className="text-xs text-muted-foreground mt-2">
                    23 conversas atendidas hoje
                  </div>
                </div>
              </CardContent>
            </Card>

            <Card className="border-0 shadow-card">
              <CardHeader>
                <CardTitle className="flex items-center gap-2">
                  <Bot className="h-5 w-5 text-purple-500" />
                  IA Vendedora
                </CardTitle>
              </CardHeader>
              <CardContent>
                <div className="space-y-2">
                  <div className="flex justify-between">
                    <span className="text-sm text-muted-foreground">Conversões</span>
                    <span className="font-semibold">89%</span>
                  </div>
                  <Progress value={89} />
                  <div className="text-xs text-muted-foreground mt-2">
                    15 negociações em andamento
                  </div>
                </div>
              </CardContent>
            </Card>

            <Card className="border-0 shadow-card">
              <CardHeader>
                <CardTitle className="flex items-center gap-2">
                  <Bot className="h-5 w-5 text-cyan-500" />
                  IA de Suporte
                </CardTitle>
              </CardHeader>
              <CardContent>
                <div className="space-y-2">
                  <div className="flex justify-between">
                    <span className="text-sm text-muted-foreground">Satisfação</span>
                    <span className="font-semibold">96%</span>
                  </div>
                  <Progress value={96} />
                  <div className="text-xs text-muted-foreground mt-2">
                    9 atendimentos resolvidos
                  </div>
                </div>
              </CardContent>
            </Card>
          </div>
        </TabsContent>
      </Tabs>
    </div>
  );
}

import { useState, useEffect } from "react";
import { DndContext, DragEndEvent, closestCenter } from "@dnd-kit/core";
import { Plus } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Label } from "@/components/ui/label";
import { supabase } from "@/integrations/supabase/client";
import { LeadCard } from "@/components/funil/LeadCard";
import { DroppableColumn } from "@/components/funil/DroppableColumn";
import { NovoLeadDialog } from "@/components/funil/NovoLeadDialog";
import { NovoFunilDialog } from "@/components/funil/NovoFunilDialog";
import { EditarFunilDialog } from "@/components/funil/EditarFunilDialog";
import { AdicionarEtapaDialog } from "@/components/funil/AdicionarEtapaDialog";
import { toast } from "sonner";
import { useLeadsSync } from "@/hooks/useLeadsSync";

interface Lead {
  id: string;
  nome: string;
  name: string;
  company?: string;
  value?: number;
  telefone?: string;
  email?: string;
  cpf?: string;
  source?: string;
  notes?: string;
  etapa_id?: string;
  funil_id?: string;
}

interface Etapa {
  id: string;
  nome: string;
  posicao: number;
  cor: string;
  funil_id: string;
}

interface Funil {
  id: string;
  nome: string;
  descricao?: string;
}

const Kanban = () => {
  const [leads, setLeads] = useState<Lead[]>([]);
  const [etapas, setEtapas] = useState<Etapa[]>([]);
  const [funis, setFunis] = useState<Funil[]>([]);
  const [selectedFunil, setSelectedFunil] = useState<string>("");
  const [loading, setLoading] = useState(true);

  // Integrar sincronização de leads em tempo real
  useLeadsSync({
    onInsert: (newLead) => {
      console.log('📡 [Funil] Novo lead adicionado via sync:', newLead);
      setLeads(prev => [{
        ...newLead,
        nome: newLead.name || "",
        name: newLead.name || ""
      }, ...prev]);
    },
    onUpdate: (updatedLead) => {
      console.log('📡 [Funil] Lead atualizado via sync:', updatedLead);
      setLeads(prev => prev.map(lead => 
        lead.id === updatedLead.id 
          ? { ...updatedLead, nome: updatedLead.name || "", name: updatedLead.name || "" }
          : lead
      ));
    },
    onDelete: (deletedLead) => {
      console.log('📡 [Funil] Lead removido via sync:', deletedLead);
      setLeads(prev => prev.filter(lead => lead.id !== deletedLead.id));
    },
    showNotifications: false // Não mostrar notificações no funil para não ficar repetitivo
  });

  useEffect(() => {
    carregarDados();
  }, []);

  const carregarDados = async () => {
    try {
      setLoading(true);
      
      const { data: funisData } = await supabase.from("funis").select("*").order("criado_em");
      setFunis(funisData || []);
      
      if (!selectedFunil && funisData && funisData.length > 0) {
        setSelectedFunil(funisData[0].id);
      }

      const { data: etapasData } = await supabase.from("etapas").select("*").order("posicao");
      setEtapas(etapasData || []);

      const { data: leadsData } = await supabase.from("leads").select("*").order("created_at", { ascending: false });
      setLeads((leadsData || []).map(lead => ({ ...lead, nome: lead.name || "", name: lead.name || "" })));
    } catch (error) {
      console.error("Erro ao carregar dados:", error);
      toast.error("Erro ao carregar dados do funil");
    } finally {
      setLoading(false);
    }
  };

  const handleDragEnd = async (event: DragEndEvent) => {
    const { active, over } = event;
    
    console.log("=== DRAG END ===");
    console.log("Active ID:", active.id);
    console.log("Active Data:", active.data.current);
    console.log("Over ID:", over?.id);
    console.log("Over Data:", over?.data.current);
    
    if (!over) {
      console.log("❌ Sem destino (over)");
      return;
    }

    // Pegar o ID do lead que está sendo movido
    const leadId = active.id as string;
    
    // Pegar o ID da etapa de destino do data do over
    const overData = over.data.current;
    const newEtapaId = overData?.type === 'etapa' ? over.id as string : overData?.etapaId as string;
    
    console.log("Lead ID:", leadId);
    console.log("Nova Etapa ID:", newEtapaId);

    if (!newEtapaId) {
      console.log("❌ ID da etapa de destino não encontrado");
      toast.error("Etapa de destino inválida");
      return;
    }

    // Buscar o lead que está sendo movido
    const lead = leads.find(l => l.id === leadId);
    if (!lead) {
      console.log("❌ Lead não encontrado:", leadId);
      toast.error("Lead não encontrado");
      return;
    }

    // Removida verificação redundante que bloqueava movimentações legítimas
    console.log(`🔄 Movendo lead "${lead.name}" para nova etapa...`);

    // Verificar se o destino é realmente uma etapa válida
    const etapaDestino = etapas.find(e => e.id === newEtapaId);
    if (!etapaDestino) {
      console.log("❌ Etapa de destino não encontrada:", newEtapaId);
      console.log("Etapas disponíveis:", etapas.map(e => ({ id: e.id, nome: e.nome })));
      toast.error("Etapa de destino inválida");
      return;
    }

    console.log(`✅ Movendo lead "${lead.name}" de "${lead.etapa_id}" para "${etapaDestino.nome}"`);

    // Atualizar localmente primeiro
    setLeads((leads) => 
      leads.map((l) => l.id === leadId ? { ...l, etapa_id: newEtapaId } : l)
    );

    // Atualizar no banco - isso vai disparar o realtime sync automaticamente
    try {
      const { error } = await supabase
        .from("leads")
        .update({ 
          etapa_id: newEtapaId,
          funil_id: etapaDestino.funil_id, // Garantir que o funil_id está correto
          stage: etapaDestino.nome.toLowerCase() // Atualizar também o stage para sincronizar
        })
        .eq("id", leadId);

      if (error) throw error;
      
      console.log("✅ Lead atualizado no banco com sucesso");
      console.log("🔄 Sincronização automática vai propagar para Conversas e Leads");
      toast.success(`Lead movido para ${etapaDestino.nome}!`);
      
      // A sincronização via realtime vai atualizar automaticamente:
      // - O componente Conversas (Info Panel)
      // - O componente Leads
      // - Este próprio componente Funil
    } catch (error) {
      console.error("❌ Erro ao mover lead:", error);
      toast.error("Erro ao mover lead");
      // Reverter mudança local em caso de erro
      setLeads((leads) => 
        leads.map((l) => l.id === leadId ? { ...l, etapa_id: lead.etapa_id } : l)
      );
    }
  };

  const etapasFiltradas = etapas.filter((etapa) => etapa.funil_id === selectedFunil);

  const calcularTotalEtapa = (etapaId: string) => {
    return leads
      .filter(l => l.etapa_id === etapaId)
      .reduce((total, lead) => total + (lead.value || 0), 0);
  };

  const funilSelecionado = funis.find(f => f.id === selectedFunil);

  if (loading) return <div className="flex items-center justify-center h-screen"><p>Carregando...</p></div>;

  return (
    <div className="container mx-auto p-6">
      <div className="flex justify-between items-center mb-6">
        <div>
          <h1 className="text-3xl font-bold">Funil de Vendas</h1>
          <p className="text-muted-foreground">Gerencie seus leads por etapas</p>
        </div>
        <div className="flex gap-2">
          <NovoFunilDialog onFunilCreated={carregarDados} />
          
          <NovoLeadDialog 
            onLeadCreated={carregarDados}
            triggerButton={
              <Button>
                <Plus className="mr-2 h-4 w-4" />
                Novo Lead
              </Button>
            }
          />
        </div>
      </div>

      {funis.length > 0 && (
        <div className="mb-6 flex items-center gap-3">
          <div className="flex-1 max-w-xs">
            <Label>Funil</Label>
            <select value={selectedFunil} onChange={(e) => setSelectedFunil(e.target.value)} className="w-full p-2 border rounded-md mt-2">
              {funis.map((funil) => <option key={funil.id} value={funil.id}>{funil.nome}</option>)}
            </select>
          </div>
          {funilSelecionado && (
            <div className="mt-6 flex gap-2">
              <AdicionarEtapaDialog 
                funilId={funilSelecionado.id}
                onEtapaAdded={carregarDados}
              />
              <EditarFunilDialog 
                funilId={funilSelecionado.id}
                funilNome={funilSelecionado.nome}
                onFunilUpdated={carregarDados}
              />
            </div>
          )}
        </div>
      )}

      {funis.length === 0 ? (
        <div className="text-center py-12">
          <p className="text-muted-foreground mb-4">Nenhum funil criado ainda</p>
          <NovoFunilDialog onFunilCreated={carregarDados} />
        </div>
      ) : (
        <DndContext collisionDetection={closestCenter} onDragEnd={handleDragEnd}>
      <div className="flex overflow-x-auto gap-4 pb-4">
        {etapasFiltradas.map((etapa) => {
              const totalEtapa = calcularTotalEtapa(etapa.id);
              const quantidadeLeads = leads.filter(l => l.etapa_id === etapa.id).length;
              const leadsNaEtapa = leads.filter(l => l.etapa_id === etapa.id);
              
              return (
                <div key={etapa.id} className="min-w-[300px] flex-shrink-0">
                  <DroppableColumn
                    id={etapa.id}
                    cor={etapa.cor}
                    nome={etapa.nome}
                    quantidadeLeads={quantidadeLeads}
                    totalEtapa={totalEtapa}
                    onEtapaUpdated={carregarDados}
                  >
                    {leadsNaEtapa.map((lead) => (
                      <LeadCard 
                        key={lead.id} 
                        lead={lead} 
                        onDelete={async (id) => {
                          const { error } = await supabase.from("leads").delete().eq("id", id);
                          if (error) {
                            toast.error("Erro ao deletar lead");
                            return;
                          }
                          toast.success("Lead deletado!");
                          carregarDados();
                        }}
                        onLeadMoved={carregarDados}
                      />
                    ))}
                    {leadsNaEtapa.length === 0 && (
                      <div className="text-center py-8 text-muted-foreground text-sm">
                        Arraste leads para cá
                      </div>
                    )}
                  </DroppableColumn>
                </div>
              );
            })}
          </div>
        </DndContext>
      )}
    </div>
  );
};

export default Kanban;

import { useState, useEffect } from "react";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Badge } from "@/components/ui/badge";
import { Plus, Upload, Search, Tag, MessageSquare, Phone, Mail, User, Building2 } from "lucide-react";
import { supabase } from "@/integrations/supabase/client";
import { useToast } from "@/hooks/use-toast";
import { LeadActionsDialog } from "@/components/leads/LeadActionsDialog";
import { LeadQuickActions } from "@/components/leads/LeadQuickActions";
import { LeadTagsDialog } from "@/components/leads/LeadTagsDialog";
import { TagsManager } from "@/components/leads/TagsManager";
import { NovoLeadDialog } from "@/components/funil/NovoLeadDialog";
import { ImportarLeadsDialog } from "@/components/funil/ImportarLeadsDialog";
import { formatPhoneNumber } from "@/utils/phoneFormatter";
import { useNavigate } from "react-router-dom";
import { useLeadsSync } from "@/hooks/useLeadsSync";

interface Lead {
  id: string;
  name: string;
  email: string | null;
  phone: string | null;
  telefone?: string | null;
  company: string | null;
  source: string | null;
  status: string;
  stage: string;
  value: number;
  created_at: string;
  tags?: string[];
  cpf?: string | null;
  notes?: string | null;
}

export default function Leads() {
  const [leads, setLeads] = useState<Lead[]>([]);
  const [filteredLeads, setFilteredLeads] = useState<Lead[]>([]);
  const [searchTerm, setSearchTerm] = useState("");
  const [selectedStatus, setSelectedStatus] = useState<string>("all");
  const [selectedTag, setSelectedTag] = useState<string | null>(null);
  const { toast } = useToast();
  const navigate = useNavigate();

  const abrirConversa = (leadId: string, leadName: string) => {
    navigate('/conversas', { state: { leadId } });
  };

  // Integrar sincronização de leads em tempo real
  useLeadsSync({
    onInsert: (newLead) => {
      console.log('📡 [Leads] Novo lead adicionado via sync:', newLead);
      setLeads(prev => [newLead, ...prev]);
    },
    onUpdate: (updatedLead) => {
      console.log('📡 [Leads] Lead atualizado via sync:', updatedLead);
      setLeads(prev => prev.map(lead => 
        lead.id === updatedLead.id ? updatedLead : lead
      ));
    },
    onDelete: (deletedLead) => {
      console.log('📡 [Leads] Lead removido via sync:', deletedLead);
      setLeads(prev => prev.filter(lead => lead.id !== deletedLead.id));
    },
    showNotifications: true
  });

  useEffect(() => {
    carregarLeads();
  }, []);

  useEffect(() => {
    filterLeads();
  }, [searchTerm, selectedStatus, selectedTag, leads]);

  const carregarLeads = async () => {
    const { data, error } = await supabase
      .from("leads")
      .select("*")
      .order("created_at", { ascending: false });

    if (error) {
      toast({
        variant: "destructive",
        title: "Erro ao carregar leads",
        description: error.message,
      });
    } else {
      setLeads(data || []);
    }
  };

  const filterLeads = () => {
    let filtered = leads;

    if (searchTerm) {
      filtered = filtered.filter(
        (lead) =>
          lead.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
          lead.email?.toLowerCase().includes(searchTerm.toLowerCase()) ||
          lead.phone?.includes(searchTerm) ||
          lead.telefone?.includes(searchTerm) ||
          lead.company?.toLowerCase().includes(searchTerm.toLowerCase())
      );
    }

    if (selectedStatus !== "all") {
      filtered = filtered.filter((lead) => lead.status === selectedStatus);
    }

    if (selectedTag) {
      filtered = filtered.filter((lead) => 
        lead.tags?.includes(selectedTag)
      );
    }

    setFilteredLeads(filtered);
  };

  const getStatusColor = (status: string) => {
    const colors: Record<string, string> = {
      novo: "bg-blue-500",
      contato: "bg-yellow-500",
      qualificado: "bg-green-500",
      proposta: "bg-purple-500",
      ganho: "bg-emerald-500",
      perdido: "bg-red-500",
    };
    return colors[status] || "bg-gray-500";
  };

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-3xl font-bold text-foreground">Leads</h1>
          <p className="text-muted-foreground">
            Gerencie todos os seus leads em um só lugar
          </p>
        </div>
        <div className="flex gap-2">
          <TagsManager 
            onTagSelected={setSelectedTag}
            selectedTag={selectedTag}
          />
          <ImportarLeadsDialog onLeadsImported={carregarLeads} />
          <NovoLeadDialog onLeadCreated={carregarLeads} />
        </div>
      </div>

      <div className="space-y-3">
        <div className="flex gap-4">
          <div className="relative flex-1">
            <Search className="absolute left-3 top-1/2 h-4 w-4 -translate-y-1/2 text-muted-foreground" />
            <Input
              placeholder="Buscar por nome, email, telefone ou empresa..."
              className="pl-10"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
          </div>
          <div className="flex gap-2">
            <Button
              variant={selectedStatus === "all" ? "default" : "outline"}
              onClick={() => setSelectedStatus("all")}
            >
              Todos
            </Button>
            <Button
              variant={selectedStatus === "novo" ? "default" : "outline"}
              onClick={() => setSelectedStatus("novo")}
            >
              Novos
            </Button>
            <Button
              variant={selectedStatus === "qualificado" ? "default" : "outline"}
              onClick={() => setSelectedStatus("qualificado")}
            >
              Qualificados
            </Button>
          </div>
        </div>

        {/* Filtro ativo de tag */}
        {selectedTag && (
          <div className="flex items-center gap-2 p-3 bg-primary/10 rounded-lg border border-primary/20">
            <Tag className="h-4 w-4 text-primary" />
            <span className="text-sm font-medium">Filtrando por tag:</span>
            <Badge variant="secondary" className="gap-1">
              {selectedTag}
            </Badge>
            <Button
              variant="ghost"
              size="sm"
              className="ml-auto"
              onClick={() => setSelectedTag(null)}
            >
              Limpar filtro
            </Button>
          </div>
        )}
      </div>

      <div className="grid gap-4">
        {filteredLeads.map((lead) => (
          <Card key={lead.id} className="transition-all hover:shadow-lg">
            <CardContent className="p-6">
              <div className="flex items-start justify-between">
                <div className="flex-1 space-y-3">
                  <div className="flex items-center gap-3">
                    <h3 className="text-lg font-semibold">{lead.name}</h3>
                    <Badge className={getStatusColor(lead.status)}>
                      {lead.status}
                    </Badge>
                    {lead.source && (
                      <Badge variant="outline">
                        <Tag className="mr-1 h-3 w-3" />
                        {lead.source}
                      </Badge>
                    )}
                  </div>
                  
                  {lead.tags && lead.tags.length > 0 && (
                    <div className="flex flex-wrap gap-2">
                      {lead.tags.map((tag) => (
                        <Badge key={tag} variant="secondary" className="gap-1">
                          <Tag className="h-3 w-3" />
                          {tag}
                        </Badge>
                      ))}
                    </div>
                  )}
                  <div className="grid grid-cols-3 gap-4 text-sm text-muted-foreground">
                    {lead.email && (
                      <div className="flex items-center gap-2">
                        <Mail className="h-4 w-4" />
                        {lead.email}
                      </div>
                    )}
                    {lead.phone && (
                      <div className="flex items-center gap-2">
                        <Phone className="h-4 w-4" />
                        {lead.phone}
                        <Button
                          variant="ghost"
                          size="sm"
                          className="h-6 px-2 ml-2 text-[#25D366] hover:text-[#25D366] hover:bg-[#25D366]/10 transition-all"
                          onClick={() => abrirConversa(lead.id, lead.name)}
                          title="Abrir Conversa no WhatsApp"
                        >
                          <MessageSquare className="h-3.5 w-3.5 mr-1" />
                          <span className="text-xs font-medium">WhatsApp</span>
                        </Button>
                      </div>
                    )}
                    {lead.company && (
                      <div className="flex items-center gap-2">
                        <Building2 className="h-4 w-4" />
                        <span className="font-medium">{lead.company}</span>
                      </div>
                    )}
                  </div>
                </div>
                <div className="flex flex-col items-end gap-2">
                  <div className="text-xl font-bold text-primary">
                    R$ {Number(lead.value).toLocaleString("pt-BR")}
                  </div>
                  <div className="flex gap-2">
                    <LeadQuickActions 
                      leadId={lead.id} 
                      leadName={lead.name} 
                      leadPhone={lead.phone || lead.telefone || undefined}
                    />
                    <LeadTagsDialog 
                      leadId={lead.id}
                      currentTags={lead.tags}
                      onTagsUpdated={carregarLeads}
                      triggerButton={
                        <Button variant="outline" size="sm">
                          <Tag className="h-4 w-4 mr-2" />
                          Tags
                        </Button>
                      }
                    />
                  </div>
                </div>
              </div>
            </CardContent>
          </Card>
        ))}
      </div>

      {filteredLeads.length === 0 && (
        <Card>
          <CardContent className="flex flex-col items-center justify-center py-12">
            <p className="text-muted-foreground">Nenhum lead encontrado</p>
          </CardContent>
        </Card>
      )}
    </div>
  );
}

import { useState, useEffect } from "react";
import { DndContext, DragEndEvent, closestCorners } from "@dnd-kit/core";
import { SortableContext, verticalListSortingStrategy } from "@dnd-kit/sortable";
import { Plus, Settings } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogTrigger } from "@/components/ui/dialog";
import { supabase } from "@/integrations/supabase/client";
import { TaskCard } from "@/components/tarefas/TaskCard";
import { NovaTarefaDialog } from "@/components/tarefas/NovaTarefaDialog";
import { EditarQuadroDialog } from "@/components/tarefas/EditarQuadroDialog";
import { AdicionarColunaDialog } from "@/components/tarefas/AdicionarColunaDialog";
import { EditarColunaDialog } from "@/components/tarefas/EditarColunaDialog";
import { DeletarColunaDialog } from "@/components/tarefas/DeletarColunaDialog";
import { toast } from "sonner";

interface Task {
  id: string;
  title: string;
  description: string | null;
  priority: string;
  assignee_id: string | null;
  assignee_name?: string;
  due_date: string | null;
  lead_id: string | null;
  lead_name?: string;
  column_id?: string | null;
  board_id?: string | null;
}

interface Column {
  id: string;
  nome: string;
  posicao: number;
  cor: string;
  board_id: string;
}

interface Board {
  id: string;
  nome: string;
  descricao?: string;
}

export default function Tarefas() {
  const [tasks, setTasks] = useState<Task[]>([]);
  const [columns, setColumns] = useState<Column[]>([]);
  const [boards, setBoards] = useState<Board[]>([]);
  const [selectedBoard, setSelectedBoard] = useState<string>("");
  const [loading, setLoading] = useState(true);
  const [novoBoardNome, setNovoBoardNome] = useState("");
  const [dialogNovoBoard, setDialogNovoBoard] = useState(false);

  useEffect(() => {
    carregarDados();
  }, []);

  const carregarDados = async () => {
    try {
      setLoading(true);
      
      const { data: boardsData } = await supabase.from("task_boards").select("*").order("criado_em");
      setBoards(boardsData || []);
      
      if (!selectedBoard && boardsData && boardsData.length > 0) {
        setSelectedBoard(boardsData[0].id);
      }

      const { data: columnsData } = await supabase.from("task_columns").select("*").order("posicao");
      setColumns(columnsData || []);

      const { data: tasksData } = await supabase
        .from("tasks")
        .select(`
          *,
          assignee:profiles!tasks_assignee_id_fkey(full_name),
          lead:leads!tasks_lead_id_fkey(name)
        `)
        .order("created_at", { ascending: false });

      const formattedTasks = (tasksData || []).map((task: any) => ({
        ...task,
        assignee_name: task.assignee?.full_name,
        lead_name: task.lead?.name,
      }));
      setTasks(formattedTasks);
    } catch (error) {
      console.error("Erro ao carregar dados:", error);
      toast.error("Erro ao carregar dados das tarefas");
    } finally {
      setLoading(false);
    }
  };

  const handleDragEnd = async (event: DragEndEvent) => {
    const { active, over } = event;
    if (!over) return;

    const taskId = active.id as string;
    let newColumnId = over.id as string;

    // Se arrastou sobre outra tarefa, buscar o column_id dessa tarefa
    const overTask = tasks.find(t => t.id === newColumnId);
    if (overTask && overTask.column_id) {
      newColumnId = overTask.column_id;
    }

    // Verificar se é uma coluna válida
    const isValidColumn = columns.some(c => c.id === newColumnId);
    if (!isValidColumn) {
      toast.error("Coluna inválida");
      return;
    }

    setTasks((tasks) => 
      tasks.map((task) => 
        task.id === taskId ? { ...task, column_id: newColumnId } : task
      )
    );

    try {
      const { data: { session } } = await supabase.auth.getSession();
      if (!session) return toast.error("Não autenticado");

      await supabase.functions.invoke("api-tarefas", {
        body: { action: "mover_tarefa", data: { task_id: taskId, nova_coluna_id: newColumnId } }
      });

      toast.success("Tarefa movida!");
    } catch (error) {
      toast.error("Erro ao mover tarefa");
      carregarDados();
    }
  };

  const criarNovoBoard = async () => {
    if (!novoBoardNome.trim()) return;

    try {
      const { data: boardData } = await supabase.functions.invoke("api-tarefas", {
        body: { action: "criar_board", data: { nome: novoBoardNome } }
      });

      const newBoardId = boardData?.data?.id;

      // Criar colunas padrão
      if (newBoardId) {
        const colunasDefault = [
          { nome: "A Fazer", cor: "#3b82f6", posicao: 0 },
          { nome: "Em Progresso", cor: "#eab308", posicao: 1 },
          { nome: "Concluído", cor: "#22c55e", posicao: 2 },
        ];

        for (const coluna of colunasDefault) {
          await supabase.functions.invoke("api-tarefas", {
            body: {
              action: "criar_coluna",
              data: { ...coluna, board_id: newBoardId },
            },
          });
        }
      }

      toast.success("Quadro criado com colunas padrão!");
      setNovoBoardNome("");
      setDialogNovoBoard(false);
      carregarDados();
    } catch (error) {
      toast.error("Erro ao criar quadro");
    }
  };

  const columnsFiltradas = columns.filter((column) => column.board_id === selectedBoard);

  if (loading) return <div className="flex items-center justify-center h-screen"><p>Carregando...</p></div>;

  return (
    <div className="container mx-auto p-6">
      <div className="flex justify-between items-center mb-6">
        <div>
          <h1 className="text-3xl font-bold">Tarefas (Trello Style)</h1>
          <p className="text-muted-foreground">Gerencie suas tarefas em quadros Kanban</p>
        </div>
        <div className="flex gap-2">
          {selectedBoard && (
            <EditarQuadroDialog
              boardId={selectedBoard}
              boardNome={boards.find((b) => b.id === selectedBoard)?.nome || ""}
              onUpdated={carregarDados}
            />
          )}
          <Dialog open={dialogNovoBoard} onOpenChange={setDialogNovoBoard}>
            <DialogTrigger asChild>
              <Button variant="outline">
                <Plus className="mr-2 h-4 w-4" />
                Novo Quadro
              </Button>
            </DialogTrigger>
            <DialogContent>
              <DialogHeader>
                <DialogTitle>Criar Novo Quadro</DialogTitle>
              </DialogHeader>
              <div className="space-y-4">
                <div>
                  <Label>Nome do Quadro</Label>
                  <Input 
                    value={novoBoardNome} 
                    onChange={(e) => setNovoBoardNome(e.target.value)} 
                    placeholder="Ex: Projeto Q1 2024"
                  />
                </div>
                <Button onClick={criarNovoBoard} className="w-full">
                  Criar
                </Button>
              </div>
            </DialogContent>
          </Dialog>
        </div>
      </div>

      {boards.length > 0 && (
        <div className="mb-6">
          <Label>Quadro</Label>
          <select 
            value={selectedBoard} 
            onChange={(e) => setSelectedBoard(e.target.value)} 
            className="w-full max-w-xs p-2 border rounded-md mt-2"
          >
            {boards.map((board) => (
              <option key={board.id} value={board.id}>
                {board.nome}
              </option>
            ))}
          </select>
        </div>
      )}

      {boards.length === 0 ? (
        <div className="text-center py-12">
          <Button onClick={() => setDialogNovoBoard(true)}>
            <Plus className="mr-2" />
            Criar Primeiro Quadro
          </Button>
        </div>
      ) : columnsFiltradas.length === 0 ? (
        <div className="text-center py-12">
          <p className="text-muted-foreground mb-4">Nenhuma coluna criada ainda</p>
          <p className="text-sm text-muted-foreground">
            Crie colunas como "A Fazer", "Em Progresso", "Concluído"
          </p>
        </div>
      ) : (
        <DndContext collisionDetection={closestCorners} onDragEnd={handleDragEnd}>
          <div className="flex overflow-x-auto gap-4 pb-4">
            {columnsFiltradas.map((column) => (
              <div key={column.id} className="min-w-[300px] flex-shrink-0">
                <div 
                  className="text-white p-3 rounded-t-lg" 
                  style={{ backgroundColor: column.cor }}
                >
                  <div className="flex items-center justify-between mb-2">
                    <h3 className="font-semibold">{column.nome}</h3>
                    <div className="flex gap-1">
                      <EditarColunaDialog
                        columnId={column.id}
                        nomeAtual={column.nome}
                        corAtual={column.cor}
                        onColumnUpdated={carregarDados}
                      />
                      <DeletarColunaDialog
                        columnId={column.id}
                        columnNome={column.nome}
                        onColumnDeleted={carregarDados}
                      />
                    </div>
                  </div>
                  <span className="text-sm">
                    {tasks.filter(t => t.column_id === column.id).length} tarefas
                  </span>
                </div>
                <SortableContext 
                  id={column.id} 
                  items={tasks.filter(t => t.column_id === column.id)} 
                  strategy={verticalListSortingStrategy}
                >
                  <div className="bg-secondary/20 p-4 rounded-b-lg min-h-[500px]">
                    <NovaTarefaDialog 
                      columnId={column.id} 
                      boardId={selectedBoard} 
                      onTaskCreated={carregarDados} 
                    />
                    {tasks.filter(t => t.column_id === column.id).map((task) => (
                      <TaskCard 
                        key={task.id} 
                        task={task}
                        onDelete={async (id) => {
                          await supabase.functions.invoke("api-tarefas", { 
                            body: { action: "deletar_tarefa", data: { task_id: id } } 
                          });
                          carregarDados();
                        }}
                        onUpdate={carregarDados}
                      />
                    ))}
                  </div>
                </SortableContext>
              </div>
            ))}
            {/* Botão para adicionar nova coluna */}
            <div className="min-w-[280px] flex-shrink-0">
              <AdicionarColunaDialog
                boardId={selectedBoard}
                currentColumnsCount={columnsFiltradas.length}
                onColumnAdded={carregarDados}
              />
            </div>
          </div>
        </DndContext>
      )}
    </div>
  );
}

import { serve } from "https://deno.land/std@0.177.0/http/server.ts";
import { z } from "https://deno.land/x/zod@v3.22.4/mod.ts";

const corsHeaders = {
  'Access-Control-Allow-Origin': '*',
  'Access-Control-Allow-Headers': 'authorization, x-client-info, apikey, content-type',
};

// Input validation schema
const enviarWhatsAppSchema = z.object({
  numero: z.string()
    .regex(/^[0-9]{10,15}$/, 'Número deve ter entre 10-15 dígitos')
    .transform(val => val.replace(/[^0-9]/g, '')),
  mensagem: z.string()
    .min(1, 'Mensagem não pode ser vazia')
    .max(4096, 'Mensagem muito longa')
    .optional(),
  tipo_mensagem: z.enum(['text', 'texto', 'image', 'audio', 'video', 'document', 'pdf']).optional(),
  mediaUrl: z.string().url('URL de mídia inválida').optional(),
  mediaBase64: z.string().optional(),
  fileName: z.string().optional(),
  mimeType: z.string().optional(),
  caption: z.string().optional(),
  company_id: z.string().uuid('Company ID deve ser UUID válido').optional(),
  quoted: z.object({
    key: z.object({
      id: z.string()
    }),
    message: z.object({
      conversation: z.string()
    })
  }).optional()
}).refine(data => data.mensagem || data.mediaUrl || data.mediaBase64, {
  message: 'Mensagem, mídia URL ou mídia Base64 é obrigatória'
});

serve(async (req) => {
  // Handle CORS preflight requests
  if (req.method === 'OPTIONS') {
    return new Response(null, { headers: corsHeaders });
  }

  try {
    const body = await req.json();

    // Validate input with Zod
    let validatedData;
    try {
      validatedData = enviarWhatsAppSchema.parse(body);
    } catch (error) {
      if (error instanceof z.ZodError) {
        console.error("❌ Dados de entrada inválidos:", error.errors);
        return new Response(
          JSON.stringify({ 
            error: 'Dados inválidos fornecidos',
            code: 'VALIDATION_ERROR',
            details: error.errors
          }),
          { status: 400, headers: { ...corsHeaders, "Content-Type": "application/json" } }
        );
      }
      throw error;
    }

    console.log("📨 Pedido de envio validado");

    // Buscar configurações dos secrets
    const EVOLUTION_API_URL = Deno.env.get("EVOLUTION_API_URL");
    const EVOLUTION_API_KEY = Deno.env.get("EVOLUTION_API_KEY");
    const SUPABASE_URL = Deno.env.get("SUPABASE_URL");
    const SUPABASE_SERVICE_ROLE_KEY = Deno.env.get("SUPABASE_SERVICE_ROLE_KEY");

    if (!EVOLUTION_API_URL || !EVOLUTION_API_KEY) {
      console.error("❌ Variáveis de ambiente da Evolution API não configuradas");
      return new Response(
        JSON.stringify({ 
          error: "Configuração da Evolution API incompleta",
          code: "CONFIG_ERROR"
        }),
        { status: 500, headers: { ...corsHeaders, "Content-Type": "application/json" } }
      );
    }

    // Buscar instância WhatsApp da company
    let EVOLUTION_INSTANCE: string;
    let INSTANCE_API_KEY: string = EVOLUTION_API_KEY;
    
    if (validatedData.company_id) {
      console.log("🔍 Buscando instância WhatsApp para company:", validatedData.company_id);
      
      // Criar cliente Supabase
      const { createClient } = await import('https://esm.sh/@supabase/supabase-js@2');
      const supabase = createClient(SUPABASE_URL!, SUPABASE_SERVICE_ROLE_KEY!);
      
      // Buscar conexão WhatsApp ativa da company (incluindo API key)
      const { data: connection, error: connError } = await supabase
        .from('whatsapp_connections')
        .select('instance_name, whatsapp_number, evolution_api_key')
        .eq('company_id', validatedData.company_id)
        .eq('status', 'connected')
        .single();
      
      if (connError || !connection) {
        console.error("❌ Nenhuma conexão WhatsApp ativa encontrada para esta empresa");
        return new Response(
          JSON.stringify({ 
            error: "Nenhuma conexão WhatsApp ativa encontrada",
            code: "NO_WHATSAPP_CONNECTION"
          }),
          { status: 404, headers: { ...corsHeaders, "Content-Type": "application/json" } }
        );
      }
      
      EVOLUTION_INSTANCE = connection.instance_name;
      
      // Usar API key da conexão se disponível
      if (connection.evolution_api_key) {
        INSTANCE_API_KEY = connection.evolution_api_key;
        console.log("✅ Usando API key da instância:", EVOLUTION_INSTANCE);
      }
      
      console.log("✅ Instância encontrada:", EVOLUTION_INSTANCE, "- Número:", connection.whatsapp_number);
    } else {
      // Fallback para instância padrão (compatibilidade)
      EVOLUTION_INSTANCE = Deno.env.get("EVOLUTION_INSTANCE") || "";
      if (!EVOLUTION_INSTANCE) {
        console.error("❌ Instância não especificada e sem fallback");
        return new Response(
          JSON.stringify({ 
            error: "Instância WhatsApp não especificada",
            code: "NO_INSTANCE"
          }),
          { status: 400, headers: { ...corsHeaders, "Content-Type": "application/json" } }
        );
      }
      console.log("⚠️ Usando instância padrão:", EVOLUTION_INSTANCE);
    }

    // Formatar número no formato correto
    const numeroFormatado = validatedData.numero.includes("@s.whatsapp.net")
      ? validatedData.numero
      : `${validatedData.numero}@s.whatsapp.net`;

    console.log("📞 Número formatado");

    let evolutionUrl: string;
    let bodyPayload: any;

    // Verificar se é mídia (base64, URL) ou texto
    if (validatedData.mediaBase64) {
      // Enviar mídia via base64
      evolutionUrl = `${EVOLUTION_API_URL}/message/sendMedia/${EVOLUTION_INSTANCE}`;
      
      // Normalizar tipo de mídia
      let mediaType = validatedData.tipo_mensagem || 'document';
      if (mediaType === 'texto') mediaType = 'text';
      // PDF e document são mantidos como document
      if (mediaType === 'pdf') mediaType = 'document';
      
      // Definir mimeType baseado no tipo de mídia e extensão do arquivo
      let mimeType = validatedData.mimeType;
      if (!mimeType) {
        const fileName = validatedData.fileName?.toLowerCase() || '';
        
        // Detectar por tipo de mídia primeiro
        if (mediaType === 'image') {
          if (fileName.endsWith('.png')) mimeType = 'image/png';
          else if (fileName.endsWith('.gif')) mimeType = 'image/gif';
          else if (fileName.endsWith('.webp')) mimeType = 'image/webp';
          else mimeType = 'image/jpeg'; // default para imagens
        } else if (mediaType === 'audio') {
          if (fileName.endsWith('.ogg')) mimeType = 'audio/ogg';
          else if (fileName.endsWith('.wav')) mimeType = 'audio/wav';
          else if (fileName.endsWith('.m4a')) mimeType = 'audio/mp4';
          else mimeType = 'audio/mpeg'; // default para áudio
        } else if (mediaType === 'video') {
          if (fileName.endsWith('.mov')) mimeType = 'video/quicktime';
          else if (fileName.endsWith('.avi')) mimeType = 'video/x-msvideo';
          else if (fileName.endsWith('.webm')) mimeType = 'video/webm';
          else mimeType = 'video/mp4'; // default para vídeo
        } else if (validatedData.tipo_mensagem === 'pdf' || fileName.endsWith('.pdf')) {
          mimeType = 'application/pdf';
        } else {
          // Detectar por extensão para documentos
          if (fileName.endsWith('.doc') || fileName.endsWith('.docx')) {
            mimeType = 'application/vnd.openxmlformats-officedocument.wordprocessingml.document';
          } else if (fileName.endsWith('.xls') || fileName.endsWith('.xlsx')) {
            mimeType = 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet';
          } else if (fileName.endsWith('.ppt') || fileName.endsWith('.pptx')) {
            mimeType = 'application/vnd.openxmlformats-officedocument.presentationml.presentation';
          } else if (fileName.endsWith('.txt')) {
            mimeType = 'text/plain';
          } else if (fileName.endsWith('.zip')) {
            mimeType = 'application/zip';
          } else {
            mimeType = 'application/octet-stream'; // fallback genérico
          }
        }
        
        console.log(`📄 MIME type detectado: ${mimeType} (arquivo: ${fileName})`);
      }
      
      bodyPayload = {
        number: numeroFormatado,
        mediatype: mediaType,
        mimetype: mimeType,
        caption: validatedData.caption || validatedData.mensagem || "",
        fileName: validatedData.fileName || 'arquivo',
        media: validatedData.mediaBase64,
      };
      console.log(`📸 Enviando mídia base64 (${mediaType})`);
    } else if (validatedData.mediaUrl) {
      // Enviar mídia via URL
      evolutionUrl = `${EVOLUTION_API_URL}/message/sendMedia/${EVOLUTION_INSTANCE}`;
      bodyPayload = {
        number: numeroFormatado,
        mediaUrl: validatedData.mediaUrl,
        caption: validatedData.mensagem || validatedData.caption || "",
      };
      console.log("📸 Enviando mídia via URL");
    } else {
      // Enviar texto
      evolutionUrl = `${EVOLUTION_API_URL}/message/sendText/${EVOLUTION_INSTANCE}`;
      bodyPayload = {
        number: numeroFormatado,
        text: validatedData.mensagem,
      };
      
      // Adicionar mensagem citada se houver
      if (validatedData.quoted) {
        bodyPayload.quoted = validatedData.quoted;
        console.log("💬 Enviando texto com citação");
      } else {
        console.log("💬 Enviando texto");
      }
    }

    // Enviar para Evolution API
    const response = await fetch(evolutionUrl, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        "apikey": INSTANCE_API_KEY,
      },
      body: JSON.stringify(bodyPayload),
    });

    const result = await response.json();

    if (!response.ok) {
      console.error("❌ Erro Evolution API:", {
        status: response.status,
        statusText: response.statusText,
        url: evolutionUrl,
        payload: bodyPayload,
        result: result
      });
      return new Response(
        JSON.stringify({
          error: "Falha ao enviar mensagem",
          code: "EXTERNAL_API_ERROR",
          details: result
        }),
        { status: 500, headers: { ...corsHeaders, "Content-Type": "application/json" } }
      );
    }

    console.log("✅ Mensagem enviada com sucesso");
    
    return new Response(
      JSON.stringify({ 
        success: true, 
        message: "Mensagem enviada com sucesso"
      }), {
      status: 200,
      headers: { ...corsHeaders, "Content-Type": "application/json" },
    });
  } catch (e) {
    console.error("❌ Erro geral:", e);
    return new Response(
      JSON.stringify({ 
        error: "Erro interno ao processar requisição",
        code: "INTERNAL_ERROR"
      }),
      { status: 500, headers: { ...corsHeaders, "Content-Type": "application/json" } }
    );
  }
});

