            {data.label || 'Novo Gatilho'}
          </div>
        </div>
      </div>
      
      {data.description && (
        <div className="mt-2 text-xs text-white/80">
          {data.description}
        </div>
      )}

      <Handle
        type="source"
        position={Position.Bottom}
        className="w-3 h-3 !bg-emerald-300 !border-2 !border-white"
      />
    </div>
  );
}

import { useState } from "react";
import { Button } from "@/components/ui/button";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogTrigger,
} from "@/components/ui/dialog";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Plus } from "lucide-react";
import { supabase } from "@/integrations/supabase/client";
import { toast } from "sonner";

interface AdicionarEtapaDialogProps {
  funilId: string;
  onEtapaAdded: () => void;
}

const CORES_PADRAO = ["#3b82f6", "#22c55e", "#eab308", "#f97316", "#ef4444", "#8b5cf6", "#ec4899"];

export function AdicionarEtapaDialog({ funilId, onEtapaAdded }: AdicionarEtapaDialogProps) {
  const [open, setOpen] = useState(false);
  const [nome, setNome] = useState("");
  const [cor, setCor] = useState(CORES_PADRAO[0]);
  const [loading, setLoading] = useState(false);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    
    const nomeFormatado = nome.trim();
    
    if (!nomeFormatado) {
      toast.error("Digite o nome da etapa");
      return;
    }

    if (nomeFormatado.length < 3) {
      toast.error("Nome deve ter pelo menos 3 caracteres");
      return;
    }

    if (nomeFormatado.length > 50) {
      toast.error("Nome deve ter no máximo 50 caracteres");
      return;
    }

    setLoading(true);

    try {
      // Pegar company_id do usuário
      const { data: userData } = await supabase.auth.getUser();
      if (!userData.user) throw new Error("Usuário não autenticado");

      const { data: userRole } = await supabase
        .from("user_roles")
        .select("company_id")
        .eq("user_id", userData.user.id)
        .single();

      if (!userRole) throw new Error("Empresa não encontrada");

      // Verificar se já existe etapa com mesmo nome neste funil
      const { data: etapaExistente } = await supabase
        .from("etapas")
        .select("id")
        .eq("funil_id", funilId)
        .ilike("nome", nomeFormatado)
        .maybeSingle();

      if (etapaExistente) {
        toast.error("Já existe uma etapa com este nome neste funil");
        setLoading(false);
        return;
      }

      // Buscar maior posição atual
      const { data: etapas } = await supabase
        .from("etapas")
        .select("posicao")
        .eq("funil_id", funilId)
        .order("posicao", { ascending: false })
        .limit(1);

      const novaPosicao = etapas && etapas.length > 0 ? etapas[0].posicao + 1 : 0;

      // Criar nova etapa
      const { error } = await supabase.from("etapas").insert({
        nome: nomeFormatado,
        cor,
        posicao: novaPosicao,
        funil_id: funilId,
        company_id: userRole.company_id,
      });

      if (error) throw error;

      toast.success(`Etapa "${nomeFormatado}" adicionada com sucesso!`);
      setNome("");
      setCor(CORES_PADRAO[0]);
      setOpen(false);
      onEtapaAdded();
    } catch (error: any) {
      console.error("Erro ao adicionar etapa:", error);
      toast.error(error.message || "Erro ao adicionar etapa");
    } finally {
      setLoading(false);
    }
  };

  return (
    <Dialog open={open} onOpenChange={setOpen}>
      <DialogTrigger asChild>
        <Button variant="outline" size="sm">
          <Plus className="h-4 w-4 mr-2" />
          Nova Etapa
        </Button>
      </DialogTrigger>
      <DialogContent>
        <DialogHeader>
          <DialogTitle>Adicionar Nova Etapa</DialogTitle>
        </DialogHeader>
        <form onSubmit={handleSubmit} className="space-y-4">
          <div>
            <Label htmlFor="nome">Nome da Etapa *</Label>
            <Input
              id="nome"
              value={nome}
              onChange={(e) => setNome(e.target.value)}
              placeholder="Ex: Qualificação, Negociação, Fechamento"
              disabled={loading}
              maxLength={50}
              required
            />
            <p className="text-xs text-muted-foreground mt-1">
              {nome.length}/50 caracteres
            </p>
          </div>

          <div>
            <Label>Cor da Etapa</Label>
            <div className="flex gap-2 mt-2 flex-wrap">
              {CORES_PADRAO.map((corPadrao) => (
                <button
                  key={corPadrao}
                  type="button"
                  className="w-10 h-10 rounded-lg border-2 transition-all hover:scale-110 shadow-sm"
                  style={{
                    backgroundColor: corPadrao,
                    borderColor: cor === corPadrao ? "#000" : "transparent",
                    boxShadow: cor === corPadrao ? "0 0 0 2px rgba(0,0,0,0.1)" : "none",
                  }}
                  onClick={() => setCor(corPadrao)}
                  disabled={loading}
                  title={corPadrao}
                />
              ))}
              <div className="flex items-center ml-2">
                <Input
                  type="color"
                  value={cor}
                  onChange={(e) => setCor(e.target.value)}
                  className="w-10 h-10 p-1 cursor-pointer"
                  disabled={loading}
                  title="Escolher cor personalizada"
                />
              </div>
            </div>
          </div>

          <div className="flex justify-end gap-2 pt-4">
            <Button
              type="button"
              variant="outline"
              onClick={() => setOpen(false)}
              disabled={loading}
            >
              Cancelar
            </Button>
            <Button type="submit" disabled={loading}>
              {loading ? "Adicionando..." : "Adicionar Etapa"}
            </Button>
          </div>
        </form>
      </DialogContent>
    </Dialog>
  );
}

import { useState, useEffect } from "react";
import { Button } from "@/components/ui/button";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogTrigger } from "@/components/ui/dialog";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Label } from "@/components/ui/label";
import { Plus } from "lucide-react";
import { supabase } from "@/integrations/supabase/client";
import { toast } from "sonner";

interface AdicionarLeadExistenteDialogProps {
  funilId: string;
  etapaInicial: {
    id: string;
    nome: string;
  };
  onLeadAdded: () => void;
}

interface Lead {
  id: string;
  name: string;
  company?: string;
  telefone?: string;
  email?: string;
}

export function AdicionarLeadExistenteDialog({ funilId, etapaInicial, onLeadAdded }: AdicionarLeadExistenteDialogProps) {
  const [open, setOpen] = useState(false);
  const [loading, setLoading] = useState(false);
  const [leads, setLeads] = useState<Lead[]>([]);
  const [selectedLead, setSelectedLead] = useState<string>("");

  useEffect(() => {
    if (open) {
      carregarLeadsDisponiveis();
    }
  }, [open]);

  const carregarLeadsDisponiveis = async () => {
    try {
      // Busca leads que não estão em nenhum funil
      const { data, error } = await supabase
        .from("leads")
        .select("id, name, company, telefone, email")
        .is("funil_id", null)
        .order("created_at", { ascending: false });

      if (error) throw error;

      setLeads(data || []);
    } catch (error: any) {
      console.error("Erro ao carregar leads:", error);
      toast.error("Erro ao carregar leads disponíveis");
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    if (!selectedLead) {
      toast.error("Selecione um lead");
      return;
    }

    setLoading(true);

    try {
      const { error } = await supabase
        .from("leads")
        .update({
          funil_id: funilId,
          etapa_id: etapaInicial.id,
          status: "ativo"
        })
        .eq("id", selectedLead);

      if (error) throw error;

      toast.success("Lead adicionado ao funil com sucesso!");
      setOpen(false);
      onLeadAdded();
    } catch (error: any) {
      console.error("Erro ao adicionar lead ao funil:", error);
      toast.error("Erro ao adicionar lead ao funil");
    } finally {
      setLoading(false);
    }
  };

  return (
    <Dialog open={open} onOpenChange={setOpen}>
      <DialogTrigger asChild>
        <Button variant="outline">
          <Plus className="mr-2 h-4 w-4" />
          Adicionar Lead Existente
        </Button>
      </DialogTrigger>
      <DialogContent>
        <DialogHeader>
          <DialogTitle>Adicionar Lead ao Funil</DialogTitle>
        </DialogHeader>
        <form onSubmit={handleSubmit} className="space-y-4">
          <div className="space-y-2">
            <Label htmlFor="lead">Selecionar Lead *</Label>
            <Select
              value={selectedLead}
              onValueChange={setSelectedLead}
            >
              <SelectTrigger id="lead">
                <SelectValue placeholder="Escolha um lead" />
              </SelectTrigger>
              <SelectContent>
                {leads.map((lead) => (
                  <SelectItem key={lead.id} value={lead.id}>
                    <div className="flex flex-col">
                      <span>{lead.name}</span>
                      <span className="text-xs text-muted-foreground">
                        {lead.company && `${lead.company} • `}
                        {lead.telefone || lead.email}
                      </span>
                    </div>
                  </SelectItem>
                ))}
                {leads.length === 0 && (
                  <div className="p-2 text-sm text-muted-foreground text-center">
                    Nenhum lead disponível
                  </div>
                )}
              </SelectContent>
            </Select>
            <p className="text-xs text-muted-foreground">
              Apenas leads que não estão em nenhum funil são exibidos
            </p>
          </div>

          <div className="pt-4 border-t flex justify-end gap-2">
            <Button
              type="button"
              variant="outline"
              onClick={() => setOpen(false)}
              disabled={loading}
            >
              Cancelar
            </Button>
            <Button
              type="submit"
              disabled={loading || !selectedLead}
            >
              {loading ? "Adicionando..." : "Adicionar ao Funil"}
            </Button>
          </div>
        </form>
      </DialogContent>
    </Dialog>
  );
}

import { useDroppable } from "@dnd-kit/core";
import { ReactNode, useState } from "react";
import { Button } from "@/components/ui/button";
import { Trash2 } from "lucide-react";
import { EditarEtapaDialog } from "./EditarEtapaDialog";
import { supabase } from "@/integrations/supabase/client";
import { toast } from "sonner";
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
} from "@/components/ui/alert-dialog";

interface DroppableColumnProps {
  id: string;
  children: ReactNode;
  cor: string;
  nome: string;
  quantidadeLeads: number;
  totalEtapa: number;
  onEtapaUpdated: () => void;
}

export function DroppableColumn({ id, children, cor, nome, quantidadeLeads, totalEtapa, onEtapaUpdated }: DroppableColumnProps) {
  const [showDeleteDialog, setShowDeleteDialog] = useState(false);
  const [isDeleting, setIsDeleting] = useState(false);
  
  const { setNodeRef, isOver } = useDroppable({
    id: id,
    data: {
      type: 'etapa',
      etapaId: id
    }
  });

  const handleDeleteClick = () => {
    if (quantidadeLeads > 0) {
      toast.error("Não é possível deletar etapa com leads. Mova os leads primeiro.");
      return;
    }
    setShowDeleteDialog(true);
  };

  const handleConfirmDelete = async () => {
    setIsDeleting(true);
    try {
      const { error } = await supabase.from("etapas").delete().eq("id", id);
      if (error) throw error;

      toast.success(`Etapa "${nome}" deletada com sucesso!`);
      setShowDeleteDialog(false);
      onEtapaUpdated();
    } catch (error: any) {
      console.error("Erro ao deletar etapa:", error);
      toast.error(error.message || "Erro ao deletar etapa");
    } finally {
      setIsDeleting(false);
    }
  };

  return (
    <>
      <div>
        <div className="text-white p-3 rounded-t-lg" style={{ backgroundColor: cor }}>
          <div className="flex items-center justify-between mb-2">
            <h3 className="font-semibold">{nome}</h3>
            <div className="flex gap-1">
              <EditarEtapaDialog 
                etapaId={id}
                nomeAtual={nome}
                corAtual={cor}
                onEtapaUpdated={onEtapaUpdated}
              />
              <Button
                variant="ghost"
                size="icon"
                className="h-7 w-7 text-white hover:bg-white/20"
                onClick={handleDeleteClick}
                title={quantidadeLeads > 0 ? "Mova os leads antes de deletar" : "Deletar Etapa"}
                disabled={isDeleting}
              >
                <Trash2 className="h-3.5 w-3.5" />
              </Button>
            </div>
          </div>
          <div className="text-sm">
            <div>{quantidadeLeads} lead{quantidadeLeads !== 1 ? 's' : ''}</div>
            <div className="font-bold">
              R$ {totalEtapa.toLocaleString('pt-BR', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}
            </div>
          </div>
        </div>
        <div 
          ref={setNodeRef}
          className={`bg-secondary/20 p-4 rounded-b-lg min-h-[500px] transition-colors ${
            isOver ? 'bg-primary/10 border-2 border-primary border-dashed' : ''
          }`}
        >
          {children}
        </div>
      </div>

      <AlertDialog open={showDeleteDialog} onOpenChange={setShowDeleteDialog}>
        <AlertDialogContent>
          <AlertDialogHeader>
            <AlertDialogTitle>Confirmar exclusão da etapa</AlertDialogTitle>
            <AlertDialogDescription>
              Tem certeza que deseja deletar a etapa <strong>"{nome}"</strong>?
              <br />
              Esta ação não pode ser desfeita.
            </AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogCancel disabled={isDeleting}>Cancelar</AlertDialogCancel>
            <AlertDialogAction
              onClick={handleConfirmDelete}
              disabled={isDeleting}
              className="bg-destructive text-destructive-foreground hover:bg-destructive/90"
            >
              {isDeleting ? "Deletando..." : "Deletar"}
            </AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>
    </>
  );
}

import { useState, useEffect } from "react";
import { Button } from "@/components/ui/button";
import {
