import { Label } from "@/components/ui/label";
import { Pencil } from "lucide-react";
import { supabase } from "@/integrations/supabase/client";
import { toast } from "sonner";

interface EditarEtapaDialogProps {
  etapaId: string;
  nomeAtual: string;
  corAtual: string;
  onEtapaUpdated: () => void;
}

const CORES_PADRAO = ["#3b82f6", "#22c55e", "#eab308", "#f97316", "#ef4444", "#8b5cf6", "#ec4899"];

export function EditarEtapaDialog({ etapaId, nomeAtual, corAtual, onEtapaUpdated }: EditarEtapaDialogProps) {
  const [open, setOpen] = useState(false);
  const [nome, setNome] = useState(nomeAtual);
  const [cor, setCor] = useState(corAtual);
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    if (open) {
      setNome(nomeAtual);
      setCor(corAtual);
    }
  }, [open, nomeAtual, corAtual]);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    
    const nomeFormatado = nome.trim();
    
    if (!nomeFormatado) {
      toast.error("Digite o nome da etapa");
      return;
    }

    if (nomeFormatado.length < 3) {
      toast.error("Nome deve ter pelo menos 3 caracteres");
      return;
    }

    if (nomeFormatado.length > 50) {
      toast.error("Nome deve ter no máximo 50 caracteres");
      return;
    }

    setLoading(true);

    try {
      // Buscar funil_id da etapa atual
      const { data: etapaAtual } = await supabase
        .from("etapas")
        .select("funil_id")
        .eq("id", etapaId)
        .single();

      if (!etapaAtual) throw new Error("Etapa não encontrada");

      // Verificar duplicata apenas se mudou o nome
      if (nomeFormatado.toLowerCase() !== nomeAtual.toLowerCase()) {
        const { data: etapaExistente } = await supabase
          .from("etapas")
          .select("id")
          .eq("funil_id", etapaAtual.funil_id)
          .ilike("nome", nomeFormatado)
          .neq("id", etapaId)
          .maybeSingle();

        if (etapaExistente) {
          toast.error("Já existe uma etapa com este nome neste funil");
          setLoading(false);
          return;
        }
      }

      const { error } = await supabase
        .from("etapas")
        .update({
          nome: nomeFormatado,
          cor,
        })
        .eq("id", etapaId);

      if (error) throw error;

      toast.success(`Etapa "${nomeFormatado}" atualizada com sucesso!`);
      setOpen(false);
      onEtapaUpdated();
    } catch (error: any) {
      console.error("Erro ao atualizar etapa:", error);
      toast.error(error.message || "Erro ao atualizar etapa");
    } finally {
      setLoading(false);
    }
  };

  return (
    <Dialog open={open} onOpenChange={setOpen}>
      <DialogTrigger asChild>
        <Button variant="ghost" size="icon" className="h-7 w-7">
          <Pencil className="h-3.5 w-3.5" />
        </Button>
      </DialogTrigger>
      <DialogContent>
        <DialogHeader>
          <DialogTitle>Editar Etapa</DialogTitle>
        </DialogHeader>
        <form onSubmit={handleSubmit} className="space-y-4">
          <div>
            <Label htmlFor="nome">Nome da Etapa *</Label>
            <Input
              id="nome"
              value={nome}
              onChange={(e) => setNome(e.target.value)}
              placeholder="Ex: Qualificação, Negociação"
              disabled={loading}
              maxLength={50}
              required
            />
            <p className="text-xs text-muted-foreground mt-1">
              {nome.length}/50 caracteres
            </p>
          </div>

          <div>
            <Label>Cor da Etapa</Label>
            <div className="flex gap-2 mt-2 flex-wrap">
              {CORES_PADRAO.map((corPadrao) => (
                <button
                  key={corPadrao}
                  type="button"
                  className="w-10 h-10 rounded-lg border-2 transition-all hover:scale-110 shadow-sm"
                  style={{
                    backgroundColor: corPadrao,
                    borderColor: cor === corPadrao ? "#000" : "transparent",
                    boxShadow: cor === corPadrao ? "0 0 0 2px rgba(0,0,0,0.1)" : "none",
                  }}
                  onClick={() => setCor(corPadrao)}
                  disabled={loading}
                  title={corPadrao}
                />
              ))}
              <div className="flex items-center ml-2">
                <Input
                  type="color"
                  value={cor}
                  onChange={(e) => setCor(e.target.value)}
                  className="w-10 h-10 p-1 cursor-pointer"
                  disabled={loading}
                  title="Escolher cor personalizada"
                />
              </div>
            </div>
          </div>

          <div className="flex justify-end gap-2 pt-4">
            <Button
              type="button"
              variant="outline"
              onClick={() => setOpen(false)}
              disabled={loading}
            >
              Cancelar
            </Button>
            <Button type="submit" disabled={loading}>
              {loading ? "Salvando..." : "Salvar Alterações"}
            </Button>
          </div>
        </form>
      </DialogContent>
    </Dialog>
  );
}

import { useState, useEffect } from "react";
import { Plus, X, GripVertical, Pencil, Settings } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogTrigger } from "@/components/ui/dialog";
import { supabase } from "@/integrations/supabase/client";
import { toast } from "sonner";

interface EditarFunilDialogProps {
  funilId: string;
  funilNome: string;
  onFunilUpdated: () => void;
}

interface Etapa {
  id: string;
  nome: string;
  posicao: number;
  cor: string;
  funil_id: string;
  status?: 'normal' | 'final';
}

const CORES_PADRAO = [
  "#ef4444", "#f97316", "#eab308", "#22c55e", "#3b82f6", "#8b5cf6", "#ec4899",
];

export function EditarFunilDialog({ funilId, funilNome, onFunilUpdated }: EditarFunilDialogProps) {
  const [open, setOpen] = useState(false);
  const [loading, setLoading] = useState(false);
  const [nomeFunil, setNomeFunil] = useState(funilNome);
  const [etapas, setEtapas] = useState<Etapa[]>([]);

  useEffect(() => {
    if (open) {
      carregarEtapas();
    }
  }, [open, funilId]);

  const carregarEtapas = async () => {
    const { data, error } = await supabase
      .from("etapas")
      .select("*")
      .eq("funil_id", funilId)
      .order("posicao");

    if (error) {
      toast.error("Erro ao carregar etapas");
      return;
    }

    setEtapas(data || []);
  };

  const adicionarEtapa = () => {
    // Encontra a última posição antes das etapas finais
    const ultimaPosicao = Math.max(...etapas
      .filter(e => e.status !== 'final')
      .map(e => e.posicao), -1);

    const novaEtapa: Etapa = {
      id: `temp-${Date.now()}`,
      nome: `Etapa ${etapas.length - 1}`,
      posicao: ultimaPosicao + 1,
      cor: CORES_PADRAO[etapas.length % CORES_PADRAO.length],
      funil_id: funilId,
      status: 'normal'
    };

    // Insere a nova etapa antes das etapas finais
    const novasEtapas = [
      ...etapas.filter(e => e.status !== 'final'),
      novaEtapa,
      ...etapas.filter(e => e.status === 'final')
    ];

    setEtapas(novasEtapas);
  };

  const removerEtapa = async (etapa: Etapa) => {
    if (etapa.status === 'final') {
      toast.error("Não é possível remover as etapas Ganho e Perdido");
      return;
    }

    const etapasNormais = etapas.filter(e => e.status !== 'final');
    if (etapasNormais.length <= 1) {
      toast.error("O funil precisa ter pelo menos uma etapa além de Ganho e Perdido");
      return;
    }

    if (!etapa.id.startsWith("temp-")) {
      console.log(`🗑️ Removendo etapa "${etapa.nome}" (ID: ${etapa.id})`);

      // Verificar se há leads nesta etapa
      const { data: leadsNaEtapa, error: checkError } = await supabase
        .from("leads")
        .select("id")
        .eq("etapa_id", etapa.id)
        .limit(1);

      if (checkError) {
        console.error("Erro ao verificar leads:", checkError);
        toast.error("Erro ao verificar etapa");
        return;
      }

      if (leadsNaEtapa && leadsNaEtapa.length > 0) {
        toast.error("Não é possível excluir uma etapa que contém leads");
        return;
      }

      // Deletar etapa do banco
      const { error: deleteError } = await supabase
        .from("etapas")
        .delete()
        .eq("id", etapa.id);

      if (deleteError) {
        console.error("Erro ao deletar etapa:", deleteError);
        toast.error("Erro ao remover etapa");
        return;
      }

      console.log(`✅ Etapa "${etapa.nome}" removida do banco`);
      toast.success("Etapa removida com sucesso");

      // Recarregar etapas após deletar
      await carregarEtapas();
    } else {
      // Apenas remover localmente se for temporária
      setEtapas([
        ...etapas.filter(e => e.id !== etapa.id && e.status !== 'final'),
        ...etapas.filter(e => e.status === 'final')
      ]);
    }
  };

  const atualizarNomeEtapa = (id: string, novoNome: string) => {
    setEtapas(etapas.map(e => e.id === id ? { ...e, nome: novoNome } : e));
  };

  const atualizarCorEtapa = (id: string, novaCor: string) => {
    setEtapas(etapas.map(e => e.id === id ? { ...e, cor: novaCor } : e));
  };

  const excluirFunil = async () => {
    if (!confirm("⚠️ ATENÇÃO: Tem certeza que deseja excluir este funil?\n\nTodas as etapas e leads associados serão perdidos permanentemente!")) {
      return;
    }

    setLoading(true);
    try {
      const { data: { session } } = await supabase.auth.getSession();
      if (!session) {
        toast.error("Não autenticado");
        setLoading(false);
        return;
      }

      console.log(`🗑️ Excluindo funil "${nomeFunil}" (ID: ${funilId})`);

      // Verificar quantos leads serão afetados
      const { data: leadsCount } = await supabase
        .from("leads")
        .select("id", { count: "exact", head: true })
        .eq("funil_id", funilId);

      console.log(`📊 Leads que serão excluídos: ${leadsCount || 0}`);

      // Deletar funil (cascade irá deletar etapas e leads)
      const { error: deleteError } = await supabase
        .from("funis")
        .delete()
        .eq("id", funilId)
        .eq("owner_id", session.user.id);

      if (deleteError) {
        console.error("❌ Erro ao excluir funil:", deleteError);
        throw deleteError;
      }

      console.log("✅ Funil excluído com sucesso");
      toast.success("Funil excluído com sucesso!");
      setOpen(false);
      onFunilUpdated();
    } catch (error: any) {
      console.error("❌ Erro ao excluir funil:", error);
      toast.error(`Erro ao excluir funil: ${error.message || 'Erro desconhecido'}`);
    } finally {
      setLoading(false);
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    if (!nomeFunil.trim()) {
      toast.error("Digite o nome do funil");
      return;
    }

    if (etapas.length === 0) {
      toast.error("Adicione pelo menos uma etapa");
      return;
    }

    const etapasInvalidas = etapas.filter(e => !e.nome.trim());
    if (etapasInvalidas.length > 0) {
      toast.error("Todas as etapas precisam ter um nome");
      return;
    }

    setLoading(true);

    try {
      const { data: { session } } = await supabase.auth.getSession();
      if (!session) {
        toast.error("Não autenticado");
        setLoading(false);
        return;
      }

      console.log("=== ATUALIZANDO FUNIL ===");
      console.log("Funil ID:", funilId);
      console.log("Novo nome:", nomeFunil);
      console.log("User ID:", session.user.id);
      console.log("Etapas a processar:", etapas);

      // 1. Atualizar nome do funil
      const { error: funilError } = await supabase
        .from("funis")
        .update({ 
          nome: nomeFunil
        })
        .eq("id", funilId)
        .eq("owner_id", session.user.id);

      if (funilError) {
        console.error("❌ Erro ao atualizar nome do funil:", funilError);
        throw funilError;
      }

      console.log("✅ Nome do funil atualizado");

      // 2. Processar etapas
      for (let i = 0; i < etapas.length; i++) {
        const etapa = etapas[i];

        if (etapa.id.startsWith("temp-")) {
          console.log(`➕ Criando nova etapa ${i + 1}: "${etapa.nome}"`);

          const { data, error: etapaError } = await supabase
            .from("etapas")
            .insert({
              nome: etapa.nome,
              funil_id: funilId,
              posicao: i,
              cor: etapa.cor
            })
            .select();

          if (etapaError) {
            console.error("❌ Erro ao criar etapa:", etapaError);
            toast.error(`Erro ao criar etapa "${etapa.nome}"`);
            throw etapaError;
          }

          console.log(`✅ Etapa "${etapa.nome}" criada:`, data);
        } else {
          console.log(`🔄 Atualizando etapa ${i + 1}: "${etapa.nome}"`);

          const { error: updateError } = await supabase
            .from("etapas")
            .update({
              nome: etapa.nome,
              posicao: i,
              cor: etapa.cor
            })
            .eq("id", etapa.id)
            .eq("funil_id", funilId);

          if (updateError) {
            console.error("❌ Erro ao atualizar etapa:", updateError);
            toast.error(`Erro ao atualizar etapa "${etapa.nome}"`);
            throw updateError;
          }

          console.log(`✅ Etapa "${etapa.nome}" atualizada`);
        }
      }

      console.log("✅ Funil completo atualizado com sucesso!");
      toast.success("Funil atualizado com sucesso!");
      setOpen(false);
      onFunilUpdated();
    } catch (error: any) {
      console.error("❌ Erro completo ao atualizar funil:", error);
      toast.error(`Erro ao atualizar: ${error.message || 'Erro desconhecido'}`);
    } finally {
      setLoading(false);
    }
  };

  return (
    <Dialog open={open} onOpenChange={setOpen}>
      <DialogTrigger asChild>
        <Button variant="ghost" size="sm" className="h-8 w-8 p-0">
          <Settings className="h-4 w-4" />
        </Button>
      </DialogTrigger>
      <DialogContent className="max-w-2xl max-h-[90vh] overflow-y-auto">
        <DialogHeader>
          <DialogTitle>Editar Funil de Vendas</DialogTitle>
        </DialogHeader>
        <form onSubmit={handleSubmit} className="space-y-6">
          <div>
            <Label htmlFor="nomeFunil">Nome do Funil *</Label>
            <Input
              id="nomeFunil"
              value={nomeFunil}
              onChange={(e) => setNomeFunil(e.target.value)}
              placeholder="Ex: Vendas Produto X"
              required
            />
          </div>

          <div className="space-y-4">
            <div className="flex items-center justify-between">
              <Label>Etapas do Funil *</Label>
              <Button 
                type="button" 
                variant="outline" 
                size="sm"
                onClick={adicionarEtapa}
              >
                <Plus className="mr-2 h-4 w-4" />
                Adicionar Etapa
              </Button>
            </div>

            <div className="space-y-3">
              {etapas.map((etapa, index) => (
                <div 
                  key={etapa.id} 
                  className="flex items-center gap-2 p-3 border rounded-lg bg-secondary/20"
                >
                  <div className="flex items-center gap-2 text-muted-foreground">
                    <GripVertical className="h-4 w-4" />
                    <span className="text-sm font-medium">{index + 1}</span>
                  </div>

                  <Input
                    value={etapa.nome}
                    onChange={(e) => atualizarNomeEtapa(etapa.id, e.target.value)}
                    placeholder="Nome da etapa"
                    className="flex-1"
                  />

                  <div className="flex items-center gap-2">
                    <div className="relative">
                      <input
                        type="color"
                        value={etapa.cor}
                        onChange={(e) => atualizarCorEtapa(etapa.id, e.target.value)}
                        className="w-10 h-10 rounded cursor-pointer border"
                        title="Escolher cor"
                      />
                    </div>

                    <Button
                      type="button"
                      variant="ghost"
                      size="sm"
                      onClick={() => removerEtapa(etapa)}
                      disabled={etapas.length <= 1}
                      className="text-destructive hover:text-destructive"
                    >
                      <X className="h-4 w-4" />
                    </Button>
                  </div>
                </div>
              ))}
            </div>
          </div>

          <div className="flex gap-2 pt-4 border-t">
            <Button 
              type="button" 
              variant="destructive" 
              onClick={excluirFunil}
              disabled={loading}
              className="flex-1"
            >
              Excluir Funil
            </Button>
            <Button 
              type="button" 
              variant="outline" 
              onClick={() => setOpen(false)} 
              className="flex-1"
            >
              Cancelar
            </Button>
            <Button 
              type="submit" 
              disabled={loading} 
              className="flex-1"
            >
              {loading ? "Salvando..." : "Salvar Alterações"}
            </Button>
          </div>
        </form>
      </DialogContent>
    </Dialog>
  );
}

import { useState, useEffect } from "react";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogTrigger } from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Pencil, Tag, X } from "lucide-react";
import { Badge } from "@/components/ui/badge";
import { supabase } from "@/integrations/supabase/client";
import { toast } from "sonner";

interface EditarLeadDialogProps {
  lead: {
    id: string;
    nome: string;
    telefone?: string;
    email?: string;
    cpf?: string;
    value?: number;
    company?: string;
    source?: string;
    notes?: string;
    tags?: string[];
    funil_id?: string;
    etapa_id?: string;
  };
  onLeadUpdated: () => void;
}

export function EditarLeadDialog({ lead, onLeadUpdated }: EditarLeadDialogProps) {
  const [open, setOpen] = useState(false);
  const [loading, setLoading] = useState(false);
  const [funis, setFunis] = useState<any[]>([]);
  const [etapas, setEtapas] = useState<any[]>([]);
  const [etapasFiltradas, setEtapasFiltradas] = useState<any[]>([]);
  const [formData, setFormData] = useState({
    nome: lead.nome || "",
    telefone: lead.telefone || "",
    email: lead.email || "",
    cpf: lead.cpf || "",
    valor: lead.value?.toString() || "",
    company: lead.company || "",
    source: lead.source || "",
    notes: lead.notes || "",
    funil_id: lead.funil_id || "",
    etapa_id: lead.etapa_id || "",
    tags: lead.tags || []
  });
  const [newTag, setNewTag] = useState("");

  useEffect(() => {
    if (open) {
      carregarDados();
    }
  }, [open]);

  useEffect(() => {
    if (formData.funil_id) {
      const filtered = etapas.filter(e => e.funil_id === formData.funil_id);
      setEtapasFiltradas(filtered);
      if (filtered.length > 0 && !formData.etapa_id) {
        setFormData(prev => ({ ...prev, etapa_id: filtered[0].id }));
      }
    }
  }, [formData.funil_id, etapas]);

  const carregarDados = async () => {
    const { data: funisData } = await supabase.from("funis").select("*").order("criado_em");
    const { data: etapasData } = await supabase.from("etapas").select("*").order("posicao");

    setFunis(funisData || []);
    setEtapas(etapasData || []);
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    if (!formData.nome.trim()) {
      toast.error("Digite o nome do lead");
      return;
    }

    if (!formData.funil_id) {
      toast.error("Selecione um funil");
      return;
    }

    if (!formData.etapa_id) {
      toast.error("Selecione uma etapa");
      return;
    }

    setLoading(true);

    try {
      const { data: { session } } = await supabase.auth.getSession();

      if (!session) {
        toast.error("Usuário não autenticado");
        return;
      }

      // Formatar telefone
      let telefoneFormatado = formData.telefone;
      if (telefoneFormatado) {
        telefoneFormatado = telefoneFormatado.replace(/\D/g, "");
        if (!telefoneFormatado.startsWith("55")) {
          telefoneFormatado = "55" + telefoneFormatado;
        }
      }

      const { error } = await supabase
        .from("leads")
        .update({
          name: formData.nome,
          telefone: telefoneFormatado || null,
          phone: telefoneFormatado || null,
          email: formData.email || null,
          cpf: formData.cpf || null,
          value: formData.valor ? parseFloat(formData.valor) : 0,
          company: formData.company || null,
          source: formData.source || null,
          notes: formData.notes || null,
          etapa_id: formData.etapa_id,
          funil_id: formData.funil_id,
          tags: formData.tags,
          updated_at: new Date().toISOString()
        })
        .eq("id", lead.id);

      if (error) {
        console.error("Erro ao atualizar lead:", error);
        throw error;
      }

      toast.success("Lead atualizado com sucesso!");
      setOpen(false);
      onLeadUpdated();
    } catch (error) {
      console.error("Erro ao atualizar lead:", error);
      toast.error("Erro ao atualizar lead. Tente novamente.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <Dialog open={open} onOpenChange={setOpen}>
      <DialogTrigger asChild>
        <Button 
          variant="ghost" 
          size="sm" 
          className="h-8 w-8 p-0"
          onClick={(e) => {
            e.preventDefault();
            e.stopPropagation();
          }}
        >
          <Pencil className="h-4 w-4" />
        </Button>
      </DialogTrigger>
      <DialogContent className="max-w-md max-h-[90vh] overflow-y-auto">
        <DialogHeader>
          <DialogTitle>Editar Lead</DialogTitle>
        </DialogHeader>
        <form onSubmit={handleSubmit} className="space-y-4">
          <div>
            <Label htmlFor="funil">Funil *</Label>
            <Select 
              value={formData.funil_id} 
              onValueChange={(value) => setFormData({ ...formData, funil_id: value })}
            >
              <SelectTrigger>
                <SelectValue placeholder="Selecione o funil" />
              </SelectTrigger>
              <SelectContent>
                {funis.map((funil) => (
                  <SelectItem key={funil.id} value={funil.id}>
                    {funil.nome}
                  </SelectItem>
                ))}
              </SelectContent>
            </Select>
          </div>

          <div>
            <Label htmlFor="etapa">Etapa *</Label>
            <Select 
              value={formData.etapa_id} 
              onValueChange={(value) => setFormData({ ...formData, etapa_id: value })}
            >
              <SelectTrigger>
                <SelectValue placeholder="Selecione a etapa" />
              </SelectTrigger>
              <SelectContent>
                {etapasFiltradas.map((etapa) => (
                  <SelectItem key={etapa.id} value={etapa.id}>
                    {etapa.nome}
                  </SelectItem>
                ))}
              </SelectContent>
            </Select>
          </div>

          <div>
            <Label htmlFor="nome">Nome *</Label>
            <Input
              id="nome"
              value={formData.nome}
              onChange={(e) => setFormData({ ...formData, nome: e.target.value })}
              placeholder="Nome do lead"
              required
            />
          </div>

          <div>
            <Label htmlFor="telefone">Telefone / WhatsApp</Label>
            <Input
              id="telefone"
              type="tel"
              value={formData.telefone}
              onChange={(e) => setFormData({ ...formData, telefone: e.target.value })}
              placeholder="(00) 00000-0000"
            />
          </div>

          <div>
            <Label htmlFor="email">E-mail</Label>
            <Input
              id="email"
              type="email"
              value={formData.email}
              onChange={(e) => setFormData({ ...formData, email: e.target.value })}
              placeholder="email@exemplo.com"
            />
          </div>

          <div>
            <Label htmlFor="cpf">CPF</Label>
            <Input
              id="cpf"
              value={formData.cpf}
              onChange={(e) => setFormData({ ...formData, cpf: e.target.value })}
              placeholder="000.000.000-00"
            />
          </div>

          <div>
            <Label htmlFor="company">Empresa</Label>
            <Input
              id="company"
              value={formData.company}
              onChange={(e) => setFormData({ ...formData, company: e.target.value })}
              placeholder="Nome da empresa"
            />
          </div>

          <div>
            <Label htmlFor="valor">Valor (R$)</Label>
            <Input
              id="valor"
              type="number"
              step="0.01"
              value={formData.valor}
              onChange={(e) => setFormData({ ...formData, valor: e.target.value })}
              placeholder="0.00"
            />
          </div>

          <div>
            <Label htmlFor="source">Origem</Label>
            <Input
              id="source"
              value={formData.source}
              onChange={(e) => setFormData({ ...formData, source: e.target.value })}
              placeholder="Ex: WhatsApp, Instagram, Indicação"
            />
          </div>

          <div>
            <Label htmlFor="notes">Observações</Label>
            <Textarea
              id="notes"
              value={formData.notes}
              onChange={(e) => setFormData({ ...formData, notes: e.target.value })}
              rows={3}
              placeholder="Informações adicionais sobre o lead"
            />
          </div>

          <div>
            <Label htmlFor="tags">Tags</Label>
            <div className="flex gap-2 mb-2">
              <Input
                id="tags"
                value={newTag}
                onChange={(e) => setNewTag(e.target.value)}
                onKeyDown={(e) => {
                  if (e.key === "Enter") {
                    e.preventDefault();
                    const tagTrimmed = newTag.trim();
                    if (tagTrimmed && !formData.tags.includes(tagTrimmed)) {
                      setFormData({ ...formData, tags: [...formData.tags, tagTrimmed] });
                      setNewTag("");
                    }
                  }
                }}
                placeholder="Digite uma tag e pressione Enter"
              />
              <Button
                type="button"
                size="icon"
                onClick={() => {
                  const tagTrimmed = newTag.trim();
                  if (tagTrimmed && !formData.tags.includes(tagTrimmed)) {
                    setFormData({ ...formData, tags: [...formData.tags, tagTrimmed] });
                    setNewTag("");
                  }
                }}
              >
                <Plus className="h-4 w-4" />
              </Button>
            </div>
            <div className="flex flex-wrap gap-2 min-h-[60px] p-2 border rounded-md bg-muted/20">
              {formData.tags.length === 0 ? (
                <p className="text-xs text-muted-foreground">Nenhuma tag adicionada</p>
              ) : (
                formData.tags.map((tag) => (
                  <Badge key={tag} variant="secondary" className="gap-1">
                    <Tag className="h-3 w-3" />
                    {tag}
                    <Button
                      type="button"
                      variant="ghost"
                      size="icon"
                      className="h-4 w-4 p-0 hover:bg-transparent"
                      onClick={() => {
                        setFormData({ ...formData, tags: formData.tags.filter(t => t !== tag) });
                      }}
                    >
                      <X className="h-3 w-3" />
                    </Button>
                  </Badge>
                ))
              )}
            </div>
          </div>

          <div className="flex gap-2 pt-4">
            <Button type="button" variant="outline" onClick={() => setOpen(false)} className="flex-1">
              Cancelar
            </Button>
            <Button type="submit" disabled={loading} className="flex-1">
              {loading ? "Salvando..." : "Salvar Alterações"}
            </Button>
          </div>
        </form>
      </DialogContent>
    </Dialog>
  );
}

