import { useState } from "react";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogTrigger } from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Upload, FileSpreadsheet, AlertCircle } from "lucide-react";
import { supabase } from "@/integrations/supabase/client";
import { toast } from "sonner";
import { Alert, AlertDescription } from "@/components/ui/alert";

interface ImportarLeadsDialogProps {
  onLeadsImported: () => void;
}

export function ImportarLeadsDialog({ onLeadsImported }: ImportarLeadsDialogProps) {
  const [open, setOpen] = useState(false);
  const [loading, setLoading] = useState(false);
  const [file, setFile] = useState<File | null>(null);
  const [preview, setPreview] = useState<any[]>([]);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const selectedFile = e.target.files?.[0];
    if (!selectedFile) return;

    if (!selectedFile.name.endsWith('.csv')) {
      toast.error("Apenas arquivos CSV são suportados no momento");
      return;
    }

    setFile(selectedFile);
    processFile(selectedFile);
  };

  const parseCSVLine = (line: string): string[] => {
    const result: string[] = [];
    let current = '';
    let inQuotes = false;

    for (let i = 0; i < line.length; i++) {
      const char = line[i];
      
      if (char === '"') {
        inQuotes = !inQuotes;
      } else if (char === ',' && !inQuotes) {
        result.push(current.trim());
        current = '';
      } else {
        current += char;
      }
    }
    result.push(current.trim());
    return result;
  };

  const processFile = (file: File) => {
    const reader = new FileReader();
    reader.onload = (event) => {
      const text = event.target?.result as string;
      const lines = text.split('\n').filter(line => line.trim());
      
      if (lines.length < 2) {
        toast.error("Arquivo CSV vazio ou inválido");
        return;
      }

      const headers = parseCSVLine(lines[0]).map(h => h.toLowerCase().trim());
      
      const previewData = lines.slice(1, 6).map(line => {
        const values = parseCSVLine(line);
        const obj: any = {};
        headers.forEach((header, index) => {
          obj[header] = values[index] || '';
        });
        return obj;
      });

      setPreview(previewData);
    };
    reader.readAsText(file, 'UTF-8');
  };

  const handleImport = async () => {
    if (!file) {
      toast.error("Selecione um arquivo primeiro");
      return;
    }

    setLoading(true);
    try {
      const { data: { user } } = await supabase.auth.getUser();
      if (!user) throw new Error("Usuário não autenticado");

      // Buscar company_id do usuário
      const { data: userRole } = await supabase
        .from("user_roles")
        .select("company_id")
        .eq("user_id", user.id)
        .single();

      if (!userRole?.company_id) {
        toast.error("Empresa não encontrada");
        setLoading(false);
        return;
      }

      // Buscar primeiro funil do usuário
      const { data: funis } = await supabase
        .from("funis")
        .select("id")
        .eq("company_id", userRole.company_id)
        .limit(1);

      if (!funis || funis.length === 0) {
        toast.error("Crie um funil antes de importar leads");
        setLoading(false);
        return;
      }

      const funilId = funis[0].id;

      // Buscar primeira etapa do funil
      const { data: etapas } = await supabase
        .from("etapas")
        .select("id")
        .eq("funil_id", funilId)
        .order("posicao", { ascending: true })
        .limit(1);

      if (!etapas || etapas.length === 0) {
        toast.error("Crie etapas no funil antes de importar leads");
        setLoading(false);
        return;
      }

      const etapaId = etapas[0].id;

      const reader = new FileReader();
      reader.onload = async (event) => {
        const text = event.target?.result as string;
        const lines = text.split('\n').filter(line => line.trim());
        const headers = parseCSVLine(lines[0]).map(h => h.trim().toLowerCase());
        
        const leadsToImport = lines.slice(1)
          .map(line => {
            const values = parseCSVLine(line);
            const lead: any = {
              owner_id: user.id,
              company_id: userRole.company_id,
              funil_id: funilId,
              etapa_id: etapaId,
              status: 'novo',
              stage: 'prospeccao',
              value: 0,
            };

            headers.forEach((header, index) => {
              const value = values[index]?.trim().replace(/^["']|["']$/g, '');
              if (!value) return;

              // Mapear colunas do CSV para campos do banco
              switch (header) {
                case 'nome':
                case 'name':
                  lead.name = value;
                  break;
                case 'telefone':
                case 'phone':
                case 'whatsapp':
                case 'celular':
                  let telefone = value.replace(/\D/g, "");
                  if (!telefone.startsWith("55")) {
                    telefone = "55" + telefone;
                  }
                  lead.telefone = telefone;
                  lead.phone = telefone;
                  break;
                case 'email':
                case 'e-mail':
                  if (value.includes('@')) {
                    lead.email = value.toLowerCase();
                  }
                  break;
                case 'cpf':
                  lead.cpf = value.replace(/\D/g, "");
                  break;
                case 'empresa':
                case 'company':
                  lead.company = value;
                  break;
                case 'origem':
                case 'source':
                case 'fonte':
                  lead.source = value;
                  break;
                case 'valor':
                case 'value':
                case 'ticket':
                  const valorLimpo = value.replace(/[^0-9,.-]+/g, "").replace(',', '.');
                  lead.value = parseFloat(valorLimpo) || 0;
                  break;
                case 'status':
                  const statusValido = ['novo', 'em_contato', 'qualificado', 'negociacao', 'ganho', 'perdido'];
                  const statusNormalizado = value.toLowerCase().replace(/\s+/g, '_');
                  if (statusValido.includes(statusNormalizado)) {
                    lead.status = statusNormalizado;
                  }
                  break;
                case 'servico':
                case 'service':
                case 'produto':
                  lead.servico = value;
                  break;
                case 'segmentacao':
                case 'segmento':
                case 'categoria':
                  lead.segmentacao = value;
                  break;
                case 'tags':
                case 'tag':
                case 'etiquetas':
                  const tagsArray = value.includes(';') 
                    ? value.split(';') 
                    : value.includes(',') 
                    ? value.split(',') 
                    : [value];
                  lead.tags = tagsArray.map((t: string) => t.trim()).filter((t: string) => t);
                  break;
                case 'observacoes':
                case 'notes':
                case 'nota':
                case 'observacao':
                  lead.notes = value;
                  break;
              }
            });

            return lead;
          })
          .filter(lead => lead.name && lead.name.length > 0); // Só importar leads com nome válido

        if (leadsToImport.length === 0) {
          toast.error("Nenhum lead válido encontrado no arquivo");
          return;
        }

        const { error } = await supabase
          .from("leads")
          .insert(leadsToImport);

        if (error) throw error;

        toast.success(`${leadsToImport.length} leads importados com sucesso!`);
        setOpen(false);
        setFile(null);
        setPreview([]);
        onLeadsImported();
      };

      reader.readAsText(file);
    } catch (error: any) {
      toast.error(error.message || "Erro ao importar leads");
    } finally {
      setLoading(false);
    }
  };

  return (
    <Dialog open={open} onOpenChange={setOpen}>
      <DialogTrigger asChild>
        <Button variant="outline">
          <Upload className="mr-2 h-4 w-4" />
          Importar
        </Button>
      </DialogTrigger>
      <DialogContent className="max-w-3xl max-h-[90vh] overflow-y-auto">
        <DialogHeader>
          <DialogTitle>Importar Leads</DialogTitle>
        </DialogHeader>

        <div className="space-y-4">
          <Alert>
            <AlertCircle className="h-4 w-4" />
            <AlertDescription>
              <strong>Formato do arquivo CSV:</strong>
              <br />
              <strong>Obrigatório:</strong> nome
              <br />
              <strong>Opcionais:</strong> telefone, email, cpf, empresa, origem, valor, status, servico, segmentacao, tags, observacoes
              <br />
              • Separe múltiplas tags com ponto e vírgula (;) ou vírgula (,)
              <br />
              • O telefone será formatado automaticamente com código do Brasil (+55)
            </AlertDescription>
          </Alert>

          <div className="space-y-2">
            <Label htmlFor="file">Arquivo CSV</Label>
            <Input
              id="file"
              type="file"
              accept=".csv"
              onChange={handleFileChange}
            />
          </div>

          {preview.length > 0 && (
            <div className="space-y-2">
              <Label>Prévia (primeiras 5 linhas)</Label>
              <div className="border rounded-lg p-4 overflow-x-auto">
                <table className="w-full text-sm">
                  <thead>
                    <tr>
                      {Object.keys(preview[0]).map((key) => (
                        <th key={key} className="text-left p-2 border-b">
                          {key}
                        </th>
                      ))}
                    </tr>
                  </thead>
                  <tbody>
                    {preview.map((row, i) => (
                      <tr key={i}>
                        {Object.values(row).map((value: any, j) => (
                          <td key={j} className="p-2 border-b">
                            {value}
                          </td>
                        ))}
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </div>
          )}

          <div className="flex justify-end gap-2">
            <Button variant="outline" onClick={() => setOpen(false)}>
              Cancelar
            </Button>
            <Button onClick={handleImport} disabled={!file || loading}>
              <FileSpreadsheet className="mr-2 h-4 w-4" />
              {loading ? "Importando..." : "Importar Leads"}
            </Button>
          </div>
        </div>
      </DialogContent>
    </Dialog>
  );
}

import { useDraggable } from "@dnd-kit/core";
import { Card } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Phone, Mail, User, Trash2, MessageCircle, Building2, Tag, Calendar, CheckSquare } from "lucide-react";
import { AgendaModal } from "@/components/agenda/AgendaModal";
import { TarefaModal } from "@/components/tarefas/TarefaModal";
import { Tooltip, TooltipContent, TooltipProvider, TooltipTrigger } from "@/components/ui/tooltip";
import { Badge } from "@/components/ui/badge";
import { EditarLeadDialog } from "./EditarLeadDialog";
import { MoverLeadFunilDialog } from "./MoverLeadFunilDialog";
import { useNavigate } from "react-router-dom";

interface LeadCardProps {
  lead: {
    id: string;
    nome: string;
    telefone?: string;
    email?: string;
    value?: number;
    company?: string;
    source?: string;
    tags?: string[];
    funil_id?: string;
    etapa_id?: string;
  };
  onDelete: (leadId: string) => void;
  onLeadMoved?: () => void;
}

export function LeadCard({ lead, onDelete, onLeadMoved }: LeadCardProps) {
  const navigate = useNavigate();
  const [agendaModalOpen, setAgendaModalOpen] = useState(false);
  const [tarefaModalOpen, setTarefaModalOpen] = useState(false);
  const [proximoCompromisso, setProximoCompromisso] = useState<string | null>(null);
  const [proximaTarefa, setProximaTarefa] = useState<string | null>(null);

  useEffect(() => {
    if (lead.id) {
      carregarProximasAtividades();
    }
  }, [lead.id]);

  const carregarProximasAtividades = async () => {
    try {
      // Carregar próximo compromisso
      const { data: compromissos } = await supabase
        .from("compromissos")
        .select("titulo, data_hora_inicio")
        .eq("lead_id", lead.id)
        .gte("data_hora_inicio", new Date().toISOString())
        .order("data_hora_inicio")
        .limit(1);

      if (compromissos?.[0]) {
        setProximoCompromisso(
          `${compromissos[0].titulo} - ${new Date(compromissos[0].data_hora_inicio).toLocaleDateString()}`
        );
      }

      // Carregar próxima tarefa
      const { data: tarefas } = await supabase
        .from("tasks")
        .select("title, due_date")
        .eq("lead_id", lead.id)
        .eq("status", "pendente")
        .order("due_date")
        .limit(1);

      if (tarefas?.[0]) {
        setProximaTarefa(
          `${tarefas[0].title} - ${new Date(tarefas[0].due_date).toLocaleDateString()}`
        );
      }
    } catch (error) {
      console.error("Erro ao carregar atividades:", error);
    }
  };

  const {
    attributes,
    listeners,
    setNodeRef,
    transform,
    isDragging,
  } = useDraggable({
    id: lead.id,
    data: {
      type: 'lead',
      lead: lead
    }
  });

  // Desabilita o drag quando estiver clicando em botões
  const modifiedListeners = {
    ...listeners,
    onMouseDown: (e: React.MouseEvent) => {
      if (!(e.target as HTMLElement).closest('button, input, select')) {
        listeners?.onMouseDown?.(e);
      }
    }
  };

  const style = transform ? {
    transform: `translate3d(${transform.x}px, ${transform.y}px, 0)`,
    opacity: isDragging ? 0.5 : 1,
    cursor: isDragging ? 'grabbing' : 'grab',
  } : undefined;

  const abrirConversa = (e: React.MouseEvent) => {
    e.preventDefault();
    e.stopPropagation();

    if (lead.telefone) {
      navigate('/conversas', { state: { leadId: lead.id } });
    } else {
      console.warn('Lead sem telefone:', lead.nome);
    }
  };

  return (
    <Card
      ref={setNodeRef}
      style={style}
      {...attributes}
      {...modifiedListeners}
      onClick={(e) => e.stopPropagation()} // Impede propagação de cliques
      onMouseDown={(e) => {
        // Permite drag apenas se não estiver clicando em um botão ou input
        if (!(e.target as HTMLElement).closest('button, input, select')) {
          listeners?.onMouseDown?.(e);
        }
      }}
      className="group relative p-4 mb-3 cursor-grab active:cursor-grabbing border-0 shadow-card hover:shadow-lg transition-all duration-300 bg-card overflow-hidden"
    >
      <div className="absolute inset-0 bg-gradient-card opacity-0 group-hover:opacity-100 transition-opacity duration-300" />

      <div className="relative space-y-3">
        <div className="flex justify-between items-start gap-2">
          <div className="flex items-start gap-2 flex-1">
            <div className="p-2 rounded-lg bg-primary/10 group-hover:bg-primary/20 transition-colors">
              <User className="h-4 w-4 text-primary" />
            </div>
            <div className="flex-1 min-w-0">
              <h4 className="font-semibold text-sm text-foreground mb-1">{lead.nome}</h4>
              {lead.tags && lead.tags.length > 0 && (
                <div className="flex flex-wrap gap-1">
                  {lead.tags.map((tag) => (
                    <Badge key={tag} variant="secondary" className="text-xs">
                      <Tag className="h-2.5 w-2.5 mr-1" />
                      {tag}
                    </Badge>
                  ))}
                </div>
              )}
            </div>
          </div>
          <div 
            className="flex gap-1"
            onClick={(e) => e.stopPropagation()}
            onMouseDown={(e) => e.stopPropagation()}
          >
            <div onClick={(e) => e.stopPropagation()}>
              <MoverLeadFunilDialog
                leadId={lead.id}
                leadNome={lead.nome}
                funilAtualId={lead.funil_id}
                etapaAtualId={lead.etapa_id}
                onLeadMoved={() => onLeadMoved?.()}
              />
            </div>
            <div onClick={(e) => e.stopPropagation()}>
              <EditarLeadDialog lead={lead} onLeadUpdated={onLeadMoved || (() => {})} />
            </div>
            <TooltipProvider>
              <Tooltip>
                <TooltipTrigger asChild>
                  <Button
                    variant="ghost"
                    size="icon"
                    className="h-8 w-8"
                    onClick={(e) => {
                      e.preventDefault();
                      e.stopPropagation();
                      setAgendaModalOpen(true);
                    }}
                  >
                    <Calendar className="h-4 w-4" />
                  </Button>
                </TooltipTrigger>
                <TooltipContent>
                  <p>Próximo compromisso:</p>
                  <p className="font-medium">{proximoCompromisso || "Nenhum agendado"}</p>
                </TooltipContent>
              </Tooltip>
            </TooltipProvider>

            <TooltipProvider>
              <Tooltip>
                <TooltipTrigger asChild>
                  <Button
                    variant="ghost"
                    size="icon"
                    className="h-8 w-8"
                    onClick={(e) => {
                      e.preventDefault();
                      e.stopPropagation();
                      setTarefaModalOpen(true);
                    }}
                  >
                    <CheckSquare className="h-4 w-4" />
                  </Button>
                </TooltipTrigger>
                <TooltipContent>
                  <p>Próxima tarefa:</p>
                  <p className="font-medium">{proximaTarefa || "Nenhuma pendente"}</p>
                </TooltipContent>
              </Tooltip>
            </TooltipProvider>

            <Button
              variant="ghost"
              size="icon"
              className="h-8 w-8 hover:bg-destructive/10 text-muted-foreground hover:text-destructive transition-colors"
              onClick={(e) => {
                e.preventDefault();
                e.stopPropagation();
                if (confirm("Tem certeza que deseja excluir este lead?")) {
                  onDelete(lead.id);
                }
              }}
            >
              <Trash2 className="h-4 w-4" />
            </Button>
          </div>
        </div>

        <AgendaModal
          open={agendaModalOpen}
          onOpenChange={setAgendaModalOpen}
          lead={lead}
          onAgendamentoCriado={() => {
            carregarProximasAtividades();
            onLeadMoved?.();
          }}
        />

        <TarefaModal
          open={tarefaModalOpen}
          onOpenChange={setTarefaModalOpen}
          lead={lead}
          onTarefaCriada={() => {
            carregarProximasAtividades();
            onLeadMoved?.();
          }}
        />

        {lead.company && (
          <div className="flex items-center gap-2 text-xs text-muted-foreground bg-muted/50 px-2 py-1.5 rounded-md">
            <Building2 className="h-3 w-3" />
            <span>{lead.company}</span>
          </div>
        )}

        {lead.telefone && (
          <div className="flex items-center justify-between gap-2">
            <div className="flex items-center gap-2 text-xs text-muted-foreground">
              <Phone className="h-3 w-3" />
              <span>{lead.telefone}</span>
            </div>
            <div onClick={(e) => e.stopPropagation()}>
              <Button
                variant="ghost"
                size="sm"
                className="h-7 px-2 text-success hover:text-success hover:bg-success/10 transition-all"
                onClick={(e) => {
                  e.preventDefault();
                  e.stopPropagation();
                  abrirConversa(e);
                }}
                title="Ver histórico de conversas"
              >
                <MessageCircle className="h-3.5 w-3.5 mr-1" />
                <span className="text-xs font-medium">Ver Conversas</span>
              </Button>
            </div>
          </div>
        )}

        {lead.email && (
          <div className="flex items-center gap-2 text-xs text-muted-foreground bg-muted/30 px-2 py-1.5 rounded-md">
            <Mail className="h-3 w-3" />
            <span className="truncate">{lead.email}</span>
          </div>
        )}

        {lead.value !== undefined && lead.value > 0 && (
          <div className="flex items-center justify-between pt-2 border-t border-border/50">
            <span className="text-xs text-muted-foreground font-medium">Valor Estimado</span>
            <Badge className="font-semibold bg-gradient-success text-success-foreground shadow-sm">
              R$ {lead.value.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
            </Badge>
          </div>
        )}

        {lead.source && (
          <Badge variant="outline" className="text-xs font-medium border-primary/20 text-primary">
            <Tag className="h-3 w-3 mr-1" />
            {lead.source}
          </Badge>
        )}
      </div>
    </Card>
  );
}

import { useState, useEffect } from "react";
import { Button } from "@/components/ui/button";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogDescription,
  DialogTrigger,
} from "@/components/ui/dialog";
import { Label } from "@/components/ui/label";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import { ArrowRightLeft } from "lucide-react";
import { supabase } from "@/integrations/supabase/client";
import { toast } from "sonner";

interface MoverLeadFunilDialogProps {
  leadId: string;
  leadNome: string;
  funilAtualId?: string;
  etapaAtualId?: string;
  onLeadMoved: () => void;
}

interface Funil {
  id: string;
  nome: string;
}

interface Etapa {
  id: string;
  nome: string;
  funil_id: string;
  cor: string;
  status?: 'normal' | 'final';
}

export function MoverLeadFunilDialog({ 
  leadId, 
  leadNome, 
  funilAtualId, 
  etapaAtualId,
  onLeadMoved 
}: MoverLeadFunilDialogProps) {
  const [open, setOpen] = useState(false);
  const [loading, setLoading] = useState(false);
  const [funis, setFunis] = useState<Funil[]>([]);
  const [etapas, setEtapas] = useState<Etapa[]>([]);
  const [selectedFunil, setSelectedFunil] = useState<string>("");
  const [selectedEtapa, setSelectedEtapa] = useState<string>("");

  useEffect(() => {
    if (open) {
      carregarFunis();
    }
  }, [open]);

  useEffect(() => {
    if (selectedFunil) {
      carregarEtapas(selectedFunil);
    } else {
      setEtapas([]);
      setSelectedEtapa("");
    }
  }, [selectedFunil]);

  const carregarFunis = async () => {
    try {
      console.log("🔄 Carregando funis...");
      const { data, error } = await supabase
        .from("funis")
        .select("id, nome")
        .order("criado_em");

      if (error) {
        console.error("❌ Erro ao carregar funis:", error);
        throw error;
      }

      console.log("✅ Funis carregados:", data);
      setFunis(data || []);

      // Se há funil atual, seleciona automaticamente
      if (funilAtualId && data?.some(f => f.id === funilAtualId)) {
        console.log("📍 Funil atual selecionado:", funilAtualId);
        setSelectedFunil(funilAtualId);
      }
    } catch (error: any) {
      console.error("❌ Erro ao carregar funis:", error);
      toast.error("Erro ao carregar funis");
    }
  };

  const carregarEtapas = async (funilId: string) => {
    try {
      console.log("🔄 Carregando etapas do funil:", funilId);
      const { data, error } = await supabase
        .from("etapas")
        .select("id, nome, funil_id, cor")
        .eq("funil_id", funilId)
        .order("posicao");

      if (error) {
        console.error("❌ Erro ao carregar etapas:", error);
        throw error;
      }

      console.log("✅ Etapas carregadas:", data);
      setEtapas(data || []);

      // Se há etapa atual no funil selecionado, seleciona automaticamente
      if (etapaAtualId && funilId === funilAtualId && data?.some(e => e.id === etapaAtualId)) {
        console.log("📍 Etapa atual selecionada:", etapaAtualId);
        setSelectedEtapa(etapaAtualId);
      } else if (data && data.length > 0) {
        // Seleciona a primeira etapa por padrão
        console.log("📍 Selecionando primeira etapa:", data[0].id);
        setSelectedEtapa(data[0].id);
      }
    } catch (error: any) {
      console.error("❌ Erro ao carregar etapas:", error);
      toast.error("Erro ao carregar etapas");
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    if (!selectedFunil) {
      toast.error("Selecione um funil");
      return;
    }

    if (!selectedEtapa) {
      toast.error("Selecione uma etapa");
      return;
    }

    // Verificar se já está nessa posição
    if (selectedFunil === funilAtualId && selectedEtapa === etapaAtualId) {
      toast.info("Lead já está nesta etapa");
      return;
    }

    setLoading(true);

    try {
      console.log("🔄 Movendo lead:", { leadId, selectedFunil, selectedEtapa });
      // Determina o status do lead baseado na etapa selecionada
      const etapaSelecionada = etapas.find(e => e.id === selectedEtapa);
      const novoStatus = etapaSelecionada?.status === 'final'
        ? etapaSelecionada.nome.toLowerCase()
        : 'ativo';

      const { error } = await supabase
        .from("leads")
        .update({
          funil_id: selectedFunil,
          etapa_id: selectedEtapa,
          status: novoStatus,
        })
        .eq("id", leadId);

      if (error) {
        console.error("❌ Erro ao mover lead:", error);
        throw error;
      }

      const funilNome = funis.find(f => f.id === selectedFunil)?.nome;
      const etapaNome = etapas.find(e => e.id === selectedEtapa)?.nome;

      console.log("✅ Lead movido com sucesso!");
      toast.success(`Lead "${leadNome}" movido para ${funilNome} - ${etapaNome}`);
      setOpen(false);
      onLeadMoved();
    } catch (error: any) {
      console.error("❌ Erro ao mover lead:", error);
      toast.error(error.message || "Erro ao mover lead");
    } finally {
      setLoading(false);
    }
  };

  return (
    <Dialog open={open} onOpenChange={setOpen}>
      <DialogTrigger asChild>
        <Button 
          variant="ghost" 
          size="icon" 
          className="h-8 w-8"
          title="Mover para outro funil"
          onClick={(e) => {
            e.preventDefault();
            e.stopPropagation();
          }}
        >
          <ArrowRightLeft className="h-4 w-4" />
        </Button>
      </DialogTrigger>
      <DialogContent>
        <DialogHeader>
          <DialogTitle>Mover Lead Entre Funis</DialogTitle>
          <DialogDescription>
            Mover <strong>{leadNome}</strong> para outro funil/etapa
          </DialogDescription>
        </DialogHeader>
        <form onSubmit={handleSubmit} className="space-y-4">
          <div>
            <Label htmlFor="funil">Selecionar Funil *</Label>
            <Select
              value={selectedFunil}
              onValueChange={setSelectedFunil}
              disabled={loading}
            >
              <SelectTrigger id="funil">
                <SelectValue placeholder="Escolha um funil" />
              </SelectTrigger>
              <SelectContent>
                {funis.map((funil) => (
                  <SelectItem key={funil.id} value={funil.id}>
                    {funil.nome}
                    {funil.id === funilAtualId && " (Atual)"}
                  </SelectItem>
                ))}
              </SelectContent>
            </Select>
          </div>

          <div>
            <Label htmlFor="etapa">Selecionar Etapa *</Label>
            <Select
              value={selectedEtapa}
              onValueChange={setSelectedEtapa}
              disabled={loading || !selectedFunil}
            >
              <SelectTrigger id="etapa">
                <SelectValue placeholder="Escolha uma etapa" />
              </SelectTrigger>
              <SelectContent>
                {etapas.map((etapa) => (
                  <SelectItem key={etapa.id} value={etapa.id}>
                    <div className="flex items-center gap-2">
                      <div
                        className="w-3 h-3 rounded-full"
                        style={{ backgroundColor: etapa.cor }}
                      />
                      {etapa.nome}
                      {etapa.id === etapaAtualId && " (Atual)"}
                    </div>
                  </SelectItem>
                ))}
              </SelectContent>
            </Select>
            {!selectedFunil && (
              <p className="text-xs text-muted-foreground mt-1">
                Selecione um funil primeiro
              </p>
            )}
          </div>

          <div className="flex justify-end gap-2 pt-4">
            <Button
              type="button"
              variant="outline"
              onClick={() => setOpen(false)}
              disabled={loading}
            >
              Cancelar
            </Button>
            <Button type="submit" disabled={loading}>
              {loading ? "Movendo..." : "Mover Lead"}
            </Button>
          </div>
        </form>
      </DialogContent>
    </Dialog>
  );
}

import { useState, useEffect } from "react";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogTrigger } from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Plus, Tag, X } from "lucide-react";
import { Badge } from "@/components/ui/badge";
import { supabase } from "@/integrations/supabase/client";
import { toast } from "sonner";

interface NovoLeadDialogProps {
  onLeadCreated: () => void;
  triggerButton?: React.ReactNode;
}

export function NovoLeadDialog({ onLeadCreated, triggerButton }: NovoLeadDialogProps) {
  const [open, setOpen] = useState(false);
  const [loading, setLoading] = useState(false);
  const [funis, setFunis] = useState<any[]>([]);
  const [etapas, setEtapas] = useState<any[]>([]);
  const [etapasFiltradas, setEtapasFiltradas] = useState<any[]>([]);
  const [formData, setFormData] = useState({
    nome: "",
    telefone: "",
    email: "",
    cpf: "",
    valor: "",
    company: "",
    source: "",
    notes: "",
    funil_id: "",
    etapa_id: "",
    tags: [] as string[]
  });
  const [newTag, setNewTag] = useState("");

  useEffect(() => {
    if (open) {
      carregarDados();
    }
  }, [open]);

  useEffect(() => {
    if (formData.funil_id) {
      const filtered = etapas.filter(e => e.funil_id === formData.funil_id);
      setEtapasFiltradas(filtered);
      if (filtered.length > 0 && !formData.etapa_id) {
        setFormData(prev => ({ ...prev, etapa_id: filtered[0].id }));
      }
    }
  }, [formData.funil_id, etapas]);

  const carregarDados = async () => {
    const { data: funisData } = await supabase.from("funis").select("*").order("criado_em");
    const { data: etapasData } = await supabase.from("etapas").select("*").order("posicao");
    
    setFunis(funisData || []);
    setEtapas(etapasData || []);
    
    if (funisData && funisData.length > 0 && !formData.funil_id) {
      setFormData(prev => ({ ...prev, funil_id: funisData[0].id }));
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    
    if (!formData.nome.trim()) {
      toast.error("Digite o nome do lead");
      return;
    }

    if (!formData.funil_id) {
      toast.error("Selecione um funil");
      return;
    }

    if (!formData.etapa_id) {
      toast.error("Selecione uma etapa");
      return;
    }

    setLoading(true);

    try {
      const { data: { session } } = await supabase.auth.getSession();

      if (!session) {
        toast.error("Usuário não autenticado");
        return;
      }

      // Buscar company_id do usuário
      const { data: userRole } = await supabase
        .from("user_roles")
        .select("company_id")
        .eq("user_id", session.user.id)
        .single();

      if (!userRole?.company_id) {
        toast.error("Empresa não encontrada");
        setLoading(false);
        return;
      }

      // Formatar telefone
      let telefoneFormatado = formData.telefone;
      if (telefoneFormatado) {
        telefoneFormatado = telefoneFormatado.replace(/\D/g, "");
        if (!telefoneFormatado.startsWith("55")) {
          telefoneFormatado = "55" + telefoneFormatado;
        }
      }

      const { data, error } = await supabase
        .from("leads")
        .insert([{
          name: formData.nome,
          telefone: telefoneFormatado || null,
          phone: telefoneFormatado || null,
          email: formData.email || null,
          cpf: formData.cpf || null,
          value: formData.valor ? parseFloat(formData.valor) : 0,
          company: formData.company || null,
          source: formData.source || null,
          notes: formData.notes || null,
          etapa_id: formData.etapa_id,
          funil_id: formData.funil_id,
          owner_id: session.user.id,
          company_id: userRole.company_id,
          status: "novo",
          stage: "prospeccao",
          tags: formData.tags
        }])
        .select();

      if (error) {
        console.error("Erro ao criar lead:", error);
        throw error;
      }

      toast.success("Lead criado com sucesso!");
      setFormData({
        nome: "",
        telefone: "",
        email: "",
        cpf: "",
        valor: "",
        company: "",
        source: "",
        notes: "",
        funil_id: funis.length > 0 ? funis[0].id : "",
        etapa_id: "",
        tags: []
      });
      setNewTag("");
      setOpen(false);
      onLeadCreated();
    } catch (error) {
      console.error("Erro ao criar lead:", error);
      toast.error("Erro ao criar lead. Tente novamente.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <Dialog open={open} onOpenChange={setOpen}>
      <DialogTrigger asChild>
        {triggerButton || (
          <Button size="sm" variant="ghost" className="w-full">
            <Plus className="h-4 w-4 mr-2" />
            Novo Lead
          </Button>
        )}
      </DialogTrigger>
      <DialogContent className="max-w-md max-h-[90vh] overflow-y-auto">
        <DialogHeader>
          <DialogTitle>Novo Lead</DialogTitle>
        </DialogHeader>
        <form onSubmit={handleSubmit} className="space-y-4">
          <div>
            <Label htmlFor="funil">Funil *</Label>
            <Select 
              value={formData.funil_id} 
              onValueChange={(value) => setFormData({ ...formData, funil_id: value })}
            >
              <SelectTrigger>
                <SelectValue placeholder="Selecione o funil" />
              </SelectTrigger>
              <SelectContent>
                {funis.map((funil) => (
                  <SelectItem key={funil.id} value={funil.id}>
                    {funil.nome}
                  </SelectItem>
                ))}
              </SelectContent>
            </Select>
          </div>

          <div>
            <Label htmlFor="etapa">Etapa *</Label>
            <Select 
              value={formData.etapa_id} 
              onValueChange={(value) => setFormData({ ...formData, etapa_id: value })}
            >
              <SelectTrigger>
                <SelectValue placeholder="Selecione a etapa" />
              </SelectTrigger>
              <SelectContent>
                {etapasFiltradas.map((etapa) => (
                  <SelectItem key={etapa.id} value={etapa.id}>
                    {etapa.nome}
                  </SelectItem>
                ))}
              </SelectContent>
            </Select>
          </div>

          <div>
            <Label htmlFor="nome">Nome *</Label>
            <Input
              id="nome"
              value={formData.nome}
              onChange={(e) => setFormData({ ...formData, nome: e.target.value })}
              placeholder="Nome do lead"
              required
            />
          </div>

          <div>
            <Label htmlFor="telefone">Telefone / WhatsApp</Label>
            <Input
              id="telefone"
              type="tel"
              value={formData.telefone}
              onChange={(e) => setFormData({ ...formData, telefone: e.target.value })}
              placeholder="(00) 00000-0000"
            />
          </div>

          <div>
            <Label htmlFor="email">E-mail</Label>
            <Input
              id="email"
              type="email"
              value={formData.email}
              onChange={(e) => setFormData({ ...formData, email: e.target.value })}
              placeholder="email@exemplo.com"
            />
          </div>

          <div>
            <Label htmlFor="cpf">CPF</Label>
            <Input
              id="cpf"
              value={formData.cpf}
              onChange={(e) => setFormData({ ...formData, cpf: e.target.value })}
              placeholder="000.000.000-00"
            />
          </div>

          <div>
            <Label htmlFor="company">Empresa</Label>
            <Input
              id="company"
              value={formData.company}
              onChange={(e) => setFormData({ ...formData, company: e.target.value })}
              placeholder="Nome da empresa"
            />
          </div>

          <div>
            <Label htmlFor="valor">Valor (R$)</Label>
            <Input
              id="valor"
              type="number"
              step="0.01"
              value={formData.valor}
              onChange={(e) => setFormData({ ...formData, valor: e.target.value })}
              placeholder="0.00"
            />
          </div>

          <div>
            <Label htmlFor="source">Origem</Label>
            <Input
              id="source"
              value={formData.source}
              onChange={(e) => setFormData({ ...formData, source: e.target.value })}
              placeholder="Ex: WhatsApp, Instagram, Indicação"
            />
          </div>

          <div>
            <Label htmlFor="notes">Observações</Label>
            <Textarea
              id="notes"
              value={formData.notes}
              onChange={(e) => setFormData({ ...formData, notes: e.target.value })}
              rows={3}
              placeholder="Informações adicionais sobre o lead"
            />
          </div>

          <div>
            <Label htmlFor="tags">Tags</Label>
            <div className="flex gap-2 mb-2">
              <Input
                id="tags"
                value={newTag}
                onChange={(e) => setNewTag(e.target.value)}
                onKeyDown={(e) => {
                  if (e.key === "Enter") {
                    e.preventDefault();
                    const tagTrimmed = newTag.trim();
                    if (tagTrimmed && !formData.tags.includes(tagTrimmed)) {
                      setFormData({ ...formData, tags: [...formData.tags, tagTrimmed] });
                      setNewTag("");
                    }
                  }
                }}
                placeholder="Digite uma tag e pressione Enter"
              />
              <Button
                type="button"
                size="icon"
                onClick={() => {
                  const tagTrimmed = newTag.trim();
                  if (tagTrimmed && !formData.tags.includes(tagTrimmed)) {
                    setFormData({ ...formData, tags: [...formData.tags, tagTrimmed] });
                    setNewTag("");
                  }
                }}
              >
                <Plus className="h-4 w-4" />
              </Button>
            </div>
            <div className="flex flex-wrap gap-2 min-h-[60px] p-2 border rounded-md bg-muted/20">
              {formData.tags.length === 0 ? (
                <p className="text-xs text-muted-foreground">Nenhuma tag adicionada</p>
              ) : (
                formData.tags.map((tag) => (
                  <Badge key={tag} variant="secondary" className="gap-1">
                    <Tag className="h-3 w-3" />
                    {tag}
                    <Button
                      type="button"
                      variant="ghost"
                      size="icon"
                      className="h-4 w-4 p-0 hover:bg-transparent"
                      onClick={() => {
                        setFormData({ ...formData, tags: formData.tags.filter(t => t !== tag) });
                      }}
                    >
                      <X className="h-3 w-3" />
                    </Button>
                  </Badge>
                ))
              )}
            </div>
          </div>

          <div className="flex gap-2 pt-4">
            <Button type="button" variant="outline" onClick={() => setOpen(false)} className="flex-1">
              Cancelar
            </Button>
            <Button type="submit" disabled={loading} className="flex-1">
              {loading ? "Criando..." : "Criar Lead"}
            </Button>
          </div>
        </form>
      </DialogContent>
    </Dialog>
  );
}

import { useState, useEffect } from "react";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Lightbulb, CheckCircle, XCircle, Clock, TrendingUp, MessageSquare } from "lucide-react";
import { supabase } from "@/integrations/supabase/client";
import { toast } from "sonner";

interface Recommendation {
  id: string;
  recommendation_type: string;
  recommendation_text: string;
  priority: string;
  status: string;
  created_at: string;
  recommendation_data: any;
}

export function RecomendacoesIA() {
  const [recommendations, setRecommendations] = useState<Recommendation[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    loadRecommendations();
    
    // Realtime para novas recomendações
    const channel = supabase
      .channel('ia-recommendations')
      .on('postgres_changes', {
        event: 'INSERT',
        schema: 'public',
        table: 'ia_recommendations'
      }, () => {
        loadRecommendations();
      })
      .subscribe();

    return () => {
      supabase.removeChannel(channel);
    };
  }, []);

  const loadRecommendations = async () => {
    const { data, error } = await supabase
      .from('ia_recommendations')
      .select('*')
      .eq('status', 'pending')
      .order('created_at', { ascending: false })
      .limit(10);

    if (error) {
      console.error('Erro ao carregar recomendações:', error);
    } else {
      setRecommendations(data || []);
    }
    setLoading(false);
  };

  const handleRecommendation = async (id: string, action: 'accepted' | 'rejected') => {
    const { error } = await supabase
      .from('ia_recommendations')
      .update({
        status: action,
        applied_at: new Date().toISOString()
      })
      .eq('id', id);

    if (error) {
      toast.error('Erro ao processar recomendação');
    } else {
      toast.success(action === 'accepted' ? 'Recomendação aplicada!' : 'Recomendação rejeitada');
      loadRecommendations();
    }
  };

  const getPriorityColor = (priority: string) => {
    switch (priority) {
      case 'high': return 'bg-destructive text-destructive-foreground';
      case 'medium': return 'bg-warning text-warning-foreground';
      default: return 'bg-secondary text-secondary-foreground';
    }
  };

  const getTypeIcon = (type: string) => {
    switch (type) {
      case 'timing': return Clock;
      case 'message': return MessageSquare;
      case 'action': return TrendingUp;
      default: return Lightbulb;
    }
  };

  if (loading) {
    return <div className="text-center py-8">Carregando recomendações...</div>;
  }

  if (recommendations.length === 0) {
    return (
      <Card>
        <CardContent className="pt-6">
          <div className="text-center py-8">
            <Lightbulb className="h-12 w-12 mx-auto mb-4 text-muted-foreground" />
            <p className="text-muted-foreground">
              Nenhuma recomendação pendente no momento
            </p>
          </div>
        </CardContent>
      </Card>
    );
  }

  return (
    <div className="space-y-4">
      {recommendations.map((rec) => {
        const Icon = getTypeIcon(rec.recommendation_type);
        
        return (
          <Card key={rec.id} className="hover:shadow-lg transition-shadow">
            <CardHeader>
              <div className="flex items-start justify-between">
                <div className="flex items-center gap-3">
                  <div className="p-2 rounded-lg bg-primary/10">
                    <Icon className="h-5 w-5 text-primary" />
                  </div>
                  <div>
                    <CardTitle className="text-lg">{rec.recommendation_text}</CardTitle>
                    <div className="flex gap-2 mt-2">
                      <Badge className={getPriorityColor(rec.priority)}>
                        {rec.priority === 'high' ? 'Alta' : rec.priority === 'medium' ? 'Média' : 'Baixa'}
                      </Badge>
                      <Badge variant="outline">
                        {rec.recommendation_type === 'timing' ? 'Momento Ideal' :
                         rec.recommendation_type === 'message' ? 'Mensagem' :
                         rec.recommendation_type === 'action' ? 'Ação' : 'Recomendação'}
                      </Badge>
                    </div>
                  </div>
                </div>
              </div>
            </CardHeader>
            <CardContent>
              <div className="flex gap-2">
                <Button
                  onClick={() => handleRecommendation(rec.id, 'accepted')}
                  className="flex-1"
                >
                  <CheckCircle className="h-4 w-4 mr-2" />
                  Aplicar
                </Button>
                <Button
                  onClick={() => handleRecommendation(rec.id, 'rejected')}
                  variant="outline"
                  className="flex-1"
                >
                  <XCircle className="h-4 w-4 mr-2" />
                  Rejeitar
                </Button>
              </div>
            </CardContent>
          </Card>
        );
      })}
    </div>
  );
}

import { Bell, Search, Building2, PanelLeftClose, PanelLeft } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Avatar, AvatarFallback } from "@/components/ui/avatar";
import { Badge } from "@/components/ui/badge";
import { useEffect, useState } from "react";
import { supabase } from "@/integrations/supabase/client";

interface HeaderProps {
  onToggleSidebar: () => void;
  sidebarCollapsed: boolean;
}

export function Header({ onToggleSidebar, sidebarCollapsed }: HeaderProps) {
  const [userName, setUserName] = useState("Usuário");
  const [companyName, setCompanyName] = useState<string>("");
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchUserData();
  }, []);

  const fetchUserData = async () => {
    const { data: { user } } = await supabase.auth.getUser();
    if (user) {
      // Get user profile
      const { data: profile } = await supabase
        .from("profiles")
        .select("full_name")
        .eq("id", user.id)
        .single();
      
      if (profile?.full_name) {
        setUserName(profile.full_name);
      }

      // Get company info
      const { data: userRole } = await supabase
        .from("user_roles")
        .select("company_id, companies(name)")
        .eq("user_id", user.id)
        .single();

      if (userRole?.companies) {
        setCompanyName((userRole.companies as any).name);
      }
    }
    setLoading(false);
  };

  const initials = userName
    .split(" ")
    .map((n) => n[0])
    .join("")
    .toUpperCase()
    .slice(0, 2);

  return (
    <header className="sticky top-0 z-40 border-b border-border/40 bg-background/95 backdrop-blur-xl supports-[backdrop-filter]:bg-background/60 shadow-sm">
      <div className="flex h-16 items-center gap-4 px-6">
        {/* Toggle Sidebar Button */}
        <Button
          variant="ghost"
          size="icon"
          onClick={onToggleSidebar}
          className="hover:bg-muted group transition-all"
          title={sidebarCollapsed ? "Expandir menu" : "Recolher menu"}
        >
          {sidebarCollapsed ? (
            <PanelLeft className="h-5 w-5 text-muted-foreground group-hover:text-primary transition-colors" />
          ) : (
            <PanelLeftClose className="h-5 w-5 text-muted-foreground group-hover:text-primary transition-colors" />
          )}
        </Button>

        {/* Search */}
        <div className="flex-1 max-w-xl">
          <div className="relative group">
            <Search className="absolute left-3 top-1/2 h-4 w-4 -translate-y-1/2 text-muted-foreground group-hover:text-primary transition-colors" />
            <Input
              placeholder="Buscar leads, conversas, tarefas..."
              className="pl-9 border-border/40 bg-muted/30 hover:bg-muted/50 focus:bg-background transition-colors"
            />
          </div>
        </div>

        {/* Actions */}
        <div className="flex items-center gap-3">
          {!loading && companyName && (
            <Badge variant="outline" className="flex items-center gap-2">
              <Building2 className="h-3 w-3" />
              {companyName}
            </Badge>
          )}

          <Button 
            variant="ghost" 
            size="icon" 
            className="relative hover:bg-muted group transition-all"
          >
            <Bell className="h-5 w-5 text-muted-foreground group-hover:text-primary transition-colors" />
            <span className="absolute top-1.5 right-1.5 h-2 w-2 rounded-full bg-destructive animate-pulse" />
          </Button>

          <div className="flex items-center gap-3 pl-3 border-l border-border/40">
            <div className="text-right hidden sm:block">
              <p className="text-sm font-medium text-foreground">{userName}</p>
              <p className="text-xs text-muted-foreground">Administrador</p>
            </div>
            <Avatar className="h-9 w-9 ring-2 ring-primary/10 hover:ring-primary/30 transition-all cursor-pointer">
              <AvatarFallback className="bg-gradient-primary text-primary-foreground text-sm font-semibold">
                {initials}
              </AvatarFallback>
            </Avatar>
          </div>
        </div>
      </div>
    </header>
  );
}

import { useState } from "react";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogTrigger } from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Calendar, MessageSquare, CheckSquare, MoreVertical } from "lucide-react";
import { supabase } from "@/integrations/supabase/client";
import { toast } from "sonner";
import { useNavigate } from "react-router-dom";

interface LeadActionsDialogProps {
  lead: {
    id: string;
    name: string;
    telefone?: string | null;
    phone?: string | null;
    email?: string | null;
  };
}

export function LeadActionsDialog({ lead }: LeadActionsDialogProps) {
  const navigate = useNavigate();
  const [open, setOpen] = useState(false);
  const [loading, setLoading] = useState(false);

  // Estados para Compromisso
  const [tipoServico, setTipoServico] = useState("");
  const [dataHoraInicio, setDataHoraInicio] = useState("");
  const [dataHoraFim, setDataHoraFim] = useState("");
  const [observacoes, setObservacoes] = useState("");

  // Estados para Tarefa
  const [tituloTarefa, setTituloTarefa] = useState("");
  const [descricaoTarefa, setDescricaoTarefa] = useState("");
  const [prioridadeTarefa, setPrioridadeTarefa] = useState("media");
  const [dataVencimento, setDataVencimento] = useState("");

  const abrirConversa = () => {
    const telefone = lead.telefone || lead.phone;
    if (telefone) {
      navigate("/conversas");
      setOpen(false);
      toast.success("Abrindo conversa...");
    } else {
      toast.error("Lead não possui telefone cadastrado");
    }
  };

  const criarCompromisso = async () => {
    if (!tipoServico || !dataHoraInicio || !dataHoraFim) {
      toast.error("Preencha todos os campos obrigatórios");
      return;
    }

    setLoading(true);
    try {
      const { data: { user } } = await supabase.auth.getUser();
      if (!user) throw new Error("Usuário não autenticado");

      const { error } = await supabase.from("compromissos").insert({
        lead_id: lead.id,
        tipo_servico: tipoServico,
        data_hora_inicio: dataHoraInicio,
        data_hora_fim: dataHoraFim,
        observacoes,
        status: "agendado",
        usuario_responsavel_id: user.id,
        owner_id: user.id,
      });

      if (error) throw error;

      toast.success("Compromisso criado com sucesso!");
      setOpen(false);
      // Limpar campos
      setTipoServico("");
      setDataHoraInicio("");
      setDataHoraFim("");
      setObservacoes("");
    } catch (error: any) {
      toast.error(error.message || "Erro ao criar compromisso");
    } finally {
      setLoading(false);
    }
  };

  const criarTarefa = async () => {
    if (!tituloTarefa) {
      toast.error("Título da tarefa é obrigatório");
      return;
    }

    setLoading(true);
    try {
      const { data: { user } } = await supabase.auth.getUser();
      if (!user) throw new Error("Usuário não autenticado");

      // Buscar primeiro board do usuário
      const { data: boards } = await supabase
        .from("task_boards")
        .select("id, task_columns(id)")
        .eq("owner_id", user.id)
        .limit(1)
        .single();

      if (!boards) {
        toast.error("Você precisa criar um quadro de tarefas primeiro");
        return;
      }

      const { error } = await supabase.from("tasks").insert({
        title: tituloTarefa,
        description: descricaoTarefa,
        priority: prioridadeTarefa,
        due_date: dataVencimento || null,
        lead_id: lead.id,
        board_id: boards.id,
        column_id: boards.task_columns?.[0]?.id || null,
        owner_id: user.id,
        status: "pendente",
      });

      if (error) throw error;

      toast.success("Tarefa criada com sucesso!");
      setOpen(false);
      // Limpar campos
      setTituloTarefa("");
      setDescricaoTarefa("");
      setPrioridadeTarefa("media");
      setDataVencimento("");
    } catch (error: any) {
      toast.error(error.message || "Erro ao criar tarefa");
    } finally {
      setLoading(false);
    }
  };

  return (
    <Dialog open={open} onOpenChange={setOpen}>
      <DialogTrigger asChild>
        <Button variant="ghost" size="icon" className="h-8 w-8">
          <MoreVertical className="h-4 w-4" />
        </Button>
      </DialogTrigger>
      <DialogContent className="max-w-2xl max-h-[90vh] overflow-y-auto">
        <DialogHeader>
          <DialogTitle>Ações para {lead.name}</DialogTitle>
        </DialogHeader>

        <Tabs defaultValue="conversa" className="w-full">
          <TabsList className="grid w-full grid-cols-3">
            <TabsTrigger value="conversa">
              <MessageSquare className="h-4 w-4 mr-2" />
              Conversa
            </TabsTrigger>
            <TabsTrigger value="agenda">
              <Calendar className="h-4 w-4 mr-2" />
              Compromisso
            </TabsTrigger>
            <TabsTrigger value="tarefa">
              <CheckSquare className="h-4 w-4 mr-2" />
              Tarefa
            </TabsTrigger>
          </TabsList>

          <TabsContent value="conversa" className="space-y-4">
            <div className="text-center py-8 space-y-4">
              <MessageSquare className="h-16 w-16 mx-auto text-muted-foreground" />
              <p className="text-sm text-muted-foreground">
                {lead.telefone || lead.phone
                  ? "Abrir conversa do WhatsApp com este lead"
                  : "Lead não possui telefone cadastrado"}
              </p>
              <Button
                onClick={abrirConversa}
                disabled={!lead.telefone && !lead.phone}
                className="w-full"
              >
                <MessageSquare className="h-4 w-4 mr-2" />
                Abrir Conversa WhatsApp
              </Button>
            </div>
          </TabsContent>

          <TabsContent value="agenda" className="space-y-4">
            <div className="space-y-4">
              <div className="space-y-2">
                <Label htmlFor="tipoServico">Tipo de Serviço *</Label>
                <Input
                  id="tipoServico"
                  placeholder="Ex: Consulta, Reunião, Atendimento"
                  value={tipoServico}
                  onChange={(e) => setTipoServico(e.target.value)}
                />
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-2">
                  <Label htmlFor="dataInicio">Data/Hora Início *</Label>
                  <Input
                    id="dataInicio"
                    type="datetime-local"
                    value={dataHoraInicio}
                    onChange={(e) => setDataHoraInicio(e.target.value)}
                  />
                </div>

                <div className="space-y-2">
                  <Label htmlFor="dataFim">Data/Hora Fim *</Label>
                  <Input
                    id="dataFim"
                    type="datetime-local"
                    value={dataHoraFim}
                    onChange={(e) => setDataHoraFim(e.target.value)}
                  />
                </div>
              </div>

              <div className="space-y-2">
                <Label htmlFor="observacoes">Observações</Label>
                <Textarea
                  id="observacoes"
                  placeholder="Observações sobre o compromisso"
                  value={observacoes}
                  onChange={(e) => setObservacoes(e.target.value)}
                  rows={3}
                />
              </div>

              <Button onClick={criarCompromisso} disabled={loading} className="w-full">
                <Calendar className="h-4 w-4 mr-2" />
                {loading ? "Criando..." : "Criar Compromisso"}
              </Button>
            </div>
          </TabsContent>

          <TabsContent value="tarefa" className="space-y-4">
            <div className="space-y-4">
              <div className="space-y-2">
                <Label htmlFor="tituloTarefa">Título *</Label>
                <Input
                  id="tituloTarefa"
                  placeholder="Ex: Enviar proposta, Follow-up"
                  value={tituloTarefa}
                  onChange={(e) => setTituloTarefa(e.target.value)}
                />
              </div>

              <div className="space-y-2">
                <Label htmlFor="descricaoTarefa">Descrição</Label>
                <Textarea
                  id="descricaoTarefa"
                  placeholder="Detalhes da tarefa"
                  value={descricaoTarefa}
                  onChange={(e) => setDescricaoTarefa(e.target.value)}
                  rows={3}
                />
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-2">
                  <Label htmlFor="prioridade">Prioridade</Label>
                  <Select value={prioridadeTarefa} onValueChange={setPrioridadeTarefa}>
                    <SelectTrigger>
                      <SelectValue />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value="baixa">Baixa</SelectItem>
                      <SelectItem value="media">Média</SelectItem>
                      <SelectItem value="alta">Alta</SelectItem>
                      <SelectItem value="urgente">Urgente</SelectItem>
                    </SelectContent>
                  </Select>
                </div>

                <div className="space-y-2">
                  <Label htmlFor="dataVencimento">Data de Vencimento</Label>
                  <Input
                    id="dataVencimento"
                    type="date"
                    value={dataVencimento}
                    onChange={(e) => setDataVencimento(e.target.value)}
                  />
                </div>
              </div>

              <Button onClick={criarTarefa} disabled={loading} className="w-full">
                <CheckSquare className="h-4 w-4 mr-2" />
                {loading ? "Criando..." : "Criar Tarefa"}
              </Button>
            </div>
          </TabsContent>
        </Tabs>
      </DialogContent>
    </Dialog>
  );
}

import { useState } from "react";
import { Button } from "@/components/ui/button";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogDescription,
  DialogTrigger,
} from "@/components/ui/dialog";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Plus } from "lucide-react";
import { supabase } from "@/integrations/supabase/client";
import { toast } from "sonner";

interface AdicionarColunaDialogProps {
  boardId: string;
  currentColumnsCount: number;
  onColumnAdded: () => void;
}

const CORES_PADRAO = [
  "#3b82f6", // blue
  "#22c55e", // green
  "#eab308", // yellow
  "#f97316", // orange
  "#ef4444", // red
  "#8b5cf6", // purple
  "#ec4899", // pink
  "#06b6d4", // cyan
];

export function AdicionarColunaDialog({ 
  boardId, 
  currentColumnsCount, 
  onColumnAdded 
}: AdicionarColunaDialogProps) {
  const [open, setOpen] = useState(false);
  const [nome, setNome] = useState("");
  const [cor, setCor] = useState(CORES_PADRAO[0]);
  const [loading, setLoading] = useState(false);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    
    const nomeFormatado = nome.trim();
    
    if (!nomeFormatado) {
      toast.error("Digite o nome da coluna");
      return;
    }

    if (nomeFormatado.length < 2) {
      toast.error("Nome deve ter pelo menos 2 caracteres");
      return;
    }

    if (nomeFormatado.length > 50) {
      toast.error("Nome deve ter no máximo 50 caracteres");
      return;
    }

    setLoading(true);

    try {
      await supabase.functions.invoke("api-tarefas", {
        body: {
          action: "criar_coluna",
          data: {
            nome: nomeFormatado,
            board_id: boardId,
            posicao: currentColumnsCount,
            cor: cor,
          },
        },
      });

      toast.success(`Coluna "${nomeFormatado}" criada com sucesso!`);
      setNome("");
      setCor(CORES_PADRAO[0]);
      setOpen(false);
      onColumnAdded();
    } catch (error: any) {
      console.error("Erro ao criar coluna:", error);
      toast.error(error.message || "Erro ao criar coluna");
    } finally {
      setLoading(false);
    }
  };

  return (
    <Dialog open={open} onOpenChange={setOpen}>
      <DialogTrigger asChild>
        <Button variant="outline" size="sm">
          <Plus className="mr-2 h-4 w-4" />
          Nova Coluna
        </Button>
      </DialogTrigger>
      <DialogContent>
        <DialogHeader>
          <DialogTitle>Adicionar Nova Coluna</DialogTitle>
          <DialogDescription>
            Crie uma nova coluna para organizar suas tarefas
          </DialogDescription>
        </DialogHeader>
        <form onSubmit={handleSubmit} className="space-y-4">
          <div>
            <Label htmlFor="nome">Nome da Coluna *</Label>
            <Input
              id="nome"
              value={nome}
              onChange={(e) => setNome(e.target.value)}
              placeholder="Ex: Em Revisão, Aguardando Cliente"
              disabled={loading}
              maxLength={50}
              required
            />
            <p className="text-xs text-muted-foreground mt-1">
              {nome.length}/50 caracteres
            </p>
          </div>

          <div>
            <Label>Cor da Coluna</Label>
            <div className="flex gap-2 mt-2 flex-wrap">
              {CORES_PADRAO.map((corPadrao) => (
                <button
                  key={corPadrao}
                  type="button"
                  className="w-10 h-10 rounded-lg border-2 transition-all hover:scale-110 shadow-sm"
                  style={{
                    backgroundColor: corPadrao,
                    borderColor: cor === corPadrao ? "#000" : "transparent",
                    boxShadow: cor === corPadrao ? "0 0 0 2px rgba(0,0,0,0.1)" : "none",
                  }}
                  onClick={() => setCor(corPadrao)}
                  disabled={loading}
                  title={corPadrao}
                />
              ))}
              <div className="flex items-center ml-2">
                <Input
                  type="color"
                  value={cor}
                  onChange={(e) => setCor(e.target.value)}
                  className="w-10 h-10 p-1 cursor-pointer"
                  disabled={loading}
                  title="Escolher cor personalizada"
                />
              </div>
            </div>
          </div>

          <div className="flex justify-end gap-2 pt-4">
            <Button
              type="button"
              variant="outline"
              onClick={() => setOpen(false)}
              disabled={loading}
            >
              Cancelar
            </Button>
            <Button type="submit" disabled={loading}>
              {loading ? "Criando..." : "Criar Coluna"}
            </Button>
          </div>
        </form>
      </DialogContent>
    </Dialog>
  );
}

import { useState } from "react";
import { Button } from "@/components/ui/button";
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
} from "@/components/ui/alert-dialog";
import { Trash2 } from "lucide-react";
import { supabase } from "@/integrations/supabase/client";
import { toast } from "sonner";

interface DeletarColunaDialogProps {
  columnId: string;
  columnNome: string;
  onColumnDeleted: () => void;
}

export function DeletarColunaDialog({ 
  columnId, 
  columnNome, 
  onColumnDeleted 
}: DeletarColunaDialogProps) {
  const [open, setOpen] = useState(false);
  const [loading, setLoading] = useState(false);

  const handleDelete = async () => {
    setLoading(true);

    try {
      // Verificar se há tarefas na coluna
      const { data: tasks } = await supabase
        .from("tasks")
        .select("id")
        .eq("column_id", columnId);

      if (tasks && tasks.length > 0) {
        toast.error(
          `Esta coluna possui ${tasks.length} tarefa(s). Mova-as para outra coluna antes de excluir.`
        );
        setOpen(false);
        setLoading(false);
        return;
      }

      await supabase.functions.invoke("api-tarefas", {
        body: {
          action: "deletar_coluna",
          data: { column_id: columnId },
        },
      });

      toast.success(`Coluna "${columnNome}" excluída com sucesso!`);
      setOpen(false);
      onColumnDeleted();
    } catch (error: any) {
      console.error("Erro ao deletar coluna:", error);
      toast.error(error.message || "Erro ao deletar coluna");
    } finally {
      setLoading(false);
    }
  };

  return (
    <>
      <Button
        variant="ghost"
        size="icon"
        className="h-7 w-7 text-destructive hover:text-destructive"
        onClick={() => setOpen(true)}
        title="Deletar Coluna"
      >
        <Trash2 className="h-3.5 w-3.5" />
      </Button>

      <AlertDialog open={open} onOpenChange={setOpen}>
        <AlertDialogContent>
          <AlertDialogHeader>
            <AlertDialogTitle>Confirmar exclusão da coluna</AlertDialogTitle>
            <AlertDialogDescription>
              Tem certeza que deseja deletar a coluna <strong>"{columnNome}"</strong>?
              <br />
              <br />
              Esta ação não pode ser desfeita. Certifique-se de que não há tarefas nesta coluna.
            </AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogCancel disabled={loading}>Cancelar</AlertDialogCancel>
            <AlertDialogAction
              onClick={handleDelete}
              disabled={loading}
              className="bg-destructive text-destructive-foreground hover:bg-destructive/90"
            >
              {loading ? "Deletando..." : "Deletar Coluna"}
            </AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>
    </>
  );
}

