import { useState, useEffect } from "react";
import { Settings, Plus, Trash2, Pencil } from "lucide-react";
import { Button } from "@/components/ui/button";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogTrigger,
} from "@/components/ui/dialog";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { supabase } from "@/integrations/supabase/client";
import { toast } from "sonner";
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
} from "@/components/ui/alert-dialog";

interface Column {
  id: string;
  nome: string;
  posicao: number;
  cor: string;
  board_id: string;
}

interface EditarQuadroDialogProps {
  boardId: string;
  boardNome: string;
  onUpdated: () => void;
}

export function EditarQuadroDialog({ boardId, boardNome, onUpdated }: EditarQuadroDialogProps) {
  const [open, setOpen] = useState(false);
  const [columns, setColumns] = useState<Column[]>([]);
  const [novoNomeQuadro, setNovoNomeQuadro] = useState(boardNome);
  const [novaColunaNome, setNovaColunaNome] = useState("");
  const [novaColunaCor, setNovaColunaCor] = useState("#3b82f6");
  const [editandoColuna, setEditandoColuna] = useState<string | null>(null);
  const [nomeEditado, setNomeEditado] = useState("");
  const [corEditada, setCorEditada] = useState("");
  const [deleteDialogOpen, setDeleteDialogOpen] = useState(false);
  const [deleteColumnId, setDeleteColumnId] = useState<string | null>(null);
  const [deleteBoardDialogOpen, setDeleteBoardDialogOpen] = useState(false);

  useEffect(() => {
    if (open) {
      carregarColunas();
      setNovoNomeQuadro(boardNome);
    }
  }, [open, boardId, boardNome]);

  const carregarColunas = async () => {
    const { data } = await supabase
      .from("task_columns")
      .select("*")
      .eq("board_id", boardId)
      .order("posicao");
    setColumns(data || []);
  };

  const salvarNomeQuadro = async () => {
    if (!novoNomeQuadro.trim()) {
      toast.error("Digite um nome para o quadro");
      return;
    }

    try {
      await supabase.functions.invoke("api-tarefas", {
        body: {
          action: "editar_board",
          data: { board_id: boardId, nome: novoNomeQuadro },
        },
      });
      toast.success("Nome do quadro atualizado!");
      onUpdated();
    } catch (error) {
      toast.error("Erro ao atualizar nome do quadro");
    }
  };

  const adicionarColuna = async () => {
    if (!novaColunaNome.trim()) {
      toast.error("Digite um nome para a coluna");
      return;
    }

    try {
      await supabase.functions.invoke("api-tarefas", {
        body: {
          action: "criar_coluna",
          data: {
            nome: novaColunaNome,
            board_id: boardId,
            posicao: columns.length,
            cor: novaColunaCor,
          },
        },
      });
      toast.success("Coluna criada!");
      setNovaColunaNome("");
      setNovaColunaCor("#3b82f6");
      carregarColunas();
      onUpdated();
    } catch (error) {
      toast.error("Erro ao criar coluna");
    }
  };

  const salvarEdicaoColuna = async (colunaId: string) => {
    if (!nomeEditado.trim()) {
      toast.error("Digite um nome para a coluna");
      return;
    }

    try {
      await supabase.functions.invoke("api-tarefas", {
        body: {
          action: "editar_coluna",
          data: { column_id: colunaId, nome: nomeEditado, cor: corEditada },
        },
      });
      toast.success("Coluna atualizada!");
      setEditandoColuna(null);
      carregarColunas();
      onUpdated();
    } catch (error) {
      toast.error("Erro ao atualizar coluna");
    }
  };

  const confirmarExclusaoColuna = async () => {
    if (!deleteColumnId) return;

    try {
      // Verificar se há tarefas na coluna
      const { data: tasks } = await supabase
        .from("tasks")
        .select("id")
        .eq("column_id", deleteColumnId);

      if (tasks && tasks.length > 0) {
        toast.error(`Esta coluna possui ${tasks.length} tarefa(s). Mova-as antes de excluir.`);
        setDeleteDialogOpen(false);
        setDeleteColumnId(null);
        return;
      }

      await supabase.functions.invoke("api-tarefas", {
        body: {
          action: "deletar_coluna",
          data: { column_id: deleteColumnId },
        },
      });
      toast.success("Coluna excluída!");
      setDeleteDialogOpen(false);
      setDeleteColumnId(null);
      carregarColunas();
      onUpdated();
    } catch (error) {
      toast.error("Erro ao excluir coluna");
    }
  };

  const confirmarExclusaoQuadro = async () => {
    try {
      // Verificar se há colunas e tarefas
      const { data: tasks } = await supabase
        .from("tasks")
        .select("id")
        .eq("board_id", boardId);

      if (tasks && tasks.length > 0) {
        toast.error(`Este quadro possui ${tasks.length} tarefa(s). Exclua-as antes de excluir o quadro.`);
        setDeleteBoardDialogOpen(false);
        return;
      }

      await supabase.functions.invoke("api-tarefas", {
        body: {
          action: "deletar_board",
          data: { board_id: boardId },
        },
      });
      toast.success("Quadro excluído!");
      setDeleteBoardDialogOpen(false);
      setOpen(false);
      onUpdated();
    } catch (error) {
      toast.error("Erro ao excluir quadro");
    }
  };

  return (
    <>
      <Dialog open={open} onOpenChange={setOpen}>
        <DialogTrigger asChild>
          <Button variant="outline">
            <Settings className="mr-2 h-4 w-4" />
            Configurar Quadro
          </Button>
        </DialogTrigger>
        <DialogContent className="max-w-2xl max-h-[80vh] overflow-y-auto">
          <DialogHeader>
            <DialogTitle>Configurar Quadro</DialogTitle>
          </DialogHeader>

          <div className="space-y-6">
            {/* Nome do Quadro */}
            <div className="space-y-2">
              <Label>Nome do Quadro</Label>
              <div className="flex gap-2">
                <Input
                  value={novoNomeQuadro}
                  onChange={(e) => setNovoNomeQuadro(e.target.value)}
                  placeholder="Nome do quadro"
                />
                <Button onClick={salvarNomeQuadro}>Salvar</Button>
              </div>
            </div>

            {/* Lista de Colunas */}
            <div className="space-y-2">
              <Label>Colunas</Label>
              <div className="space-y-2">
                {columns.map((column) => (
                  <div key={column.id} className="flex items-center gap-2 p-2 border rounded-md">
                    {editandoColuna === column.id ? (
                      <>
                        <Input
                          value={nomeEditado}
                          onChange={(e) => setNomeEditado(e.target.value)}
                          className="flex-1"
                        />
                        <Input
                          type="color"
                          value={corEditada}
                          onChange={(e) => setCorEditada(e.target.value)}
                          className="w-16"
                        />
                        <Button size="sm" onClick={() => salvarEdicaoColuna(column.id)}>
                          Salvar
                        </Button>
                        <Button
                          size="sm"
                          variant="ghost"
                          onClick={() => setEditandoColuna(null)}
                        >
                          Cancelar
                        </Button>
                      </>
                    ) : (
                      <>
                        <div
                          className="w-8 h-8 rounded"
                          style={{ backgroundColor: column.cor }}
                        />
                        <span className="flex-1">{column.nome}</span>
                        <Button
                          size="sm"
                          variant="ghost"
                          onClick={() => {
                            setEditandoColuna(column.id);
                            setNomeEditado(column.nome);
                            setCorEditada(column.cor);
                          }}
                        >
                          <Pencil className="h-4 w-4" />
                        </Button>
                        <Button
                          size="sm"
                          variant="ghost"
                          onClick={() => {
                            setDeleteColumnId(column.id);
                            setDeleteDialogOpen(true);
                          }}
                          className="text-destructive"
                        >
                          <Trash2 className="h-4 w-4" />
                        </Button>
                      </>
                    )}
                  </div>
                ))}
              </div>
            </div>

            {/* Adicionar Nova Coluna */}
            <div className="space-y-2">
              <Label>Adicionar Coluna</Label>
              <div className="flex gap-2">
                <Input
                  value={novaColunaNome}
                  onChange={(e) => setNovaColunaNome(e.target.value)}
                  placeholder="Nome da coluna"
                  className="flex-1"
                />
                <Input
                  type="color"
                  value={novaColunaCor}
                  onChange={(e) => setNovaColunaCor(e.target.value)}
                  className="w-16"
                />
                <Button onClick={adicionarColuna}>
                  <Plus className="h-4 w-4" />
                </Button>
              </div>
            </div>

            {/* Excluir Quadro */}
            <div className="pt-4 border-t">
              <Button
                variant="destructive"
                onClick={() => setDeleteBoardDialogOpen(true)}
                className="w-full"
              >
                <Trash2 className="mr-2 h-4 w-4" />
                Excluir Quadro
              </Button>
            </div>
          </div>
        </DialogContent>
      </Dialog>

      {/* Dialog de confirmação de exclusão de coluna */}
      <AlertDialog open={deleteDialogOpen} onOpenChange={setDeleteDialogOpen}>
        <AlertDialogContent>
          <AlertDialogHeader>
            <AlertDialogTitle>Confirmar Exclusão</AlertDialogTitle>
            <AlertDialogDescription>
              Tem certeza que deseja excluir esta coluna? Esta ação não pode ser desfeita.
            </AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogCancel>Cancelar</AlertDialogCancel>
            <AlertDialogAction onClick={confirmarExclusaoColuna}>
              Excluir
            </AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>

      {/* Dialog de confirmação de exclusão de quadro */}
      <AlertDialog open={deleteBoardDialogOpen} onOpenChange={setDeleteBoardDialogOpen}>
        <AlertDialogContent>
          <AlertDialogHeader>
            <AlertDialogTitle>Confirmar Exclusão</AlertDialogTitle>
            <AlertDialogDescription>
              Tem certeza que deseja excluir este quadro? Todas as colunas serão excluídas. Esta ação não pode ser desfeita.
            </AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogCancel>Cancelar</AlertDialogCancel>
            <AlertDialogAction onClick={confirmarExclusaoQuadro}>
              Excluir
            </AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>
    </>
  );
}

import { useState, useEffect } from "react";
import { Pencil } from "lucide-react";
import { Button } from "@/components/ui/button";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogTrigger,
} from "@/components/ui/dialog";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import { supabase } from "@/integrations/supabase/client";
import { toast } from "sonner";

interface Task {
  id: string;
  title: string;
  description: string | null;
  priority: string;
  assignee_id: string | null;
  due_date: string | null;
  lead_id: string | null;
}

interface EditarTarefaDialogProps {
  task: Task;
  onTaskUpdated: () => void;
}

export function EditarTarefaDialog({ task, onTaskUpdated }: EditarTarefaDialogProps) {
  const [open, setOpen] = useState(false);
  const [title, setTitle] = useState(task.title);
  const [description, setDescription] = useState(task.description || "");
  const [priority, setPriority] = useState(task.priority);
  const [dueDate, setDueDate] = useState(
    task.due_date ? new Date(task.due_date).toISOString().split("T")[0] : ""
  );
  const [assigneeId, setAssigneeId] = useState(task.assignee_id || "");
  const [leadId, setLeadId] = useState(task.lead_id || "");
  const [users, setUsers] = useState<any[]>([]);
  const [leads, setLeads] = useState<any[]>([]);
  const [errors, setErrors] = useState<Record<string, string>>({});

  useEffect(() => {
    if (open) {
      loadData();
      setTitle(task.title);
      setDescription(task.description || "");
      setPriority(task.priority);
      setDueDate(task.due_date ? new Date(task.due_date).toISOString().split("T")[0] : "");
      setAssigneeId(task.assignee_id || "");
      setLeadId(task.lead_id || "");
    }
  }, [open, task]);

  const loadData = async () => {
    const { data: usersData } = await supabase.from("profiles").select("id, full_name");
    const { data: leadsData } = await supabase.from("leads").select("id, name");
    setUsers(usersData || []);
    setLeads(leadsData || []);
  };

  const validateForm = () => {
    const newErrors: Record<string, string> = {};

    // Validar título
    if (!title.trim()) {
      newErrors.title = "Título é obrigatório";
    } else if (title.trim().length < 3) {
      newErrors.title = "Título deve ter no mínimo 3 caracteres";
    } else if (title.length > 100) {
      newErrors.title = "Título deve ter no máximo 100 caracteres";
    }

    // Validar descrição
    if (description.length > 500) {
      newErrors.description = "Descrição deve ter no máximo 500 caracteres";
    }

    // Validar data
    if (dueDate) {
      const selectedDate = new Date(dueDate);
      const today = new Date();
      today.setHours(0, 0, 0, 0);
      
      if (selectedDate < today) {
        newErrors.dueDate = "A data não pode ser no passado";
      }
    }

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleSubmit = async () => {
    if (!validateForm()) {
      toast.error("Corrija os erros antes de salvar");
      return;
    }

    try {
      await supabase.functions.invoke("api-tarefas", {
        body: {
          action: "editar_tarefa",
          data: {
            task_id: task.id,
            title: title.trim(),
            description: description.trim(),
            priority,
            due_date: dueDate || null,
            assignee_id: assigneeId || null,
            lead_id: leadId || null,
          },
        },
      });

      toast.success("Tarefa atualizada com sucesso!");
      setOpen(false);
      setErrors({});
      onTaskUpdated();
    } catch (error) {
      console.error("Erro ao atualizar tarefa:", error);
      toast.error("Erro ao atualizar tarefa");
    }
  };

  return (
    <Dialog open={open} onOpenChange={setOpen}>
      <DialogTrigger asChild>
        <Button
          variant="ghost"
          size="sm"
          className="h-6 w-6 p-0"
          onClick={(e) => e.stopPropagation()}
        >
          <Pencil className="h-3 w-3" />
        </Button>
      </DialogTrigger>
      <DialogContent className="max-w-md">
        <DialogHeader>
          <DialogTitle>Editar Tarefa</DialogTitle>
        </DialogHeader>
        <div className="space-y-4">
          <div>
            <Label>Título *</Label>
            <Input
              value={title}
              onChange={(e) => {
                setTitle(e.target.value);
                if (errors.title) setErrors({ ...errors, title: "" });
              }}
              placeholder="Digite o título da tarefa"
              className={errors.title ? "border-destructive" : ""}
            />
            {errors.title && (
              <p className="text-xs text-destructive mt-1">{errors.title}</p>
            )}
          </div>

          <div>
            <Label>Descrição</Label>
            <Textarea
              value={description}
              onChange={(e) => {
                setDescription(e.target.value);
                if (errors.description) setErrors({ ...errors, description: "" });
              }}
              placeholder="Descreva a tarefa..."
              rows={3}
              className={errors.description ? "border-destructive" : ""}
            />
            {errors.description && (
              <p className="text-xs text-destructive mt-1">{errors.description}</p>
            )}
            <p className="text-xs text-muted-foreground mt-1">
              {description.length}/500 caracteres
            </p>
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div>
              <Label>Prioridade</Label>
              <Select value={priority} onValueChange={setPriority}>
                <SelectTrigger>
                  <SelectValue />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="baixa">Baixa</SelectItem>
                  <SelectItem value="media">Média</SelectItem>
                  <SelectItem value="alta">Alta</SelectItem>
                  <SelectItem value="urgente">Urgente</SelectItem>
                </SelectContent>
              </Select>
            </div>

            <div>
              <Label>Prazo</Label>
              <Input
                type="date"
                value={dueDate}
                onChange={(e) => {
                  setDueDate(e.target.value);
                  if (errors.dueDate) setErrors({ ...errors, dueDate: "" });
                }}
                className={errors.dueDate ? "border-destructive" : ""}
              />
              {errors.dueDate && (
                <p className="text-xs text-destructive mt-1">{errors.dueDate}</p>
              )}
            </div>
          </div>

          <div>
            <Label>Responsável</Label>
            <Select value={assigneeId} onValueChange={setAssigneeId}>
              <SelectTrigger>
                <SelectValue placeholder="Selecione um responsável" />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value="">Nenhum</SelectItem>
                {users.map((user) => (
                  <SelectItem key={user.id} value={user.id}>
                    {user.full_name}
                  </SelectItem>
                ))}
              </SelectContent>
            </Select>
          </div>

          <div>
            <Label>Lead Relacionado</Label>
            <Select value={leadId} onValueChange={setLeadId}>
              <SelectTrigger>
                <SelectValue placeholder="Selecione um lead" />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value="">Nenhum</SelectItem>
                {leads.map((lead) => (
                  <SelectItem key={lead.id} value={lead.id}>
                    {lead.name}
                  </SelectItem>
                ))}
              </SelectContent>
            </Select>
          </div>

          <Button onClick={handleSubmit} className="w-full">
            Salvar Alterações
          </Button>
        </div>
      </DialogContent>
    </Dialog>
  );
}

import { useState, useEffect } from "react";
import { Plus } from "lucide-react";
import { Button } from "@/components/ui/button";
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogTrigger,
} from "@/components/ui/dialog";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select";
import { supabase } from "@/integrations/supabase/client";
import { toast } from "sonner";

interface NovaTarefaDialogProps {
  columnId: string;
  boardId: string;
  onTaskCreated: () => void;
}

export function NovaTarefaDialog({
  columnId,
  boardId,
  onTaskCreated,
}: NovaTarefaDialogProps) {
  const [open, setOpen] = useState(false);
  const [title, setTitle] = useState("");
  const [description, setDescription] = useState("");
  const [priority, setPriority] = useState("media");
  const [dueDate, setDueDate] = useState("");
  const [assigneeId, setAssigneeId] = useState("");
  const [leadId, setLeadId] = useState("");
  const [users, setUsers] = useState<any[]>([]);
  const [leads, setLeads] = useState<any[]>([]);

  useEffect(() => {
    if (open) {
      loadData();
    }
  }, [open]);

  const loadData = async () => {
    const { data: usersData } = await supabase.from("profiles").select("id, full_name");
    const { data: leadsData } = await supabase.from("leads").select("id, name");
    setUsers(usersData || []);
    setLeads(leadsData || []);
  };

  const handleSubmit = async () => {
    if (!title.trim()) {
      toast.error("Digite um título para a tarefa");
      return;
    }

    try {
      const { data: { session } } = await supabase.auth.getSession();
      if (!session) {
        toast.error("Não autenticado");
        return;
      }

      await supabase.functions.invoke("api-tarefas", {
        body: {
          action: "criar_tarefa",
          data: {
            title,
            description,
            priority,
            due_date: dueDate || null,
            assignee_id: assigneeId || null,
            lead_id: leadId || null,
            column_id: columnId,
            board_id: boardId,
          },
        },
      });

      toast.success("Tarefa criada com sucesso!");
      setOpen(false);
      setTitle("");
      setDescription("");
      setPriority("media");
      setDueDate("");
      setAssigneeId("");
      setLeadId("");
      onTaskCreated();
    } catch (error) {
      console.error("Erro ao criar tarefa:", error);
      toast.error("Erro ao criar tarefa");
    }
  };

  return (
    <Dialog open={open} onOpenChange={setOpen}>
      <DialogTrigger asChild>
        <Button variant="ghost" size="sm" className="w-full justify-start">
          <Plus className="mr-2 h-4 w-4" />
          Nova Tarefa
        </Button>
      </DialogTrigger>
      <DialogContent className="max-w-md">
        <DialogHeader>
          <DialogTitle>Nova Tarefa</DialogTitle>
        </DialogHeader>
        <div className="space-y-4">
          <div>
            <Label>Título *</Label>
            <Input
              value={title}
              onChange={(e) => setTitle(e.target.value)}
              placeholder="Digite o título da tarefa"
            />
          </div>

          <div>
            <Label>Descrição</Label>
            <Textarea
              value={description}
              onChange={(e) => setDescription(e.target.value)}
              placeholder="Descreva a tarefa..."
              rows={3}
            />
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div>
              <Label>Prioridade</Label>
              <Select value={priority} onValueChange={setPriority}>
                <SelectTrigger>
                  <SelectValue />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="baixa">Baixa</SelectItem>
                  <SelectItem value="media">Média</SelectItem>
                  <SelectItem value="alta">Alta</SelectItem>
                  <SelectItem value="urgente">Urgente</SelectItem>
                </SelectContent>
              </Select>
            </div>

            <div>
              <Label>Prazo</Label>
              <Input
                type="date"
                value={dueDate}
                onChange={(e) => setDueDate(e.target.value)}
              />
            </div>
          </div>

          <div>
            <Label>Responsável</Label>
            <Select value={assigneeId} onValueChange={setAssigneeId}>
              <SelectTrigger>
                <SelectValue placeholder="Selecione um responsável" />
              </SelectTrigger>
              <SelectContent>
                {users.map((user) => (
                  <SelectItem key={user.id} value={user.id}>
                    {user.full_name}
                  </SelectItem>
                ))}
              </SelectContent>
            </Select>
          </div>

          <div>
            <Label>Lead Relacionado</Label>
            <Select value={leadId} onValueChange={setLeadId}>
              <SelectTrigger>
                <SelectValue placeholder="Selecione um lead" />
              </SelectTrigger>
              <SelectContent>
                {leads.map((lead) => (
                  <SelectItem key={lead.id} value={lead.id}>
                    {lead.name}
                  </SelectItem>
                ))}
              </SelectContent>
            </Select>
          </div>

          <Button onClick={handleSubmit} className="w-full">
            Criar Tarefa
          </Button>
        </div>
      </DialogContent>
    </Dialog>
  );
}

import * as React from "react";
import { cva, type VariantProps } from "class-variance-authority";

