    data_hora_inicio: string;
    tipo_servico: string;
    lead_id?: string;
  };
}

interface ScheduledMessage {
  id: string;
  conversationId: string;
  content: string;
  datetime: string;
}

interface Meeting {
  id: string;
  lead_id?: string;
  usuario_responsavel_id: string;
  data_hora_inicio: string;
  data_hora_fim: string;
  tipo_servico: string;
  status: string;
  observacoes?: string;
  custo_estimado?: number;
  lembrete_enviado: boolean;
  created_at: string;
  company_id?: string;
  lead?: {
    name: string;
    phone?: string;
  };
}

