      .on(
        'postgres_changes',
        {
          event: '*',
          schema: 'public',
          table: 'scheduled_whatsapp_messages',
        },
        (payload) => {
          console.log('📡 Atualização de mensagem agendada:', payload);
          carregarMensagensAgendadas();
