import React, { useState, useEffect } from "react";
import { DndContext, DragEndEvent, closestCenter } from "@dnd-kit/core";
import { Plus } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Label } from "@/components/ui/label";
import { supabase } from "@/integrations/supabase/client";
import { LeadCard } from "@/components/funil/LeadCard";
import { DroppableColumn } from "@/components/funil/DroppableColumn";
import { NovoLeadDialog } from "@/components/funil/NovoLeadDialog";
import { NovoFunilDialog } from "@/components/funil/NovoFunilDialog";
import { EditarFunilDialog } from "@/components/funil/EditarFunilDialog";
import { AdicionarEtapaDialog } from "@/components/funil/AdicionarEtapaDialog";
import { toast } from "sonner";

interface Lead {
  id: string;
  nome: string;
  name: string;
  company?: string;
  value?: number;
  telefone?: string;
  email?: string;
  cpf?: string;
  source?: string;
  notes?: string;
  etapa_id?: string;
  funil_id?: string;
}

interface Etapa {
  id: string;
  nome: string;
  posicao: number;
  cor: string;
  funil_id: string;
}

interface Funil {
  id: string;
  nome: string;
  descricao?: string;
}

export default function KanbanPage() {
  const [leads, setLeads] = useState<Lead[]>([]);
  const [etapas, setEtapas] = useState<Etapa[]>([]);
  const [funis, setFunis] = useState<Funil[]>([]);
  const [selectedFunil, setSelectedFunil] = useState<string>("");
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    let mounted = true;

    const loadData = async () => {
      try {
        setLoading(true);
        setError(null);

        // Carregar funis
        const { data: funisData, error: funisError } = await supabase
          .from("funis")
          .select("*")
          .order("criado_em");

        if (funisError) throw funisError;

        if (!mounted) return;

        // Atualizar funis
        const loadedFunis = funisData || [];
        setFunis(loadedFunis);

        // Selecionar primeiro funil se necessário
        if (loadedFunis.length > 0 && !selectedFunil) {
          setSelectedFunil(loadedFunis[0].id);
        }

        // Carregar etapas
        const { data: etapasData, error: etapasError } = await supabase
          .from("etapas")
          .select("*")
          .order("posicao");

        if (etapasError) throw etapasError;
        if (!mounted) return;

        setEtapas(etapasData || []);

        // Carregar leads
        const { data: leadsData, error: leadsError } = await supabase
          .from("leads")
          .select("*")
          .order("created_at", { ascending: false });

        if (leadsError) throw leadsError;
        if (!mounted) return;

        setLeads((leadsData || []).map(lead => ({
          ...lead,
          nome: lead.name || "",
          name: lead.name || ""
        })));

      } catch (err: any) {
        console.error("Erro ao carregar dados:", err);
        if (mounted) {
          setError(err.message || "Erro ao carregar dados");
          toast.error("Erro ao carregar funil de vendas");
        }
      } finally {
        if (mounted) {
          setLoading(false);
        }
      }
    };

    loadData();

    return () => {
      mounted = false;
    };
  }, [selectedFunil]);

  const handleDragEnd = async (event: DragEndEvent) => {
    try {
      const { active, over } = event;
      
      if (!over) return;

      const leadId = active.id as string;
      const overData = over.data.current;
      const newEtapaId = overData?.type === 'etapa' ? over.id as string : overData?.etapaId as string;
      
      if (!newEtapaId) {
        toast.error("Etapa de destino inválida");
        return;
      }

      const lead = leads.find(l => l.id === leadId);
      if (!lead) {
        toast.error("Lead não encontrado");
        return;
      }

      const etapaDestino = etapas.find(e => e.id === newEtapaId);
      if (!etapaDestino) {
        toast.error("Etapa de destino inválida");
        return;
      }

      // Atualizar localmente primeiro
      setLeads(leads => 
        leads.map(l => l.id === leadId ? { ...l, etapa_id: newEtapaId } : l)
      );

      // Atualizar no banco
      const { error } = await supabase
        .from("leads")
        .update({ 
          etapa_id: newEtapaId,
          funil_id: etapaDestino.funil_id,
          stage: etapaDestino.nome.toLowerCase()
        })
        .eq("id", leadId);

      if (error) throw error;
      
    } catch (error) {
      console.error("Erro ao mover lead:", error);
      toast.error("Erro ao mover lead");
    }
  };

  const etapasFiltradas = etapas.filter((etapa) => etapa.funil_id === selectedFunil);

  const calcularTotalEtapa = (etapaId: string) => {
    return leads
      .filter(l => l.etapa_id === etapaId)
      .reduce((total, lead) => total + (lead.value || 0), 0);
  };

  const funilSelecionado = funis.find(f => f.id === selectedFunil);

  if (loading) {
    return (
      <div className="container mx-auto p-6">
        <div className="flex justify-between items-center mb-6">
          <div>
            <h1 className="text-3xl font-bold">Funil de Vendas</h1>
            <p className="text-muted-foreground">Gerencie seus leads por etapas</p>
          </div>
        </div>
        <div className="flex items-center justify-center min-h-[500px]">
          <div className="text-center">
            <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-primary mb-4"></div>
            <p className="text-muted-foreground">Carregando funil de vendas...</p>
          </div>
        </div>
      </div>
    );
  }

  if (error) {
    return (
      <div className="container mx-auto p-6">
        <div className="flex justify-between items-center mb-6">
          <div>
            <h1 className="text-3xl font-bold">Funil de Vendas</h1>
            <p className="text-muted-foreground">Gerencie seus leads por etapas</p>
          </div>
        </div>
        <div className="flex items-center justify-center min-h-[500px]">
          <div className="text-center">
            <p className="text-red-500 mb-4">{error}</p>
            <Button onClick={() => window.location.reload()}>
              Tentar Novamente
            </Button>
          </div>
        </div>
      </div>
    );
  }

  if (!funis || funis.length === 0) {
    return (
      <div className="container mx-auto p-6">
        <div className="flex justify-between items-center mb-6">
          <div>
            <h1 className="text-3xl font-bold">Funil de Vendas</h1>
            <p className="text-muted-foreground">Gerencie seus leads por etapas</p>
          </div>
          <NovoFunilDialog onFunilCreated={() => window.location.reload()} />
        </div>
        <div className="text-center py-12">
          <p className="text-muted-foreground mb-4">Nenhum funil criado ainda</p>
          <NovoFunilDialog onFunilCreated={() => window.location.reload()} />
        </div>
      </div>
    );
  }

  return (
    <div className="container mx-auto p-6">
      <div className="flex justify-between items-center mb-6">
        <div>
          <h1 className="text-3xl font-bold">Funil de Vendas</h1>
          <p className="text-muted-foreground">Gerencie seus leads por etapas</p>
        </div>
        <div className="flex gap-2">
          <NovoFunilDialog onFunilCreated={() => window.location.reload()} />
          <NovoLeadDialog 
            onLeadCreated={() => window.location.reload()}
            triggerButton={
              <Button>
                <Plus className="mr-2 h-4 w-4" />
                Novo Lead
              </Button>
            }
          />
        </div>
      </div>

      <div className="mb-6 flex items-center gap-3">
        <div className="flex-1 max-w-xs">
          <Label>Funil</Label>
          <select 
            value={selectedFunil} 
            onChange={(e) => setSelectedFunil(e.target.value)} 
            className="w-full p-2 border rounded-md mt-2"
          >
            {funis.map((funil) => (
              <option key={funil.id} value={funil.id}>{funil.nome}</option>
            ))}
          </select>
        </div>
        {funilSelecionado && (
          <div className="mt-6 flex gap-2">
            <AdicionarEtapaDialog 
              funilId={funilSelecionado.id}
              onEtapaAdded={() => window.location.reload()}
            />
            <EditarFunilDialog 
              funilId={funilSelecionado.id}
              funilNome={funilSelecionado.nome}
              onFunilUpdated={() => window.location.reload()}
            />
          </div>
        )}
      </div>

      <DndContext collisionDetection={closestCenter} onDragEnd={handleDragEnd}>
        <div className="flex overflow-x-auto gap-4 pb-4">
          {etapasFiltradas.map((etapa) => {
            const totalEtapa = calcularTotalEtapa(etapa.id);
            const quantidadeLeads = leads.filter(l => l.etapa_id === etapa.id).length;
            const leadsNaEtapa = leads.filter(l => l.etapa_id === etapa.id);
            
            return (
              <div key={etapa.id} className="min-w-[300px] flex-shrink-0">
                <DroppableColumn
                  id={etapa.id}
                  cor={etapa.cor}
                  nome={etapa.nome}
                  quantidadeLeads={quantidadeLeads}
                  totalEtapa={totalEtapa}
                  onEtapaUpdated={() => window.location.reload()}
                >
                  {leadsNaEtapa.map((lead) => (
                    <LeadCard 
                      key={lead.id} 
                      lead={lead} 
                      onDelete={async (id) => {
                        try {
                          const { error } = await supabase.from("leads").delete().eq("id", id);
                          if (error) throw error;
                          toast.success("Lead deletado!");
                          window.location.reload();
                        } catch (error) {
                          console.error("Erro ao deletar lead:", error);
                          toast.error("Erro ao deletar lead");
                        }
                      }}
                      onLeadMoved={() => window.location.reload()}
                    />
                  ))}
                  {leadsNaEtapa.length === 0 && (
                    <div className="text-center py-8 text-muted-foreground text-sm">
                      Arraste leads para cá
                    </div>
                  )}
                </DroppableColumn>
              </div>
            );
          })}
        </div>
      </DndContext>
    </div>
  );
}

import { useState, useEffect } from "react";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Badge } from "@/components/ui/badge";
import { Plus, Upload, Search, Tag, MessageSquare, Phone, Mail, User, Building2 } from "lucide-react";
import { supabase } from "@/integrations/supabase/client";
import { useToast } from "@/hooks/use-toast";
import { LeadActionsDialog } from "@/components/leads/LeadActionsDialog";
import { LeadQuickActions } from "@/components/leads/LeadQuickActions";
import { LeadTagsDialog } from "@/components/leads/LeadTagsDialog";
import { TagsManager } from "@/components/leads/TagsManager";
import { NovoLeadDialog } from "@/components/funil/NovoLeadDialog";
import { ImportarLeadsDialog } from "@/components/funil/ImportarLeadsDialog";
import { formatPhoneNumber } from "@/utils/phoneFormatter";
import { useNavigate } from "react-router-dom";
import { useLeadsSync } from "@/hooks/useLeadsSync";

interface Lead {
  id: string;
  name: string;
  email: string | null;
  phone: string | null;
  telefone?: string | null;
  company: string | null;
  source: string | null;
  status: string;
  stage: string;
  value: number;
  created_at: string;
  tags?: string[];
  cpf?: string | null;
  notes?: string | null;
}

export default function Leads() {
  const [leads, setLeads] = useState<Lead[]>([]);
  const [filteredLeads, setFilteredLeads] = useState<Lead[]>([]);
  const [searchTerm, setSearchTerm] = useState("");
  const [selectedStatus, setSelectedStatus] = useState<string>("all");
  const [selectedTag, setSelectedTag] = useState<string | null>(null);
  const { toast } = useToast();
  const navigate = useNavigate();

  const abrirConversa = (leadId: string, leadName: string) => {
    navigate('/conversas', { state: { leadId } });
  };

  // Integrar sincronização de leads em tempo real
  useLeadsSync({
    onInsert: (newLead) => {
      console.log('📡 [Leads] Novo lead adicionado via sync:', newLead);
      setLeads(prev => [newLead, ...prev]);
    },
    onUpdate: (updatedLead) => {
      console.log('📡 [Leads] Lead atualizado via sync:', updatedLead);
      setLeads(prev => prev.map(lead => 
        lead.id === updatedLead.id ? updatedLead : lead
      ));
    },
    onDelete: (deletedLead) => {
      console.log('📡 [Leads] Lead removido via sync:', deletedLead);
      setLeads(prev => prev.filter(lead => lead.id !== deletedLead.id));
    },
    showNotifications: true
  });

  useEffect(() => {
    carregarLeads();
  }, []);

  useEffect(() => {
    filterLeads();
  }, [searchTerm, selectedStatus, selectedTag, leads]);

  const carregarLeads = async () => {
    const { data, error } = await supabase
      .from("leads")
      .select("*")
      .order("created_at", { ascending: false });

    if (error) {
      toast({
        variant: "destructive",
        title: "Erro ao carregar leads",
        description: error.message,
      });
    } else {
      setLeads(data || []);
    }
  };

  const filterLeads = () => {
    let filtered = leads;

    if (searchTerm) {
      filtered = filtered.filter(
        (lead) =>
          lead.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
          lead.email?.toLowerCase().includes(searchTerm.toLowerCase()) ||
          lead.phone?.includes(searchTerm) ||
          lead.telefone?.includes(searchTerm) ||
          lead.company?.toLowerCase().includes(searchTerm.toLowerCase())
      );
    }

    if (selectedStatus !== "all") {
      filtered = filtered.filter((lead) => lead.status === selectedStatus);
    }

    if (selectedTag) {
      filtered = filtered.filter((lead) => 
        lead.tags?.includes(selectedTag)
      );
    }

    setFilteredLeads(filtered);
  };

  const getStatusColor = (status: string) => {
    const colors: Record<string, string> = {
      novo: "bg-blue-500",
      contato: "bg-yellow-500",
      qualificado: "bg-green-500",
      proposta: "bg-purple-500",
      ganho: "bg-emerald-500",
      perdido: "bg-red-500",
    };
    return colors[status] || "bg-gray-500";
  };

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-3xl font-bold text-foreground">Leads</h1>
          <p className="text-muted-foreground">
            Gerencie todos os seus leads em um só lugar
          </p>
        </div>
        <div className="flex gap-2">
          <TagsManager 
            onTagSelected={setSelectedTag}
            selectedTag={selectedTag}
          />
          <ImportarLeadsDialog onLeadsImported={carregarLeads} />
          <NovoLeadDialog onLeadCreated={carregarLeads} />
        </div>
      </div>

      <div className="space-y-3">
        <div className="flex gap-4">
          <div className="relative flex-1">
            <Search className="absolute left-3 top-1/2 h-4 w-4 -translate-y-1/2 text-muted-foreground" />
            <Input
              placeholder="Buscar por nome, email, telefone ou empresa..."
              className="pl-10"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
          </div>
          <div className="flex gap-2">
            <Button
              variant={selectedStatus === "all" ? "default" : "outline"}
              onClick={() => setSelectedStatus("all")}
            >
              Todos
            </Button>
            <Button
              variant={selectedStatus === "novo" ? "default" : "outline"}
              onClick={() => setSelectedStatus("novo")}
            >
              Novos
            </Button>
            <Button
              variant={selectedStatus === "qualificado" ? "default" : "outline"}
              onClick={() => setSelectedStatus("qualificado")}
            >
              Qualificados
            </Button>
          </div>
        </div>

        {/* Filtro ativo de tag */}
        {selectedTag && (
          <div className="flex items-center gap-2 p-3 bg-primary/10 rounded-lg border border-primary/20">
            <Tag className="h-4 w-4 text-primary" />
            <span className="text-sm font-medium">Filtrando por tag:</span>
            <Badge variant="secondary" className="gap-1">
              {selectedTag}
            </Badge>
            <Button
              variant="ghost"
              size="sm"
              className="ml-auto"
              onClick={() => setSelectedTag(null)}
            >
              Limpar filtro
            </Button>
          </div>
        )}
      </div>

      <div className="grid gap-4">
        {filteredLeads.map((lead) => (
          <Card key={lead.id} className="transition-all hover:shadow-lg">
            <CardContent className="p-6">
              <div className="flex items-start justify-between">
                <div className="flex-1 space-y-3">
                  <div className="flex items-center gap-3">
                    <h3 className="text-lg font-semibold">{lead.name}</h3>
                    <Badge className={getStatusColor(lead.status)}>
                      {lead.status}
                    </Badge>
                    {lead.source && (
                      <Badge variant="outline">
                        <Tag className="mr-1 h-3 w-3" />
                        {lead.source}
                      </Badge>
                    )}
                  </div>
                  
                  {lead.tags && lead.tags.length > 0 && (
                    <div className="flex flex-wrap gap-2">
                      {lead.tags.map((tag) => (
                        <Badge key={tag} variant="secondary" className="gap-1">
                          <Tag className="h-3 w-3" />
                          {tag}
                        </Badge>
                      ))}
                    </div>
                  )}
                  <div className="grid grid-cols-3 gap-4 text-sm text-muted-foreground">
                    {lead.email && (
                      <div className="flex items-center gap-2">
                        <Mail className="h-4 w-4" />
                        {lead.email}
                      </div>
                    )}
                    {lead.phone && (
                      <div className="flex items-center gap-2">
                        <Phone className="h-4 w-4" />
                        {lead.phone}
                        <Button
                          variant="ghost"
                          size="sm"
                          className="h-6 px-2 ml-2 text-[#25D366] hover:text-[#25D366] hover:bg-[#25D366]/10 transition-all"
                          onClick={() => abrirConversa(lead.id, lead.name)}
                          title="Abrir Conversa no WhatsApp"
                        >
                          <MessageSquare className="h-3.5 w-3.5 mr-1" />
                          <span className="text-xs font-medium">WhatsApp</span>
                        </Button>
                      </div>
                    )}
                    {lead.company && (
                      <div className="flex items-center gap-2">
                        <Building2 className="h-4 w-4" />
                        <span className="font-medium">{lead.company}</span>
                      </div>
                    )}
                  </div>
                </div>
                <div className="flex flex-col items-end gap-2">
                  <div className="text-xl font-bold text-primary">
                    R$ {Number(lead.value).toLocaleString("pt-BR")}
                  </div>
                  <div className="flex gap-2">
                    <LeadQuickActions 
                      leadId={lead.id} 
                      leadName={lead.name} 
                      leadPhone={lead.phone || lead.telefone || undefined}
                    />
                    <LeadTagsDialog 
                      leadId={lead.id}
                      currentTags={lead.tags}
                      onTagsUpdated={carregarLeads}
                      triggerButton={
                        <Button variant="outline" size="sm">
                          <Tag className="h-4 w-4 mr-2" />
                          Tags
                        </Button>
                      }
                    />
                  </div>
                </div>
              </div>
            </CardContent>
          </Card>
        ))}
      </div>

      {filteredLeads.length === 0 && (
        <Card>
          <CardContent className="flex flex-col items-center justify-center py-12">
            <p className="text-muted-foreground">Nenhum lead encontrado</p>
          </CardContent>
        </Card>
      )}
    </div>
  );
}

import { useState, useEffect } from "react";
import { DndContext, DragEndEvent, closestCorners } from "@dnd-kit/core";
import { SortableContext, verticalListSortingStrategy } from "@dnd-kit/sortable";
import { Plus, Settings } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogTrigger } from "@/components/ui/dialog";
import { supabase } from "@/integrations/supabase/client";
import { TaskCard } from "@/components/tarefas/TaskCard";
import { NovaTarefaDialog } from "@/components/tarefas/NovaTarefaDialog";
import { EditarQuadroDialog } from "@/components/tarefas/EditarQuadroDialog";
import { AdicionarColunaDialog } from "@/components/tarefas/AdicionarColunaDialog";
import { EditarColunaDialog } from "@/components/tarefas/EditarColunaDialog";
import { DeletarColunaDialog } from "@/components/tarefas/DeletarColunaDialog";
import { toast } from "sonner";

interface Task {
  id: string;
  title: string;
  description: string | null;
  priority: string;
  assignee_id: string | null;
  assignee_name?: string;
  due_date: string | null;
  lead_id: string | null;
  lead_name?: string;
  column_id?: string | null;
  board_id?: string | null;
}

interface Column {
  id: string;
  nome: string;
  posicao: number;
  cor: string;
  board_id: string;
}

interface Board {
  id: string;
  nome: string;
  descricao?: string;
}

export default function Tarefas() {
  const [tasks, setTasks] = useState<Task[]>([]);
  const [columns, setColumns] = useState<Column[]>([]);
  const [boards, setBoards] = useState<Board[]>([]);
  const [selectedBoard, setSelectedBoard] = useState<string>("");
  const [loading, setLoading] = useState(true);
  const [novoBoardNome, setNovoBoardNome] = useState("");
  const [dialogNovoBoard, setDialogNovoBoard] = useState(false);

  useEffect(() => {
    carregarDados();
  }, []);

  const carregarDados = async () => {
    try {
      setLoading(true);
      
      const { data: boardsData } = await supabase.from("task_boards").select("*").order("criado_em");
      setBoards(boardsData || []);
      
      if (!selectedBoard && boardsData && boardsData.length > 0) {
        setSelectedBoard(boardsData[0].id);
      }

      const { data: columnsData } = await supabase.from("task_columns").select("*").order("posicao");
      setColumns(columnsData || []);

      const { data: tasksData } = await supabase
        .from("tasks")
        .select(`
          *,
          assignee:profiles!tasks_assignee_id_fkey(full_name),
          lead:leads!tasks_lead_id_fkey(name)
        `)
        .order("created_at", { ascending: false });

      const formattedTasks = (tasksData || []).map((task: any) => ({
        ...task,
        assignee_name: task.assignee?.full_name,
        lead_name: task.lead?.name,
      }));
      setTasks(formattedTasks);
    } catch (error) {
      console.error("Erro ao carregar dados:", error);
      toast.error("Erro ao carregar dados das tarefas");
    } finally {
      setLoading(false);
    }
  };

  const handleDragEnd = async (event: DragEndEvent) => {
    const { active, over } = event;
    if (!over) return;

    const taskId = active.id as string;
    let newColumnId = over.id as string;

    // Se arrastou sobre outra tarefa, buscar o column_id dessa tarefa
    const overTask = tasks.find(t => t.id === newColumnId);
    if (overTask && overTask.column_id) {
      newColumnId = overTask.column_id;
    }

    // Verificar se é uma coluna válida
    const isValidColumn = columns.some(c => c.id === newColumnId);
    if (!isValidColumn) {
      toast.error("Coluna inválida");
      return;
    }

    setTasks((tasks) => 
      tasks.map((task) => 
        task.id === taskId ? { ...task, column_id: newColumnId } : task
      )
    );

    try {
      const { data: { session } } = await supabase.auth.getSession();
      if (!session) return toast.error("Não autenticado");

      await supabase.functions.invoke("api-tarefas", {
        body: { action: "mover_tarefa", data: { task_id: taskId, nova_coluna_id: newColumnId } }
      });

      toast.success("Tarefa movida!");
    } catch (error) {
      toast.error("Erro ao mover tarefa");
      carregarDados();
    }
  };

  const criarNovoBoard = async () => {
    if (!novoBoardNome.trim()) return;

    try {
      const { data: boardData } = await supabase.functions.invoke("api-tarefas", {
        body: { action: "criar_board", data: { nome: novoBoardNome } }
      });

      const newBoardId = boardData?.data?.id;

      // Criar colunas padrão
      if (newBoardId) {
        const colunasDefault = [
          { nome: "A Fazer", cor: "#3b82f6", posicao: 0 },
          { nome: "Em Progresso", cor: "#eab308", posicao: 1 },
          { nome: "Concluído", cor: "#22c55e", posicao: 2 },
        ];

        for (const coluna of colunasDefault) {
          await supabase.functions.invoke("api-tarefas", {
            body: {
              action: "criar_coluna",
              data: { ...coluna, board_id: newBoardId },
            },
          });
        }
      }

      toast.success("Quadro criado com colunas padrão!");
      setNovoBoardNome("");
      setDialogNovoBoard(false);
      carregarDados();
    } catch (error) {
      toast.error("Erro ao criar quadro");
    }
  };

  const columnsFiltradas = columns.filter((column) => column.board_id === selectedBoard);

  if (loading) return <div className="flex items-center justify-center h-screen"><p>Carregando...</p></div>;

  return (
    <div className="container mx-auto p-6">
      <div className="flex justify-between items-center mb-6">
        <div>
          <h1 className="text-3xl font-bold">Tarefas (Trello Style)</h1>
          <p className="text-muted-foreground">Gerencie suas tarefas em quadros Kanban</p>
        </div>
        <div className="flex gap-2">
          {selectedBoard && (
            <EditarQuadroDialog
              boardId={selectedBoard}
              boardNome={boards.find((b) => b.id === selectedBoard)?.nome || ""}
              onUpdated={carregarDados}
            />
          )}
          <Dialog open={dialogNovoBoard} onOpenChange={setDialogNovoBoard}>
            <DialogTrigger asChild>
              <Button variant="outline">
                <Plus className="mr-2 h-4 w-4" />
                Novo Quadro
              </Button>
            </DialogTrigger>
            <DialogContent>
              <DialogHeader>
                <DialogTitle>Criar Novo Quadro</DialogTitle>
              </DialogHeader>
              <div className="space-y-4">
                <div>
                  <Label>Nome do Quadro</Label>
                  <Input 
                    value={novoBoardNome} 
                    onChange={(e) => setNovoBoardNome(e.target.value)} 
                    placeholder="Ex: Projeto Q1 2024"
                  />
                </div>
                <Button onClick={criarNovoBoard} className="w-full">
                  Criar
                </Button>
              </div>
            </DialogContent>
          </Dialog>
        </div>
      </div>

      {boards.length > 0 && (
        <div className="mb-6">
          <Label>Quadro</Label>
          <select 
            value={selectedBoard} 
            onChange={(e) => setSelectedBoard(e.target.value)} 
            className="w-full max-w-xs p-2 border rounded-md mt-2"
          >
            {boards.map((board) => (
              <option key={board.id} value={board.id}>
                {board.nome}
              </option>
            ))}
          </select>
        </div>
      )}

      {boards.length === 0 ? (
        <div className="text-center py-12">
          <Button onClick={() => setDialogNovoBoard(true)}>
            <Plus className="mr-2" />
            Criar Primeiro Quadro
          </Button>
        </div>
      ) : columnsFiltradas.length === 0 ? (
        <div className="text-center py-12">
          <p className="text-muted-foreground mb-4">Nenhuma coluna criada ainda</p>
          <p className="text-sm text-muted-foreground">
            Crie colunas como "A Fazer", "Em Progresso", "Concluído"
          </p>
        </div>
      ) : (
        <DndContext collisionDetection={closestCorners} onDragEnd={handleDragEnd}>
          <div className="flex overflow-x-auto gap-4 pb-4">
            {columnsFiltradas.map((column) => (
              <div key={column.id} className="min-w-[300px] flex-shrink-0">
                <div 
                  className="text-white p-3 rounded-t-lg" 
                  style={{ backgroundColor: column.cor }}
                >
                  <div className="flex items-center justify-between mb-2">
                    <h3 className="font-semibold">{column.nome}</h3>
                    <div className="flex gap-1">
                      <EditarColunaDialog
                        columnId={column.id}
                        nomeAtual={column.nome}
                        corAtual={column.cor}
                        onColumnUpdated={carregarDados}
                      />
                      <DeletarColunaDialog
                        columnId={column.id}
                        columnNome={column.nome}
                        onColumnDeleted={carregarDados}
                      />
                    </div>
                  </div>
                  <span className="text-sm">
                    {tasks.filter(t => t.column_id === column.id).length} tarefas
                  </span>
                </div>
                <SortableContext 
                  id={column.id} 
                  items={tasks.filter(t => t.column_id === column.id)} 
                  strategy={verticalListSortingStrategy}
                >
                  <div className="bg-secondary/20 p-4 rounded-b-lg min-h-[500px]">
                    <NovaTarefaDialog 
                      columnId={column.id} 
                      boardId={selectedBoard} 
                      onTaskCreated={carregarDados} 
                    />
                    {tasks.filter(t => t.column_id === column.id).map((task) => (
                      <TaskCard 
                        key={task.id} 
                        task={task}
                        onDelete={async (id) => {
                          await supabase.functions.invoke("api-tarefas", { 
                            body: { action: "deletar_tarefa", data: { task_id: id } } 
                          });
                          carregarDados();
                        }}
                        onUpdate={carregarDados}
                      />
                    ))}
                  </div>
                </SortableContext>
              </div>
            ))}
            {/* Botão para adicionar nova coluna */}
            <div className="min-w-[280px] flex-shrink-0">
              <AdicionarColunaDialog
                boardId={selectedBoard}
                currentColumnsCount={columnsFiltradas.length}
                onColumnAdded={carregarDados}
              />
            </div>
          </div>
        </DndContext>
      )}
    </div>
  );
}

import { serve } from "https://deno.land/std@0.177.0/http/server.ts";
import { z } from "https://deno.land/x/zod@v3.22.4/mod.ts";

const corsHeaders = {
  'Access-Control-Allow-Origin': '*',
  'Access-Control-Allow-Headers': 'authorization, x-client-info, apikey, content-type',
};

// Input validation schema
const enviarWhatsAppSchema = z.object({
  numero: z.string()
    .regex(/^[0-9]{10,15}$/, 'Número deve ter entre 10-15 dígitos')
    .transform(val => val.replace(/[^0-9]/g, '')),
  mensagem: z.string()
    .min(1, 'Mensagem não pode ser vazia')
    .max(4096, 'Mensagem muito longa')
    .optional(),
  tipo_mensagem: z.enum(['text', 'texto', 'image', 'audio', 'video', 'document', 'pdf']).optional(),
  mediaUrl: z.string().url('URL de mídia inválida').optional(),
  mediaBase64: z.string().optional(),
  fileName: z.string().optional(),
  mimeType: z.string().optional(),
  caption: z.string().optional(),
  company_id: z.string().uuid('Company ID deve ser UUID válido').optional(),
  quoted: z.object({
    key: z.object({
      id: z.string()
    }),
    message: z.object({
      conversation: z.string()
    })
  }).optional()
}).refine(data => data.mensagem || data.mediaUrl || data.mediaBase64, {
  message: 'Mensagem, mídia URL ou mídia Base64 é obrigatória'
});

serve(async (req) => {
  // Handle CORS preflight requests
  if (req.method === 'OPTIONS') {
    return new Response(null, { headers: corsHeaders });
  }

  try {
    const body = await req.json();

    // Validate input with Zod
    let validatedData;
    try {
      validatedData = enviarWhatsAppSchema.parse(body);
    } catch (error) {
      if (error instanceof z.ZodError) {
        console.error("❌ Dados de entrada inválidos:", error.errors);
        return new Response(
          JSON.stringify({ 
            error: 'Dados inválidos fornecidos',
            code: 'VALIDATION_ERROR',
            details: error.errors
          }),
          { status: 400, headers: { ...corsHeaders, "Content-Type": "application/json" } }
        );
      }
      throw error;
    }

    console.log("📨 Pedido de envio validado");

    // Buscar configurações dos secrets
    const EVOLUTION_API_URL = Deno.env.get("EVOLUTION_API_URL");
    const EVOLUTION_API_KEY = Deno.env.get("EVOLUTION_API_KEY");
    const SUPABASE_URL = Deno.env.get("SUPABASE_URL");
    const SUPABASE_SERVICE_ROLE_KEY = Deno.env.get("SUPABASE_SERVICE_ROLE_KEY");

    if (!EVOLUTION_API_URL || !EVOLUTION_API_KEY) {
      console.error("❌ Variáveis de ambiente da Evolution API não configuradas");
      return new Response(
        JSON.stringify({ 
          error: "Configuração da Evolution API incompleta",
          code: "CONFIG_ERROR"
        }),
        { status: 500, headers: { ...corsHeaders, "Content-Type": "application/json" } }
      );
    }

    // Buscar instância WhatsApp da company
    let EVOLUTION_INSTANCE: string;
    let INSTANCE_API_KEY: string = EVOLUTION_API_KEY;
    
    if (validatedData.company_id) {
      console.log("🔍 Buscando instância WhatsApp para company:", validatedData.company_id);
      
      // Criar cliente Supabase
      const { createClient } = await import('https://esm.sh/@supabase/supabase-js@2');
      const supabase = createClient(SUPABASE_URL!, SUPABASE_SERVICE_ROLE_KEY!);
      
      // Buscar conexão WhatsApp ativa da company (incluindo API key)
      const { data: connection, error: connError } = await supabase
        .from('whatsapp_connections')
        .select('instance_name, whatsapp_number, evolution_api_key')
        .eq('company_id', validatedData.company_id)
        .eq('status', 'connected')
        .single();
      
      if (connError || !connection) {
        console.error("❌ Nenhuma conexão WhatsApp ativa encontrada para esta empresa");
        return new Response(
          JSON.stringify({ 
            error: "Nenhuma conexão WhatsApp ativa encontrada",
            code: "NO_WHATSAPP_CONNECTION"
          }),
          { status: 404, headers: { ...corsHeaders, "Content-Type": "application/json" } }
        );
      }
      
      EVOLUTION_INSTANCE = connection.instance_name;
      
      // Usar API key da conexão se disponível
      if (connection.evolution_api_key) {
        INSTANCE_API_KEY = connection.evolution_api_key;
        console.log("✅ Usando API key da instância:", EVOLUTION_INSTANCE);
      }
      
      console.log("✅ Instância encontrada:", EVOLUTION_INSTANCE, "- Número:", connection.whatsapp_number);
    } else {
      // Fallback para instância padrão (compatibilidade)
      EVOLUTION_INSTANCE = Deno.env.get("EVOLUTION_INSTANCE") || "";
      if (!EVOLUTION_INSTANCE) {
        console.error("❌ Instância não especificada e sem fallback");
        return new Response(
          JSON.stringify({ 
            error: "Instância WhatsApp não especificada",
            code: "NO_INSTANCE"
          }),
          { status: 400, headers: { ...corsHeaders, "Content-Type": "application/json" } }
        );
      }
      console.log("⚠️ Usando instância padrão:", EVOLUTION_INSTANCE);
    }

    // Formatar número no formato correto
    const numeroFormatado = validatedData.numero.includes("@s.whatsapp.net")
      ? validatedData.numero
      : `${validatedData.numero}@s.whatsapp.net`;

    console.log("📞 Número formatado");

    let evolutionUrl: string;
    let bodyPayload: any;

    // Verificar se é mídia (base64, URL) ou texto
    if (validatedData.mediaBase64) {
      // Enviar mídia via base64
      evolutionUrl = `${EVOLUTION_API_URL}/message/sendMedia/${EVOLUTION_INSTANCE}`;
      
      // Normalizar tipo de mídia
      let mediaType = validatedData.tipo_mensagem || 'document';
      if (mediaType === 'texto') mediaType = 'text';
      // PDF e document são mantidos como document
      if (mediaType === 'pdf') mediaType = 'document';
      
      // Definir mimeType baseado no tipo de mídia e extensão do arquivo
      let mimeType = validatedData.mimeType;
      if (!mimeType) {
        const fileName = validatedData.fileName?.toLowerCase() || '';
        
        // Detectar por tipo de mídia primeiro
        if (mediaType === 'image') {
          if (fileName.endsWith('.png')) mimeType = 'image/png';
          else if (fileName.endsWith('.gif')) mimeType = 'image/gif';
          else if (fileName.endsWith('.webp')) mimeType = 'image/webp';
          else mimeType = 'image/jpeg'; // default para imagens
        } else if (mediaType === 'audio') {
          if (fileName.endsWith('.ogg')) mimeType = 'audio/ogg';
          else if (fileName.endsWith('.wav')) mimeType = 'audio/wav';
          else if (fileName.endsWith('.m4a')) mimeType = 'audio/mp4';
          else mimeType = 'audio/mpeg'; // default para áudio
        } else if (mediaType === 'video') {
          if (fileName.endsWith('.mov')) mimeType = 'video/quicktime';
          else if (fileName.endsWith('.avi')) mimeType = 'video/x-msvideo';
          else if (fileName.endsWith('.webm')) mimeType = 'video/webm';
          else mimeType = 'video/mp4'; // default para vídeo
        } else if (validatedData.tipo_mensagem === 'pdf' || fileName.endsWith('.pdf')) {
          mimeType = 'application/pdf';
        } else {
          // Detectar por extensão para documentos
          if (fileName.endsWith('.doc') || fileName.endsWith('.docx')) {
            mimeType = 'application/vnd.openxmlformats-officedocument.wordprocessingml.document';
          } else if (fileName.endsWith('.xls') || fileName.endsWith('.xlsx')) {
            mimeType = 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet';
          } else if (fileName.endsWith('.ppt') || fileName.endsWith('.pptx')) {
            mimeType = 'application/vnd.openxmlformats-officedocument.presentationml.presentation';
          } else if (fileName.endsWith('.txt')) {
            mimeType = 'text/plain';
          } else if (fileName.endsWith('.zip')) {
            mimeType = 'application/zip';
          } else {
            mimeType = 'application/octet-stream'; // fallback genérico
          }
        }
        
        console.log(`📄 MIME type detectado: ${mimeType} (arquivo: ${fileName})`);
      }
      
      bodyPayload = {
        number: numeroFormatado,
        mediatype: mediaType,
        mimetype: mimeType,
        caption: validatedData.caption || validatedData.mensagem || "",
        fileName: validatedData.fileName || 'arquivo',
        media: validatedData.mediaBase64,
      };
      console.log(`📸 Enviando mídia base64 (${mediaType})`);
    } else if (validatedData.mediaUrl) {
      // Enviar mídia via URL
      evolutionUrl = `${EVOLUTION_API_URL}/message/sendMedia/${EVOLUTION_INSTANCE}`;
      bodyPayload = {
        number: numeroFormatado,
        mediaUrl: validatedData.mediaUrl,
        caption: validatedData.mensagem || validatedData.caption || "",
      };
      console.log("📸 Enviando mídia via URL");
    } else {
      // Enviar texto
      evolutionUrl = `${EVOLUTION_API_URL}/message/sendText/${EVOLUTION_INSTANCE}`;
      bodyPayload = {
        number: numeroFormatado,
        text: validatedData.mensagem,
      };
      
      // Adicionar mensagem citada se houver
      if (validatedData.quoted) {
        bodyPayload.quoted = validatedData.quoted;
        console.log("💬 Enviando texto com citação");
      } else {
        console.log("💬 Enviando texto");
      }
    }

    // Enviar para Evolution API
    const response = await fetch(evolutionUrl, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        "apikey": INSTANCE_API_KEY,
      },
      body: JSON.stringify(bodyPayload),
    });

    const result = await response.json();

    if (!response.ok) {
      console.error("❌ Erro Evolution API:", {
        status: response.status,
        statusText: response.statusText,
        url: evolutionUrl,
        payload: bodyPayload,
        result: result
      });
      return new Response(
        JSON.stringify({
          error: "Falha ao enviar mensagem",
          code: "EXTERNAL_API_ERROR",
          details: result
        }),
        { status: 500, headers: { ...corsHeaders, "Content-Type": "application/json" } }
      );
    }

    console.log("✅ Mensagem enviada com sucesso");
    
    return new Response(
      JSON.stringify({ 
        success: true, 
        message: "Mensagem enviada com sucesso"
      }), {
      status: 200,
      headers: { ...corsHeaders, "Content-Type": "application/json" },
    });
  } catch (e) {
    console.error("❌ Erro geral:", e);
    return new Response(
      JSON.stringify({ 
        error: "Erro interno ao processar requisição",
        code: "INTERNAL_ERROR"
      }),
      { status: 500, headers: { ...corsHeaders, "Content-Type": "application/json" } }
    );
  }
});

